-- Poems batch 439
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-0','聞笛','張巡','唐','御定全唐诗','yuding','','[]','岧嶢試一臨，虜騎附城陰。不辨風塵色，安知天地心。',48,'御定全唐詩/json/158.json','["岧嶢試一臨，虜騎附城陰。不辨風塵色，安知天地心。", "營開邊月近，戰苦陣雲深。旦夕更樓上，遙聞橫笛音。"]'),
('yuding-1','守睢陽作','張巡','唐','御定全唐诗','yuding','','[]','接戰春來苦，孤城日漸危。合圍侔月暈，分守若魚麗。',72,'御定全唐詩/json/158.json','["接戰春來苦，孤城日漸危。合圍侔月暈，分守若魚麗。", "屢厭黃塵起，時將白羽揮。裹瘡猶出陣，飲血更登陴。", "忠信應難敵，堅貞諒不移。無人報天子，心計欲何施。"]'),
('yuding-2','題衡陽泗州寺','張抃','唐','御定全唐诗','yuding','','[]','一水悠悠百粵通，片帆無奈信秋風。幾層峽浪寒舂月，',40,'御定全唐詩/json/158.json','["一水悠悠百粵通，片帆無奈信秋風。幾層峽浪寒舂月，", "未知今夜依何處，一點漁燈出葦叢。"]'),
('yuding-3','古意二首','賀蘭進明','唐','御定全唐诗','yuding','','[]','秦庭初指鹿，群盜滿山東。忤意皆誅死，所言誰肯忠。',96,'御定全唐詩/json/158.json','["秦庭初指鹿，群盜滿山東。忤意皆誅死，所言誰肯忠。", "武關猶未啟，兵入望夷宮。為祟非涇水，人君道自窮。", "崇蘭生澗底，香氣滿幽林。采采欲為贈，何人是同心。", "日暮徒盈把，裴回憂思深。慨然紉雜佩，重奏丘中琴。"]'),
('yuding-4','行路難五首','賀蘭進明','唐','御定全唐诗','yuding','','[]','君不見岩下井，百尺不及泉。君不見山上苗，',192,'御定全唐詩/json/158.json','["君不見岩下井，百尺不及泉。君不見山上苗，", "但願親友長含笑，相逢不乏杖頭錢。寒夜邀歡須秉燭，", "君不見門前柳，榮耀暫時蕭索久。君不見陌上花，", "盛年夫婿長別離，歲暮相逢色已換。", "君不見芳樹枝，春花落盡蜂不窺。君不見梁上泥，", "獨宿自然堪下淚，況複時聞烏夜啼。", "君不見雲中月，暫盈還複缺。君不見林下風，", "歎息青青陵上柏，歲寒能有幾人同。", "君不見東流水，一去無窮已。君不見西郊雲，", "人生結交在終始，莫以升沈中路分。"]'),
('yuding-5','夜渡江','閭丘曉','唐','御定全唐诗','yuding','','[]','舟人自相報，落日下芳潭。夜火連淮市，春風滿客帆。',48,'御定全唐詩/json/158.json','["舟人自相報，落日下芳潭。夜火連淮市，春風滿客帆。", "水窮滄海畔，路盡小山南。且喜鄉園近，言榮意未甘。"]'),
('yuding-6','奉和劉採訪縉雲南嶺作','庾光先','唐','御定全唐诗','yuding','','[]','百越城池枕海圻，永嘉山水複相依。懸蘿弱筱垂清淺，',40,'御定全唐詩/json/158.json','["百越城池枕海圻，永嘉山水複相依。懸蘿弱筱垂清淺，", "幸陪謝客題詩句，誰與王孫此地歸。"]'),
('yuding-7','思歸，寄東林澈上人','韋丹','唐','御定全唐诗','yuding','','[]','王事紛紛無暇日，浮生冉冉只如雲。',32,'御定全唐詩/json/158.json','["王事紛紛無暇日，浮生冉冉只如雲。", "已為平子歸休計，五老岩前必共聞。"]'),
('yuding-8','答澈公','韋丹','唐','御定全唐诗','yuding','','[]','空山泉落松窗靜，閑地草生春日遲。',32,'御定全唐詩/json/158.json','["空山泉落松窗靜，閑地草生春日遲。", "白髮漸多身未退，依依常在永禪師。"]'),
('yuding-9','洛出書','蕭昕','唐','御定全唐诗','yuding','','[]','海內昔凋瘵，天網斯浡潏。龜靈啟聖圖，龍馬負書出。',72,'御定全唐詩/json/158.json','["海內昔凋瘵，天網斯浡潏。龜靈啟聖圖，龍馬負書出。", "大哉明德盛，遠矣彝倫秩。地敷作乂功，人免為魚恤。", "既彰千國理，豈止百川溢。永賴至於今，疇庸未雲畢。"]'),
('yuding-10','臨風舒錦','蕭昕','唐','御定全唐诗','yuding','','[]','麗錦匹雲終，襜襜展向風。花開翻覆翠，色亂動搖紅。',72,'御定全唐詩/json/158.json','["麗錦匹雲終，襜襜展向風。花開翻覆翠，色亂動搖紅。", "縷散悠揚裏，文回照灼中。低垂疑步障，吹起作晴虹。", "既與丘遲夢，深知卓氏功。還鄉將制服，從此表亨通。"]'),
('yuding-11','東皇太一詞','李希仲','唐','御定全唐诗','yuding','','[]','吉日初齊戒，靈巫穆上皇。焚香布瑤席，鳴佩奠椒漿。',48,'御定全唐詩/json/158.json','["吉日初齊戒，靈巫穆上皇。焚香布瑤席，鳴佩奠椒漿。", "緩舞花飛滿，清歌水去長。回波送神曲，雲雨滿瀟湘。"]'),
('yuding-12','薊北行二首','李希仲','唐','御定全唐诗','yuding','','[]','旄頭有精芒，胡騎獵秋草。羽檄南渡河，邊庭用兵早。',96,'御定全唐詩/json/158.json','["旄頭有精芒，胡騎獵秋草。羽檄南渡河，邊庭用兵早。", "漢家愛征戰，宿將今已老。辛苦羽林兒，從戎榆關道。", "一身救邊速，烽火通薊門。前軍飛鳥斷，格鬥塵沙昏。", "寒日鼓聲急，單于夜將奔。當須徇忠義，身死報國恩。"]'),
('yuding-13','送妻','楊志堅','唐','御定全唐诗','yuding','','[]','平生志業在琴詩，頭上如今有二絲。漁父尚知溪穀暗，',40,'御定全唐詩/json/158.json','["平生志業在琴詩，頭上如今有二絲。漁父尚知溪穀暗，", "今日便同行路客，相逢即是下山時。"]'),
('yuding-0','從張丞相游南紀城獵，戲贈裴迪張參軍','孟浩然','唐','御定全唐诗','yuding','','[]','從禽非吾樂，不好雲夢田。歲暮登城望，偏令鄉思懸。',96,'御定全唐詩/json/159.json','["從禽非吾樂，不好雲夢田。歲暮登城望，偏令鄉思懸。", "公卿有幾幾，車騎何翩翩。世祿金張貴，官曹幕府賢。", "順時行殺氣，飛刃爭割鮮。十裏屆賓館，征聲匝妓筵。", "高標回落日，平楚散芳煙。何意狂歌客，從公亦在旃。"]'),
('yuding-1','登江中孤嶼，贈白雲先生王迥','孟浩然','唐','御定全唐诗','yuding','','[]','悠悠清江水，水落沙嶼出。回潭石下深，綠筱岸傍密。',72,'御定全唐詩/json/159.json','["悠悠清江水，水落沙嶼出。回潭石下深，綠筱岸傍密。", "鮫人潛不見，漁父歌自逸。憶與君別時，泛舟如昨日。", "夕陽開返照，中坐興非一。南望鹿門山，歸來恨如失。"]'),
('yuding-2','晚春臥病寄張八','孟浩然','唐','御定全唐诗','yuding','','[]','南陌春將晚，北窗猶臥病。林園久不遊，草木一何盛。',144,'御定全唐詩/json/159.json','["南陌春將晚，北窗猶臥病。林園久不遊，草木一何盛。", "狹逕花障迷，閒庭竹掃淨。翠羽戲蘭苕，赬鱗動荷柄。", "念我平生好，江鄉遠從政。雲山阻夢思，衾枕勞歌詠。", "歌詠複何為，同心恨別離。世途皆自媚，流俗寡相知。", "賈誼才空逸，安仁鬢欲絲。遙情每東注，奔晷複西馳。", "常恐填溝壑，無由振羽儀。窮通若有命，欲向論中推。"]'),
('yuding-3','秋登蘭山寄張五','孟浩然','唐','御定全唐诗','yuding','','[]','北山白雲裏，隱者自怡悅。相望試登高，心飛逐鳥滅。',72,'御定全唐詩/json/159.json','["北山白雲裏，隱者自怡悅。相望試登高，心飛逐鳥滅。", "愁因薄暮起，興是清秋發。時見歸村人，沙行渡頭歇。", "天邊樹若薺，江畔舟如月。何當載酒來，共醉重陽節。"]'),
('yuding-4','入峽寄弟','孟浩然','唐','御定全唐诗','yuding','','[]','吾昔與爾輩，讀書常閉門。未嘗冒湍險，豈顧垂堂言。',120,'御定全唐詩/json/159.json','["吾昔與爾輩，讀書常閉門。未嘗冒湍險，豈顧垂堂言。", "自此曆江湖，辛勤難具論。往來行旅弊，開鑿禹功存。", "壁立千峰峻，潈流萬壑奔。我來凡幾宿，無夕不聞猿。", "浦上搖歸戀，舟中失夢魂。淚沾明月峽，心斷鶺鴒原。", "離闊星難聚，秋深露已繁。因君下南楚，書此示鄉園。"]'),
('yuding-5','湖中旅泊，寄閻九司戶防','孟浩然','唐','御定全唐诗','yuding','','[]','桂水通百越，扁舟期曉發。荊雲蔽三巴，夕望不見家。',84,'御定全唐詩/json/159.json','["桂水通百越，扁舟期曉發。荊雲蔽三巴，夕望不見家。", "襄王夢行雨，才子謫長沙。長沙饒瘴癘，胡為苦留滯。", "久別思款顏，承歡懷接袂。接袂杳無由，徒增旅泊愁。", "清猿不可聽，沿月下湘流。"]'),
('yuding-6','大堤行寄萬七','孟浩然','唐','御定全唐诗','yuding','','[]','大堤行樂處，車馬相馳突。歲歲春草生，踏青二三月。',48,'御定全唐詩/json/159.json','["大堤行樂處，車馬相馳突。歲歲春草生，踏青二三月。", "王孫挾珠彈，游女矜羅襪。攜手今莫同，江花為誰發。"]'),
('yuding-7','仲夏歸漢南園，寄京邑耆舊','孟浩然','唐','御定全唐诗','yuding','','[]','嘗讀高士傳，最嘉陶征君。日耽田園趣，自謂羲皇人。',96,'御定全唐詩/json/159.json','["嘗讀高士傳，最嘉陶征君。日耽田園趣，自謂羲皇人。", "予複何為者，棲棲徒問津。中年廢丘壑，上國旅風塵。", "忠欲事明主，孝思侍老親。歸來當炎夏，耕稼不及春。", "扇枕北窗下，采芝南澗濱。因聲謝同列，吾慕潁陽真。"]'),
('yuding-8','題雲門山，寄越府包戶曹、徐起居','孟浩然','唐','御定全唐诗','yuding','','[]','我行適諸越，夢寐懷所歡。久負獨往願，今來恣遊盤。',108,'御定全唐詩/json/159.json','["我行適諸越，夢寐懷所歡。久負獨往願，今來恣遊盤。", "台嶺踐磴石，耶溪溯林湍。舍舟入香界，登閣憩旃檀。", "晴山秦望近，春水鏡湖寬。遠懷佇應接，卑位徒勞安。", "白雲日夕滯，滄海去來觀。故國眇天末，良朋在朝端。", "遲爾同攜手，何時方掛冠。"]'),
('yuding-9','宿揚子津，寄潤州長山劉隱士','孟浩然','唐','御定全唐诗','yuding','','[]','所思在建業，欲往大江深。日夕望京口，煙波愁我心。',48,'御定全唐詩/json/159.json','["所思在建業，欲往大江深。日夕望京口，煙波愁我心。", "心馳茅山洞，目極楓樹林。不見少微星，星霜勞夜吟。"]'),
('yuding-10','書懷貽京邑同好','孟浩然','唐','御定全唐诗','yuding','','[]','維先自鄒魯，家世重儒風。詩禮襲遺訓，趨庭沾末躬。',120,'御定全唐詩/json/159.json','["維先自鄒魯，家世重儒風。詩禮襲遺訓，趨庭沾末躬。", "晝夜常自強，詞翰頗亦工。三十既成立，嗟籲命不通。", "慈親向羸老，喜懼在深衷。甘脆朝不足，簞瓢夕屢空。", "執鞭慕夫子，捧檄懷毛公。感激遂彈冠，安能守固窮。", "當途訴知己，投刺匪求蒙。秦楚邈離異，翻飛何日同。"]'),
('yuding-11','還山貽湛法師','孟浩然','唐','御定全唐诗','yuding','','[]','幼聞無生理，常欲觀此身。心跡罕兼遂，崎嶇多在塵。',120,'御定全唐詩/json/159.json','["幼聞無生理，常欲觀此身。心跡罕兼遂，崎嶇多在塵。", "晚途歸舊壑，偶與支公鄰。導以微妙法，結為清淨因。", "煩惱業頓舍，山林情轉殷。朝來問疑義，夕話得清真。", "墨妙稱古絕，詞華驚世人。禪房閉虛靜，花藥連冬春。", "平石藉琴硯，落泉灑衣巾。欲知冥滅意，朝夕海鷗馴。"]'),
('yuding-12','夏日南亭懷辛大','孟浩然','唐','御定全唐诗','yuding','','[]','山光忽西落，池月漸東上。散發乘夕涼，開軒臥閑敞。',60,'御定全唐詩/json/159.json','["山光忽西落，池月漸東上。散發乘夕涼，開軒臥閑敞。", "荷風送香氣，竹露滴清響。欲取鳴琴彈，恨無知音賞。", "感此懷故人，中宵勞夢想。"]'),
('yuding-13','秋宵月下有懷','孟浩然','唐','御定全唐诗','yuding','','[]','秋空明月懸，光彩露沾濕。驚鵲棲未定，飛螢捲簾入。',48,'御定全唐詩/json/159.json','["秋空明月懸，光彩露沾濕。驚鵲棲未定，飛螢捲簾入。", "庭槐寒影疏，鄰杵夜聲急。佳期曠何許，望望空佇立。"]'),
('yuding-14','將適天臺，留別臨安李主簿','孟浩然','唐','御定全唐诗','yuding','','[]','枳棘君尚棲，匏瓜吾豈系。念離當夏首，漂泊指炎裔。',84,'御定全唐詩/json/159.json','["枳棘君尚棲，匏瓜吾豈系。念離當夏首，漂泊指炎裔。", "江海非墮游，田園失歸計。定山既早發，漁浦亦宵濟。", "泛泛隨波瀾，行行任艫枻。故林日已遠，群木坐成翳。", "羽人在丹丘，吾亦從此逝。"]'),
('yuding-15','送丁大鳳進士赴舉，呈張九齡','孟浩然','唐','御定全唐诗','yuding','','[]','吾觀鷦鷯賦，君負王佐才。惜無金張援，十上空歸來。',48,'御定全唐詩/json/159.json','["吾觀鷦鷯賦，君負王佐才。惜無金張援，十上空歸來。", "棄置鄉園老，翻飛羽翼摧。故人今在位，岐路莫遲回。"]'),
('yuding-16','送吳悅游韶陽','孟浩然','唐','御定全唐诗','yuding','','[]','五色憐鳳雛，南飛適鷓鴣。楚人不相識，何處求椅梧。',48,'御定全唐詩/json/159.json','["五色憐鳳雛，南飛適鷓鴣。楚人不相識，何處求椅梧。", "去去日千里，茫茫天一隅。安能與斥鷃，決起但槍榆。"]'),
('yuding-17','適越留別譙縣張主簿、申屠少府','孟浩然','唐','御定全唐诗','yuding','','[]','朝乘汴河流，夕次譙縣界。幸值西風吹，得與故人會。',48,'御定全唐詩/json/159.json','["朝乘汴河流，夕次譙縣界。幸值西風吹，得與故人會。", "君學梅福隱，余從伯鸞邁。別後能相思，浮雲在吳會。"]'),
('yuding-18','送陳七赴西軍','孟浩然','唐','御定全唐诗','yuding','','[]','吾觀非常者，碌碌在目前。君負鴻鵠志，蹉跎書劍年。',48,'御定全唐詩/json/159.json','["吾觀非常者，碌碌在目前。君負鴻鵠志，蹉跎書劍年。", "一聞邊烽動，萬里忽爭先。余亦赴京國，何當獻凱還。"]'),
('yuding-19','送從弟邕下第後尋會稽','孟浩然','唐','御定全唐诗','yuding','','[]','疾風吹征帆，倏爾向空沒。千里在俄頃，三江坐超忽。',48,'御定全唐詩/json/159.json','["疾風吹征帆，倏爾向空沒。千里在俄頃，三江坐超忽。", "向來共歡娛，日夕成楚越。落羽更分飛，誰能不驚骨。"]'),
('yuding-20','送辛大之鄂渚不及','孟浩然','唐','御定全唐诗','yuding','','[]','送君不相見，日暮獨愁緒。江上空裴回，天邊迷處所。',48,'御定全唐詩/json/159.json','["送君不相見，日暮獨愁緒。江上空裴回，天邊迷處所。", "郡邑經樊鄧，山河入嵩汝。蒲輪去漸遙，石徑徒延佇。"]'),
('yuding-21','江上別流人','孟浩然','唐','御定全唐诗','yuding','','[]','以我越鄉客，逢君謫居者。分飛黃鶴樓，流落蒼梧野。',48,'御定全唐詩/json/159.json','["以我越鄉客，逢君謫居者。分飛黃鶴樓，流落蒼梧野。", "驛使乘雲去，征帆沿溜下。不知從此分，還袂何時把。"]'),
('yuding-22','宴包二融宅','孟浩然','唐','御定全唐诗','yuding','','[]','閒居枕清洛，左右接大野。門庭無雜賓，車轍多長者。',72,'御定全唐詩/json/159.json','["閒居枕清洛，左右接大野。門庭無雜賓，車轍多長者。", "是時方盛夏，風物自瀟灑。五日休沐歸，相攜竹林下。", "開襟成歡趣，對酒不能罷。煙暝棲鳥迷，余將歸白社。"]'),
('yuding-23','與王昌齡宴王道士房','孟浩然','唐','御定全唐诗','yuding','','[]','歸來臥青山，常夢遊清都。漆園有傲吏，惠好在招呼。',48,'御定全唐詩/json/159.json','["歸來臥青山，常夢遊清都。漆園有傲吏，惠好在招呼。", "書幌神仙籙，畫屏山海圖。酌霞複對此，宛似入蓬壺。"]'),
('yuding-24','襄陽公宅飲','孟浩然','唐','御定全唐诗','yuding','','[]','窈窕夕陽佳，豐茸春色好。欲覓淹留處，無過狹斜道。',96,'御定全唐詩/json/159.json','["窈窕夕陽佳，豐茸春色好。欲覓淹留處，無過狹斜道。", "綺席捲龍須，香杯浮瑪瑙。北林積修樹，南池生別島。", "手撥金翠花，心迷玉紅草。談笑光六義，發論明三倒。", "座非陳子驚，門還魏公掃。榮辱應無間，歡娛當共保。"]'),
('yuding-25','尋香山湛上人','孟浩然','唐','御定全唐诗','yuding','','[]','朝遊訪名山，山遠在空翠。氛氳亙百里，日入行始至。',120,'御定全唐詩/json/159.json','["朝遊訪名山，山遠在空翠。氛氳亙百里，日入行始至。", "杖策尋故人，解鞭暫停騎。石門殊豁險，篁徑轉森邃。", "法侶欣相逢，清談曉不寐。平生慕真隱，累日探奇異。", "野老朝入田，山僧暮歸寺。松泉多逸響，苔壁饒古意。", "谷口聞鐘聲，林端識香氣。願言投此山，身世兩相棄。"]'),
('yuding-26','雲門寺西六七裏，聞符公蘭若最幽，與薛八同往','孟浩然','唐','御定全唐诗','yuding','','[]','謂予獨迷方，逢子亦在野。結交指松柏，問法尋蘭若。',108,'御定全唐詩/json/159.json','["謂予獨迷方，逢子亦在野。結交指松柏，問法尋蘭若。", "小溪劣容舟，怪石屢驚馬。所居最幽絕，所住皆靜者。", "雲簇興座隅，天空落階下。上人亦何聞，塵念都已舍。", "四禪合真如，一切是虛假。願承甘露潤，喜得惠風灑。", "依止托山門，誰能效丘也。"]'),
('yuding-27','宿天臺桐柏觀','孟浩然','唐','御定全唐诗','yuding','','[]','海行信風帆，夕宿逗雲島。緬尋滄洲趣，近愛赤城好。',108,'御定全唐詩/json/159.json','["海行信風帆，夕宿逗雲島。緬尋滄洲趣，近愛赤城好。", "捫蘿亦踐苔，輟棹恣探討。息陰憩桐柏，采秀弄芝草。", "鶴唳清露垂，雞鳴信潮早。願言解纓紱，從此去煩惱。", "高步淩四明，玄蹤得三老。紛吾遠遊意，學彼長生道。", "日夕望三山，雲濤空浩浩。"]'),
('yuding-28','峴潭作','孟浩然','唐','御定全唐诗','yuding','','[]','石潭傍隈隩，沙岸曉夤緣。試垂竹竿釣，果得槎頭鯿。',48,'御定全唐詩/json/159.json','["石潭傍隈隩，沙岸曉夤緣。試垂竹竿釣，果得槎頭鯿。", "美人騁金錯，纖手膾紅鮮。因謝陸內史，蓴羹何足傳。"]'),
('yuding-29','題終南翠微寺空上人房','孟浩然','唐','御定全唐诗','yuding','','[]','翠微終南裏，雨後宜返照。閉關久沈冥，杖策一登眺。',96,'御定全唐詩/json/159.json','["翠微終南裏，雨後宜返照。閉關久沈冥，杖策一登眺。", "遂造幽人室，始知靜者妙。儒道雖異門，雲林頗同調。", "兩心相喜得，畢景共談笑。暝還高窗眠，時見遠山燒。", "緬懷赤城標，更憶臨海嶠。風泉有清音，何必蘇門嘯。"]'),
('yuding-30','初春漢中漾舟','孟浩然','唐','御定全唐诗','yuding','','[]','羊公峴山下，神女漢皋曲。雪罷冰複開，春潭千丈綠。',72,'御定全唐詩/json/159.json','["羊公峴山下，神女漢皋曲。雪罷冰複開，春潭千丈綠。", "輕舟恣來往，探玩無厭足。波影搖妓釵，沙光逐人目。", "傾杯魚鳥醉，聯句鶯花續。良會難再逢，日入須秉燭。"]'),
('yuding-31','宿業師山房，期丁大不至','孟浩然','唐','御定全唐诗','yuding','','[]','夕陽度西嶺，群壑倏已暝。松月生夜涼，風泉滿清聽。',48,'御定全唐詩/json/159.json','["夕陽度西嶺，群壑倏已暝。松月生夜涼，風泉滿清聽。", "樵人歸欲盡，煙鳥棲初定。之子期宿來，孤琴候蘿徑。"]'),
('yuding-32','耶溪泛舟','孟浩然','唐','御定全唐诗','yuding','','[]','落景餘清輝，輕橈弄溪渚。澄明愛水物，臨泛何容與。',48,'御定全唐詩/json/159.json','["落景餘清輝，輕橈弄溪渚。澄明愛水物，臨泛何容與。", "白首垂釣翁，新妝浣紗女。相看似相識，脈脈不得語。"]'),
('yuding-33','彭蠡湖中望廬山','孟浩然','唐','御定全唐诗','yuding','','[]','太虛生月暈，舟子知天風。掛席候明發，眇漫平湖中。',108,'御定全唐詩/json/159.json','["太虛生月暈，舟子知天風。掛席候明發，眇漫平湖中。", "中流見匡阜，勢壓九江雄。黤黕容霽色，崢嶸當曉空。", "香爐初上日，瀑布噴成虹。久欲追尚子，況茲懷遠公。", "我來限於役，未暇息微躬。淮海途將半，星霜歲欲窮。", "寄言岩棲者，畢趣當來同。"]'),
('yuding-34','登鹿門山','孟浩然','唐','御定全唐诗','yuding','','[]','清曉因興來，乘流越江峴。沙禽近方識，浦樹遙莫辨。',120,'御定全唐詩/json/159.json','["清曉因興來，乘流越江峴。沙禽近方識，浦樹遙莫辨。", "漸至鹿門山，山明翠微淺。岩潭多屈曲，舟楫屢回轉。", "昔聞龐德公，采藥遂不返。金澗餌芝朮，石床臥苔蘚。", "紛吾感耆舊，結攬事攀踐。隱跡今尚存，高風邈已遠。", "白雲何時去，丹桂空偃蹇。探討意未窮，回艇夕陽晚。"]'),
('yuding-35','游明禪師西山蘭若','孟浩然','唐','御定全唐诗','yuding','','[]','西山多奇狀，秀出倚前楹。停午收彩翠，夕陽照分明。',72,'御定全唐詩/json/159.json','["西山多奇狀，秀出倚前楹。停午收彩翠，夕陽照分明。", "吾師住其下，禪坐證無生。結廬就嵌窟，剪苕通往行。", "談空對樵叟，授法與山精。日暮方辭去，田園歸冶城。"]'),
('yuding-36','登望楚山最高頂','孟浩然','唐','御定全唐诗','yuding','','[]','山水觀形勝，襄陽美會稽。最高唯望楚，曾未一攀躋。',72,'御定全唐詩/json/159.json','["山水觀形勝，襄陽美會稽。最高唯望楚，曾未一攀躋。", "石壁疑削成，眾山比全低。晴明試登陟，目極無端倪。", "雲夢掌中小，武陵花處迷。暝還歸騎下，蘿月映深溪。"]'),
('yuding-37','疾愈過龍泉寺精舍，呈易、業二公','孟浩然','唐','御定全唐诗','yuding','','[]','停午聞山鐘，起行散愁疾。尋林采芝去，轉穀松翠密。',84,'御定全唐詩/json/159.json','["停午聞山鐘，起行散愁疾。尋林采芝去，轉穀松翠密。", "傍見精舍開，長廊飯僧畢。石渠流雪水，金子耀霜橘。", "竹房思舊遊，過憩終永日。入洞窺石髓，傍崖采蜂蜜。", "日暮辭遠公，虎溪相送出。"]'),
('yuding-38','萬山潭作','孟浩然','唐','御定全唐诗','yuding','','[]','垂釣坐磐石，水清心亦閑。魚行潭樹下，猿掛島藤間。',48,'御定全唐詩/json/159.json','["垂釣坐磐石，水清心亦閑。魚行潭樹下，猿掛島藤間。", "游女昔解佩，傳聞於此山。求之不可得，沿月棹歌還。"]'),
('yuding-39','與黃侍禦北津泛舟','孟浩然','唐','御定全唐诗','yuding','','[]','津無蛟龍患，日夕常安流。本欲避驄馬，何如同鷁舟。',84,'御定全唐詩/json/159.json','["津無蛟龍患，日夕常安流。本欲避驄馬，何如同鷁舟。", "豈伊今日幸，曾是昔年遊。莫奏琴中鶴，且隨波上鷗。", "堤緣九裏郭，山面百城樓。自顧躬耕者，才非管樂儔。", "聞君薦草澤，從此泛滄洲。"]'),
('yuding-40','洗然弟竹亭','孟浩然','唐','御定全唐诗','yuding','','[]','吾與二三子，平生結交深。俱懷鴻鵠志，昔有鶺鴒心。',48,'御定全唐詩/json/159.json','["吾與二三子，平生結交深。俱懷鴻鵠志，昔有鶺鴒心。", "逸氣假毫翰，清風在竹林。達是酒中趣，琴上偶然音。"]'),
('yuding-41','山中逢道士雲公','孟浩然','唐','御定全唐诗','yuding','','[]','春餘草木繁，耕種滿田園。酌酒聊自勸，農夫安與言。',156,'御定全唐詩/json/159.json','["春餘草木繁，耕種滿田園。酌酒聊自勸，農夫安與言。", "忽聞荊山子，時出桃花源。采樵過北穀，賣藥來西村。", "村煙日雲夕，榛路有歸客。杖策前相逢，依然是疇昔。", "邂逅歡覯止，殷勤敘離隔。謂予搏扶桑，輕舉振六翮。", "奈何偶昌運，獨見遺草澤。既笑接輿狂，仍憐孔丘厄。", "物情趨勢利，吾道貴閑寂。偃息西山下，門庭罕人跡。", "何時還清溪，從爾煉丹液。"]'),
('yuding-42','越中逢天臺太乙子','孟浩然','唐','御定全唐诗','yuding','','[]','仙穴逢羽人，停艫向前拜。問余涉風水，何處遠行邁。',120,'御定全唐詩/json/159.json','["仙穴逢羽人，停艫向前拜。問余涉風水，何處遠行邁。", "登陸尋天臺，順流下吳會。茲山夙所尚，安得問靈怪。", "上逼青天高，俯臨滄海大。雞鳴見日出，常覿仙人旆。", "往來赤城中，逍遙白雲外。莓苔異人間，瀑布當空界。", "福庭長自然，華頂舊稱最。永此從之游，何當濟所屆。"]'),
('yuding-43','家園臥疾，畢太祝曜見尋','孟浩然','唐','御定全唐诗','yuding','','[]','伏枕舊遊曠，笙簧勞夢思。平生重交結，迨此令人疑。',120,'御定全唐詩/json/159.json','["伏枕舊遊曠，笙簧勞夢思。平生重交結，迨此令人疑。", "冰室無暖氣，炎雲空赫曦。隙駒不暫駐，日聽涼蟬悲。", "壯圖哀未立，斑白恨吾衰。夫子自南楚，緬懷嵩汝期。", "顧予衡茅下，兼致稟物資。脫分趨庭禮，殷勤伐木詩。", "脫君車前鞅，設我園中葵。鬥酒須寒興，明朝難重持。"]'),
('yuding-44','白雲先生王迥見訪','孟浩然','唐','御定全唐诗','yuding','','[]','閑歸日無事，雲臥晝不起。有客款柴扉，自雲巢居子。',72,'御定全唐詩/json/159.json','["閑歸日無事，雲臥晝不起。有客款柴扉，自雲巢居子。", "居閑好芝朮，采藥來城市。家在鹿門山，常游澗澤水。", "手持白羽扇，腳步青芒履。聞道鶴書征，臨流還洗耳。"]'),
('yuding-45','田園作','孟浩然','唐','御定全唐诗','yuding','','[]','弊廬隔塵喧，惟先養恬素。卜鄰近三徑，植果盈千樹。',108,'御定全唐詩/json/159.json','["弊廬隔塵喧，惟先養恬素。卜鄰近三徑，植果盈千樹。", "粵余任推遷，三十猶未遇。書劍時將晚，丘園日已暮。", "晨興自多懷，晝坐常寡悟。沖天羨鴻鵠，爭食羞雞鶩。", "望斷金馬門，勞歌采樵路。鄉曲無知己，朝端乏親故。", "誰能為揚雄，一薦甘泉賦。"]'),
('yuding-46','采樵作','孟浩然','唐','御定全唐诗','yuding','','[]','采樵人深山，山深樹重疊。橋崩臥槎擁，路險垂藤接。',48,'御定全唐詩/json/159.json','["采樵人深山，山深樹重疊。橋崩臥槎擁，路險垂藤接。", "日落伴將稀，山風拂蘿衣。長歌負輕策，平野望煙歸。"]'),
('yuding-47','自潯陽泛舟經明海','孟浩然','唐','御定全唐诗','yuding','','[]','大江分九流，淼淼成水鄉。舟子乘利涉，往來至潯陽。',72,'御定全唐詩/json/159.json','["大江分九流，淼淼成水鄉。舟子乘利涉，往來至潯陽。", "因之泛五湖，流浪經三湘。觀濤壯枚發，吊屈痛沉湘。", "魏闕心恒在，金門詔不忘。遙憐上林雁，冰泮也回翔。"]'),
('yuding-48','早發漁浦潭','孟浩然','唐','御定全唐诗','yuding','','[]','東旭早光芒，渚禽已驚聒。臥聞漁浦口，橈聲暗相撥。',72,'御定全唐詩/json/159.json','["東旭早光芒，渚禽已驚聒。臥聞漁浦口，橈聲暗相撥。", "日出氣象分，始知江湖闊。美人常晏起，照影弄流沫。", "飲水畏驚猿，祭魚時見獺。舟行自無悶，況值晴景豁。"]'),
('yuding-49','經七裏灘','孟浩然','唐','御定全唐诗','yuding','','[]','予奉垂堂誡，千金非所輕。為多山水樂，頻作泛舟行。',132,'御定全唐詩/json/159.json','["予奉垂堂誡，千金非所輕。為多山水樂，頻作泛舟行。", "五嶽追向子，三湘吊屈平。湖經洞庭闊，江入新安清。", "複聞嚴陵瀨，乃在茲湍路。疊障數百里，沿洄非一趣。", "彩翠相氛氳，別流亂奔注。釣磯平可坐，苔磴滑難步。", "猿飲石下潭，鳥還日邊樹。觀奇恨來晚，倚棹惜將暮。", "揮手弄潺湲，從茲洗塵慮。"]'),
('yuding-50','歲暮海上作','孟浩然','唐','御定全唐诗','yuding','','[]','仲尼既雲歿，余亦浮於海。昏見斗柄回，方知歲星改。',48,'御定全唐詩/json/159.json','["仲尼既雲歿，余亦浮於海。昏見斗柄回，方知歲星改。", "虛舟任所適，垂釣非有待。為問乘槎人，滄洲複誰在。"]'),
('yuding-51','南歸阻雪','孟浩然','唐','御定全唐诗','yuding','','[]','我行滯宛許，日夕望京豫。曠野莽茫茫，鄉山在何處。',72,'御定全唐詩/json/159.json','["我行滯宛許，日夕望京豫。曠野莽茫茫，鄉山在何處。", "孤煙村際起，歸雁天邊去。積雪覆平皋，饑鷹捉寒兔。", "少年弄文墨，屬意在章句。十上恥還家，裴回守歸路。"]'),
('yuding-52','聽鄭五愔彈琴','孟浩然','唐','御定全唐诗','yuding','','[]','阮籍推名飲，清風滿竹林。半酣下衫袖，拂拭龍唇琴。',48,'御定全唐詩/json/159.json','["阮籍推名飲，清風滿竹林。半酣下衫袖，拂拭龍唇琴。", "一杯彈一曲，不覺夕陽沉。予意在山水，聞之諧夙心。"]'),
('yuding-53','同張明府清鏡歎','孟浩然','唐','御定全唐诗','yuding','','[]','妾有盤龍鏡，清光常晝發。自從生塵埃，有若霧中月。',48,'御定全唐詩/json/159.json','["妾有盤龍鏡，清光常晝發。自從生塵埃，有若霧中月。", "愁來試取照，坐歎生白髮。寄語邊塞人，如何久離別。"]'),
('yuding-54','庭橘','孟浩然','唐','御定全唐诗','yuding','','[]','明發覽群物，萬木何陰森。凝霜漸漸水，庭橘似懸金。',72,'御定全唐詩/json/159.json','["明發覽群物，萬木何陰森。凝霜漸漸水，庭橘似懸金。", "女伴爭攀摘，摘窺礙葉深。並生憐共蒂，相示感同心。", "骨刺紅羅被，香黏翠羽簪。擎來玉盤裏，全勝在幽林。"]'),
('yuding-55','早梅','孟浩然','唐','御定全唐诗','yuding','','[]','園中有早梅，年例犯寒開。少婦曾攀折，將歸插鏡臺。',36,'御定全唐詩/json/159.json','["園中有早梅，年例犯寒開。少婦曾攀折，將歸插鏡臺。", "猶言看不足，更欲剪刀裁。"]'),
('yuding-56','清明即事','孟浩然','唐','御定全唐诗','yuding','','[]','帝裏重清明，人心自愁思。車聲上路合，柳色東城翠。',48,'御定全唐詩/json/159.json','["帝裏重清明，人心自愁思。車聲上路合，柳色東城翠。", "花落草齊生，鶯飛蝶雙戲。空堂坐相憶，酌茗聊代醉。"]'),
('yuding-57','和盧明府送鄭十三還京兼寄之什','孟浩然','唐','御定全唐诗','yuding','','[]','昔時風景登臨地，今日衣冠送別筵。醉坐自傾彭澤酒，',40,'御定全唐詩/json/159.json','["昔時風景登臨地，今日衣冠送別筵。醉坐自傾彭澤酒，", "寄語朝廷當世人，何時重見長安道。"]'),
('yuding-58','高陽池送朱二','孟浩然','唐','御定全唐诗','yuding','','[]','當昔襄陽雄盛時，山公常醉習家池。池邊釣女日相隨，',72,'御定全唐詩/json/159.json','["當昔襄陽雄盛時，山公常醉習家池。池邊釣女日相隨，", "一朝物變人亦非，四面荒涼人徑稀。意氣豪華何處在，", "征馬分飛日漸斜，見此空為人所嗟。殷勤為訪桃源路，"]'),
('yuding-59','鸚鵡洲送王九之江左','孟浩然','唐','御定全唐诗','yuding','','[]','昔登江上黃鶴樓，遙愛江中鸚鵡洲。洲勢逶迤繞碧流，',44,'御定全唐詩/json/159.json','["昔登江上黃鶴樓，遙愛江中鸚鵡洲。洲勢逶迤繞碧流，", "舟人牽錦纜，浣女結羅裳。月明全見蘆花白，"]'),
('yuding-60','送王七尉松滋，得陽臺雲','孟浩然','唐','御定全唐诗','yuding','','[]','君不見巫山神女作行雲，霏紅遝翠曉氛氳。',43,'御定全唐詩/json/159.json','["君不見巫山神女作行雲，霏紅遝翠曉氛氳。", "嬋娟流入楚王夢，倏忽還隨零雨分。空中飛去複飛來，"]'),
('yuding-61','夜歸鹿門山歌','孟浩然','唐','御定全唐诗','yuding','','[]','山寺鐘鳴晝已昏，漁梁渡頭爭渡喧。人隨沙路向江村，',40,'御定全唐詩/json/159.json','["山寺鐘鳴晝已昏，漁梁渡頭爭渡喧。人隨沙路向江村，", "岩扉松徑長寂寥，惟有幽人夜來去。"]'),
('yuding-62','長樂宮','孟浩然','唐','御定全唐诗','yuding','','[]','秦城舊來稱窈窕，漢家更衣應不少。紅粉邀君在何處，',40,'御定全唐詩/json/159.json','["秦城舊來稱窈窕，漢家更衣應不少。紅粉邀君在何處，", "歡娛此事今寂寞，惟有年年陵樹哀。"]'),
('yuding-63','示孟郊','孟浩然','唐','御定全唐诗','yuding','','[]','蔓草蔽極野，蘭芝結孤根。眾音何其繁，伯牙獨不喧。',60,'御定全唐詩/json/159.json','["蔓草蔽極野，蘭芝結孤根。眾音何其繁，伯牙獨不喧。", "當時高深意，舉世無能分。鐘期一見知，山水千秋聞。", "爾其保靜節，薄俗徒云云。"]'),
('yuding-0','和張丞相春朝對雪','孟浩然','唐','御定全唐诗','yuding','','[]','迎氣當春至，承恩喜雪來。潤從河漢下，花逼豔陽開。',48,'御定全唐詩/json/160.json','["迎氣當春至，承恩喜雪來。潤從河漢下，花逼豔陽開。", "不睹豐年瑞，焉知燮理才。撒鹽如可擬，願糝和羹梅。"]'),
('yuding-1','和張明府登鹿門作','孟浩然','唐','御定全唐诗','yuding','','[]','忽示登高作，能寬旅寓情。弦歌既多暇，山水思微清。',48,'御定全唐詩/json/160.json','["忽示登高作，能寬旅寓情。弦歌既多暇，山水思微清。", "草得風光動，虹因雨氣成。謬承巴里和，非敢應同聲。"]'),
('yuding-2','和張二自穰縣還途中遇雪','孟浩然','唐','御定全唐诗','yuding','','[]','風吹沙海雪，漸作柳園春。宛轉隨香騎，輕盈伴玉人。',48,'御定全唐詩/json/160.json','["風吹沙海雪，漸作柳園春。宛轉隨香騎，輕盈伴玉人。", "歌疑郢中客，態比洛川神。今日南歸楚，雙飛似入秦。"]'),
('yuding-3','和賈主簿弁九日登峴山','孟浩然','唐','御定全唐诗','yuding','','[]','楚萬重陽日，群公賞宴來。共乘休沐暇，同醉菊花杯。',48,'御定全唐詩/json/160.json','["楚萬重陽日，群公賞宴來。共乘休沐暇，同醉菊花杯。", "逸思高秋發，歡情落景催。國人咸寡和，遙愧洛陽才。"]'),
('yuding-4','望洞庭湖，贈張丞相','孟浩然','唐','御定全唐诗','yuding','','[]','八月湖水平，涵虛混太清。氣蒸雲夢澤，波撼岳陽城。',48,'御定全唐詩/json/160.json','["八月湖水平，涵虛混太清。氣蒸雲夢澤，波撼岳陽城。", "欲濟無舟楫，端居恥聖明。坐觀垂釣者，空有羨魚情。"]'),
('yuding-5','贈道士參寥','孟浩然','唐','御定全唐诗','yuding','','[]','蜀琴久不弄，玉匣細塵生。絲脆弦將斷，金徽色尚榮。',48,'御定全唐詩/json/160.json','["蜀琴久不弄，玉匣細塵生。絲脆弦將斷，金徽色尚榮。", "知音徒自惜，聾俗本相輕。不遇鐘期聽，誰知鸞鳳聲。"]'),
('yuding-6','京還贈張維','孟浩然','唐','御定全唐诗','yuding','','[]','拂衣何處去，高枕南山南。欲徇五鬥祿，其如七不堪。',48,'御定全唐詩/json/160.json','["拂衣何處去，高枕南山南。欲徇五鬥祿，其如七不堪。", "早朝非晚起，束帶異抽簪。因向智者說，游魚思舊潭。"]'),
('yuding-7','題李十四莊，兼贈綦毋校書','孟浩然','唐','御定全唐诗','yuding','','[]','聞君息陰地，東郭柳林間。左右瀍澗水，門庭緱氏山。',48,'御定全唐詩/json/160.json','["聞君息陰地，東郭柳林間。左右瀍澗水，門庭緱氏山。", "抱琴來取醉，垂釣坐乘閑。歸客莫相待，尋源殊未還。"]'),
('yuding-8','九日龍沙作，寄劉大昚虛','孟浩然','唐','御定全唐诗','yuding','','[]','龍沙豫章北，九日掛帆過。風俗因時見，湖山發興多。',48,'御定全唐詩/json/160.json','["龍沙豫章北，九日掛帆過。風俗因時見，湖山發興多。", "客中誰送酒，棹裏自成歌。歌竟乘流去，滔滔任夕波。"]'),
('yuding-9','寄趙正字','孟浩然','唐','御定全唐诗','yuding','','[]','正字芸香閣，幽人竹素園。經過宛如昨，歸臥寂無喧。',48,'御定全唐詩/json/160.json','["正字芸香閣，幽人竹素園。經過宛如昨，歸臥寂無喧。", "高鳥能擇木，羝羊漫觸藩。物情今已見，從此願忘言。"]'),
('yuding-10','洞庭湖寄閻九','孟浩然','唐','御定全唐诗','yuding','','[]','洞庭秋正闊，餘欲泛歸船。莫辨荊吳地，唯餘水共天。',48,'御定全唐詩/json/160.json','["洞庭秋正闊，餘欲泛歸船。莫辨荊吳地，唯餘水共天。", "渺彌江樹沒，合遝海潮連。遲爾為舟楫，相將濟巨川。"]'),
('yuding-11','秦中感秋，寄遠上人','孟浩然','唐','御定全唐诗','yuding','','[]','一丘常欲臥，三徑苦無資。北土非吾願，東林懷我師。',48,'御定全唐詩/json/160.json','["一丘常欲臥，三徑苦無資。北土非吾願，東林懷我師。", "黃金然桂盡，壯志逐年衰。日夕涼風至，聞蟬但益悲。"]'),
('yuding-12','宿永嘉江，寄山陰崔少府國輔','孟浩然','唐','御定全唐诗','yuding','','[]','我行窮水國，君使入京華。相去日千里，孤帆天一涯。',48,'御定全唐詩/json/160.json','["我行窮水國，君使入京華。相去日千里，孤帆天一涯。", "臥聞海潮至，起視江月斜。借問同舟客，何時到永嘉。"]'),
('yuding-13','上巳洛中寄王九迥','孟浩然','唐','御定全唐诗','yuding','','[]','卜洛成周地，浮杯上巳筵。鬥雞寒食下，走馬射堂前。',48,'御定全唐詩/json/160.json','["卜洛成周地，浮杯上巳筵。鬥雞寒食下，走馬射堂前。", "垂柳金堤合，平沙翠幕連。不知王逸少，何處會群賢。"]'),
('yuding-14','聞裴侍禦朏自襄州司戶除豫州司戶，因以投寄','孟浩然','唐','御定全唐诗','yuding','','[]','故人荊府掾，尚有柏台威。移職自樊衍，芳聲聞帝畿。',48,'御定全唐詩/json/160.json','["故人荊府掾，尚有柏台威。移職自樊衍，芳聲聞帝畿。", "昔余臥林巷，載酒過柴扉。松菊無時賞，鄉園欲懶歸。"]'),
('yuding-15','江上寄山陰崔少府國輔','孟浩然','唐','御定全唐诗','yuding','','[]','春堤楊柳發，憶與故人期。草木本無意，榮枯自有時。',48,'御定全唐詩/json/160.json','["春堤楊柳發，憶與故人期。草木本無意，榮枯自有時。", "山陰定遠近，江上日相思。不及蘭亭會，空吟祓禊詩。"]'),
('yuding-16','夜泊廬江，聞故人在東寺，以詩寄之','孟浩然','唐','御定全唐诗','yuding','','[]','江路經廬阜，松門入虎溪。聞君尋寂樂，清夜宿招提。',48,'御定全唐詩/json/160.json','["江路經廬阜，松門入虎溪。聞君尋寂樂，清夜宿招提。", "石鏡山精怯，禪枝怖鴿棲。一燈如悟道，為照客心迷。"]'),
('yuding-17','宿桐廬江，寄廣陵舊游','孟浩然','唐','御定全唐诗','yuding','','[]','山暝聞猿愁，滄江急夜流。風鳴兩岸葉，月照一孤舟。',48,'御定全唐詩/json/160.json','["山暝聞猿愁，滄江急夜流。風鳴兩岸葉，月照一孤舟。", "建德非吾土，維揚憶舊遊。還將兩行淚，遙寄海西頭。"]'),
('yuding-18','南還舟中寄袁太祝','孟浩然','唐','御定全唐诗','yuding','','[]','沿溯非便習，風波厭苦辛。忽聞遷穀鳥，來報五陵春。',48,'御定全唐詩/json/160.json','["沿溯非便習，風波厭苦辛。忽聞遷穀鳥，來報五陵春。", "嶺北回征帆，巴東問故人。桃源何處是，遊子正迷津。"]'),
('yuding-19','東陂遇雨，率爾貽謝南池','孟浩然','唐','御定全唐诗','yuding','','[]','田家春事起，丁壯就東陂。殷殷雷聲作，森森雨足垂。',48,'御定全唐詩/json/160.json','["田家春事起，丁壯就東陂。殷殷雷聲作，森森雨足垂。", "海虹晴始見，河柳潤初移。予意在耕鑿，因君問土宜。"]'),
('yuding-20','行至汝墳寄盧征君','孟浩然','唐','御定全唐诗','yuding','','[]','行乏憩予駕，依然見汝墳。洛川方罷雪，嵩嶂有殘雲。',48,'御定全唐詩/json/160.json','["行乏憩予駕，依然見汝墳。洛川方罷雪，嵩嶂有殘雲。", "曳曳半空裏，明明五色分。聊題一時興，因寄盧征君。"]'),
('yuding-21','寄天臺道士','孟浩然','唐','御定全唐诗','yuding','','[]','海上求仙客，三山望幾時。焚香宿華頂，裛露采靈芝。',48,'御定全唐詩/json/160.json','["海上求仙客，三山望幾時。焚香宿華頂，裛露采靈芝。", "屢躡莓苔滑，將尋汗漫期。倘因松子去，長與世人辭。"]'),
('yuding-22','唐城館中早發，寄楊使君','孟浩然','唐','御定全唐诗','yuding','','[]','犯霜驅曉駕，數裏見唐城。旅館歸心逼，荒村客思盈。',48,'御定全唐詩/json/160.json','["犯霜驅曉駕，數裏見唐城。旅館歸心逼，荒村客思盈。", "訪人留後信，策蹇赴前程。欲識離魂斷，長空聽雁聲。"]'),
('yuding-23','澗南即事，貽皎上人','孟浩然','唐','御定全唐诗','yuding','','[]','弊廬在郭外，素產惟田園。左右林野曠，不聞朝市喧。',48,'御定全唐詩/json/160.json','["弊廬在郭外，素產惟田園。左右林野曠，不聞朝市喧。", "釣竿垂北澗，樵唱入南軒。書取幽棲事，將尋靜者論。"]'),
('yuding-24','重酬李少府見贈','孟浩然','唐','御定全唐诗','yuding','','[]','養疾衡簷下，由來浩氣真。五行將禁火，十步任尋春。',48,'御定全唐詩/json/160.json','["養疾衡簷下，由來浩氣真。五行將禁火，十步任尋春。", "致敬惟桑梓，邀歡即主人。回看後凋色，青翠有松筠。"]'),
('yuding-25','九日懷襄陽','孟浩然','唐','御定全唐诗','yuding','','[]','去國似如昨，倏然經杪秋。峴山不可見，風景令人愁。',48,'御定全唐詩/json/160.json','["去國似如昨，倏然經杪秋。峴山不可見，風景令人愁。", "誰采籬下菊，應閑池上樓。宜城多美酒，歸與葛強遊。"]'),
('yuding-26','初出關旅亭夜坐，懷王大校書','孟浩然','唐','御定全唐诗','yuding','','[]','向夕槐煙起，蔥蘢池館曛。客中無偶坐，關外惜離群。',48,'御定全唐詩/json/160.json','["向夕槐煙起，蔥蘢池館曛。客中無偶坐，關外惜離群。", "燭至螢光滅，荷枯雨滴聞。永懷芸閣友，寂寞滯揚雲。"]'),
('yuding-27','人日登南陽驛門亭子，懷漢川諸友','孟浩然','唐','御定全唐诗','yuding','','[]','朝來登陟處，不似豔陽時。異縣殊風物，羈懷多所思。',48,'御定全唐詩/json/160.json','["朝來登陟處，不似豔陽時。異縣殊風物，羈懷多所思。", "剪花驚歲早，看柳訝春遲。未有南飛雁，裁書欲寄誰。"]'),
('yuding-28','早寒江上有懷','孟浩然','唐','御定全唐诗','yuding','','[]','木落雁南度，北風江上寒。我家襄水上，遙隔楚雲端。',48,'御定全唐詩/json/160.json','["木落雁南度，北風江上寒。我家襄水上，遙隔楚雲端。", "鄉淚客中盡，孤帆天際看。迷津欲有問，平海夕漫漫。"]'),
('yuding-29','閑園懷蘇子','孟浩然','唐','御定全唐诗','yuding','','[]','林園雖少事，幽獨自多違。向夕開簾坐，庭陰落景微。',48,'御定全唐詩/json/160.json','["林園雖少事，幽獨自多違。向夕開簾坐，庭陰落景微。", "鳥過煙樹宿，螢傍水軒飛。感念同懷子，京華去不歸。"]'),
('yuding-30','同盧明府餞張郎中除義王府司馬，海園作','孟浩然','唐','御定全唐诗','yuding','','[]','上國山河列，賢王邸第開。故人分職去，潘令寵行來。',48,'御定全唐詩/json/160.json','["上國山河列，賢王邸第開。故人分職去，潘令寵行來。", "冠蓋趨梁苑，江湘失楚材。豫愁軒騎動，賓客散池台。"]'),
('yuding-31','送張子容進士赴舉','孟浩然','唐','御定全唐诗','yuding','','[]','夕曛山照滅，送客出柴門。惆悵野中別，殷勤岐路言。',48,'御定全唐詩/json/160.json','["夕曛山照滅，送客出柴門。惆悵野中別，殷勤岐路言。", "茂林予偃息，喬木爾飛翻。無使穀風誚，須令友道存。"]'),
('yuding-32','送張參明經舉，兼向涇州覲省','孟浩然','唐','御定全唐诗','yuding','','[]','十五彩衣年，承歡慈母前。孝廉因歲貢，懷橘向秦川。',48,'御定全唐詩/json/160.json','["十五彩衣年，承歡慈母前。孝廉因歲貢，懷橘向秦川。", "四座推文舉，中郎許仲宣。泛舟江上別，誰不仰神仙。"]'),
('yuding-33','送張祥之房陵','孟浩然','唐','御定全唐诗','yuding','','[]','我家南渡頭，慣習野人舟。日夕弄清淺，林湍逆上流。',48,'御定全唐詩/json/160.json','["我家南渡頭，慣習野人舟。日夕弄清淺，林湍逆上流。", "山河據形勝，天地生豪酋。君意在利往，知音期自投。"]'),
('yuding-34','送吳宣從事','孟浩然','唐','御定全唐诗','yuding','','[]','才有幕中士，甯無塞上勳。漢兵將滅虜，王粲始從軍。',48,'御定全唐詩/json/160.json','["才有幕中士，甯無塞上勳。漢兵將滅虜，王粲始從軍。", "旌旆邊庭去，山川地脈分。平生一匕首，感激贈夫君。"]'),
('yuding-35','送桓子之郢成禮','孟浩然','唐','御定全唐诗','yuding','','[]','聞君馳彩騎，躞蹀指南荊。為結潘楊好，言過鄢郢城。',48,'御定全唐詩/json/160.json','["聞君馳彩騎，躞蹀指南荊。為結潘楊好，言過鄢郢城。", "摽梅詩有贈，羔雁禮將行。今夜神仙女，應來感夢情。"]'),
('yuding-36','留別王侍禦維','孟浩然','唐','御定全唐诗','yuding','','[]','寂寂竟何待，朝朝空自歸。欲尋芳草去，惜與故人違。',48,'御定全唐詩/json/160.json','["寂寂竟何待，朝朝空自歸。欲尋芳草去，惜與故人違。", "當路誰相假，知音世所稀。只應守索寞，還掩故園扉。"]'),
('yuding-37','早春潤州送從弟還鄉','孟浩然','唐','御定全唐诗','yuding','','[]','兄弟游吳國，庭闈戀楚關。已多新歲感，更餞白眉還。',48,'御定全唐詩/json/160.json','["兄弟游吳國，庭闈戀楚關。已多新歲感，更餞白眉還。", "歸泛西江水，離筵北固山。鄉園欲有贈，梅柳著先攀。"]'),
('yuding-38','峴山餞房管、崔宗之','孟浩然','唐','御定全唐诗','yuding','','[]','貴賤平生隔，軒車是日來。青陽一覯止，雲路豁然開。',48,'御定全唐詩/json/160.json','["貴賤平生隔，軒車是日來。青陽一覯止，雲路豁然開。", "祖道衣冠列，分亭驛騎催。方期九日聚，還待二星回。"]'),
('yuding-39','送謝錄事之越','孟浩然','唐','御定全唐诗','yuding','','[]','清旦江天迥，涼風西北吹。白雲向吳會，征帆亦相隨。',48,'御定全唐詩/json/160.json','["清旦江天迥，涼風西北吹。白雲向吳會，征帆亦相隨。", "想到耶溪日，應探禹穴奇。仙書倘相示，予在此山陲。"]'),
('yuding-40','洛中送奚三還揚州','孟浩然','唐','御定全唐诗','yuding','','[]','水國無邊際，舟行共使風。羨君從此去，朝夕見鄉中。',48,'御定全唐詩/json/160.json','["水國無邊際，舟行共使風。羨君從此去，朝夕見鄉中。", "予亦離家久，南歸恨不同。音書若有問，江上會相逢。"]'),
('yuding-41','送告八從軍','孟浩然','唐','御定全唐诗','yuding','','[]','男兒一片氣，何必五車書。好勇方過我，多才便起予。',48,'御定全唐詩/json/160.json','["男兒一片氣，何必五車書。好勇方過我，多才便起予。", "運籌將入幕，養拙就閒居。正待功名遂，從君繼兩疏。"]'),
('yuding-42','送元公之鄂渚，尋觀主張驂鸞','孟浩然','唐','御定全唐诗','yuding','','[]','桃花春水漲，之子忽乘流。峴首辭蛟浦，江中問鶴樓。',48,'御定全唐詩/json/160.json','["桃花春水漲，之子忽乘流。峴首辭蛟浦，江中問鶴樓。", "贈君青竹杖，送爾白蘋洲。應是神仙子，相期汗漫遊。"]'),
('yuding-43','送王五昆季省覲','孟浩然','唐','御定全唐诗','yuding','','[]','公子戀庭闈，勞歌涉海涯。水乘舟楫去，親望老萊歸。',48,'御定全唐詩/json/160.json','["公子戀庭闈，勞歌涉海涯。水乘舟楫去，親望老萊歸。", "斜日催烏鳥，清江照彩衣。平生急難意，遙仰鶺鴒飛。"]'),
('yuding-44','送崔遏','孟浩然','唐','御定全唐诗','yuding','','[]','片玉來誇楚，治中作主人。江山增潤色，詞賦動陽春。',48,'御定全唐詩/json/160.json','["片玉來誇楚，治中作主人。江山增潤色，詞賦動陽春。", "別館當虛敞，離情任吐伸。因聲兩京舊，誰念臥漳濱。"]'),
('yuding-45','送盧少府使入秦','孟浩然','唐','御定全唐诗','yuding','','[]','楚關望秦國，相去千里餘。州縣勤王事，山河轉使車。',48,'御定全唐詩/json/160.json','["楚關望秦國，相去千里餘。州縣勤王事，山河轉使車。", "祖筵江上列，離恨別前書。願及芳年賞，嬌鶯二月初。"]'),
('yuding-46','送袁十嶺南尋弟','孟浩然','唐','御定全唐诗','yuding','','[]','早聞牛渚詠，今見鶺鴒心。羽翼嗟零落，悲鳴別故林。',48,'御定全唐詩/json/160.json','["早聞牛渚詠，今見鶺鴒心。羽翼嗟零落，悲鳴別故林。", "蒼梧白雲遠，煙水洞庭深。萬里獨飛去，南風遲爾音。"]'),
('yuding-47','永嘉別張子容','孟浩然','唐','御定全唐诗','yuding','','[]','舊國余歸楚，新年子北征。掛帆愁海路，分手戀朋情。',48,'御定全唐詩/json/160.json','["舊國余歸楚，新年子北征。掛帆愁海路，分手戀朋情。", "日夕故園意，汀洲春草生。何時一杯酒，重與季鷹傾。"]'),
('yuding-48','東京留別諸公','孟浩然','唐','御定全唐诗','yuding','','[]','吾道昧所適，驅車還向東。主人開舊館，留客醉新豐。',48,'御定全唐詩/json/160.json','["吾道昧所適，驅車還向東。主人開舊館，留客醉新豐。", "樹繞溫泉綠，塵遮晚日紅。拂衣從此去，高步躡華嵩。"]'),
('yuding-49','送袁太祝尉豫章','孟浩然','唐','御定全唐诗','yuding','','[]','何幸遇休明，觀光來上京。相逢武陵客，獨送豫章行。',48,'御定全唐詩/json/160.json','["何幸遇休明，觀光來上京。相逢武陵客，獨送豫章行。", "隨牒牽黃綬，離群會墨卿。江南佳麗地，山水舊難名。"]'),
('yuding-50','都下送辛大之鄂','孟浩然','唐','御定全唐诗','yuding','','[]','南國辛居士，言歸舊竹林。未逢調鼎用，徒有濟川心。',48,'御定全唐詩/json/160.json','["南國辛居士，言歸舊竹林。未逢調鼎用，徒有濟川心。", "予亦忘機者，田園在漢陰。因君故鄉去，遙寄式微吟。"]'),
('yuding-51','送席大','孟浩然','唐','御定全唐诗','yuding','','[]','惜爾懷其寶，迷邦倦客遊。江山曆全楚，河洛越成周。',48,'御定全唐詩/json/160.json','["惜爾懷其寶，迷邦倦客遊。江山曆全楚，河洛越成周。", "道路疲千里，鄉園老一丘。知君命不偶，同病亦同憂。"]'),
('yuding-52','送賈升主簿之荊府','孟浩然','唐','御定全唐诗','yuding','','[]','奉使推能者，勤王不暫閑。觀風隨按察，乘騎度荊關。',48,'御定全唐詩/json/160.json','["奉使推能者，勤王不暫閑。觀風隨按察，乘騎度荊關。", "送別登何處，開筵舊峴山。征軒明日遠，空望郢門間。"]'),
('yuding-53','送王大校書','孟浩然','唐','御定全唐诗','yuding','','[]','導漾自嶓塚，東流為漢川。維桑君有意，解纜我開筵。',48,'御定全唐詩/json/160.json','["導漾自嶓塚，東流為漢川。維桑君有意，解纜我開筵。", "雲雨從茲別，林端意渺然。尺書能不吝，時望鯉魚傳。"]'),
('yuding-54','游江西留別富陽裴、劉二少府','孟浩然','唐','御定全唐诗','yuding','','[]','西上游江西，臨流恨解攜。千山疊成嶂，萬水瀉為溪。',48,'御定全唐詩/json/160.json','["西上游江西，臨流恨解攜。千山疊成嶂，萬水瀉為溪。", "石淺流難溯，藤長險易躋。誰憐問津者，歲晏此中迷。"]'),
('yuding-55','廣陵別薛八','孟浩然','唐','御定全唐诗','yuding','','[]','士有不得志，棲棲吳楚間。廣陵相遇罷，彭蠡泛舟還。',48,'御定全唐詩/json/160.json','["士有不得志，棲棲吳楚間。廣陵相遇罷，彭蠡泛舟還。", "檣出江中樹，波連海上山。風帆明日遠，何處更追攀。"]'),
('yuding-56','送洗然弟進士舉','孟浩然','唐','御定全唐诗','yuding','','[]','獻策金門去，承歡彩服違。以吾一日長，念爾聚星稀。',48,'御定全唐詩/json/160.json','["獻策金門去，承歡彩服違。以吾一日長，念爾聚星稀。", "昏定須溫席，寒多未授衣。桂枝如已擢，早逐雁南飛。"]'),
('yuding-57','崔明府宅夜觀妓','孟浩然','唐','御定全唐诗','yuding','','[]','白日既雲暮，朱顏亦已酡。畫堂初點燭，金幌半垂羅。',48,'御定全唐詩/json/160.json','["白日既雲暮，朱顏亦已酡。畫堂初點燭，金幌半垂羅。", "長袖平陽曲，新聲子夜歌。從來慣留客，茲夕為誰多。"]'),
('yuding-58','同盧明府早秋宴張郎中海亭','孟浩然','唐','御定全唐诗','yuding','','[]','側聽弦歌宰，文書游夏徒。故園欣賞竹，為邑幸來蘇。',48,'御定全唐詩/json/160.json','["側聽弦歌宰，文書游夏徒。故園欣賞竹，為邑幸來蘇。", "華省曾聯事，仙舟複與俱。欲知臨泛久，荷露漸成珠。"]'),
('yuding-59','盧明府早秋宴張郎中海園即事，得秋字','孟浩然','唐','御定全唐诗','yuding','','[]','邑有弦歌宰，翔鸞狎野鷗。眷言華省舊，暫拂海池遊。',48,'御定全唐詩/json/160.json','["邑有弦歌宰，翔鸞狎野鷗。眷言華省舊，暫拂海池遊。", "郁島藏深竹，前溪對舞樓。更聞書即事，雲物是清秋。"]'),
('yuding-60','宴榮二山池','孟浩然','唐','御定全唐诗','yuding','','[]','甲第開金穴，榮期樂自多。櫪嘶支遁馬，池養右軍鵝。',49,'御定全唐詩/json/160.json','["甲第開金穴，榮期樂自多。櫪嘶支遁馬，池養右軍鵝。", "竹引攜琴入，花邀載酒過。山公來取醉，時唱接z5歌。"]'),
('yuding-61','夏日與崔二十一同集衛明府宅','孟浩然','唐','御定全唐诗','yuding','','[]','言避一時暑，池亭五月開。喜逢金馬客，同飲玉人杯。',48,'御定全唐詩/json/160.json','["言避一時暑，池亭五月開。喜逢金馬客，同飲玉人杯。", "舞鶴乘軒至，遊魚擁釣來。座中殊未起，簫管莫相催。"]'),
('yuding-62','清明日宴梅道士房','孟浩然','唐','御定全唐诗','yuding','','[]','林臥愁春盡，開軒覽物華。忽逢青鳥使，邀入赤松家。',48,'御定全唐詩/json/160.json','["林臥愁春盡，開軒覽物華。忽逢青鳥使，邀入赤松家。", "丹灶初開火，仙桃正落花。童顏若可駐，何惜醉流霞。"]'),
('yuding-63','寒夜張明府宅宴','孟浩然','唐','御定全唐诗','yuding','','[]','瑞雪初盈尺，寒宵始半更。列筵邀酒伴，刻燭限詩成。',48,'御定全唐詩/json/160.json','["瑞雪初盈尺，寒宵始半更。列筵邀酒伴，刻燭限詩成。", "香炭金爐暖，嬌弦玉指清。醉來方欲臥，不覺曉雞鳴。"]'),
('yuding-64','宴張別駕新齋','孟浩然','唐','御定全唐诗','yuding','','[]','世業傳珪組，江城佐股肱。高齋征學問，虛薄濫先登。',48,'御定全唐詩/json/160.json','["世業傳珪組，江城佐股肱。高齋征學問，虛薄濫先登。", "講論陪諸子，文章得舊朋。士元多賞激，衰病恨無能。"]'),
('yuding-65','與諸子登峴山','孟浩然','唐','御定全唐诗','yuding','','[]','人事有代謝，往來成古今。江山留勝跡，我輩複登臨。',48,'御定全唐詩/json/160.json','["人事有代謝，往來成古今。江山留勝跡，我輩複登臨。", "水落魚梁淺，天寒夢澤深。羊公碑字在，讀罷淚沾襟。"]'),
('yuding-66','與杭州薛司戶登樟亭樓作','孟浩然','唐','御定全唐诗','yuding','','[]','水樓一登眺，半出青林高。帟幕英僚敞，芳筵下客叨。',48,'御定全唐詩/json/160.json','["水樓一登眺，半出青林高。帟幕英僚敞，芳筵下客叨。", "山藏伯禹穴，城壓伍胥濤。今日觀溟漲，垂綸學釣鼇。"]'),
('yuding-67','尋天臺山','孟浩然','唐','御定全唐诗','yuding','','[]','吾友太乙子，餐霞臥赤城。欲尋華頂去，不憚惡溪名。',48,'御定全唐詩/json/160.json','["吾友太乙子，餐霞臥赤城。欲尋華頂去，不憚惡溪名。", "歇馬憑雲宿，揚帆截海行。高高翠微裏，遙見石樑橫。"]'),
('yuding-68','同曹三禦史行泛湖歸越','孟浩然','唐','御定全唐诗','yuding','','[]','秋入詩人意，巴歌和者稀。泛湖同逸旅，吟會是思歸。',48,'御定全唐詩/json/160.json','["秋入詩人意，巴歌和者稀。泛湖同逸旅，吟會是思歸。", "白簡徒推薦，滄洲已拂衣。杳冥雲外去，誰不羨鴻飛。"]'),
('yuding-69','晚泊潯陽望廬山','孟浩然','唐','御定全唐诗','yuding','','[]','掛席幾千里，名山都未逢。泊舟潯陽郭，始見香爐峰。',48,'御定全唐詩/json/160.json','["掛席幾千里，名山都未逢。泊舟潯陽郭，始見香爐峰。", "嘗讀遠公傳，永懷塵外蹤。東林精舍近，日暮但聞鐘。"]'),
('yuding-70','陪張丞相登嵩陽樓','孟浩然','唐','御定全唐诗','yuding','','[]','獨步人何在，嵩陽有故樓。歲寒問耆舊，行縣擁諸侯。',48,'御定全唐詩/json/160.json','["獨步人何在，嵩陽有故樓。歲寒問耆舊，行縣擁諸侯。", "林莽北彌望，沮漳東會流。客中遇知己，無複越鄉憂。"]'),
('yuding-71','武陵泛舟','孟浩然','唐','御定全唐诗','yuding','','[]','武陵川路狹，前棹入花林。莫測幽源裏，仙家信幾深。',48,'御定全唐詩/json/160.json','["武陵川路狹，前棹入花林。莫測幽源裏，仙家信幾深。", "水回青嶂合，雲度綠溪陰。坐聽閑猿嘯，彌清塵外心。"]'),
('yuding-72','與顏錢塘登障樓望潮作','孟浩然','唐','御定全唐诗','yuding','','[]','百里聞雷震，鳴弦暫輟彈。府中連騎出，江上待潮觀。',48,'御定全唐詩/json/160.json','["百里聞雷震，鳴弦暫輟彈。府中連騎出，江上待潮觀。", "照日秋雲迥，浮天渤澥寬。驚濤來似雪，一坐凜生寒。"]'),
('yuding-73','姚開府山池','孟浩然','唐','御定全唐诗','yuding','','[]','主人新邸第，相國舊池台。館是招賢辟，樓因教舞開。',48,'御定全唐詩/json/160.json','["主人新邸第，相國舊池台。館是招賢辟，樓因教舞開。", "軒車人已散，簫管鳳初來。今日龍門下，誰知文舉才。"]'),
('yuding-74','夏日浮舟過陳大水亭','孟浩然','唐','御定全唐诗','yuding','','[]','水亭涼氣多，閑棹晚來過。澗影見松竹，潭香聞芰荷。',48,'御定全唐詩/json/160.json','["水亭涼氣多，閑棹晚來過。澗影見松竹，潭香聞芰荷。", "野童扶醉舞，山鳥助酣歌。幽賞未雲遍，煙光奈夕何。"]'),
('yuding-75','與白明府游江','孟浩然','唐','御定全唐诗','yuding','','[]','故人來自遠，邑宰複初臨。執手恨為別，同舟無異心。',48,'御定全唐詩/json/160.json','["故人來自遠，邑宰複初臨。執手恨為別，同舟無異心。", "沿洄洲渚趣，演漾弦歌音。誰識躬耕者，年年梁甫吟。"]'),
('yuding-76','游鳳林寺西嶺','孟浩然','唐','御定全唐诗','yuding','','[]','共喜年華好，來游水石間。煙容開遠樹，春色滿幽山。',48,'御定全唐詩/json/160.json','["共喜年華好，來游水石間。煙容開遠樹，春色滿幽山。", "壺酒朋情洽，琴歌野興閑。莫愁歸路暝，招月伴人還。"]'),
('yuding-77','秋日陪李侍禦渡松滋江','孟浩然','唐','御定全唐诗','yuding','','[]','南紀西江闊，皇華禦史雄。截流寧假楫，掛席自生風。',48,'御定全唐詩/json/160.json','["南紀西江闊，皇華禦史雄。截流寧假楫，掛席自生風。", "僚寀爭攀鷁，魚龍亦避驄。坐聽白雪唱，翻入棹歌中。"]'),
('yuding-78','陪獨孤使君同與蕭員外證登萬山亭','孟浩然','唐','御定全唐诗','yuding','','[]','萬山青嶂曲，千騎使君遊。神女鳴環佩，仙郎接獻酬。',48,'御定全唐詩/json/160.json','["萬山青嶂曲，千騎使君遊。神女鳴環佩，仙郎接獻酬。", "遍觀雲夢野，自愛江城樓。何必東南守，空傳沈隱侯。"]'),
('yuding-79','秋登張明府海亭','孟浩然','唐','御定全唐诗','yuding','','[]','海亭秋日望，委曲見江山。染翰聊題壁，傾壺一解顏。',48,'御定全唐詩/json/160.json','["海亭秋日望，委曲見江山。染翰聊題壁，傾壺一解顏。", "歌逢彭澤令，歸賞故園間。予亦將琴史，棲遲共取閑。"]'),
('yuding-80','臨渙裴明府席遇張十一、房六','孟浩然','唐','御定全唐诗','yuding','','[]','河縣柳林邊，河橋晚泊船。文叨才子會，官喜故人連。',48,'御定全唐詩/json/160.json','["河縣柳林邊，河橋晚泊船。文叨才子會，官喜故人連。", "笑語同今夕，輕肥異往年。晨風理歸棹，吳楚各依然。"]'),
('yuding-81','梅道士水亭','孟浩然','唐','御定全唐诗','yuding','','[]','傲吏非凡吏，名流即道流。隱居不可見，高論莫能酬。',48,'御定全唐詩/json/160.json','["傲吏非凡吏，名流即道流。隱居不可見，高論莫能酬。", "水接仙源近，山藏鬼穀幽。再來迷處所，花下問漁舟。"]'),
('yuding-82','游景空寺蘭若','孟浩然','唐','御定全唐诗','yuding','','[]','龍象經行處，山腰度石關。屢迷青嶂合，時愛綠蘿閑。',48,'御定全唐詩/json/160.json','["龍象經行處，山腰度石關。屢迷青嶂合，時愛綠蘿閑。", "宴息花林下，高談竹嶼間。寥寥隔塵事，疑是入雞山。"]'),
('yuding-83','陪李侍禦訪聰上人禪居','孟浩然','唐','御定全唐诗','yuding','','[]','欣逢柏台友，共謁聰公禪。石室無人到，繩床見虎眠。',48,'御定全唐詩/json/160.json','["欣逢柏台友，共謁聰公禪。石室無人到，繩床見虎眠。", "陰崖常抱雪，枯澗為生泉。出處雖雲異，同歡在法筵。"]'),
('yuding-84','遊精思觀回，王白雲在後','孟浩然','唐','御定全唐诗','yuding','','[]','出穀未停午，到家日已曛。回瞻下山路，但見牛羊群。',48,'御定全唐詩/json/160.json','["出穀未停午，到家日已曛。回瞻下山路，但見牛羊群。", "樵子暗相失，草蟲寒不聞。衡門猶未掩，佇立望夫君。"]'),
('yuding-85','夏日辨玉法師茅齋','孟浩然','唐','御定全唐诗','yuding','','[]','夏日茅齋裏，無風坐亦涼。竹林深筍穊，藤架引梢長。',48,'御定全唐詩/json/160.json','["夏日茅齋裏，無風坐亦涼。竹林深筍穊，藤架引梢長。", "燕覓巢窠處，蜂來造蜜房。物華皆可玩，花蕊四時芳。"]'),
('yuding-86','與張折沖遊耆闍寺','孟浩然','唐','御定全唐诗','yuding','','[]','釋子彌天秀，將軍武庫才。橫行塞北盡，獨步漢南來。',48,'御定全唐詩/json/160.json','["釋子彌天秀，將軍武庫才。橫行塞北盡，獨步漢南來。", "貝葉傳金口，山樓作賦開。因君振嘉藻，江楚氣雄哉。"]'),
('yuding-87','遊精思，題觀主山房','孟浩然','唐','御定全唐诗','yuding','','[]','誤入桃源裏，初憐竹徑深。方知仙子宅，未有世人尋。',48,'御定全唐詩/json/160.json','["誤入桃源裏，初憐竹徑深。方知仙子宅，未有世人尋。", "舞鶴過閑砌，飛猿嘯密林。漸通玄妙理，深得坐忘心。"]'),
('yuding-88','宿立公房','孟浩然','唐','御定全唐诗','yuding','','[]','支遁初求道，深公笑買山。何如石岩趣，自入戶庭間。',48,'御定全唐詩/json/160.json','["支遁初求道，深公笑買山。何如石岩趣，自入戶庭間。", "苔澗春泉滿，蘿軒夜月閑。能令許玄度，吟臥不知還。"]'),
('yuding-89','尋陳逸人故居','孟浩然','唐','御定全唐诗','yuding','','[]','人事一朝盡，荒蕪三徑休。始聞漳浦臥，奄作岱宗遊。',48,'御定全唐詩/json/160.json','["人事一朝盡，荒蕪三徑休。始聞漳浦臥，奄作岱宗遊。", "池水猶含墨，風雲已落秋。今宵泉壑裏，何處覓藏舟。"]'),
('yuding-90','尋梅道士','孟浩然','唐','御定全唐诗','yuding','','[]','彭澤先生柳，山陰道士鵝。我來從所好，停策漢陰多。',48,'御定全唐詩/json/160.json','["彭澤先生柳，山陰道士鵝。我來從所好，停策漢陰多。", "重以觀魚樂，因之鼓枻歌。崔徐跡未朽，千載揖清波。"]'),
('yuding-91','陪姚使君題惠上人房','孟浩然','唐','御定全唐诗','yuding','','[]','帶雪梅初暖，含煙柳尚青。來窺童子偈，得聽法王經。',48,'御定全唐詩/json/160.json','["帶雪梅初暖，含煙柳尚青。來窺童子偈，得聽法王經。", "會理知無我，觀空厭有形。迷心應覺悟，客思未遑寧。"]'),
('yuding-92','晚春題遠上人南亭','孟浩然','唐','御定全唐诗','yuding','','[]','給園支遁隱，虛寂養身和。春晚群木秀，間關黃鳥歌。',48,'御定全唐詩/json/160.json','["給園支遁隱，虛寂養身和。春晚群木秀，間關黃鳥歌。", "林棲居士竹，池養右軍鵝。炎月北窗下，清風期再過。"]'),
('yuding-93','題大禹寺義公禪房','孟浩然','唐','御定全唐诗','yuding','','[]','義公習禪處，結構依空林。戶外一峰秀，階前群壑深。',48,'御定全唐詩/json/160.json','["義公習禪處，結構依空林。戶外一峰秀，階前群壑深。", "夕陽連雨足，空翠落庭陰。看取蓮花淨，應知不染心。"]'),
('yuding-94','尋白鶴岩張子容隱居','孟浩然','唐','御定全唐诗','yuding','','[]','白鶴青岩半，幽人有隱居。階庭空水石，林壑罷樵漁。',48,'御定全唐詩/json/160.json','["白鶴青岩半，幽人有隱居。階庭空水石，林壑罷樵漁。", "歲月青松老，風霜苦竹疏。睹茲懷舊業，回策返吾廬。"]'),
('yuding-95','題融公蘭若','孟浩然','唐','御定全唐诗','yuding','','[]','精舍買金開，流泉繞砌回。芰荷熏講席，松柏映香台。',48,'御定全唐詩/json/160.json','["精舍買金開，流泉繞砌回。芰荷熏講席，松柏映香台。", "法雨晴飛去，天花晝下來。談玄殊未已，歸騎夕陽催。"]'),
('yuding-96','過景空寺故融公蘭若','孟浩然','唐','御定全唐诗','yuding','','[]','池上青蓮宇，林間白馬泉。故人成異物，過客獨潸然。',48,'御定全唐詩/json/160.json','["池上青蓮宇，林間白馬泉。故人成異物，過客獨潸然。", "既禮新松塔，還尋舊石筵。平生竹如意，猶掛草堂前。"]'),
('yuding-97','題張野人園廬','孟浩然','唐','御定全唐诗','yuding','','[]','與君園廬並，微尚頗亦同。耕釣方自逸，壺觴趣不空。',48,'御定全唐詩/json/160.json','["與君園廬並，微尚頗亦同。耕釣方自逸，壺觴趣不空。", "門無俗士駕，人有上皇風。何處先賢傳，惟稱龐德公。"]'),
('yuding-98','李少府與楊九再來','孟浩然','唐','御定全唐诗','yuding','','[]','弱歲早登龍，今來喜再逢。如何春月柳，猶憶歲寒松。',48,'御定全唐詩/json/160.json','["弱歲早登龍，今來喜再逢。如何春月柳，猶憶歲寒松。", "煙火臨寒食，笙歌達曙鐘。喧喧鬥雞道，行樂羨朋從。"]'),
('yuding-99','尋張五回夜園作','孟浩然','唐','御定全唐诗','yuding','','[]','聞就龐公隱，移居近洞湖。興來林是竹，歸臥穀名愚。',48,'御定全唐詩/json/160.json','["聞就龐公隱，移居近洞湖。興來林是竹，歸臥穀名愚。", "掛席樵風便，開軒琴月孤。歲寒何用賞，霜落故園蕪。"]'),
('yuding-100','裴司士、員司戶見尋','孟浩然','唐','御定全唐诗','yuding','','[]','府僚能枉駕，家醞複新開。落日池上酌，清風松下來。',48,'御定全唐詩/json/160.json','["府僚能枉駕，家醞複新開。落日池上酌，清風松下來。", "廚人具雞黍，稚子摘楊梅。誰道山公醉，猶能騎馬回。"]'),
('yuding-101','春中喜王九相尋','孟浩然','唐','御定全唐诗','yuding','','[]','二月湖水清，家家春鳥鳴。林花掃更落，徑草踏還生。',48,'御定全唐詩/json/160.json','["二月湖水清，家家春鳥鳴。林花掃更落，徑草踏還生。", "酒伴來相命，開尊共解酲。當杯已入手，歌妓莫停聲。"]'),
('yuding-102','李氏園林臥疾','孟浩然','唐','御定全唐诗','yuding','','[]','我愛陶家趣，園林無俗情。春雷百卉坼，寒食四鄰清。',48,'御定全唐詩/json/160.json','["我愛陶家趣，園林無俗情。春雷百卉坼，寒食四鄰清。", "伏枕嗟公幹，歸山羨子平。年年白社客，空滯洛陽城。"]'),
('yuding-103','過故人莊','孟浩然','唐','御定全唐诗','yuding','','[]','故人具雞黍，邀我至田家。綠樹村邊合，青山郭外斜。',48,'御定全唐詩/json/160.json','["故人具雞黍，邀我至田家。綠樹村邊合，青山郭外斜。", "開筵面場圃，把酒話桑麻。待到重陽日，還來就菊花。"]'),
('yuding-104','張七及辛大見尋南亭醉作','孟浩然','唐','御定全唐诗','yuding','','[]','山公能飲酒，居士好彈箏。世外交初得，林中契已並。',48,'御定全唐詩/json/160.json','["山公能飲酒，居士好彈箏。世外交初得，林中契已並。", "納涼風颯至，逃暑日將傾。便就南亭裏，餘尊惜解酲。"]'),
('yuding-105','歲暮歸南山','孟浩然','唐','御定全唐诗','yuding','','[]','北闕休上書，南山歸敝廬。不才明主棄，多病故人疏。',48,'御定全唐詩/json/160.json','["北闕休上書，南山歸敝廬。不才明主棄，多病故人疏。", "白髮催年老，青陽逼歲除。永懷愁不寐，松月夜窗虛。"]'),
('yuding-106','南山下與老圃期種瓜','孟浩然','唐','御定全唐诗','yuding','','[]','樵牧南山近，林閭北郭賒。先人留素業，老圃作鄰家。',48,'御定全唐詩/json/160.json','["樵牧南山近，林閭北郭賒。先人留素業，老圃作鄰家。", "不種千株橘，惟資五色瓜。邵平能就我，開徑剪蓬麻。"]'),
('yuding-107','溯江至武昌','孟浩然','唐','御定全唐诗','yuding','','[]','家本洞湖上，歲時歸思催。客心徒欲速，江路苦邅回。',48,'御定全唐詩/json/160.json','["家本洞湖上，歲時歸思催。客心徒欲速，江路苦邅回。", "殘凍因風解，新正度臘開。行看武昌柳，仿佛映樓臺。"]'),
('yuding-108','舟中曉望','孟浩然','唐','御定全唐诗','yuding','','[]','掛席東南望，青山水國遙。舳艫爭利涉，來往接風潮。',48,'御定全唐詩/json/160.json','["掛席東南望，青山水國遙。舳艫爭利涉，來往接風潮。", "問我今何去，天臺訪石橋。坐看霞色曉，疑是赤城標。"]'),
('yuding-109','自洛之越','孟浩然','唐','御定全唐诗','yuding','','[]','皇皇三十載，書劍兩無成。山水尋吳越，風塵厭洛京。',48,'御定全唐詩/json/160.json','["皇皇三十載，書劍兩無成。山水尋吳越，風塵厭洛京。", "扁舟泛湖海，長揖謝公卿。且樂杯中物，誰論世上名。"]'),
('yuding-110','途中遇晴','孟浩然','唐','御定全唐诗','yuding','','[]','已失巴陵雨，猶逢蜀阪泥。天開斜景遍，山出晚雲低。',48,'御定全唐詩/json/160.json','["已失巴陵雨，猶逢蜀阪泥。天開斜景遍，山出晚雲低。", "餘濕猶沾草，殘流尚入溪。今宵有明月，鄉思遠淒淒。"]'),
('yuding-111','歸至郢中','孟浩然','唐','御定全唐诗','yuding','','[]','遠遊經海嶠，返棹歸山阿。日夕見喬木，鄉關在伐柯。',48,'御定全唐詩/json/160.json','["遠遊經海嶠，返棹歸山阿。日夕見喬木，鄉關在伐柯。", "愁隨江路盡，喜入郢門多。左右看桑土，依然即匪他。"]'),
('yuding-112','夕次蔡陽館','孟浩然','唐','御定全唐诗','yuding','','[]','日暮馬行疾，城荒人住稀。聽歌知近楚，投館忽如歸。',48,'御定全唐詩/json/160.json','["日暮馬行疾，城荒人住稀。聽歌知近楚，投館忽如歸。", "魯堰田疇廣，章陵氣色微。明朝拜嘉慶，須著老萊衣。"]'),
('yuding-113','他鄉七夕','孟浩然','唐','御定全唐诗','yuding','','[]','他鄉逢七夕，旅館益羈愁。不見穿針婦，空懷故國樓。',48,'御定全唐詩/json/160.json','["他鄉逢七夕，旅館益羈愁。不見穿針婦，空懷故國樓。", "緒風初減熱，新月始臨秋。誰忍窺河漢，迢迢問鬥牛。"]'),
('yuding-114','夜泊牛渚，趁薛八船不及','孟浩然','唐','御定全唐诗','yuding','','[]','星羅牛渚夕，風退鷁舟遲。浦漵嘗同宿，煙波忽間之。',48,'御定全唐詩/json/160.json','["星羅牛渚夕，風退鷁舟遲。浦漵嘗同宿，煙波忽間之。", "榜歌空裏失，船火望中疑。明發泛潮海，茫茫何處期。"]'),
('yuding-115','曉入南山','孟浩然','唐','御定全唐诗','yuding','','[]','瘴氣曉氛氳，南山複水雲。鯤飛今始見，鳥墜舊來聞。',48,'御定全唐詩/json/160.json','["瘴氣曉氛氳，南山複水雲。鯤飛今始見，鳥墜舊來聞。", "地接長沙近，江從汨渚分。賈生曾吊屈，予亦痛斯文。"]'),
('yuding-116','夜渡湘水','孟浩然','唐','御定全唐诗','yuding','','[]','客舟貪利涉，暗裏渡湘川。露氣聞芳杜，歌聲識採蓮。',48,'御定全唐詩/json/160.json','["客舟貪利涉，暗裏渡湘川。露氣聞芳杜，歌聲識採蓮。", "榜人投岸火，漁子宿潭煙。行侶時相問，潯陽何處邊。"]'),
('yuding-117','赴京途中遇雪','孟浩然','唐','御定全唐诗','yuding','','[]','迢遞秦京道，蒼茫歲暮天。窮陰連晦朔，積雪滿山川。',48,'御定全唐詩/json/160.json','["迢遞秦京道，蒼茫歲暮天。窮陰連晦朔，積雪滿山川。", "落雁迷沙渚，饑烏集野田。客愁空佇立，不見有人煙。"]'),
('yuding-118','途次望鄉','孟浩然','唐','御定全唐诗','yuding','','[]','客行愁落日，鄉思重相催。況在他山外，天寒夕鳥來。',48,'御定全唐詩/json/160.json','["客行愁落日，鄉思重相催。況在他山外，天寒夕鳥來。", "雪深迷郢路，雲暗失陽臺。可歎悽惶子，高歌誰為媒。"]'),
('yuding-119','永嘉上浦館逢張八子容','孟浩然','唐','御定全唐诗','yuding','','[]','逆旅相逢處，江村日暮時。眾山遙對酒，孤嶼共題詩。',48,'御定全唐詩/json/160.json','["逆旅相逢處，江村日暮時。眾山遙對酒，孤嶼共題詩。", "廨宇鄰蛟室，人煙接島夷。鄉園萬餘裏，失路一相悲。"]'),
('yuding-120','宿武陽即事','孟浩然','唐','御定全唐诗','yuding','','[]','川暗夕陽盡，孤舟泊岸初。嶺猿相叫嘯，潭嶂似空虛。',48,'御定全唐詩/json/160.json','["川暗夕陽盡，孤舟泊岸初。嶺猿相叫嘯，潭嶂似空虛。", "就枕滅明燭，扣舷聞夜漁。雞鳴問何處，人物是秦餘。"]'),
('yuding-121','渡揚子江','孟浩然','唐','御定全唐诗','yuding','','[]','桂楫中流望，京江兩畔明。林開揚子驛，山出潤州城。',48,'御定全唐詩/json/160.json','["桂楫中流望，京江兩畔明。林開揚子驛，山出潤州城。", "海盡邊陰靜，江寒朔吹生。更聞楓葉下，淅瀝度秋聲。"]'),
('yuding-122','田家元日','孟浩然','唐','御定全唐诗','yuding','','[]','昨夜鬥回北，今朝歲起東。我年已強仕，無祿尚憂農。',48,'御定全唐詩/json/160.json','["昨夜鬥回北，今朝歲起東。我年已強仕，無祿尚憂農。", "桑野就耕父，荷鋤隨牧童。田家占氣候，共說此年豐。"]'),
('yuding-123','九日得新字','孟浩然','唐','御定全唐诗','yuding','','[]','初九未成旬，重陽即此晨。登高聞古事，載酒訪幽人。',48,'御定全唐詩/json/160.json','["初九未成旬，重陽即此晨。登高聞古事，載酒訪幽人。", "落帽恣歡飲，授衣同試新。茱萸正可佩，折取寄情親。"]'),
('yuding-124','除夜樂城逢張少府','孟浩然','唐','御定全唐诗','yuding','','[]','雲海泛甌閩，風潮泊島濱。何知歲除夜，得見故鄉親。',48,'御定全唐詩/json/160.json','["雲海泛甌閩，風潮泊島濱。何知歲除夜，得見故鄉親。", "餘是乘槎客，君為失路人。平生複能幾，一別十餘春。"]'),
('yuding-125','歲除夜會樂城張少府宅','孟浩然','唐','御定全唐诗','yuding','','[]','疇昔通家好，相知無間然。續明催畫燭，守歲接長筵。',48,'御定全唐詩/json/160.json','["疇昔通家好，相知無間然。續明催畫燭，守歲接長筵。", "舊曲梅花唱，新正柏酒傳。客行隨處樂，不見度年年。"]'),
('yuding-126','寒夜','孟浩然','唐','御定全唐诗','yuding','','[]','閨夕綺窗閉，佳人罷縫衣。理琴開寶匣，就枕臥重幃。',48,'御定全唐詩/json/160.json','["閨夕綺窗閉，佳人罷縫衣。理琴開寶匣，就枕臥重幃。", "夜久燈花落，熏籠香氣微。錦衾重自暖，遮莫曉霜飛。"]'),
('yuding-127','賦得盈盈樓上女','孟浩然','唐','御定全唐诗','yuding','','[]','夫婿久離別，青樓空望歸。妝成捲簾坐，愁思懶縫衣。',48,'御定全唐詩/json/160.json','["夫婿久離別，青樓空望歸。妝成捲簾坐，愁思懶縫衣。", "燕子家家入，楊花處處飛。空床難獨守，誰為報金徽。"]'),
('yuding-128','春意','孟浩然','唐','御定全唐诗','yuding','','[]','佳人能畫眉，妝罷出簾帷。照水空自愛，折花將遺誰。',48,'御定全唐詩/json/160.json','["佳人能畫眉，妝罷出簾帷。照水空自愛，折花將遺誰。", "春情多豔逸，春意倍相思。愁心極楊柳，一種亂如絲。"]'),
('yuding-129','閨情','孟浩然','唐','御定全唐诗','yuding','','[]','一別隔炎涼，君衣忘短長。裁縫無處等，以意忖情量。',48,'御定全唐詩/json/160.json','["一別隔炎涼，君衣忘短長。裁縫無處等，以意忖情量。", "畏瘦疑傷窄，防寒更厚裝。半啼封裹了，知欲寄誰將。"]'),
('yuding-130','美人分香','孟浩然','唐','御定全唐诗','yuding','','[]','豔色本傾城，分香更有情。髻鬟垂欲解，眉黛拂能輕。',48,'御定全唐詩/json/160.json','["豔色本傾城，分香更有情。髻鬟垂欲解，眉黛拂能輕。", "舞學平陽態，歌翻子夜聲。春風狹斜道，含笑待逢迎。"]'),
('yuding-131','傷峴山雲表觀主','孟浩然','唐','御定全唐诗','yuding','','[]','少小學書劍，秦吳多歲年。歸來一登眺，陵谷尚依然。',48,'御定全唐詩/json/160.json','["少小學書劍，秦吳多歲年。歸來一登眺，陵谷尚依然。", "豈意餐霞客，溘隨朝露先。因之問閭裏，把臂幾人全。"]'),
('yuding-132','題梧州陳司馬山齋','孟浩然','唐','御定全唐诗','yuding','','[]','南國無霜霰，連年對物華。青林暗換葉，紅蕊亦開花。',48,'御定全唐詩/json/160.json','["南國無霜霰，連年對物華。青林暗換葉，紅蕊亦開花。", "春去無山鳥，秋來見海槎。流芳雖可悅，會自泣長沙。"]'),
('yuding-133','歲除夜有懷','孟浩然','唐','御定全唐诗','yuding','','[]','迢遞三巴路，羈危萬里身。亂山殘雪夜，孤燭異鄉人。',48,'御定全唐詩/json/160.json','["迢遞三巴路，羈危萬里身。亂山殘雪夜，孤燭異鄉人。", "漸與骨肉遠，轉于奴僕親。那堪正飄泊，來日歲華新。"]'),
('yuding-134','登安陽城樓','孟浩然','唐','御定全唐诗','yuding','','[]','縣城南面漢江流，江漲開成南雍州。才子乘春來騁望，',40,'御定全唐詩/json/160.json','["縣城南面漢江流，江漲開成南雍州。才子乘春來騁望，", "向夕波搖明月動，更疑神女弄珠游。"]'),
('yuding-135','登萬歲樓','孟浩然','唐','御定全唐诗','yuding','','[]','萬歲樓頭望故鄉，獨令鄉思更茫茫。天寒雁度堪垂淚，',40,'御定全唐詩/json/160.json','["萬歲樓頭望故鄉，獨令鄉思更茫茫。天寒雁度堪垂淚，", "今朝偶見同袍友，卻喜家書寄八行。"]'),
('yuding-136','除夜有懷','孟浩然','唐','御定全唐诗','yuding','','[]','五更鐘漏欲相催，四氣推遷往復回。帳裏殘燈才去焰，',40,'御定全唐詩/json/160.json','["五更鐘漏欲相催，四氣推遷往復回。帳裏殘燈才去焰，", "守歲家家應未臥，相思那得夢魂來。"]'),
('yuding-137','春情','孟浩然','唐','御定全唐诗','yuding','','[]','青樓曉日珠簾映，紅粉春妝寶鏡催。已厭交歡憐枕席，',40,'御定全唐詩/json/160.json','["青樓曉日珠簾映，紅粉春妝寶鏡催。已厭交歡憐枕席，", "更道明朝不當作，相期共鬥管弦來。"]'),
('yuding-138','長安早春','孟浩然','唐','御定全唐诗','yuding','','[]','關戍惟東井，城池起北辰。咸歌太平日，共樂建寅春。',72,'御定全唐詩/json/160.json','["關戍惟東井，城池起北辰。咸歌太平日，共樂建寅春。", "雪盡青山樹，冰開黑水濱。草迎金埒馬，花伴玉樓人。", "鴻漸看無數，鶯歌聽欲頻。何當遂榮擢，歸及柳條新。"]'),
('yuding-139','荊門上張丞相','孟浩然','唐','御定全唐诗','yuding','','[]','共理分荊國，招賢愧不材。召南風更闡，丞相閣還開。',96,'御定全唐詩/json/160.json','["共理分荊國，招賢愧不材。召南風更闡，丞相閣還開。", "覯止欣眉睫，沉淪拔草萊。坐登徐孺榻，頻接李膺杯。", "始慰蟬鳴柳，俄看雪間梅。四時年鑰盡，千里客程催。", "日下瞻歸翼，沙邊厭曝鰓。佇聞宣室召，星象列三台。"]'),
('yuding-140','陪張丞相登荊城樓，因寄薊州張使君及浪泊戍主劉家','孟浩然','唐','御定全唐诗','yuding','','[]','薊門天北畔，銅柱日南端。出守聲彌遠，投荒法未寬。',72,'御定全唐詩/json/160.json','["薊門天北畔，銅柱日南端。出守聲彌遠，投荒法未寬。", "側身聊倚望，攜手莫同歡。白璧無瑕玷，青松有歲寒。", "府中丞相閣，江上使君灘。興盡回舟去，方知行路難。"]'),
('yuding-141','陪張丞相祠紫蓋山，途經玉泉寺','孟浩然','唐','御定全唐诗','yuding','','[]','望秩宣王命，齋心待漏行。青衿列胄子，從事有參卿。',120,'御定全唐詩/json/160.json','["望秩宣王命，齋心待漏行。青衿列胄子，從事有參卿。", "五馬尋歸路，雙林指化城。聞鐘度門近，照膽玉泉清。", "皂蓋依松憩，緇徒擁錫迎。天宮上兜率，沙界豁迷明。", "欲就終焉志，恭聞智者名。人隨逝水沒，波逐覆舟傾。", "想像若在眼，周流空複情。謝公還欲臥，誰與濟蒼生。"]'),
('yuding-142','陪張丞相自松滋江東泊渚宮','孟浩然','唐','御定全唐诗','yuding','','[]','放溜下松滋，登舟命楫師。詎忘經濟日，不憚冱寒時。',96,'御定全唐詩/json/160.json','["放溜下松滋，登舟命楫師。詎忘經濟日，不憚冱寒時。", "洗幘豈獨古，濯纓良在茲。政成人自理，機息鳥無疑。", "雲物凝孤嶼，江山辨四維。晚來風稍急，冬至日行遲。", "臘響驚雲夢，漁歌激楚辭。渚宮何處是，川暝欲安之。"]'),
('yuding-143','和張判官登萬山亭，因贈洪府都督韓公','孟浩然','唐','御定全唐诗','yuding','','[]','韓公是襄士，日賞城西岑。結構意不淺，岩潭趣轉深。',120,'御定全唐詩/json/160.json','["韓公是襄士，日賞城西岑。結構意不淺，岩潭趣轉深。", "皇華一動詠，荊國幾謠吟。舊徑蘭勿剪，新堤柳欲陰。", "砌傍餘怪石，沙上有閑禽。自牧豫章郡，空瞻楓樹林。", "因聲寄流水，善聽在知音。耆舊眇不接，崔徐無處尋。", "物情多貴遠，賢俊豈無今。遲爾長江暮，澄清一洗心。"]'),
('yuding-144','和宋太史北樓新亭','孟浩然','唐','御定全唐诗','yuding','','[]','返耕意未遂，日夕登城隅。誰道山林近，坐為符竹拘。',72,'御定全唐詩/json/160.json','["返耕意未遂，日夕登城隅。誰道山林近，坐為符竹拘。", "麗譙非改作，軒檻是新圖。遠水自嶓塚，長雲吞具區。", "願隨江燕賀，羞逐府僚趨。欲識狂歌者，丘園一豎儒。"]'),
('yuding-145','贈蕭少府','孟浩然','唐','御定全唐诗','yuding','','[]','上德如流水，安仁道若山。聞君秉高節，而得奉清顏。',72,'御定全唐詩/json/160.json','["上德如流水，安仁道若山。聞君秉高節，而得奉清顏。", "鴻漸升儀羽，牛刀列下班。處腴能不潤，居劇體常閑。", "去詐人無諂，除邪吏息奸。欲知清與潔，明月照澄灣。"]'),
('yuding-146','秦中苦雨思歸，贈袁左丞、賀侍郎','孟浩然','唐','御定全唐诗','yuding','','[]','苦學三十載，閉門江漢陰。用賢遭聖日，羈旅屬秋霖。',96,'御定全唐詩/json/160.json','["苦學三十載，閉門江漢陰。用賢遭聖日，羈旅屬秋霖。", "豈直昏墊苦，亦為權勢沈。二毛催白髮，百鎰罄黃金。", "淚憶峴山墮，愁懷湘水深。謝公積憤懣，莊舄空謠吟。", "躍馬非吾事，狎鷗宜我心。寄言當路者，去矣北山岑。"]'),
('yuding-147','同張明府碧溪贈答','孟浩然','唐','御定全唐诗','yuding','','[]','別業聞新制，同聲和者多。還看碧溪答，不羨綠珠歌。',96,'御定全唐詩/json/160.json','["別業聞新制，同聲和者多。還看碧溪答，不羨綠珠歌。", "自有陽臺女，朝朝拾翠過。綺筵鋪錦繡，妝牖閉藤蘿。", "秩滿休閒日，春餘景氣和。仙鳧能作伴，羅襪共淩波。", "曲島尋花藥，回潭折芰荷。更憐斜日照，紅粉豔青娥。"]'),
('yuding-148','久滯越中，貽謝南池、會稽賀少府','孟浩然','唐','御定全唐诗','yuding','','[]','陳平無產業，尼父倦東西。負郭昔雲翳，問津今亦迷。',72,'御定全唐詩/json/160.json','["陳平無產業，尼父倦東西。負郭昔雲翳，問津今亦迷。", "未能忘魏闕，空此滯秦稽。兩見夏雲起，再聞春鳥啼。", "懷仙梅福市，訪舊若耶溪。聖主賢為寶，君何隱遁棲。"]'),
('yuding-149','送韓使君除洪州都曹','孟浩然','唐','御定全唐诗','yuding','','[]','述職撫荊衡，分符襲寵榮。往來看擁傳，前後賴專城。',96,'御定全唐詩/json/160.json','["述職撫荊衡，分符襲寵榮。往來看擁傳，前後賴專城。", "勿翦棠猶在，波澄水更清。重推江漢理，旋改豫章行。", "召父多遺愛，羊公有令名。衣冠列祖道，耆舊擁前旌。", "峴首晨風送，江陵夜火迎。無才慚孺子，千里愧同聲。"]'),
('yuding-150','送莫甥兼諸昆弟從韓司馬入西軍','孟浩然','唐','御定全唐诗','yuding','','[]','念爾習詩禮，未曾違戶庭。平生早偏露，萬里更飄零。',72,'御定全唐詩/json/160.json','["念爾習詩禮，未曾違戶庭。平生早偏露，萬里更飄零。", "坐棄三牲養，行觀八陣形。飾裝辭故里，謀策赴邊庭。", "壯志吞鴻鵠，遙心伴鶺鴒。所從文且武，不戰自應寧。"]'),
('yuding-151','峴山送蕭員外之荊州','孟浩然','唐','御定全唐诗','yuding','','[]','峴山江岸曲，郢水郭門前。自古登臨處，非今獨黯然。',72,'御定全唐詩/json/160.json','["峴山江岸曲，郢水郭門前。自古登臨處，非今獨黯然。", "亭樓明落照，井邑秀通川。澗竹生幽興，林風入管弦。", "再飛鵬激水，一舉鶴沖天。佇立三荊使，看君駟馬旋。"]'),
('yuding-152','送王昌齡之嶺南','孟浩然','唐','御定全唐诗','yuding','','[]','洞庭去遠近，楓葉早驚秋。峴首羊公愛，長沙賈誼愁。',72,'御定全唐詩/json/160.json','["洞庭去遠近，楓葉早驚秋。峴首羊公愛，長沙賈誼愁。", "土毛無縞紵，鄉味有槎頭。已抱沈痼疾，更貽魑魅憂。", "數年同筆硯，茲夕間衾裯。意氣今何在，相思望鬥牛。"]'),
('yuding-153','峴山送張去非遊巴東','孟浩然','唐','御定全唐诗','yuding','','[]','峴山南郭外，送別每登臨。沙岸江村近，松門山寺深。',72,'御定全唐詩/json/160.json','["峴山南郭外，送別每登臨。沙岸江村近，松門山寺深。", "一言予有贈，三峽爾將尋。祖席宜城酒，征途雲夢林。", "蹉跎遊子意，眷戀故人心。去矣勿淹滯，巴東猿夜吟。"]'),
('yuding-154','奉先張明府休沐還鄉，海亭宴集','孟浩然','唐','御定全唐诗','yuding','','[]','自君理畿甸，予亦經江淮。萬里書信斷，數年雲雨乖。',72,'御定全唐詩/json/160.json','["自君理畿甸，予亦經江淮。萬里書信斷，數年雲雨乖。", "歸來休浣日，始得賞心諧。朱紱恩雖重，滄洲趣每懷。", "樹低新舞閣，山對舊書齋。何以發秋興，陰蟲鳴夜階。"]'),
('yuding-155','宴張記室宅','孟浩然','唐','御定全唐诗','yuding','','[]','甲第金張館，門庭車騎多。家封漢陽郡，文會楚材過。',72,'御定全唐詩/json/160.json','["甲第金張館，門庭車騎多。家封漢陽郡，文會楚材過。", "曲島浮觴酌，前山入詠歌。妓堂花映發，書閣柳逶迤。", "玉指調箏柱，金泥飾舞羅。寧知書劍者，歲月獨蹉跎。"]'),
('yuding-156','宴崔明府宅夜觀妓','孟浩然','唐','御定全唐诗','yuding','','[]','畫堂觀妙妓，長夜正留賓。燭吐蓮花豔，妝成桃李春。',72,'御定全唐詩/json/160.json','["畫堂觀妙妓，長夜正留賓。燭吐蓮花豔，妝成桃李春。", "髻鬟低舞席，衫袖掩歌唇。汗濕偏宜粉，羅輕詎著身。", "調移箏柱促，歡會酒杯頻。倘使曹王見，應嫌洛浦神。"]'),
('yuding-157','盧明府九日峴山宴袁使君、張郎中、崔員外','孟浩然','唐','御定全唐诗','yuding','','[]','宇宙誰開闢，江山此鬱盤。登臨今古用，風俗歲時觀。',120,'御定全唐詩/json/160.json','["宇宙誰開闢，江山此鬱盤。登臨今古用，風俗歲時觀。", "地理荊州分，天涯楚塞寬。百城今刺史，華省舊郎官。", "共美重陽節，俱懷落帽歡。酒邀彭澤載，琴輟武城彈。", "獻壽先浮菊，尋幽或藉蘭。煙虹鋪藻翰，松竹掛衣冠。", "叔子神如在，山公興未闌。傳聞騎馬醉，還向習池看。"]'),
('yuding-158','登龍興寺閣','孟浩然','唐','御定全唐诗','yuding','','[]','閣道乘空出，披軒遠目開。逶迤見江勢，客至屢緣回。',72,'御定全唐詩/json/160.json','["閣道乘空出，披軒遠目開。逶迤見江勢，客至屢緣回。", "茲郡何填委，遙山複幾哉。蒼蒼皆草木，處處盡樓臺。", "驟雨一陽散，行舟四海來。鳥歸餘興遠，周覽更裴回。"]'),
('yuding-159','登總持寺浮圖','孟浩然','唐','御定全唐诗','yuding','','[]','半空躋寶塔，晴望盡京華。竹繞渭川遍，山連上苑斜。',72,'御定全唐詩/json/160.json','["半空躋寶塔，晴望盡京華。竹繞渭川遍，山連上苑斜。", "四門開帝宅，阡陌俯人家。累劫從初地，為童憶聚沙。", "一窺功德見，彌益道心加。坐覺諸天近，空香送落花。"]'),
('yuding-160','與崔二十一遊鏡湖，寄包、賀二公','孟浩然','唐','御定全唐诗','yuding','','[]','試覽鏡湖物，中流到底清。不知鱸魚味，但識鷗鳥情。',72,'御定全唐詩/json/160.json','["試覽鏡湖物，中流到底清。不知鱸魚味，但識鷗鳥情。", "帆得樵風送，春逢穀雨晴。將探夏禹穴，稍背越王城。", "府掾有包子，文章推賀生。滄浪醉後唱，因此寄同聲。"]'),
('yuding-161','夜登孔伯昭南樓，時沈太清、朱升在座','孟浩然','唐','御定全唐诗','yuding','','[]','誰家無風月，此地有琴尊。山水會稽郡，詩書孔氏門。',72,'御定全唐詩/json/160.json','["誰家無風月，此地有琴尊。山水會稽郡，詩書孔氏門。", "再來值秋杪，高閣夜無喧。華燭罷然蠟，清弦方奏鶤。", "沈生隱侯胤，朱子買臣孫。好我意不淺，登茲共話言。"]'),
('yuding-162','陪盧明府泛舟回作','孟浩然','唐','御定全唐诗','yuding','','[]','百里行春返，清流逸興多。鷁舟隨雁泊，江火共星羅。',72,'御定全唐詩/json/160.json','["百里行春返，清流逸興多。鷁舟隨雁泊，江火共星羅。", "已救田家旱，仍醫俗化訛。文章推後輩，風雅激頹波。", "高岸迷陵穀，新聲滿棹歌。猶憐不才子，白首未登科。"]'),
('yuding-163','臘月八日於剡縣石城寺禮拜','孟浩然','唐','御定全唐诗','yuding','','[]','石壁開金像，香山倚鐵圍。下生彌勒見，回向一心歸。',72,'御定全唐詩/json/160.json','["石壁開金像，香山倚鐵圍。下生彌勒見，回向一心歸。", "竹柏禪庭古，樓臺世界稀。夕嵐增氣色，餘照發光輝。", "講席邀談柄，泉堂施浴衣。願承功德水，從此濯塵機。"]'),
('yuding-164','同獨孤使君東齋作','孟浩然','唐','御定全唐诗','yuding','','[]','郎官舊華省，天子命分憂。襄土歲頻旱，隨車雨再流。',72,'御定全唐詩/json/160.json','["郎官舊華省，天子命分憂。襄土歲頻旱，隨車雨再流。", "雲陰自南楚，河潤及東周。廨宇宜新霽，田家賀有秋。", "竹間殘照入，池上夕陽浮。寄謝東陽守，何如八詠樓。"]'),
('yuding-165','同王九題就師山房','孟浩然','唐','御定全唐诗','yuding','','[]','晚憩支公室，故人逢右軍。軒窗避炎暑，翰墨動新文。',72,'御定全唐詩/json/160.json','["晚憩支公室，故人逢右軍。軒窗避炎暑，翰墨動新文。", "竹蔽簷前日，雨隨階下雲。周遊清蔭遍，吟臥夕陽曛。", "江靜棹歌歇，溪深樵語聞。歸途未忍去，攜手戀清芬。"]'),
('yuding-166','冬至後過吳、張二子檀溪別業','孟浩然','唐','御定全唐诗','yuding','','[]','卜築因自然，檀溪不更穿。園廬二友接，水竹數家連。',120,'御定全唐詩/json/160.json','["卜築因自然，檀溪不更穿。園廬二友接，水竹數家連。", "直與南山對，非關選地偏。草堂時偃曝，蘭枻日周旋。", "外事情都遠，中流性所便。閑垂太公釣，興發子猷船。", "餘亦幽棲者，經過竊慕焉。梅花殘臘月，柳色半春天。", "鳥泊隨陽雁，魚藏縮項鯿。停杯問山簡，何似習池邊。"]'),
('yuding-167','韓大使東齋會岳上人、諸學士','孟浩然','唐','御定全唐诗','yuding','','[]','郡守虛陳榻，林間召楚材。山川祈雨畢，雲物喜晴開。',72,'御定全唐詩/json/160.json','["郡守虛陳榻，林間召楚材。山川祈雨畢，雲物喜晴開。", "抗禮尊縫掖，臨流揖渡杯。徒攀朱仲李，誰薦和羹梅。", "翰墨緣情制，高深以意裁。滄洲趣不遠，何必問蓬萊。"]'),
('yuding-168','上巳日澗南園期王山人、陳七諸公不至','孟浩然','唐','御定全唐诗','yuding','','[]','搖艇候明發，花源弄晚春。在山懷綺季，臨漢憶荀陳。',96,'御定全唐詩/json/160.json','["搖艇候明發，花源弄晚春。在山懷綺季，臨漢憶荀陳。", "上巳期三月，浮杯興十旬。坐歌空有待，行樂恨無鄰。", "日晚蘭亭北，煙開曲水濱。浴蠶逢姹女，采艾值幽人。", "石壁堪題序，沙場好解紳。群公望不至，虛擲此芳晨。"]'),
('yuding-169','齒坐呈山南諸隱','孟浩然','唐','御定全唐诗','yuding','','[]','習公有遺坐，高在白雲陲。樵子不見識，山僧賞自知。',72,'御定全唐詩/json/160.json','["習公有遺坐，高在白雲陲。樵子不見識，山僧賞自知。", "以餘為好事，攜手一來窺。竹露閑夜滴，松風清晝吹。", "從來抱微尚，況複感前規。於此無奇策，蒼生奚以為。"]'),
('yuding-170','來闍黎新亭作','孟浩然','唐','御定全唐诗','yuding','','[]','八解禪林秀，三明給苑才。地偏香界遠，心淨水亭開。',96,'御定全唐詩/json/160.json','["八解禪林秀，三明給苑才。地偏香界遠，心淨水亭開。", "傍險山查立，尋幽石徑回。瑞花長自下，靈藥豈須栽。", "碧網交紅樹，清泉盡綠苔。戲魚聞法聚，閑鳥誦經來。", "棄象玄應悟，忘言理必該。靜中何所得，吟詠也徒哉。"]'),
('yuding-171','西山尋辛諤','孟浩然','唐','御定全唐诗','yuding','','[]','漾舟尋水便，因訪故人居。落日清川裏，誰言獨羨魚。',72,'御定全唐詩/json/160.json','["漾舟尋水便，因訪故人居。落日清川裏，誰言獨羨魚。", "石潭窺洞徹，沙岸曆紆徐。竹嶼見垂釣，茅齋聞讀書。", "款言忘景夕，清興屬涼初。回也一瓢飲，賢哉常晏如。"]'),
('yuding-172','題長安主人壁','孟浩然','唐','御定全唐诗','yuding','','[]','久廢南山田，叨陪東閣賢。欲隨平子去，猶未獻甘泉。',72,'御定全唐詩/json/160.json','["久廢南山田，叨陪東閣賢。欲隨平子去，猶未獻甘泉。", "枕籍琴書滿，褰帷遠岫連。我來如昨日，庭樹忽鳴蟬。", "促織驚寒女，秋風感長年。授衣當九月，無褐竟誰憐。"]'),
('yuding-173','行出東山望漢川','孟浩然','唐','御定全唐诗','yuding','','[]','異縣非吾土，連山盡綠篁。平田出郭少，盤阪入雲長。',96,'御定全唐詩/json/160.json','["異縣非吾土，連山盡綠篁。平田出郭少，盤阪入雲長。", "萬壑歸於漢，千峰劃彼蒼。猿聲亂楚峽，人語帶巴鄉。", "石上攢椒樹，藤間綴蜜房。雪餘春未暖，嵐解晝初陽。", "征馬疲登頓，歸帆愛渺茫。坐欣沿溜下，信宿見維桑。"]'),
('yuding-174','夜泊宣城界','孟浩然','唐','御定全唐诗','yuding','','[]','西塞沿江島，南陵問驛樓。湖平津濟闊，風止客帆收。',72,'御定全唐詩/json/160.json','["西塞沿江島，南陵問驛樓。湖平津濟闊，風止客帆收。", "去去懷前浦，茫茫泛夕流。石逢羅刹礙，山泊敬亭幽。", "火識梅根冶，煙迷楊葉洲。離家複水宿，相伴賴沙鷗。"]'),
('yuding-175','下贛石','孟浩然','唐','御定全唐诗','yuding','','[]','贛石三百里，沿洄千嶂間。沸聲常活活，洊勢亦潺潺。',72,'御定全唐詩/json/160.json','["贛石三百里，沿洄千嶂間。沸聲常活活，洊勢亦潺潺。", "跳沫魚龍沸，垂藤猿狖攀。榜人苦奔峭，而我忘險艱。", "放溜情彌愜，登艫目自閑。暝帆何處宿，遙指落星灣。"]'),
('yuding-176','初年樂城館中臥疾懷歸作','孟浩然','唐','御定全唐诗','yuding','','[]','異縣天隅僻，孤帆海畔過。往來鄉信斷，留滯客情多。',72,'御定全唐詩/json/160.json','["異縣天隅僻，孤帆海畔過。往來鄉信斷，留滯客情多。", "臘月聞雷震，東風感歲和。蟄蟲驚戶穴，巢鵲眄庭柯。", "徒對芳尊酒，其如伏枕何。歸嶼理舟楫，江海正無波。"]'),
('yuding-177','醉後贈馬四','孟浩然','唐','御定全唐诗','yuding','','[]','四海重然諾，吾嘗聞白眉。秦城游俠客，相得半酣時。',24,'御定全唐詩/json/160.json','["四海重然諾，吾嘗聞白眉。秦城游俠客，相得半酣時。"]'),
('yuding-178','贈王九','孟浩然','唐','御定全唐诗','yuding','','[]','日暮田家遠，山中勿久淹。歸人須早去，稚子望陶潛。',24,'御定全唐詩/json/160.json','["日暮田家遠，山中勿久淹。歸人須早去，稚子望陶潛。"]'),
('yuding-179','登峴山亭，寄晉陵張少府','孟浩然','唐','御定全唐诗','yuding','','[]','峴首風湍急，雲帆若鳥飛。憑軒試一問，張翰欲來歸。',24,'御定全唐詩/json/160.json','["峴首風湍急，雲帆若鳥飛。憑軒試一問，張翰欲來歸。"]'),
('yuding-180','送朱大入秦','孟浩然','唐','御定全唐诗','yuding','','[]','遊人武陵去，寶劍直千金。分手脫相贈，平生一片心。',24,'御定全唐詩/json/160.json','["遊人武陵去，寶劍直千金。分手脫相贈，平生一片心。"]'),
('yuding-181','送友人之京','孟浩然','唐','御定全唐诗','yuding','','[]','君登青雲去，予望青山歸。雲山從此別，淚濕薜蘿衣。',24,'御定全唐詩/json/160.json','["君登青雲去，予望青山歸。雲山從此別，淚濕薜蘿衣。"]'),
('yuding-182','送張郎中遷京','孟浩然','唐','御定全唐诗','yuding','','[]','碧溪常共賞，朱邸忽遷榮。豫有相思意，聞君琴上聲。',24,'御定全唐詩/json/160.json','["碧溪常共賞，朱邸忽遷榮。豫有相思意，聞君琴上聲。"]'),
('yuding-183','同張將薊門觀燈','孟浩然','唐','御定全唐诗','yuding','','[]','異俗非鄉俗，新年改故年。薊門看火樹，疑是燭龍燃。',24,'御定全唐詩/json/160.json','["異俗非鄉俗，新年改故年。薊門看火樹，疑是燭龍燃。"]'),
('yuding-184','張郎中梅園中','孟浩然','唐','御定全唐诗','yuding','','[]','綺席鋪蘭杜，珠盤折芰荷。故園留不住，應是戀弦歌。',24,'御定全唐詩/json/160.json','["綺席鋪蘭杜，珠盤折芰荷。故園留不住，應是戀弦歌。"]'),
('yuding-185','北澗泛舟','孟浩然','唐','御定全唐诗','yuding','','[]','北澗流恒滿，浮舟觸處通。沿洄自有趣，何必五湖中。',24,'御定全唐詩/json/160.json','["北澗流恒滿，浮舟觸處通。沿洄自有趣，何必五湖中。"]'),
('yuding-186','春曉','孟浩然','唐','御定全唐诗','yuding','','[]','春眠不覺曉，處處聞啼鳥。夜來風雨聲，花落知多少。',24,'御定全唐詩/json/160.json','["春眠不覺曉，處處聞啼鳥。夜來風雨聲，花落知多少。"]'),
('yuding-187','洛中訪袁拾遺不遇','孟浩然','唐','御定全唐诗','yuding','','[]','洛陽訪才子，江嶺作流人。聞說梅花早，何如北地春。',24,'御定全唐詩/json/160.json','["洛陽訪才子，江嶺作流人。聞說梅花早，何如北地春。"]'),
('yuding-188','尋菊花潭主人不遇','孟浩然','唐','御定全唐诗','yuding','','[]','行至菊花潭，村西日已斜。主人登高去，雞犬空在家。',24,'御定全唐詩/json/160.json','["行至菊花潭，村西日已斜。主人登高去，雞犬空在家。"]'),
('yuding-189','檀溪尋故人','孟浩然','唐','御定全唐诗','yuding','','[]','花伴成龍竹，池分躍馬溪。田園人不見，疑向洞中棲。',24,'御定全唐詩/json/160.json','["花伴成龍竹，池分躍馬溪。田園人不見，疑向洞中棲。"]'),
('yuding-190','揚子津望京口','孟浩然','唐','御定全唐诗','yuding','','[]','北固臨京口，夷山近海濱。江風白浪起，愁殺渡頭人。',24,'御定全唐詩/json/160.json','["北固臨京口，夷山近海濱。江風白浪起，愁殺渡頭人。"]'),
('yuding-191','同儲十二洛陽道中作','孟浩然','唐','御定全唐诗','yuding','','[]','珠彈繁華子，金羈遊俠人。酒酣白日暮，走馬入紅塵。',24,'御定全唐詩/json/160.json','["珠彈繁華子，金羈遊俠人。酒酣白日暮，走馬入紅塵。"]'),
('yuding-192','初下浙江舟中口號','孟浩然','唐','御定全唐诗','yuding','','[]','八月觀潮罷，三江越海潯。回瞻魏闕路，空複子牟心。',24,'御定全唐詩/json/160.json','["八月觀潮罷，三江越海潯。回瞻魏闕路，空複子牟心。"]'),
('yuding-193','宿建德江','孟浩然','唐','御定全唐诗','yuding','','[]','移舟泊煙渚，日暮客愁新。野曠天低樹，江清月近人。',24,'御定全唐詩/json/160.json','["移舟泊煙渚，日暮客愁新。野曠天低樹，江清月近人。"]'),
('yuding-194','問舟子','孟浩然','唐','御定全唐诗','yuding','','[]','向夕問舟子，前程複幾多。灣頭正堪泊，淮裏足風波。',24,'御定全唐詩/json/160.json','["向夕問舟子，前程複幾多。灣頭正堪泊，淮裏足風波。"]'),
('yuding-195','戲題','孟浩然','唐','御定全唐诗','yuding','','[]','客醉眠未起，主人呼解酲。已言雞黍熟，複道甕頭清。',24,'御定全唐詩/json/160.json','["客醉眠未起，主人呼解酲。已言雞黍熟，複道甕頭清。"]'),
('yuding-196','涼州詞','孟浩然','唐','御定全唐诗','yuding','','[]','渾成紫檀金屑文，作得琵琶聲入雲。',64,'御定全唐詩/json/160.json','["渾成紫檀金屑文，作得琵琶聲入雲。", "胡地迢迢三萬里，那堪馬上送明君。", "異方之樂令人悲，羌笛胡笳不用吹。", "坐看今夜關山月，思殺邊城遊俠兒。"]'),
('yuding-197','送新安張少府歸秦中','孟浩然','唐','御定全唐诗','yuding','','[]','試登秦嶺望秦川，遙憶青門春可憐。',32,'御定全唐詩/json/160.json','["試登秦嶺望秦川，遙憶青門春可憐。", "仲月送君從此去，瓜時須及邵平田。"]'),
('yuding-198','送杜十四之江南','孟浩然','唐','御定全唐诗','yuding','','[]','荊吳相接水為鄉，君去春江正淼茫。',32,'御定全唐詩/json/160.json','["荊吳相接水為鄉，君去春江正淼茫。", "日暮征帆何處泊，天涯一望斷人腸。"]'),
('yuding-199','渡浙江問舟中人','孟浩然','唐','御定全唐诗','yuding','','[]','潮落江平未有風，扁舟共濟與君同。',32,'御定全唐詩/json/160.json','["潮落江平未有風，扁舟共濟與君同。", "時時引領望天末，何處青山是越中。"]'),
('yuding-200','初秋','孟浩然','唐','御定全唐诗','yuding','','[]','不覺初秋夜漸長，清風習習重淒涼。',32,'御定全唐詩/json/160.json','["不覺初秋夜漸長，清風習習重淒涼。", "炎炎暑退茅齋靜，階下叢莎有露光。"]'),
('yuding-201','過融上人蘭若','孟浩然','唐','御定全唐诗','yuding','','[]','山頭禪室掛僧衣，窗外無人水鳥飛。',32,'御定全唐詩/json/160.json','["山頭禪室掛僧衣，窗外無人水鳥飛。", "黃昏半在下山路，卻聽泉聲戀翠微。"]'),
('yuding-202','句','孟浩然','唐','御定全唐诗','yuding','','[]','微雲淡河漢，疏雨滴梧桐。',35,'御定全唐詩/json/160.json','["微雲淡河漢，疏雨滴梧桐。", "逐逐懷良馭，蕭蕭顧樂鳴。（《省試騏驥長鳴》詩，"]'),
('yuding-0','古風','李白','唐','御定全唐诗','yuding','','[]','大雅久不作，吾衰竟誰陳。王風委蔓草，戰國多荊榛。',552,'御定全唐詩/json/161.json','["大雅久不作，吾衰竟誰陳。王風委蔓草，戰國多荊榛。", "龍虎相啖食，兵戈逮狂秦。正聲何微茫，哀怨起騷人。", "揚馬激頹波，開流蕩無垠。廢興雖萬變，憲章亦已淪。", "自從建安來，綺麗不足珍。聖代複元古，垂衣貴清真。", "群才屬休明，乘運共躍鱗。文質相炳煥，眾星羅秋旻。", "我志在刪述，垂輝映千春。希聖如有立，絕筆於獲麟。", "蟾蜍薄太清，蝕此瑤台月。圓光虧中天，金魄遂淪沒。", "螮蝀入紫微，大明夷朝暉。浮雲隔兩曜，萬象昏陰霏。", "蕭蕭長門宮，昔是今已非。桂蠹花不實，天霜下嚴威。", "沈歎終永夕，感我涕沾衣。", "秦皇掃六合，虎視何雄哉。飛劍決浮雲，諸侯盡西來。", "明斷自天啟，大略駕群才。收兵鑄金人，函穀正東開。", "銘功會稽嶺，騁望琅琊台。刑徒七十萬，起土驪山隈。", "尚采不死藥，茫然使心哀。連弩射海魚，長鯨正崔嵬。", "額鼻象五嶽，揚波噴雲雷。鬐鬣蔽青天，何由睹蓬萊。", "徐巿載秦女，樓船幾時回。但見三泉下，金棺葬寒灰。", "鳳飛九千仞，五章備彩珍。銜書且虛歸，空入周與秦。", "橫絕曆四海，所居未得鄰。吾營紫河車，千載落風塵。", "藥物秘海嶽，采鉛青溪濱。時登大樓山，舉手望仙真。", "羽駕滅去影，飆車絕回輪。尚恐丹液遲，志願不及申。", "徒霜鏡中發，羞彼鶴上人。桃李何處開，此花非我春。", "唯應清都境，長與韓眾親。", "太白何蒼蒼，星辰上森列。去天三百里，邈爾與世絕。", "中有綠發翁，披雲臥松雪。不笑亦不語，冥棲在岩穴。"]'),
('yuding-0','遠別離','李白','唐','御定全唐诗','yuding','','[]','遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。',87,'御定全唐詩/json/162.json','["遠別離，古有皇英之二女，乃在洞庭之南，瀟湘之浦。", "海水直下萬里深，誰人不言此離苦。日慘慘兮雲冥冥，", "或言堯幽囚，舜野死，九疑聯綿皆相似，", "慟哭兮遠望，見蒼梧之深山。蒼梧山崩湘水絕，"]'),
('yuding-1','公無渡河','李白','唐','御定全唐诗','yuding','','[]','黃河西來決昆侖，咆哮萬里觸龍門。波滔天，堯咨嗟。',91,'御定全唐詩/json/162.json','["黃河西來決昆侖，咆哮萬里觸龍門。波滔天，堯咨嗟。", "大禹理百川，兒啼不窺家。殺湍湮洪水，九州始蠶麻。", "其害乃去，茫然風沙。被發之叟狂而癡，", "虎可搏，河難憑，公果溺死流海湄。有長鯨白齒若雪山，"]'),
('yuding-2','蜀道難','李白','唐','御定全唐诗','yuding','','[]','噫籲戲危乎高哉，蜀道之難難於上青天。蠶叢及魚鳧，',116,'御定全唐詩/json/162.json','["噫籲戲危乎高哉，蜀道之難難於上青天。蠶叢及魚鳧，", "西當太白有鳥道，可以橫絕峨眉顛。地崩山摧壯士死，", "捫參曆井仰脅息，以手撫膺坐長歎。問君西遊何時還，", "又聞子規啼夜月，愁空山。蜀道之難難於上青天，", "飛湍瀑流爭喧豗，砯崖轉石萬壑雷。其險也如此，"]'),
('yuding-3','梁甫吟','李白','唐','御定全唐诗','yuding','','[]','長嘯梁甫吟，何時見陽春。君不見朝歌屠叟辭棘津，',143,'御定全唐詩/json/162.json','["長嘯梁甫吟，何時見陽春。君不見朝歌屠叟辭棘津，", "廣張三千六百釣，風期暗與文王親。大賢虎變愚不測，", "東下齊城七十二，指揮楚漢如旋蓬。狂客落魄尚如此，", "帝傍投壺多玉女，三時大笑開電光。倏爍晦冥起風雨，", "手接飛猱搏雕虎，側足焦原未言苦。智者可卷愚者豪，", "吳楚弄兵無劇孟，亞夫咍爾為徒勞。梁甫吟，梁甫吟，"]'),
('yuding-4','烏夜啼','李白','唐','御定全唐诗','yuding','','[]','黃雲城邊烏欲棲，歸飛啞啞枝上啼。機中織錦秦川女，',24,'御定全唐詩/json/162.json','["黃雲城邊烏欲棲，歸飛啞啞枝上啼。機中織錦秦川女，"]'),
('yuding-5','烏棲曲','李白','唐','御定全唐诗','yuding','','[]','姑蘇臺上烏棲時，吳王宮裏醉西施。吳歌楚舞歡未畢，',32,'御定全唐詩/json/162.json','["姑蘇臺上烏棲時，吳王宮裏醉西施。吳歌楚舞歡未畢，", "東方漸高奈樂何。"]'),
('yuding-6','戰城南','李白','唐','御定全唐诗','yuding','','[]','去年戰桑幹源，今年戰蔥河道。洗兵條支海上波，',83,'御定全唐詩/json/162.json','["去年戰桑幹源，今年戰蔥河道。洗兵條支海上波，", "匈奴以殺戮為耕作，古來唯見白骨黃沙田。", "秦家築城避胡處，漢家還有烽火然。烽火然不息，", "烏鳶啄人腸，銜飛上掛枯樹枝。士卒塗草莽，"]'),
('yuding-7','將進酒','李白','唐','御定全唐诗','yuding','','[]','君不見黃河之水天上來，奔流到海不復回。',132,'御定全唐詩/json/162.json','["君不見黃河之水天上來，奔流到海不復回。", "君不見高堂明鏡悲白髮，朝如青絲暮成雪。", "人生得意須盡歡，莫使金樽空對月。天生我材必有用，", "岑夫子，丹丘生，將進酒，君莫停。與君歌一曲，", "古來聖賢皆寂寞，惟有飲者留其名。陳王昔時宴平樂，", "五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"]'),
('yuding-8','行行遊且獵篇','李白','唐','御定全唐诗','yuding','','[]','邊城兒，生年不讀一字書，但將遊獵誇輕趫。',68,'御定全唐詩/json/162.json','["邊城兒，生年不讀一字書，但將遊獵誇輕趫。", "胡馬秋肥宜白草，騎來躡影何矜驕。金鞭拂雪揮鳴鞘，", "海邊觀者皆辟易，猛氣英風振沙磧。儒生不及遊俠人，"]'),
('yuding-9','飛龍引二首','李白','唐','御定全唐诗','yuding','','[]','黃帝鑄鼎于荊山，煉丹砂。丹砂成黃金，',130,'御定全唐詩/json/162.json','["黃帝鑄鼎于荊山，煉丹砂。丹砂成黃金，", "飄然揮手淩紫霞，從風縱體登鸞車。登鸞車，侍軒轅，", "鼎湖流水清且閑，軒轅去時有弓劍，古人傳道留其間。", "後宮嬋娟多花顏，乘鸞飛煙亦不還，騎龍攀天造天關。", "造天關，聞天語，長雲河車載玉女。載玉女，過紫皇，", "下視瑤池見王母，蛾眉蕭颯如秋霜。"]'),
('yuding-10','天馬歌','李白','唐','御定全唐诗','yuding','','[]','天馬來出月支窟，背為虎文龍翼骨。嘶青雲，振綠發，',138,'御定全唐詩/json/162.json','["天馬來出月支窟，背為虎文龍翼骨。嘶青雲，振綠發，", "雞鳴刷燕晡秣越，神行電邁躡慌惚。天馬呼，飛龍趨，", "曾陪時龍躡天衢，羈金絡月照皇都。逸氣棱棱淩九區，", "不逢寒風子，誰采逸景孫。白雲在青天，丘陵遠崔嵬。", "鹽車上峻阪，倒行逆施畏日晚。伯樂翦拂中道遺，", "雖有玉山禾，不能療苦饑。嚴霜五月凋桂枝，"]'),
('yuding-11','行路難三首','李白','唐','御定全唐诗','yuding','','[]','金樽清酒鬥十千，玉盤珍羞直萬錢。停杯投箸不能食，',210,'御定全唐詩/json/162.json','["金樽清酒鬥十千，玉盤珍羞直萬錢。停杯投箸不能食，", "閑來垂釣碧溪上，忽複乘舟夢日邊。行路難，行路難，", "大道如青天，我獨不得出。羞逐長安社中兒，", "淮陰市井笑韓信，漢朝公卿忌賈生。", "君不見昔時燕家重郭隗，擁篲折節無嫌猜。", "劇辛樂毅感恩分，輸肝剖膽效英才。昭王白骨縈爛草，", "有耳莫洗潁川水，有口莫食首陽蕨。含光混世貴無名，", "子胥既棄吳江上，屈原終投湘水濱。陸機雄才豈自保，", "君不見吳中張翰稱達生，秋風忽憶江東行。", "且樂生前一杯酒，何須身後千載名。"]'),
('yuding-12','長相思','李白','唐','御定全唐诗','yuding','','[]','長相思，在長安。絡緯秋啼金井闌，微霜淒淒簟色寒。',72,'御定全唐詩/json/162.json','["長相思，在長安。絡緯秋啼金井闌，微霜淒淒簟色寒。", "孤燈不明思欲絕，卷帷望月空長歎，美人如花隔雲端。", "上有青冥之長天，下有淥水之波瀾。天長路遠魂飛苦，"]'),
('yuding-13','上留田行','李白','唐','御定全唐诗','yuding','','[]','行至上留田，孤墳何崢嶸。積此萬古恨，春草不復生。',171,'御定全唐詩/json/162.json','["行至上留田，孤墳何崢嶸。積此萬古恨，春草不復生。", "悲風四邊來，腸斷白楊聲。借問誰家地，埋沒蒿裏塋。", "古老向餘言，言是上留田，蓬科馬鬣今已平。", "昔之弟死兄不葬，他人於此舉銘旌。一鳥死，百鳥鳴。", "一獸走，百獸驚。桓山之禽別離苦，欲去回翔不能征。", "田氏倉卒骨肉分，青天白日摧紫荊。交柯之木本同形，", "孤竹延陵，讓國揚名。高風緬邈，頹波激清。", "尺布之謠，塞耳不能聽。"]'),
('yuding-14','春日行','李白','唐','御定全唐诗','yuding','','[]','深宮高樓入紫清，金作蛟龍盤繡楹。佳人當窗弄白日，',92,'御定全唐詩/json/162.json','["深宮高樓入紫清，金作蛟龍盤繡楹。佳人當窗弄白日，", "因出天池泛蓬瀛，樓船蹙遝波浪驚。三千雙蛾獻歌笑，", "三十六帝欲相迎，仙人飄翩下雲輧。帝不去，留鎬京。", "安能為軒轅，獨往入窅冥。小臣拜獻南山壽，"]'),
('yuding-15','前有一樽酒行二首','李白','唐','御定全唐诗','yuding','','[]','春風東來忽相過，金樽淥酒生微波。落花紛紛稍覺多，',72,'御定全唐詩/json/162.json','["春風東來忽相過，金樽淥酒生微波。落花紛紛稍覺多，", "君起舞，日西夕。當年意氣不肯平，白髮如絲歎何益。", "琴奏龍門之綠桐，玉壺美酒清若空。催弦拂柱與君飲，"]'),
('yuding-16','夜坐吟','李白','唐','御定全唐诗','yuding','','[]','冬夜夜寒覺夜長，沉吟久坐坐北堂。冰合井泉月入閨，',46,'御定全唐詩/json/162.json','["冬夜夜寒覺夜長，沉吟久坐坐北堂。冰合井泉月入閨，", "歌有聲，妾有情。情聲合，兩無違。一語不入意，"]'),
('yuding-17','野田黃雀行','李白','唐','御定全唐诗','yuding','','[]','游莫逐炎洲翠，棲莫近吳宮燕。吳宮火起焚巢窠，',22,'御定全唐詩/json/162.json','["游莫逐炎洲翠，棲莫近吳宮燕。吳宮火起焚巢窠，"]'),
('yuding-18','箜篌謠','李白','唐','御定全唐诗','yuding','','[]','攀天莫登龍，走山莫騎虎。貴賤結交心不移，',92,'御定全唐詩/json/162.json','["攀天莫登龍，走山莫騎虎。貴賤結交心不移，", "漢謠一鬥粟，不與淮南舂。兄弟尚路人，吾心安所從。", "他人方寸間，山海幾千重。輕言托朋友，對面九疑峰。", "開花必早落，桃李不如松。管鮑久已死，何人繼其蹤。"]'),
('yuding-19','雉朝飛','李白','唐','御定全唐诗','yuding','','[]','麥隴青青三月時，白雉朝飛挾兩雌。錦衣繡翼何離褷，',48,'御定全唐詩/json/162.json','["麥隴青青三月時，白雉朝飛挾兩雌。錦衣繡翼何離褷，", "枯楊枯楊爾生稊，我獨七十而孤棲。彈弦寫恨意不盡，"]'),
('yuding-20','上雲樂','李白','唐','御定全唐诗','yuding','','[]','金天之西，白日所沒。康老胡雛，生彼月窟。巉岩容儀，',287,'御定全唐詩/json/162.json','["金天之西，白日所沒。康老胡雛，生彼月窟。巉岩容儀，", "華蓋垂下睫，嵩嶽臨上唇。不睹詭譎貌，豈知造化神。", "大道是文康之嚴父，元氣乃文康之老親。撫頂弄盤古，", "陽烏未出谷，顧兔半藏身。女媧戲黃土，團作愚下人。", "散在六合間，濛濛若沙塵。生死了不盡，", "別來幾多時，枝葉萬里長。中國有七聖，半路頹洪荒。", "陛下應運起，龍飛入咸陽。赤眉立盆子，白水興漢光。", "叱吒四海動，洪濤為簸揚。舉足蹋紫微，天關自開張。", "老胡感至德，東來進仙倡。五色師子，九苞鳳凰。", "是老胡雞犬，鳴舞飛帝鄉。淋漓颯遝，進退成行。", "能胡歌，獻漢酒。跪雙膝，立兩肘。散花指天舉素手。", "拜龍顏，獻聖壽。北斗戾，南山摧。", "天子九九八十一萬歲，長傾萬歲杯。"]'),
('yuding-21','白鳩辭','李白','唐','御定全唐诗','yuding','','[]','鏗鳴鐘，考朗鼓。歌白鳩，引拂舞。白鳩之白誰與鄰，',80,'御定全唐詩/json/162.json','["鏗鳴鐘，考朗鼓。歌白鳩，引拂舞。白鳩之白誰與鄰，", "首農政，鳴陽春。天子刻玉杖，鏤形賜耆人。", "白鷺之白非純真，外潔其色心匪仁。闕五德，無司晨，", "鳳凰雖大聖，不願以為臣。"]'),
('yuding-22','日出行','李白','唐','御定全唐诗','yuding','','[]','日出東方隈，似從地底來。曆天又入海，',68,'御定全唐詩/json/162.json','["日出東方隈，似從地底來。曆天又入海，", "羲和羲和，汝奚汩沒於荒淫之波。魯陽何德，駐景揮戈。", "逆道違天，矯誣實多。吾將囊括大塊，浩然與溟涬同科。"]'),
('yuding-23','胡無人','李白','唐','御定全唐诗','yuding','','[]','嚴風吹霜海草凋，筋幹精堅胡馬驕。漢家戰士三十萬，',68,'御定全唐詩/json/162.json','["嚴風吹霜海草凋，筋幹精堅胡馬驕。漢家戰士三十萬，", "天兵照雪下玉關，虜箭如沙射金甲。雲龍風虎盡交回，", "懸胡青天上，埋胡紫塞傍。胡無人，漢道昌。"]'),
('yuding-24','北風行','李白','唐','御定全唐诗','yuding','','[]','燭龍棲寒門，光曜猶旦開。日月照之何不及此，',85,'御定全唐詩/json/162.json','["燭龍棲寒門，光曜猶旦開。日月照之何不及此，", "倚門望行人，念君長城苦寒良可哀。別時提劍救邊去，", "箭空在，人今戰死不復回。不忍見此物，焚之已成灰。", "黃河捧土尚可塞，北風雨雪恨難裁。"]'),
('yuding-25','俠客行','李白','唐','御定全唐诗','yuding','','[]','趙客縵胡纓，吳鉤霜雪明。銀鞍照白馬，颯遝如流星。',144,'御定全唐詩/json/162.json','["趙客縵胡纓，吳鉤霜雪明。銀鞍照白馬，颯遝如流星。", "十步殺一人，千里不留行。事了拂衣去，深藏身與名。", "閑過信陵飲，脫劍膝前橫。將炙啖朱亥，持觴勸侯嬴。", "三杯吐然諾，五嶽倒為輕。眼花耳熱後，意氣素霓生。", "救趙揮金槌，邯鄲先震驚。千秋二壯士，煊赫大樑城。", "縱死俠骨香，不慚世上英。誰能書合下，白首太玄經。"]'),
('yuding-0','關山月','李白','唐','御定全唐诗','yuding','','[]','明月出天山，蒼茫雲海間。長風幾萬里，吹度玉門關。',72,'御定全唐詩/json/163.json','["明月出天山，蒼茫雲海間。長風幾萬里，吹度玉門關。", "漢下白登道，胡窺青海灣。由來征戰地，不見有人還。", "戍客望邊色，思歸多苦顏。高樓當此夜，歎息未應閑。"]'),
('yuding-1','獨漉篇','李白','唐','御定全唐诗','yuding','','[]','獨漉水中泥，水濁不見月。不見月尚可，水深行人沒。',69,'御定全唐詩/json/163.json','["獨漉水中泥，水濁不見月。不見月尚可，水深行人沒。", "越鳥從南來，胡鷹亦北渡。我欲彎弓向天射，", "雄劍掛壁，時時龍鳴。不斷犀象，繡澀苔生。國恥未雪，"]'),
('yuding-2','登高丘而望遠','李白','唐','御定全唐诗','yuding','','[]','登高丘，望遠海。六鼇骨已霜，三山流安在。',65,'御定全唐詩/json/163.json','["登高丘，望遠海。六鼇骨已霜，三山流安在。", "扶桑半摧折，白日沈光彩。銀台金闕如夢中，", "君不見驪山茂陵盡灰滅，牧羊之子來攀登。盜賊劫寶玉，"]'),
('yuding-3','陽春歌','李白','唐','御定全唐诗','yuding','','[]','長安白日照春空，綠楊結煙垂嫋風。披香殿前花始紅，',24,'御定全唐詩/json/163.json','["長安白日照春空，綠楊結煙垂嫋風。披香殿前花始紅，"]'),
('yuding-4','楊叛兒','李白','唐','御定全唐诗','yuding','','[]','君歌楊叛兒，妾勸新豐酒。何許最關人，烏啼白門柳。',44,'御定全唐詩/json/163.json','["君歌楊叛兒，妾勸新豐酒。何許最關人，烏啼白門柳。", "烏啼隱楊花，君醉留妾家。博山爐中沉香火，"]'),
('yuding-5','雙燕離','李白','唐','御定全唐诗','yuding','','[]','雙燕複雙燕，雙飛令人羨。玉樓珠閣不獨棲，',56,'御定全唐詩/json/163.json','["雙燕複雙燕，雙飛令人羨。玉樓珠閣不獨棲，", "吳宮又焚蕩，雛盡巢亦空。憔悴一身在，孀雌憶故雄。", "雙飛難再得，傷我寸心中。"]'),
('yuding-6','山人勸酒','李白','唐','御定全唐诗','yuding','','[]','蒼蒼雲松，落落綺皓。春風爾來為阿誰，',40,'御定全唐詩/json/163.json','["蒼蒼雲松，落落綺皓。春風爾來為阿誰，", "稱是秦時避世人，勸酒相歡不知老。各守麋鹿志，"]'),
('yuding-7','於闐采花','李白','唐','御定全唐诗','yuding','','[]','於闐采花人，自言花相似。明妃一朝西入胡，',48,'御定全唐詩/json/163.json','["於闐采花人，自言花相似。明妃一朝西入胡，", "丹青能令醜者妍，無鹽翻在深宮裏。", "自古妒蛾眉，胡沙埋皓齒。"]'),
('yuding-8','鞠歌行','李白','唐','御定全唐诗','yuding','','[]','玉不自言如桃李，魚目笑之卞和恥。楚國青蠅何太多，',108,'御定全唐詩/json/163.json','["玉不自言如桃李，魚目笑之卞和恥。楚國青蠅何太多，", "聽曲知甯戚，夷吾因小妻。秦穆五羊皮，買死百里奚。", "洗拂青雲上，當時賤如泥。朝歌鼓刀叟，虎變磻溪中。", "一舉釣六合，遂荒營丘東。平生渭水曲，誰識此老翁。", "奈何今之人，雙目送飛鴻。"]'),
('yuding-9','幽澗泉','李白','唐','御定全唐诗','yuding','','[]','拂彼白石，彈吾素琴。幽澗愀兮流泉深，',67,'御定全唐詩/json/163.json','["拂彼白石，彈吾素琴。幽澗愀兮流泉深，", "中見愁猿吊影而危處兮，叫秋木而長吟。", "客有哀時失職而聽者，淚淋浪以沾襟。乃緝商綴羽，", "幽澗泉，鳴深林。"]'),
('yuding-10','王昭君二首','李白','唐','御定全唐诗','yuding','','[]','漢家秦地月，流影照明妃。一上玉關道，天涯去不歸。',72,'御定全唐詩/json/163.json','["漢家秦地月，流影照明妃。一上玉關道，天涯去不歸。", "漢月還從東海出，明妃西嫁無來日。燕支長寒雪作花，", "昭君拂玉鞍，上馬啼紅頰。今日漢宮人，明朝胡地妾。"]'),
('yuding-11','中山孺子妾歌','李白','唐','御定全唐诗','yuding','','[]','中山孺子妾，特以色見珍。雖然不如延年妹，',58,'御定全唐詩/json/163.json','["中山孺子妾，特以色見珍。雖然不如延年妹，", "一貴複一賤，關天豈由身。芙蓉老秋霜，團扇羞網塵。", "戚姬髡發入舂市，萬古共悲辛。"]'),
('yuding-12','荊州歌','李白','唐','御定全唐诗','yuding','','[]','白帝城邊足風波，瞿塘五月誰敢過。荊州麥熟繭成蛾，',24,'御定全唐詩/json/163.json','["白帝城邊足風波，瞿塘五月誰敢過。荊州麥熟繭成蛾，"]'),
('yuding-13','雉子斑','李白','唐','御定全唐诗','yuding','','[]','辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。',66,'御定全唐詩/json/163.json','["辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。", "扇錦翼，雄風生。雙雌同飲啄，趫悍誰能爭。", "乍向草中耿介死，不求黃金籠下生。天地至廣大，"]'),
('yuding-14','相逢行','李白','唐','御定全唐诗','yuding','','[]','相逢紅塵內，高揖黃金鞭。萬戶垂楊裏，君家阿那邊。',24,'御定全唐詩/json/163.json','["相逢紅塵內，高揖黃金鞭。萬戶垂楊裏，君家阿那邊。"]'),
('yuding-15','有所思','李白','唐','御定全唐诗','yuding','','[]','我思仙人乃在碧海之東隅。海寒多天風，',34,'御定全唐詩/json/163.json','["我思仙人乃在碧海之東隅。海寒多天風，", "西來青鳥東飛去，願寄一書謝麻姑。"]'),
('yuding-16','久別離','李白','唐','御定全唐诗','yuding','','[]','別來幾春未還家，玉窗五見櫻桃花。況有錦字書，',43,'御定全唐詩/json/163.json','["別來幾春未還家，玉窗五見櫻桃花。況有錦字書，", "東風兮東風，為我吹行雲使西來。待來竟不來，"]'),
('yuding-17','白頭吟','李白','唐','御定全唐诗','yuding','','[]','錦水東北流，波蕩雙鴛鴦。雄巢漢宮樹，雌弄秦草芳。',140,'御定全唐詩/json/163.json','["錦水東北流，波蕩雙鴛鴦。雄巢漢宮樹，雌弄秦草芳。", "甯同萬死碎綺翼，不忍雲間兩分張。此時阿嬌正嬌妒，", "相如作賦得黃金，丈夫好新多異心。一朝將聘茂陵女，", "兔絲固無情，隨風任傾倒。誰使女蘿枝，而來強縈抱。", "兩草猶一心，人心不如草。莫卷龍須席，從他生網絲。", "且留琥珀枕，或有夢來時。覆水再收豈滿杯，"]'),
('yuding-18','採蓮曲','李白','唐','御定全唐诗','yuding','','[]','若耶溪傍採蓮女，笑隔荷花共人語。日照新妝水底明，',40,'御定全唐詩/json/163.json','["若耶溪傍採蓮女，笑隔荷花共人語。日照新妝水底明，", "紫騮嘶入落花去，見此踟躕空斷腸。"]'),
('yuding-19','臨江王節士歌','李白','唐','御定全唐诗','yuding','','[]','洞庭白波木葉稀，燕鴻始入吳雲飛。吳雲寒，燕鴻苦。',46,'御定全唐詩/json/163.json','["洞庭白波木葉稀，燕鴻始入吳雲飛。吳雲寒，燕鴻苦。", "風號沙宿瀟湘浦，節士悲秋淚如雨。白日當天心，"]'),
('yuding-20','司馬將軍歌','李白','唐','御定全唐诗','yuding','','[]','狂風吹古月，竊弄章華台。北落明星動光彩，',60,'御定全唐詩/json/163.json','["狂風吹古月，竊弄章華台。北落明星動光彩，", "我見樓船壯心目，頗似龍驤下三蜀。揚兵習戰張虎旗，", "功成獻凱見明主，丹青畫像麒麟台。"]'),
('yuding-21','君道曲','李白','唐','御定全唐诗','yuding','','[]','大君若天覆，廣運無不至。軒後爪牙嘗先太山稽，',34,'御定全唐詩/json/163.json','["大君若天覆，廣運無不至。軒後爪牙嘗先太山稽，", "土校可成牆，積德為厚地。"]'),
('yuding-22','結襪子','李白','唐','御定全唐诗','yuding','','[]','燕南壯士吳門豪，築中置鉛魚隱刀。',32,'御定全唐詩/json/163.json','["燕南壯士吳門豪，築中置鉛魚隱刀。", "感君恩重許君命，太山一擲輕鴻毛。"]'),
('yuding-23','結客少年場行','李白','唐','御定全唐诗','yuding','','[]','紫燕黃金瞳，啾啾搖綠鬃。平明相馳逐，結客洛門東。',120,'御定全唐詩/json/163.json','["紫燕黃金瞳，啾啾搖綠鬃。平明相馳逐，結客洛門東。", "少年學劍術，淩轢白猿公。珠袍曳錦帶，匕首插吳鴻。", "由來萬夫勇，挾此生雄風。托交從劇孟，買醉入新豐。", "笑盡一杯酒，殺人都市中。羞道易水寒，從令日貫虹。", "燕丹事不立，虛沒秦帝宮。舞陽死灰人，安可與成功。"]'),
('yuding-24','長干行二首','李白','唐','御定全唐诗','yuding','','[]','妾發初覆額，折花門前劇。郎騎竹馬來，繞床弄青梅。',324,'御定全唐詩/json/163.json','["妾發初覆額，折花門前劇。郎騎竹馬來，繞床弄青梅。", "同居長干裏，兩小無嫌猜。十四為君婦，羞顏未嘗開。", "低頭向暗壁，千喚不一回。十五始展眉，願同塵與灰。", "常存抱柱信，豈上望夫台。十六君遠行，瞿塘灩澦堆。", "五月不可觸，猿聲天上哀。門前遲行跡，一一生綠苔。", "苔深不能掃，落葉秋風早。八月蝴蝶來，雙飛西園草。", "感此傷妾心，坐愁紅顏老。早晚下三巴，預將書報家。", "相迎不道遠，直至長風沙。", "憶妾深閨裏，煙塵不曾識。嫁與長干人，沙頭候風色。", "五月南風興，思君下巴陵。八月西風起，想君發揚子。", "去來悲如何，見少離別多。湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。淼淼暗無邊，行人在何處。", "好乘浮雲驄，佳期蘭渚東。鴛鴦綠蒲上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。那作商人婦，愁水複愁風。"]'),
('yuding-25','古朗月行','李白','唐','御定全唐诗','yuding','','[]','小時不識月，呼作白玉盤。又疑瑤台鏡，飛在白雲端。',96,'御定全唐詩/json/163.json','["小時不識月，呼作白玉盤。又疑瑤台鏡，飛在白雲端。", "仙人垂兩足，桂樹作團團。白兔搗藥成，問言與誰餐。", "蟾蜍蝕圓影，大明夜已殘。羿昔落九烏，天人清且安。", "陰精此淪惑，去去不足觀。憂來其如何，悽愴摧心肝。"]'),
('yuding-26','上之回','李白','唐','御定全唐诗','yuding','','[]','三十六離宮，樓臺與天通。閣道步行月，美人愁煙空。',96,'御定全唐詩/json/163.json','["三十六離宮，樓臺與天通。閣道步行月，美人愁煙空。", "恩疏寵不及，桃李傷春風。淫樂意何極，金輿向回中。", "萬乘出黃道，千旗揚彩虹。前軍細柳北，後騎甘泉東。", "豈問渭川老，寧邀襄野童。但慕瑤池宴，歸來樂未窮。"]'),
('yuding-27','獨不見','李白','唐','御定全唐诗','yuding','','[]','白馬誰家子，黃龍邊塞兒。天山三丈雪，豈是遠行時。',84,'御定全唐詩/json/163.json','["白馬誰家子，黃龍邊塞兒。天山三丈雪，豈是遠行時。", "春蕙忽秋草，莎雞鳴西池。風摧寒棕響，月入霜閨悲。", "憶與君別年，種桃齊蛾眉。桃今百餘尺，花落成枯枝。", "終然獨不見，流淚空自知。"]'),
('yuding-28','白紵辭三首','李白','唐','御定全唐诗','yuding','','[]','揚清歌，發皓齒，北方佳人東鄰子。且吟白紵停綠水，',104,'御定全唐詩/json/163.json','["揚清歌，發皓齒，北方佳人東鄰子。且吟白紵停綠水，", "玉顏滿堂樂未終，館娃日落歌吹蒙。", "月寒江清夜沉沉，美人一笑千黃金。垂羅舞縠揚哀音，", "願作天池雙鴛鴦，一朝飛去青雲上。", "吳刀剪綵縫舞衣，明妝麗服奪春暉。揚眉轉袖若雪飛，"]'),
('yuding-29','鳴雁行','李白','唐','御定全唐诗','yuding','','[]','胡雁鳴，辭燕山，昨發委羽朝度關。一一銜蘆枝，',30,'御定全唐詩/json/163.json','["胡雁鳴，辭燕山，昨發委羽朝度關。一一銜蘆枝，", "君更彈射何為乎。"]'),
('yuding-30','妾薄命','李白','唐','御定全唐诗','yuding','','[]','漢帝寵阿嬌，貯之黃金屋。咳唾落九天，隨風生珠玉。',96,'御定全唐詩/json/163.json','["漢帝寵阿嬌，貯之黃金屋。咳唾落九天，隨風生珠玉。", "寵極愛還歇，妒深情卻疏。長門一步地，不肯暫回車。", "雨落不上天，水覆難再收。君情與妾意，各自東西流。", "昔日芙蓉花，今成斷根草。以色事他人，能得幾時好。"]'),
('yuding-31','幽州胡馬客歌','李白','唐','御定全唐诗','yuding','','[]','幽州胡馬客，綠眼虎皮冠。笑拂兩隻箭，萬人不可干。',168,'御定全唐詩/json/163.json','["幽州胡馬客，綠眼虎皮冠。笑拂兩隻箭，萬人不可干。", "彎弓若轉月，白雁落雲端。雙雙掉鞭行，游獵向樓蘭。", "出門不顧後，報國死何難。天驕五單于，狼戾好兇殘。", "牛馬散北海，割鮮若虎餐。雖居燕支山，不道朔雪寒。", "婦女馬上笑，顏如赬玉盤。翻飛射鳥獸，花月醉雕鞍。", "旄頭四光芒，爭戰若蜂攢。白刃灑赤血，流沙為之丹。", "名將古誰是，疲兵良可歎。何時天狼滅，父子得閒安。"]'),
('yuding-0','門有車馬客行','李白','唐','御定全唐诗','yuding','','[]','門有車馬賓，金鞍曜朱輪。謂從丹霄落，乃是故鄉親。',156,'御定全唐詩/json/164.json','["門有車馬賓，金鞍曜朱輪。謂從丹霄落，乃是故鄉親。", "呼兒掃中堂，坐客論悲辛。對酒兩不飲，停觴淚盈巾。", "歎我萬里遊，飄飄三十春。空談帝王略，紫綬不掛身。", "雄劍藏玉匣，陰符生素塵。廓落無所合，流離湘水濱。", "借問宗黨間，多為泉下人。生苦百戰役，死托萬鬼鄰。", "北風揚胡沙，埋翳周與秦。大運且如此，蒼穹寧匪仁。", "惻愴竟何道，存亡任大鈞。"]'),
('yuding-1','君子有所思行','李白','唐','御定全唐诗','yuding','','[]','紫閣連終南，青冥天倪色。憑崖望咸陽，宮闕羅北極。',132,'御定全唐詩/json/164.json','["紫閣連終南，青冥天倪色。憑崖望咸陽，宮闕羅北極。", "萬井驚畫出，九衢如弦直。渭水銀河清，橫天流不息。", "朝野盛文物，衣冠何翕赩。廄馬散連山，軍容威絕域。", "伊皋運元化，衛霍輸筋力。歌鐘樂未休，榮去老還逼。", "圓光過滿缺，太陽移中昃。不散東海金，何爭西飛匿。", "無作牛山悲，惻愴淚沾臆。"]'),
('yuding-2','東海有勇婦','李白','唐','御定全唐诗','yuding','','[]','梁山感杞妻，慟哭為之傾。金石忽暫開，都由激深情。',228,'御定全唐詩/json/164.json','["梁山感杞妻，慟哭為之傾。金石忽暫開，都由激深情。", "東海有勇婦，何慚蘇子卿。學劍越處子，超然若流星。", "損軀報夫仇，萬死不顧生。白刃耀素雪，蒼天感精誠。", "十步兩躩躍，三呼一交兵。斬首掉國門，蹴踏五藏行。", "豁此伉儷憤，粲然大義明。北海李使君，飛章奏天庭。", "舍罪警風俗，流芳播滄瀛。名在列女籍，竹帛已光榮。", "淳於免詔獄，漢主為緹縈。津妾一棹歌，脫父于嚴刑。", "十子若不肖，不如一女英。豫讓斬空衣，有心竟無成。", "要離殺慶忌，壯夫所素輕。妻子亦何辜，焚之買虛聲。", "豈如東海婦，事立獨揚名。"]'),
('yuding-3','黃葛篇','李白','唐','御定全唐诗','yuding','','[]','黃葛生洛溪，黃花自綿冪。青煙蔓長條，繚繞幾百尺。',72,'御定全唐詩/json/164.json','["黃葛生洛溪，黃花自綿冪。青煙蔓長條，繚繞幾百尺。", "閨人費素手，采緝作絺綌。縫為絕國衣，遠寄日南客。", "蒼梧大火落，暑服莫輕擲。此物雖過時，是妾手中跡。"]'),
('yuding-4','白馬篇','李白','唐','御定全唐诗','yuding','','[]','龍馬花雪毛，金鞍五陵豪。秋霜切玉劍，落日明珠袍。',120,'御定全唐詩/json/164.json','["龍馬花雪毛，金鞍五陵豪。秋霜切玉劍，落日明珠袍。", "鬥雞事萬乘，軒蓋一何高。弓摧南山虎，手接太行猱。", "酒後競風采，三杯弄寶刀。殺人如剪草，劇孟同遊遨。", "發憤去函谷，從軍向臨洮。叱吒萬戰場，匈奴盡奔逃。", "歸來使酒氣，未肯拜蕭曹。羞入原憲室，荒淫隱蓬蒿。"]'),
('yuding-5','鳳吹笙曲','李白','唐','御定全唐诗','yuding','','[]','仙人十五愛吹笙，學得昆丘彩鳳鳴。始聞煉氣餐金液，',72,'御定全唐詩/json/164.json','["仙人十五愛吹笙，學得昆丘彩鳳鳴。始聞煉氣餐金液，", "欲歎離聲發絳唇，更嗟別調流纖指。此時惜別詎堪聞，", "綠雲紫氣向函關，訪道應尋緱氏山。莫學吹笙王子晉，"]'),
('yuding-6','怨歌行','李白','唐','御定全唐诗','yuding','','[]','十五入漢宮，花顏笑春紅。君王選玉色，侍寢金屏中。',108,'御定全唐詩/json/164.json','["十五入漢宮，花顏笑春紅。君王選玉色，侍寢金屏中。", "薦枕嬌夕月，卷衣戀春風。甯知趙飛燕，奪寵恨無窮。", "沉憂能傷人，綠鬢成霜蓬。一朝不得意，世事徒為空。", "鷫鸘換美酒，舞衣罷雕龍。寒苦不忍言，為君奏絲桐。", "腸斷弦亦絕，悲心夜忡忡。"]'),
('yuding-7','塞下曲六首','李白','唐','御定全唐诗','yuding','','[]','五月天山雪，無花只有寒。笛中聞折柳，春色未曾看。',300,'御定全唐詩/json/164.json','["五月天山雪，無花只有寒。笛中聞折柳，春色未曾看。", "曉戰隨金鼓，宵眠抱玉鞍。願將腰下劍，直為斬樓蘭。", "天兵下北荒，胡馬欲南飲。橫戈從百戰，直為銜恩甚。", "握雪海上餐，拂沙隴頭寢。何當破月氏，然後方高枕。", "駿馬似風飆，鳴鞭出渭橋。彎弓辭漢月，插羽破天驕。", "陣解星芒盡，營空海霧消。功成畫麟閣，獨有霍嫖姚。", "白馬黃金塞，雲砂繞夢思。那堪愁苦節，遠憶邊城兒。", "螢飛秋窗滿，月度霜閨遲。摧殘梧桐葉，蕭颯沙棠枝。", "無時獨不見，流淚空自知。", "塞虜乘秋下，天兵出漢家。將軍分虎竹，戰士臥龍沙。", "邊月隨弓影，胡霜拂劍花。玉關殊未入，少婦莫長嗟。", "烽火動沙漠，連照甘泉雲。漢皇按劍起，還召李將軍。", "兵氣天上合，鼓聲隴底聞。橫行負勇氣，一戰淨妖氛。"]'),
('yuding-8','來日大難','李白','唐','御定全唐诗','yuding','','[]','來日一身，攜糧負薪。道長食盡，苦口焦唇。今日醉飽，',70,'御定全唐詩/json/164.json','["來日一身，攜糧負薪。道長食盡，苦口焦唇。今日醉飽，", "乘龍天飛，目瞻兩角。授以仙藥，金丹滿握。蟪蛄蒙恩，", "蟬翼九五，以求長生。下士大笑，如蒼蠅聲。"]'),
('yuding-9','塞上曲','李白','唐','御定全唐诗','yuding','','[]','大漢無中策，匈奴犯渭橋。五原秋草綠，胡馬一何驕。',72,'御定全唐詩/json/164.json','["大漢無中策，匈奴犯渭橋。五原秋草綠，胡馬一何驕。", "命將征西極，橫行陰山側。燕支落漢家，婦女無華色。", "轉戰渡黃河，休兵樂事多。蕭條清萬里，瀚海寂無波。"]'),
('yuding-10','玉階怨','李白','唐','御定全唐诗','yuding','','[]','玉階生白露，夜久侵羅襪。卻下水晶簾，玲瓏望秋月。',24,'御定全唐詩/json/164.json','["玉階生白露，夜久侵羅襪。卻下水晶簾，玲瓏望秋月。"]'),
('yuding-11','襄陽曲四首','李白','唐','御定全唐诗','yuding','','[]','襄陽行樂處，歌舞白銅鞮。江城回淥水，花月使人迷。',97,'御定全唐詩/json/164.json','["襄陽行樂處，歌舞白銅鞮。江城回淥水，花月使人迷。", "山公醉酒時，酩酊高陽下。頭上白接z5，倒著還騎馬。", "峴山臨漢江，水綠沙如雪。上有墮淚碑，青苔久磨滅。", "且醉習家池，莫看墮淚碑。山公欲上馬，笑殺襄陽兒。"]'),
('yuding-12','大堤曲','李白','唐','御定全唐诗','yuding','','[]','漢水臨襄陽，花開大堤暖。佳期大堤下，淚向南雲滿。',48,'御定全唐詩/json/164.json','["漢水臨襄陽，花開大堤暖。佳期大堤下，淚向南雲滿。", "春風無複情，吹我夢魂散。不見眼中人，天長音信斷。"]'),
('yuding-13','宮中行樂詞八首','李白','唐','御定全唐诗','yuding','','[]','小小生金屋，盈盈在紫微。山花插寶髻，石竹繡羅衣。',384,'御定全唐詩/json/164.json','["小小生金屋，盈盈在紫微。山花插寶髻，石竹繡羅衣。", "每出深宮裏，常隨步輦歸。只愁歌舞散，化作彩雲飛。", "柳色黃金嫩，梨花白雪香。玉樓巢翡翠，金殿鎖鴛鴦。", "選妓隨雕輦，征歌出洞房。宮中誰第一，飛燕在昭陽。", "盧橘為秦樹，蒲萄出漢宮。煙花宜落日，絲管醉春風。", "笛奏龍吟水，簫鳴鳳下空。君王多樂事，還與萬方同。", "玉樹春歸日，金宮樂事多。後庭朝未入，輕輦夜相過。", "笑出花間語，嬌來竹下歌。莫教明月去，留著醉嫦娥。", "繡戶香風暖，紗窗曙色新。宮花爭笑日，池草暗生春。", "綠樹聞歌鳥，青樓見舞人。昭陽桃李月，羅綺自相親。", "今日明光裏，還須結伴遊。春風開紫殿，天樂下朱樓。", "豔舞全知巧，嬌歌半欲羞。更憐花月夜，宮女笑藏鉤。", "寒雪梅中盡，春風柳上歸。宮鶯嬌欲醉，簷燕語還飛。", "遲日明歌席，新花豔舞衣。晚來移彩仗，行樂泥光輝。", "水綠南熏殿，花紅北闕樓。鶯歌聞太液，鳳吹繞瀛洲。", "素女鳴珠佩，天人弄彩球。今朝風日好，宜入未央遊。"]'),
('yuding-14','清平調詞三首','李白','唐','御定全唐诗','yuding','','[]','雲想衣裳花相容，春風拂檻露華濃。',96,'御定全唐詩/json/164.json','["雲想衣裳花相容，春風拂檻露華濃。", "若非群玉山頭見，會向瑤台月下逢。", "一枝穠豔露凝香，雲雨巫山枉斷腸。", "借問漢宮誰得似，可憐飛燕倚新妝。", "名花傾國兩相歡，長得君王帶笑看。", "解釋春風無限恨，沉香亭北倚闌干。"]'),
('yuding-15','入朝曲','李白','唐','御定全唐诗','yuding','','[]','金陵控海浦，淥水帶吳京。鐃歌列騎吹，颯遝引公卿。',84,'御定全唐詩/json/164.json','["金陵控海浦，淥水帶吳京。鐃歌列騎吹，颯遝引公卿。", "槌鐘速嚴妝，伐鼓啟重城。天子憑玉幾，劍履若雲行。", "日出照萬戶，簪裾爛明星。朝罷沐浴閑，遨遊閬風亭。", "濟濟雙闕下，歡娛樂恩榮。"]'),
('yuding-16','秦女休行','李白','唐','御定全唐诗','yuding','','[]','西門秦氏女，秀色如瓊花。手揮白楊刀，清晝殺讎家。',108,'御定全唐詩/json/164.json','["西門秦氏女，秀色如瓊花。手揮白楊刀，清晝殺讎家。", "羅袖灑赤血，英氣淩紫霞。直上西山去，關吏相邀遮。", "婿為燕國王，身被詔獄加。犯刑若履虎，不畏落爪牙。", "素頸未及斷，摧眉伏泥沙。金雞忽放赦，大辟得寬賒。", "何慚聶政姊，萬古共驚嗟。"]'),
('yuding-17','秦女卷衣','李白','唐','御定全唐诗','yuding','','[]','天子居未央，妾侍卷衣裳。顧無紫宮寵，敢拂黃金床。',60,'御定全唐詩/json/164.json','["天子居未央，妾侍卷衣裳。顧無紫宮寵，敢拂黃金床。", "水至亦不去，熊來尚可當。微身奉日月，飄若螢之光。", "願君采葑菲，無以下體妨。"]'),
('yuding-18','東武吟','李白','唐','御定全唐诗','yuding','','[]','好古笑流俗，素聞賢達風。方希佐明主，長揖辭成功。',204,'御定全唐詩/json/164.json','["好古笑流俗，素聞賢達風。方希佐明主，長揖辭成功。", "白日在高天，回光燭微躬。恭承鳳凰詔，欻起雲蘿中。", "清切紫霄迥，優遊丹禁通。君王賜顏色，聲價淩煙虹。", "乘輿擁翠蓋，扈從金城東。寶馬麗絕景，錦衣入新豐。", "依岩望松雪，對酒鳴絲桐。因學揚子雲，獻賦甘泉宮。", "天書美片善，清芬播無窮。歸來入咸陽，談笑皆王公。", "一朝去金馬，飄落成飛蓬。賓客日疏散，玉樽亦已空。", "才力猶可倚，不慚世上雄。閑作東武吟，曲盡情未終。", "書此謝知己，吾尋黃綺翁。"]'),
('yuding-19','邯鄲才人嫁為廝養卒婦','李白','唐','御定全唐诗','yuding','','[]','妾本崇台女，揚蛾入丹闕。自倚顏如花，寧知有凋歇。',60,'御定全唐詩/json/164.json','["妾本崇台女，揚蛾入丹闕。自倚顏如花，寧知有凋歇。", "一辭玉階下，去若朝雲沒。每憶邯鄲城，深宮夢秋月。", "君王不可見，惆悵至明發。"]'),
('yuding-20','出自薊北門行','李白','唐','御定全唐诗','yuding','','[]','虜陣橫北荒，胡星耀精芒。羽書速驚電，烽火晝連光。',144,'御定全唐詩/json/164.json','["虜陣橫北荒，胡星耀精芒。羽書速驚電，烽火晝連光。", "虎竹救邊急，戎車森已行。明主不安席，按劍心飛揚。", "推轂出猛將，連旗登戰場。兵威沖絕幕，殺氣淩穹蒼。", "列卒赤山下，開營紫塞傍。孟冬風沙緊，旌旗颯凋傷。", "畫角悲海月，征衣卷天霜。揮刃斬樓蘭，彎弓射賢王。", "單于一平蕩，種落自奔亡。收功報天子，行歌歸咸陽。"]'),
('yuding-21','洛陽陌','李白','唐','御定全唐诗','yuding','','[]','白玉誰家郎，回車渡天津。看花東陌上，驚動洛陽人。',24,'御定全唐詩/json/164.json','["白玉誰家郎，回車渡天津。看花東陌上，驚動洛陽人。"]'),
('yuding-22','北上行','李白','唐','御定全唐诗','yuding','','[]','北上何所苦，北上緣太行。磴道盤且峻，巉岩淩穹蒼。',168,'御定全唐詩/json/164.json','["北上何所苦，北上緣太行。磴道盤且峻，巉岩淩穹蒼。", "馬足蹶側石，車輪摧高岡。沙塵接幽州，烽火連朔方。", "殺氣毒劍戟，嚴風裂衣裳。奔鯨夾黃河，鑿齒屯洛陽。", "前行無歸日，返顧思舊鄉。慘戚冰雪裏，悲號絕中腸。", "尺布不掩體，皮膚劇枯桑。汲水澗穀阻，采薪隴阪長。", "猛虎又掉尾，磨牙皓秋霜。草木不可餐，饑飲零露漿。", "歎此北上苦，停驂為之傷。何日王道平，開顏睹天光。"]'),
('yuding-23','短歌行','李白','唐','御定全唐诗','yuding','','[]','白日何短短，百年苦易滿。蒼穹浩茫茫，萬劫太極長。',84,'御定全唐詩/json/164.json','["白日何短短，百年苦易滿。蒼穹浩茫茫，萬劫太極長。", "麻姑垂兩鬢，一半已成霜。天公見玉女，大笑億千場。", "吾欲攬六龍，回車掛扶桑。北斗酌美酒，勸龍各一觴。", "富貴非所願，與人駐顏光。"]'),
('yuding-24','空城雀','李白','唐','御定全唐诗','yuding','','[]','嗷嗷空城雀，身計何戚促。本與鷦鷯群，不隨鳳凰族。',72,'御定全唐詩/json/164.json','["嗷嗷空城雀，身計何戚促。本與鷦鷯群，不隨鳳凰族。", "提攜四黃口，飲乳未嘗足。食君糠秕餘，嘗恐烏鳶逐。", "恥涉太行險，羞營覆車粟。天命有定端，守分絕所欲。"]'),
('yuding-0','發白馬','李白','唐','御定全唐诗','yuding','','[]','將軍發白馬，旌節度黃河。簫鼓聒川嶽，滄溟湧濤波。',96,'御定全唐詩/json/165.json','["將軍發白馬，旌節度黃河。簫鼓聒川嶽，滄溟湧濤波。", "武安有振瓦，易水無寒歌。鐵騎若雪山，飲流涸滹沱。", "揚兵獵月窟，轉戰略朝那。倚劍登燕然，邊烽列嵯峨。", "蕭條萬里外，耕作五原多。一掃清大漠，包虎戢金戈。"]'),
('yuding-1','陌上桑','李白','唐','御定全唐诗','yuding','','[]','美女渭橋東，春還事蠶作。五馬如飛龍，青絲結金絡。',108,'御定全唐詩/json/165.json','["美女渭橋東，春還事蠶作。五馬如飛龍，青絲結金絡。", "不知誰家子，調笑來相謔。妾本秦羅敷，玉顏豔名都。", "綠條映素手，采桑向城隅。使君且不顧，況複論秋胡。", "寒螿愛碧草，鳴鳳棲青梧。托心自有處，但怪傍人愚。", "徒令白日暮，高駕空踟躕。"]'),
('yuding-2','枯魚過河泣','李白','唐','御定全唐诗','yuding','','[]','白龍改常服，偶被豫且制。誰使爾為魚，徒勞訴天帝。',60,'御定全唐詩/json/165.json','["白龍改常服，偶被豫且制。誰使爾為魚，徒勞訴天帝。", "作書報鯨鯢，勿恃風濤勢。濤落歸泥沙，翻遭螻蟻噬。", "萬乘慎出入，柏人以為識。"]'),
('yuding-3','丁督護歌','李白','唐','御定全唐诗','yuding','','[]','雲陽上征去，兩岸饒商賈。吳牛喘月時，拖船一何苦。',72,'御定全唐詩/json/165.json','["雲陽上征去，兩岸饒商賈。吳牛喘月時，拖船一何苦。", "水濁不可飲，壺漿半成土。一唱督護歌，心摧淚如雨。", "萬人鑿磐石，無由達江滸。君看石芒碭，掩淚悲千古。"]'),
('yuding-4','相逢行','李白','唐','御定全唐诗','yuding','','[]','朝騎五花馬，謁帝出銀台。秀色誰家子，雲車珠箔開。',180,'御定全唐詩/json/165.json','["朝騎五花馬，謁帝出銀台。秀色誰家子，雲車珠箔開。", "金鞭遙指點，玉勒近遲回。夾轂相借問，疑從天上來。", "蹙入青綺門，當歌共銜杯。銜杯映歌扇，似月雲中見。", "相見不得親，不如不相見。相見情已深，未語可知心。", "胡為守空閨，孤眠愁錦衾。錦衾與羅幃，纏綿會有時。", "春風正澹蕩，暮雨來何遲。願因三青鳥，更報長相思。", "光景不待人，須臾發成絲。當年失行樂，老去徒傷悲。", "持此道密意，毋令曠佳期。"]'),
('yuding-5','千里思','李白','唐','御定全唐诗','yuding','','[]','李陵沒胡沙，蘇武還漢家。迢迢五原關，朔雪亂邊花。',48,'御定全唐詩/json/165.json','["李陵沒胡沙，蘇武還漢家。迢迢五原關，朔雪亂邊花。", "一去隔絕國，思歸但長嗟。鴻雁向西北，因書報天涯。"]'),
('yuding-6','樹中草','李白','唐','御定全唐诗','yuding','','[]','鳥銜野田草，誤入枯桑裏。客土植危根，逢春猶不死。',48,'御定全唐詩/json/165.json','["鳥銜野田草，誤入枯桑裏。客土植危根，逢春猶不死。", "草木雖無情，因依尚可生。如何同枝葉，各自有枯榮。"]'),
('yuding-7','君馬黃','李白','唐','御定全唐诗','yuding','','[]','君馬黃，我馬白。馬色雖不同，人心本無隔。',80,'御定全唐詩/json/165.json','["君馬黃，我馬白。馬色雖不同，人心本無隔。", "共作遊冶盤，雙行洛陽陌。長劍既照曜，高冠何赩赫。", "各有千金裘，俱為五侯客。猛虎落陷阱，壯夫時屈厄。", "相知在急難，獨好亦何益。"]'),
('yuding-8','擬古','李白','唐','御定全唐诗','yuding','','[]','融融白玉輝，映我青蛾眉。寶鏡似空水，落花如風吹。',48,'御定全唐詩/json/165.json','["融融白玉輝，映我青蛾眉。寶鏡似空水，落花如風吹。", "出門望帝子，蕩漾不可期。安得黃鶴羽，一報佳人知。"]'),
('yuding-9','折楊柳','李白','唐','御定全唐诗','yuding','','[]','垂楊拂綠水，搖豔東風年。花明玉關雪，葉暖金窗煙。',48,'御定全唐詩/json/165.json','["垂楊拂綠水，搖豔東風年。花明玉關雪，葉暖金窗煙。", "美人結長想，對此心淒然。攀條折春色，遠寄龍庭前。"]'),
('yuding-10','少年子','李白','唐','御定全唐诗','yuding','','[]','青雲年少子，挾彈章台左。鞍馬四邊開，突如流星過。',48,'御定全唐詩/json/165.json','["青雲年少子，挾彈章台左。鞍馬四邊開，突如流星過。", "金丸落飛鳥，夜入瓊樓臥。夷齊是何人，獨守西山餓。"]'),
('yuding-11','紫騮馬','李白','唐','御定全唐诗','yuding','','[]','紫騮行且嘶，雙翻碧玉蹄。臨流不肯渡，似惜錦障泥。',48,'御定全唐詩/json/165.json','["紫騮行且嘶，雙翻碧玉蹄。臨流不肯渡，似惜錦障泥。", "白雪關山遠，黃雲海戍迷。揮鞭萬里去，安得念春閨。"]'),
('yuding-12','少年行二首','李白','唐','御定全唐诗','yuding','','[]','擊築飲美酒，劍歌易水湄。經過燕太子，結托並州兒。',80,'御定全唐詩/json/165.json','["擊築飲美酒，劍歌易水湄。經過燕太子，結托並州兒。", "少年負壯氣，奮烈自有時。因擊魯勾踐，爭博勿相欺。", "五陵年少金市東，銀鞍白馬度春風。", "落花踏盡遊何處，笑入胡姬酒肆中。"]'),
('yuding-13','白鼻騧','李白','唐','御定全唐诗','yuding','','[]','銀鞍白鼻騧，綠地障泥錦。細雨春風花落時，',20,'御定全唐詩/json/165.json','["銀鞍白鼻騧，綠地障泥錦。細雨春風花落時，"]'),
('yuding-14','豫章行','李白','唐','御定全唐诗','yuding','','[]','胡風吹代馬，北擁魯陽關。吳兵照海雪，西討何時還。',132,'御定全唐詩/json/165.json','["胡風吹代馬，北擁魯陽關。吳兵照海雪，西討何時還。", "半渡上遼津，黃雲慘無顏。老母與子別，呼天野草間。", "白馬繞旌旗，悲鳴相追攀。白楊秋月苦，早落豫章山。", "本為休明人，斬虜素不閑。豈惜戰鬥死，為君掃凶頑。", "精感石沒羽，豈雲憚險艱。樓船若鯨飛，波蕩落星灣。", "此曲不可奏，三軍鬢成斑。"]'),
('yuding-15','沐浴子','李白','唐','御定全唐诗','yuding','','[]','沐芳莫彈冠，浴蘭莫振衣。處世忌太潔，至人貴藏暉。',36,'御定全唐詩/json/165.json','["沐芳莫彈冠，浴蘭莫振衣。處世忌太潔，至人貴藏暉。", "滄浪有釣叟，吾與爾同歸。"]'),
('yuding-16','高句驪','李白','唐','御定全唐诗','yuding','','[]','金花折風帽，白馬小遲回。翩翩舞廣袖，似鳥海東來。',24,'御定全唐詩/json/165.json','["金花折風帽，白馬小遲回。翩翩舞廣袖，似鳥海東來。"]'),
('yuding-17','舍利弗','李白','唐','御定全唐诗','yuding','','[]','金繩界寶地，珍木蔭瑤池。雲間妙音奏，天際法蠡吹。',24,'御定全唐詩/json/165.json','["金繩界寶地，珍木蔭瑤池。雲間妙音奏，天際法蠡吹。"]'),
('yuding-18','靜夜思','李白','唐','御定全唐诗','yuding','','[]','床前看月光，疑是地上霜。舉頭望山月，低頭思故鄉。',24,'御定全唐詩/json/165.json','["床前看月光，疑是地上霜。舉頭望山月，低頭思故鄉。"]'),
('yuding-19','淥水曲','李白','唐','御定全唐诗','yuding','','[]','淥水明秋月，南湖采白蘋。荷花嬌欲語，愁殺蕩舟人。',24,'御定全唐詩/json/165.json','["淥水明秋月，南湖采白蘋。荷花嬌欲語，愁殺蕩舟人。"]'),
('yuding-20','鳳凰曲','李白','唐','御定全唐诗','yuding','','[]','嬴女吹玉簫，吟弄天上春。青鸞不獨去，更有攜手人。',36,'御定全唐詩/json/165.json','["嬴女吹玉簫，吟弄天上春。青鸞不獨去，更有攜手人。", "影滅彩雲斷，遺聲落西秦。"]'),
('yuding-21','鳳台曲','李白','唐','御定全唐诗','yuding','','[]','嘗聞秦帝女，傳得鳳凰聲。是日逢仙子，當時別有情。',48,'御定全唐詩/json/165.json','["嘗聞秦帝女，傳得鳳凰聲。是日逢仙子，當時別有情。", "人吹彩簫去，天借綠雲迎。曲在身不返，空餘弄玉名。"]'),
('yuding-22','從軍行','李白','唐','御定全唐诗','yuding','','[]','從軍玉門道，逐虜金微山。笛奏梅花曲，刀開明月環。',48,'御定全唐詩/json/165.json','["從軍玉門道，逐虜金微山。笛奏梅花曲，刀開明月環。", "鼓聲鳴海上，兵氣擁雲間。願斬單于首，長驅靜鐵關。"]'),
('yuding-23','秋思','李白','唐','御定全唐诗','yuding','','[]','春陽如昨日，碧樹鳴黃鸝。蕪然蕙草暮，颯爾涼風吹。',48,'御定全唐詩/json/165.json','["春陽如昨日，碧樹鳴黃鸝。蕪然蕙草暮，颯爾涼風吹。", "天秋木葉下，月冷莎雞悲。坐愁群芳歇，白露凋華滋。"]'),
('yuding-24','春思','李白','唐','御定全唐诗','yuding','','[]','燕草如碧絲，秦桑低綠枝。當君懷歸日，是妾斷腸時。',36,'御定全唐詩/json/165.json','["燕草如碧絲，秦桑低綠枝。當君懷歸日，是妾斷腸時。", "春風不相識，何事入羅幃。"]'),
('yuding-25','秋思','李白','唐','御定全唐诗','yuding','','[]','燕支黃葉落，妾望自登臺。海上碧雲斷，單于秋色來。',48,'御定全唐詩/json/165.json','["燕支黃葉落，妾望自登臺。海上碧雲斷，單于秋色來。", "胡兵沙塞合，漢使玉關回。征客無歸日，空悲蕙草摧。"]'),
('yuding-26','子夜吳歌：春歌','李白','唐','御定全唐诗','yuding','','[]','秦地羅敷女，采桑綠水邊。素手青條上，紅妝白日鮮。',36,'御定全唐詩/json/165.json','["秦地羅敷女，采桑綠水邊。素手青條上，紅妝白日鮮。", "蠶饑妾欲去，五馬莫留連。"]'),
('yuding-27','子夜吳歌：夏歌','李白','唐','御定全唐诗','yuding','','[]','鏡湖三百里，菡萏發荷花。五月西施采，人看隘若耶。',36,'御定全唐詩/json/165.json','["鏡湖三百里，菡萏發荷花。五月西施采，人看隘若耶。", "回舟不待月，歸去越王家。"]'),
('yuding-28','子夜吳歌：秋歌','李白','唐','御定全唐诗','yuding','','[]','長安一片月，萬戶擣衣聲。秋風吹不盡，總是玉關情。',36,'御定全唐詩/json/165.json','["長安一片月，萬戶擣衣聲。秋風吹不盡，總是玉關情。", "何日平胡虜，良人罷遠征。"]'),
('yuding-29','子夜吳歌：冬歌','李白','唐','御定全唐诗','yuding','','[]','明朝驛使發，一夜絮征袍。素手抽針冷，那堪把剪刀。',36,'御定全唐詩/json/165.json','["明朝驛使發，一夜絮征袍。素手抽針冷，那堪把剪刀。", "裁縫寄遠道，幾日到臨洮。"]'),
('yuding-30','對酒行','李白','唐','御定全唐诗','yuding','','[]','松子棲金華，安期入蓬海。此人古之仙，羽化竟何在。',60,'御定全唐詩/json/165.json','["松子棲金華，安期入蓬海。此人古之仙，羽化竟何在。", "浮生速流電，倏忽變光彩。天地無凋換，容顏有遷改。", "對酒不肯飲，含情欲誰待。"]'),
('yuding-31','估客行','李白','唐','御定全唐诗','yuding','','[]','海客乘天風，將船遠行役。譬如雲中鳥，一去無蹤跡。',24,'御定全唐詩/json/165.json','["海客乘天風，將船遠行役。譬如雲中鳥，一去無蹤跡。"]'),
('yuding-32','擣衣篇','李白','唐','御定全唐诗','yuding','','[]','閨裏佳人年十餘，顰蛾對影恨離居。忽逢江上春歸燕，',96,'御定全唐詩/json/165.json','["閨裏佳人年十餘，顰蛾對影恨離居。忽逢江上春歸燕，", "萬里交河水北流，願為雙燕泛中洲。君邊雲擁青絲騎，", "曉吹員管隨落花，夜搗戎衣向明月。明月高高刻漏長，", "瓊筵寶幄連枝錦，燈燭熒熒照孤寢。有便憑將金剪刀，"]'),
('yuding-33','少年行','李白','唐','御定全唐诗','yuding','','[]','君不見淮南少年游俠客，白日球獵夜擁擲。',139,'御定全唐詩/json/165.json','["君不見淮南少年游俠客，白日球獵夜擁擲。", "呼盧百萬終不惜，報仇千里如咫尺。少年遊俠好經過，", "驕矜自言不可有，俠士堂中養來久。好鞍好馬乞與人，", "桃李栽來幾度春，一回花落一回新。府縣盡為門下客，", "男兒百年且榮身，何須徇節甘風塵。衣冠半是征戰士，", "遮莫姻親連帝城，不如當身自簪纓。看取富貴眼前者，"]'),
('yuding-34','長歌行','李白','唐','御定全唐诗','yuding','','[]','桃李待日開，榮華照當年。東風動百物，草木盡欲言。',120,'御定全唐詩/json/165.json','["桃李待日開，榮華照當年。東風動百物，草木盡欲言。", "枯枝無醜葉，涸水吐清泉。大力運天地，羲和無停鞭。", "功名不早著，竹帛將何宣。桃李務青春，誰能貫白日。", "富貴與神仙，蹉跎成兩失。金石猶銷鑠，風霜無久質。", "畏落日月後，強歡歌與酒。秋霜不惜人，倏忽侵蒲柳。"]'),
('yuding-35','長相思','李白','唐','御定全唐诗','yuding','','[]','日色已盡花含煙，月明欲素愁不眠。趙瑟初停鳳凰柱，',74,'御定全唐詩/json/165.json','["日色已盡花含煙，月明欲素愁不眠。趙瑟初停鳳凰柱，", "不信妾腸斷，歸來看取明鏡前。", "美人在時花滿堂，美人去後空餘床。床中繡被卷不寢，", "相思黃葉落，白露點青苔。"]'),
('yuding-36','猛虎行','李白','唐','御定全唐诗','yuding','','[]','朝作猛虎行，暮作猛虎吟。腸斷非關隴頭水，',188,'御定全唐詩/json/165.json','["朝作猛虎行，暮作猛虎吟。腸斷非關隴頭水，", "秦人半作燕地囚，胡馬翻銜洛陽草。一輸一失關下兵，", "頗似楚漢時，翻覆無定止，朝過博浪沙，暮入淮陰市。", "張良未遇韓信貧，劉項存亡在兩臣。暫到下邳受兵略，", "有策不敢犯龍鱗，竄身南國避胡塵。寶書玉劍掛高閣，", "有時六博快壯心，繞床三匝呼一擲。楚人每道張旭奇，", "蕭曹曾作沛中吏，攀龍附鳳當有時。溧陽酒樓三月春，", "丈夫相見且為樂，槌牛撾鼓會眾賓。我從此去釣東海，"]'),
('yuding-37','去婦詞','李白','唐','御定全唐诗','yuding','','[]','古來有棄婦，棄婦有歸處。今日妾辭君，辭君遣何去。',92,'御定全唐詩/json/165.json','["古來有棄婦，棄婦有歸處。今日妾辭君，辭君遣何去。", "本家零落盡，慟哭來時路。憶昔未嫁君，聞君卻周旋。", "綺羅錦繡段，有贈黃金千。十五許嫁君，二十移所天。", "自從結髮日未幾，離君緬山川。家家盡歡喜，"]'),
('yuding-0','襄陽歌','李白','唐','御定全唐诗','yuding','','[]','落日欲沒峴山西，倒著接z5花下迷。襄陽小兒齊拍手，',123,'御定全唐詩/json/166.json','["落日欲沒峴山西，倒著接z5花下迷。襄陽小兒齊拍手，", "鸕鷀杓，鸚鵡杯。百年三萬六千日，一日須傾三百杯。", "遙看漢水鴨頭綠，恰似葡萄初醱醅。此江若變作春酒，", "車傍側掛一壺酒，鳳笙龍管行相催。咸陽市中歎黃犬，", "清風朗月不用一錢買，玉山自倒非人推。舒州杓，力士鐺，"]'),
('yuding-1','南都行','李白','唐','御定全唐诗','yuding','','[]','南都信佳麗，武闕橫西關。白水真人居，萬商羅鄽闤。',120,'御定全唐詩/json/166.json','["南都信佳麗，武闕橫西關。白水真人居，萬商羅鄽闤。", "高樓對紫陌，甲第連青山。此地多英豪，邈然不可攀。", "陶朱與五羖，名播天壤間。麗華秀玉色，漢女嬌朱顏。", "清歌遏流雲，豔舞有餘閑。遨遊盛宛洛，冠蓋隨風還。", "走馬紅陽城，呼鷹白河灣。誰識臥龍客，長吟愁鬢斑。"]'),
('yuding-2','江上吟','李白','唐','御定全唐诗','yuding','','[]','木蘭之枻沙棠舟，玉簫金管坐兩頭。美酒尊中置千斛，',48,'御定全唐詩/json/166.json','["木蘭之枻沙棠舟，玉簫金管坐兩頭。美酒尊中置千斛，", "屈平詞賦懸日月，楚王台榭空山丘。興酣落筆搖五嶽，"]'),
('yuding-3','侍從宜春苑奉詔賦龍池柳色初青聽新鶯百囀歌','李白','唐','御定全唐诗','yuding','','[]','東風已綠瀛洲草，紫殿紅樓覺春好。池南柳色半青青，',64,'御定全唐詩/json/166.json','["東風已綠瀛洲草，紫殿紅樓覺春好。池南柳色半青青，", "是時君王在鎬京，五雲垂暉耀紫清。仗出金宮隨日轉，", "新鶯飛繞上林苑，願入簫韶雜鳳笙。"]'),
('yuding-4','玉壺吟','李白','唐','御定全唐诗','yuding','','[]','烈士擊玉壺，壯心惜暮年。三杯拂劍舞秋月，',68,'御定全唐詩/json/166.json','["烈士擊玉壺，壯心惜暮年。三杯拂劍舞秋月，", "揄揚九重萬乘主，謔浪赤墀青瑣賢。朝天數換飛龍馬，", "西施宜笑複宜顰，醜女效之徒累身。君王雖愛蛾眉好，"]'),
('yuding-5','豳歌行，上新平長史兄粲','李白','唐','御定全唐诗','yuding','','[]','豳穀稍稍振庭柯，涇水浩浩揚湍波。哀鴻酸嘶暮聲急，',88,'御定全唐詩/json/166.json','["豳穀稍稍振庭柯，涇水浩浩揚湍波。哀鴻酸嘶暮聲急，", "中宵出飲三百杯，明朝歸揖二千石。甯知流寓變光輝，", "吾兄行樂窮曛旭，滿堂有美顏如玉。趙女長歌入彩雲，", "前榮後枯相翻覆，何惜餘光及棣華。"]'),
('yuding-6','西嶽雲台歌，送丹丘子','李白','唐','御定全唐诗','yuding','','[]','西嶽崢嶸何壯哉，黃河如絲天際來。黃河萬里觸山動，',96,'御定全唐詩/json/166.json','["西嶽崢嶸何壯哉，黃河如絲天際來。黃河萬里觸山動，", "巨靈咆哮擘兩山，洪波噴箭射東海。三峰卻立如欲摧，", "雲台閣道連窈冥，中有不死丹丘生。明星玉女備灑掃，", "九重出入生光輝，東來蓬萊複西歸。玉漿倘惠故人飲，"]'),
('yuding-7','元丹丘歌','李白','唐','御定全唐诗','yuding','','[]','元丹丘，愛神仙。朝飲潁川之清流，暮還嵩岑之紫煙，',24,'御定全唐詩/json/166.json','["元丹丘，愛神仙。朝飲潁川之清流，暮還嵩岑之紫煙，"]'),
('yuding-8','扶風豪士歌','李白','唐','御定全唐诗','yuding','','[]','洛陽三月飛胡沙，洛陽城中人怨嗟。天津流水波赤血，',112,'御定全唐詩/json/166.json','["洛陽三月飛胡沙，洛陽城中人怨嗟。天津流水波赤血，", "東方日出啼早鴉，城門人開掃落花。梧桐楊柳拂金井，", "作人不倚將軍勢，飲酒豈顧尚書期。雕盤綺食會眾客，", "堂中各有三千士，明日報恩知是誰。撫長劍，一揚眉，", "張良未逐赤松去，橋邊黃石知我心。"]'),
('yuding-9','同族弟金城尉叔卿燭照山水壁畫歌','李白','唐','御定全唐诗','yuding','','[]','高堂粉壁圖蓬瀛，燭前一見滄洲清。洪波洶湧山崢嶸，',40,'御定全唐詩/json/166.json','["高堂粉壁圖蓬瀛，燭前一見滄洲清。洪波洶湧山崢嶸，", "卻顧海客揚雲帆，便欲因之向溟渤。"]'),
('yuding-10','白毫子歌','李白','唐','御定全唐诗','yuding','','[]','淮南小山白毫子，乃在淮南小山裏。夜臥松下雲，',66,'御定全唐詩/json/166.json','["淮南小山白毫子，乃在淮南小山裏。夜臥松下雲，", "余配白毫子，獨酌流霞杯。拂花弄琴坐青苔，", "可得見，未得親。八公攜手五雲去，空餘桂樹愁殺人。"]'),
('yuding-11','梁園吟','李白','唐','御定全唐诗','yuding','','[]','我浮黃雲去京闕，掛席欲進波連山。天長水闊厭遠涉，',144,'御定全唐詩/json/166.json','["我浮黃雲去京闕，掛席欲進波連山。天長水闊厭遠涉，", "卻憶蓬池阮公詠，因吟淥水揚洪波。洪波浩蕩迷舊國，", "平頭奴子搖大扇，五月不熱疑清秋。玉盤楊梅為君設，", "昔人豪貴信陵君，今人耕種信陵墳。荒城虛照碧山月，", "舞影歌聲散綠池，空餘汴水東流海。沉吟此事淚滿衣，", "歌且謠，意方遠。東山高臥時起來，欲濟蒼生未應晚。"]'),
('yuding-12','鳴皋歌，送岑征君','李白','唐','御定全唐诗','yuding','','[]','若有人兮思鳴皋，阻積雪兮心煩勞。',242,'御定全唐詩/json/166.json','["若有人兮思鳴皋，阻積雪兮心煩勞。", "洪河淩競不可以徑度，冰龍鱗兮難容舠。", "邈仙山之峻極兮，聞天籟之嘈嘈。霜崖縞皓以合遝兮，", "危柯振石，駭膽栗魄，群呼而相號。峰崢嶸以路絕，", "交鼓吹兮彈絲，觴清泠之池閣。君不行兮何待，", "巾征軒兮曆阻折，尋幽居兮越巘崿。盤白石兮坐素月，", "水橫洞以下淥，波小聲而上聞。虎嘯穀而生風，", "蝘蜓嘲龍，魚目混珍。嫫母衣錦，西施負薪。", "若使巢由桎梏於軒冕兮，亦奚異乎夔龍蹩躠於風塵。", "哭何苦而救楚，笑何誇而卻秦。", "吾誠不能學二子沽名矯節以耀世兮，固將棄天地而遺身。", "白鷗兮飛來，長與君兮相親。"]'),
('yuding-13','鳴皋歌奉餞從翁清歸五崖山居','李白','唐','御定全唐诗','yuding','','[]','憶昨鳴皋夢裏還，手弄素月清潭間。覺時枕席非碧山，',64,'御定全唐詩/json/166.json','["憶昨鳴皋夢裏還，手弄素月清潭間。覺時枕席非碧山，", "青松來風吹古道，綠蘿飛花覆煙草。我家仙翁愛清真，", "去時應過嵩少間，相思為折三花樹。"]'),
('yuding-14','勞勞亭歌','李白','唐','御定全唐诗','yuding','','[]','金陵勞勞送客堂，蔓草離離生道傍。古情不盡東流水，',48,'御定全唐詩/json/166.json','["金陵勞勞送客堂，蔓草離離生道傍。古情不盡東流水，", "昔聞牛渚吟五章，今來何謝袁家郎。苦竹寒聲動秋月，"]'),
('yuding-15','橫江詞六首','李白','唐','御定全唐诗','yuding','','[]','人道橫江好，儂道橫江惡。一風三日吹倒山，',180,'御定全唐詩/json/166.json','["人道橫江好，儂道橫江惡。一風三日吹倒山，", "海潮南去過潯陽，牛渚由來險馬當。", "橫江欲渡風波惡，一水牽愁萬里長。", "橫江西望阻西秦，漢水東連揚子津。", "白浪如山那可渡，狂風愁殺峭帆人。", "海神來過惡風回，浪打天門石壁開。", "浙江八月何如此，濤似連山噴雪來。", "橫江館前津吏迎，向餘東指海雲生。", "郎今欲渡緣何事，如此風波不可行。", "月暈天風霧不開，海鯨東蹙百川回。", "驚波一起三山動，公無渡河歸去來。"]'),
('yuding-16','金陵城西樓月下吟','李白','唐','御定全唐诗','yuding','','[]','金陵夜寂涼風發，獨上高樓望吳越。白雲映水搖空城，',40,'御定全唐詩/json/166.json','["金陵夜寂涼風發，獨上高樓望吳越。白雲映水搖空城，", "解道澄江淨如練，令人長憶謝玄暉。"]'),
('yuding-17','東山吟','李白','唐','御定全唐诗','yuding','','[]','攜妓東土山，悵然悲謝安。我妓今朝如花月，',41,'御定全唐詩/json/166.json','["攜妓東土山，悵然悲謝安。我妓今朝如花月，", "酣來自作青海舞，秋風吹落紫綺冠。彼亦一時，"]'),
('yuding-18','僧伽歌','李白','唐','御定全唐诗','yuding','','[]','真僧法號號僧伽，有時與我論三車。問言誦咒幾千遍，',96,'御定全唐詩/json/166.json','["真僧法號號僧伽，有時與我論三車。問言誦咒幾千遍，", "戒得長天秋月明，心如世上青蓮色。意清淨，貌棱棱。", "亦不減，亦不增。瓶裏千年鐵柱骨，手中萬歲胡孫藤。", "嗟予落魄江淮久，罕遇真僧說空有。一言散盡波羅夷，"]'),
('yuding-19','白雲歌，送劉十六歸山','李白','唐','御定全唐诗','yuding','','[]','楚山秦山皆白雲，白雲處處長隨君。長隨君，',20,'御定全唐詩/json/166.json','["楚山秦山皆白雲，白雲處處長隨君。長隨君，"]'),
('yuding-20','金陵歌，送別范宣','李白','唐','御定全唐诗','yuding','','[]','石頭巉岩如虎踞，淩波欲過滄江去。鐘山龍盤走勢來，',88,'御定全唐詩/json/166.json','["石頭巉岩如虎踞，淩波欲過滄江去。鐘山龍盤走勢來，", "白馬小兒誰家子，泰清之歲來關囚。金陵昔時何壯哉，", "扣劍悲吟空咄嗟，梁陳白骨亂如麻。天子龍沉景陽井，", "送爾長江萬里心，他年來訪南山老。"]'),
('yuding-21','笑歌行','李白','唐','御定全唐诗','yuding','','[]','笑矣乎，笑矣乎。君不見曲如鉤，古人知爾封公侯。',175,'御定全唐詩/json/166.json','["笑矣乎，笑矣乎。君不見曲如鉤，古人知爾封公侯。", "君不見直如弦，古人知爾死道邊。張儀所以只掉三寸舌，", "君不見滄浪老人歌一曲，還道滄浪濯吾足。", "平生不解謀此身，虛作離騷遣人讀。笑矣乎，笑矣乎。", "趙有豫讓楚屈平，賣身買得千年名。巢由洗耳有何益，", "飲酒眼前樂，虛名何處有。男兒窮通當有時，", "笑矣乎，笑矣乎。甯武子，朱買臣，扣角行歌背負薪。", "今日逢君君不識，豈得不如佯狂人。"]'),
('yuding-22','悲歌行','李白','唐','御定全唐诗','yuding','','[]','悲來乎，悲來乎。主人有酒且莫斟，聽我一曲悲來吟。',156,'御定全唐詩/json/166.json','["悲來乎，悲來乎。主人有酒且莫斟，聽我一曲悲來吟。", "悲來不吟還不笑，天下無人知我心。君有數鬥酒，", "悲來乎，悲來乎。天雖長，地雖久，金玉滿堂應不守。", "富貴百年能幾何，死生一度人皆有。孤猿坐啼墳上月，", "悲來乎，悲來乎。秦家李斯早追悔，虛名撥向身之外。", "範子何曾愛五湖，功成名遂身自退。劍是一夫用，", "還須黑頭取方伯，莫謾白首為儒生。"]'),
('yuding-0','秋浦歌十七首','李白','唐','御定全唐诗','yuding','','[]','秋浦長似秋，蕭條使人愁。客愁不可度，行上東大樓。',480,'御定全唐詩/json/167.json','["秋浦長似秋，蕭條使人愁。客愁不可度，行上東大樓。", "正西望長安，下見江水流。寄言向江水，汝意憶儂不。", "遙傳一掬淚，為我達揚州。", "秋浦猿夜愁，黃山堪白頭。清溪非隴水，翻作斷腸流。", "欲去不得去，薄游成久遊。何年是歸日，雨淚下孤舟。", "秋浦錦駝鳥，人間天上稀。山雞羞淥水，不敢照毛衣。", "兩鬢入秋浦，一朝颯已衰。猿聲催白髮，長短盡成絲。", "秋浦多白猿，超騰若飛雪。牽引條上兒，飲弄水中月。", "愁作秋浦客，強看秋浦花。山川如剡縣，風日似長沙。", "醉上山公馬，寒歌甯戚牛。空吟白石爛，淚滿黑貂裘。", "秋浦千重嶺，水車嶺最奇。天傾欲墮石，水拂寄生枝。", "江祖一片石，青天掃畫屏。題詩留萬古，綠字錦苔生。", "千千石楠樹，萬萬女貞林。山山白鷺滿，澗澗白猿吟。", "君莫向秋浦，猿聲碎客心。", "邏人橫鳥道，江祖出魚梁。水急客舟疾，山花拂面香。", "水如一匹練，此地即平天。耐可乘明月，看花上酒船。", "淥水淨素月，月明白鷺飛。郎聽采菱女，一道夜歌歸。", "爐火照天地，紅星亂紫煙。赧郎明月夜，歌曲動寒川。", "白髮三千丈，緣愁似個長。不知明鏡裏，何處得秋霜。", "秋浦田舍翁，采魚水中宿。妻子張白鷳，結罝映深竹。", "桃波一步地，了了語聲聞。暗與山僧別，低頭禮白雲。"]'),
('yuding-1','當塗趙炎少府粉圖山水歌','李白','唐','御定全唐诗','yuding','','[]','峨眉高出西極天，羅浮直與南溟連。名公繹思揮彩筆，',120,'御定全唐詩/json/167.json','["峨眉高出西極天，羅浮直與南溟連。名公繹思揮彩筆，", "洞庭瀟湘意渺綿，三江七澤情洄沿。驚濤洶湧向何處，", "心搖目斷興難盡，幾時可到三山巔。西峰崢嶸噴流泉，", "此中冥昧失晝夜，隱幾寂聽無鳴蟬。長松之下列羽客，", "訟庭無事羅眾賓，杳然如在丹青裏。五色粉圖安足珍，"]'),
('yuding-2','永王東巡歌十一首','李白','唐','御定全唐诗','yuding','','[]','永王正月東出師，天子遙分龍虎旗。',352,'御定全唐詩/json/167.json','["永王正月東出師，天子遙分龍虎旗。", "樓船一舉風波靜，江漢翻為雁鶩池。", "三川北虜亂如麻，四海南奔似永嘉。", "但用東山謝安石，為君談笑靜胡沙。", "雷鼓嘈嘈喧武昌，雲旗獵獵過尋陽。", "秋毫不犯三吳悅，春日遙看五色光。", "龍蟠虎踞帝王州，帝子金陵訪古丘。", "春風試暖昭陽殿，明月還過鳷鵲樓。", "二帝巡遊俱未回，五陵松柏使人哀。", "諸侯不救河南地，更喜賢王遠道來。", "丹陽北固是吳關，畫出樓臺雲水間。", "千岩烽火連滄海，兩岸旌旗繞碧山。", "王出三山按五湖，樓船跨海次陪都。", "戰艦森森羅虎士，征帆一一引龍駒。", "長風掛席勢難回，海動山傾古月摧。", "君看帝子浮江日，何似龍驤出峽來。", "祖龍浮海不成橋，漢武尋陽空射蛟。", "我王樓艦輕秦漢，卻似文皇欲渡遼。", "帝寵賢王入楚關，掃清江漢始應還。", "初從雲夢開朱邸，更取金陵作小山。", "試借君王玉馬鞭，指揮戎虜坐瓊筵。", "南風一掃胡塵靜，西入長安到日邊。"]'),
('yuding-3','上皇西巡南京歌十首','李白','唐','御定全唐诗','yuding','','[]','胡塵輕拂建章台，聖主西巡蜀道來。',320,'御定全唐詩/json/167.json','["胡塵輕拂建章台，聖主西巡蜀道來。", "劍壁門高五千尺，石為樓閣九天開。", "九天開出一成都，萬戶千門入畫圖。", "草樹雲山如錦繡，秦川得及此間無。", "華陽春樹號新豐，行入新都若舊宮。", "柳色未饒秦地綠，花光不減上陽紅。", "誰道君王行路難，六龍西幸萬人歡。", "地轉錦江成渭水，天回玉壘作長安。", "萬國同風共一時，錦江何謝曲江池。", "石鏡更明天上月，後宮親得照蛾眉。", "濯錦清江萬里流，雲帆龍舸下揚州。", "北地雖誇上林苑，南京還有散花樓。", "錦水東流繞錦城，星橋北掛象天星。", "四海此中朝聖主，峨眉山下列仙庭。", "秦開蜀道置金牛，漢水元通星漢流。", "天子一行遺聖跡，錦城長作帝王州。", "水綠天青不起塵，風光和暖勝三秦。", "萬國煙花隨玉輦，西來添作錦江春。", "劍閣重關蜀北門，上皇歸馬若雲屯。", "少帝長安開紫極，雙懸日月照乾坤。"]'),
('yuding-4','峨眉山月歌','李白','唐','御定全唐诗','yuding','','[]','峨眉山月半輪秋，影入平羌江水流。',32,'御定全唐詩/json/167.json','["峨眉山月半輪秋，影入平羌江水流。", "夜發清溪向三峽，思君不見下渝州。"]'),
('yuding-5','峨眉山月歌，送蜀僧晏入中京','李白','唐','御定全唐诗','yuding','','[]','我在巴東三峽時，西看明月憶峨眉。月出峨眉照滄海，',72,'御定全唐詩/json/167.json','["我在巴東三峽時，西看明月憶峨眉。月出峨眉照滄海，", "峨眉山月還送君，風吹西到長安陌。長安大道橫九天，", "我似浮雲殢吳越，君逢聖主游丹闕。一振高名滿帝都，"]'),
('yuding-6','赤壁歌送別','李白','唐','御定全唐诗','yuding','','[]','二龍爭戰決雌雄，赤壁樓船掃地空。烈火張天照雲海，',40,'御定全唐詩/json/167.json','["二龍爭戰決雌雄，赤壁樓船掃地空。烈火張天照雲海，", "一一書來報故人，我欲因之壯心魄。"]'),
('yuding-7','江夏行','李白','唐','御定全唐诗','yuding','','[]','憶昔嬌小姿，春心亦自持。為言嫁夫婿，得免長相思。',188,'御定全唐詩/json/167.json','["憶昔嬌小姿，春心亦自持。為言嫁夫婿，得免長相思。", "誰知嫁商賈，令人卻愁苦。自從為夫妻，何曾在鄉土。", "去年下揚州，相送黃鶴樓。眼看帆去遠，心逐江水流。", "只言期一載，誰謂曆三秋。使妾腸欲斷，恨君情悠悠。", "東家西舍同時發，北去南來不逾月。未知行李游何方，", "正見當壚女，紅妝二八年。一種為人妻，獨自多悲淒。", "對鏡便垂淚，逢人只欲啼。不如輕薄兒，旦暮長相隨。", "悔作商人婦，青春長別離。如今正好同歡樂，"]'),
('yuding-8','懷仙歌','李白','唐','御定全唐诗','yuding','','[]','一鶴東飛過滄海，放心散漫知何在。仙人浩歌望我來，',40,'御定全唐詩/json/167.json','["一鶴東飛過滄海，放心散漫知何在。仙人浩歌望我來，", "巨鼇莫戴三山去，我欲蓬萊頂上行。"]'),
('yuding-9','玉真仙人詞','李白','唐','御定全唐诗','yuding','','[]','玉真之仙人，時往太華峰。清晨鳴天鼓，飆欻騰雙龍。',48,'御定全唐詩/json/167.json','["玉真之仙人，時往太華峰。清晨鳴天鼓，飆欻騰雙龍。", "弄電不輟手，行雲本無蹤。幾時入少室，王母應相逢。"]'),
('yuding-10','清溪行','李白','唐','御定全唐诗','yuding','','[]','清溪清我心，水色異諸水。借問新安江，見底何如此。',48,'御定全唐詩/json/167.json','["清溪清我心，水色異諸水。借問新安江，見底何如此。", "人行明鏡中，鳥度屏風裏。向晚猩猩啼，空悲遠遊子。"]'),
('yuding-11','酬殷明佐見贈五雲裘歌','李白','唐','御定全唐诗','yuding','','[]','我吟謝脁詩上語，朔風颯颯吹飛雨。謝脁已沒青山空，',136,'御定全唐詩/json/167.json','["我吟謝脁詩上語，朔風颯颯吹飛雨。謝脁已沒青山空，", "文章彪炳光陸離，應是素娥玉女之所為。", "輕如松花落金粉，濃似苔錦含碧滋。遠山積翠橫海島，", "故人贈我我不違，著令山水含清暉。頓驚謝康樂，", "群仙長歎驚此物，千崖萬嶺相縈鬱。身騎白鹿行飄颻，", "瑤台雪花數千點，片片吹落春風香。為君持此淩蒼蒼，"]'),
('yuding-12','臨路歌','李白','唐','御定全唐诗','yuding','','[]','大鵬飛兮振八裔，中天摧兮力不濟。餘風激兮萬世，',23,'御定全唐詩/json/167.json','["大鵬飛兮振八裔，中天摧兮力不濟。餘風激兮萬世，"]'),
('yuding-13','古意','李白','唐','御定全唐诗','yuding','','[]','君為女蘿草，妾作兔絲花。輕條不自引，為逐春風斜。',108,'御定全唐詩/json/167.json','["君為女蘿草，妾作兔絲花。輕條不自引，為逐春風斜。", "百丈托遠松，纏綿成一家。誰言會面易，各在青山崖。", "女蘿發馨香，兔絲斷人腸。枝枝相糾結，葉葉競飄揚。", "生子不知根，因誰共芬芳。中巢雙翡翠，上宿紫鴛鴦。", "若識二草心，海潮亦可量。"]'),
('yuding-14','山鷓鴣詞','李白','唐','御定全唐诗','yuding','','[]','苦竹嶺頭秋月輝，苦竹南枝鷓鴣飛。嫁得燕山胡雁婿，',48,'御定全唐詩/json/167.json','["苦竹嶺頭秋月輝，苦竹南枝鷓鴣飛。嫁得燕山胡雁婿，", "紫塞嚴霜如劍戟，蒼梧欲巢難背違。我今誓死不能去，"]'),
('yuding-15','曆陽壯士勤將軍名思齊歌','李白','唐','御定全唐诗','yuding','','[]','太古曆陽郡，化為洪川在。江山猶郁盤，龍虎秘光彩。',49,'御定全唐詩/json/167.json','["太古曆陽郡，化為洪川在。江山猶郁盤，龍虎秘光彩。", "蓄泄數千載，風雲何霮zw。特生勤將軍，神力百夫倍。"]'),
('yuding-16','草書歌行','李白','唐','御定全唐诗','yuding','','[]','少年上人號懷素，草書天下稱獨步。墨池飛出北溟魚，',115,'御定全唐詩/json/167.json','["少年上人號懷素，草書天下稱獨步。墨池飛出北溟魚，", "箋麻素絹排數廂，宣州石硯墨色光。吾師醉後倚繩床，", "起來向壁不停手，一行數字大如鬥。怳怳如聞神鬼驚，", "湖南七郡凡幾家，家家屏障書題遍。王逸少，張伯英，", "古來萬事貴天生，何必要公孫大娘渾脫舞。"]'),
('yuding-17','和盧侍禦通塘曲','李白','唐','御定全唐诗','yuding','','[]','君誇通塘好，通塘勝耶溪。通塘在何處，遠在尋陽西。',114,'御定全唐詩/json/167.json','["君誇通塘好，通塘勝耶溪。通塘在何處，遠在尋陽西。", "青蘿嫋嫋掛煙樹，白鷳處處聚沙堤。石門中斷平湖出，", "相逢不相識，出沒繞通塘。浦邊清水明素足，", "秦人雞犬桃花裏，將比通塘渠見羞。通塘不忍別，", "月出青山送行子，四邊苦竹秋聲起。長吟白雪望星河，"]'),
('yuding-0','贈孟浩然','李白','唐','御定全唐诗','yuding','','[]','吾愛孟夫子，風流天下聞。紅顏棄軒冕，白首臥松雲。',48,'御定全唐詩/json/168.json','["吾愛孟夫子，風流天下聞。紅顏棄軒冕，白首臥松雲。", "醉月頻中聖，迷花不事君。高山安可仰，徒此揖清芬。"]'),
('yuding-1','贈從兄襄陽少府皓','李白','唐','御定全唐诗','yuding','','[]','結髮未識事，所交盡豪雄。卻秦不受賞，擊晉寧為功。',108,'御定全唐詩/json/168.json','["結髮未識事，所交盡豪雄。卻秦不受賞，擊晉寧為功。", "小節豈足言，退耕舂陵東。歸來無產業，生事如轉蓬。", "一朝烏裘敝，百鎰黃金空。彈劍徒激昂，出門悲路窮。", "吾兄青雲士，然諾聞諸公。所以陳片言，片言貴情通。", "棣華倘不接，甘與秋草同。"]'),
('yuding-2','淮海對雪贈傅靄','李白','唐','御定全唐诗','yuding','','[]','朔雪落吳天，從風渡溟渤。海樹成陽春，江沙浩明月。',48,'御定全唐詩/json/168.json','["朔雪落吳天，從風渡溟渤。海樹成陽春，江沙浩明月。", "興從剡溪起，思繞梁園發。寄君郢中歌，曲罷心斷絕。"]'),
('yuding-3','贈徐安宜','李白','唐','御定全唐诗','yuding','','[]','白田見楚老，歌詠徐安宜。制錦不擇地，操刀良在茲。',108,'御定全唐詩/json/168.json','["白田見楚老，歌詠徐安宜。制錦不擇地，操刀良在茲。", "清風動百里，惠化聞京師。浮人若雲歸，耕種滿郊岐。", "川光淨麥隴，日色明桑枝。訟息但長嘯，賓來或解頤。", "青橙拂戶牖，白水流園池。遊子滯安邑，懷恩未忍辭。", "翳君樹桃李，歲晚托深期。"]'),
('yuding-4','贈任城盧主簿','李白','唐','御定全唐诗','yuding','','[]','海鳥知天風，竄身魯門東。臨觴不能飲，矯翼思淩空。',48,'御定全唐詩/json/168.json','["海鳥知天風，竄身魯門東。臨觴不能飲，矯翼思淩空。", "鐘鼓不為樂，煙霜誰與同。歸飛未忍去，流淚謝鴛鴻。"]'),
('yuding-5','早秋贈裴十七仲堪','李白','唐','御定全唐诗','yuding','','[]','遠海動風色，吹愁落天涯。南星變大火，熱氣餘丹霞。',144,'御定全唐詩/json/168.json','["遠海動風色，吹愁落天涯。南星變大火，熱氣餘丹霞。", "光景不可回，六龍轉天車。荊人泣美玉，魯叟悲匏瓜。", "功業若夢裏，撫琴發長嗟。裴生信英邁，屈起多才華。", "曆抵海岱豪，結交魯朱家。複攜兩少女，豔色驚荷葩。", "雙歌入青雲，但惜白日斜。窮溟出寶貝，大澤饒龍蛇。", "明主倘見收，煙霞路非賒。時命若不會，歸應煉丹砂。"]'),
('yuding-6','贈范金卿二首','李白','唐','御定全唐诗','yuding','','[]','君子枉清盼，不知東走迷。離家來幾月，絡緯鳴中閨。',180,'御定全唐詩/json/168.json','["君子枉清盼，不知東走迷。離家來幾月，絡緯鳴中閨。", "桃李君不言，攀花願成蹊。那能吐芳信，惠好相招攜。", "我有結綠珍，久藏濁水泥。時人棄此物，乃與燕瑉齊。", "摭拭欲贈之，申眉路無梯。遼東慚白豕，楚客羞山雞。", "徒有獻芹心，終流泣玉啼。只應自索漠，留舌示山妻。", "範宰不買名，弦歌對前楹。為邦默自化，日覺冰壺清。", "百里雞犬靜，千廬機杼鳴。浮人少蕩析，愛客多逢迎。", "遊子睹嘉政，因之聽頌聲。"]'),
('yuding-7','贈瑕丘王少府','李白','唐','御定全唐诗','yuding','','[]','皎皎鸞鳳姿，飄飄神仙氣。梅生亦何事，來作南昌尉。',84,'御定全唐詩/json/168.json','["皎皎鸞鳳姿，飄飄神仙氣。梅生亦何事，來作南昌尉。", "清風佐鳴琴，寂寞道為貴。一見過所聞，操持難與群。", "毫揮魯邑訟，目送瀛洲雲。我隱屠釣下，爾當玉石分。", "無由接高論，空此仰清芬。"]'),
('yuding-8','東魯見狄博通','李白','唐','御定全唐诗','yuding','','[]','去年別我向何處，有人傳道游江東。',32,'御定全唐詩/json/168.json','["去年別我向何處，有人傳道游江東。", "謂言掛席度滄海，卻來應是無長風。"]'),
('yuding-9','見京兆韋參軍量移東陽二首','李白','唐','御定全唐诗','yuding','','[]','潮水還歸海，流人卻到吳。相逢問愁苦，淚盡日南珠。',72,'御定全唐詩/json/168.json','["潮水還歸海，流人卻到吳。相逢問愁苦，淚盡日南珠。", "聞說金華渡，東連五百灘。全勝若耶好，莫道此行難。", "猿嘯千溪合，松風五月寒。他年一攜手，搖艇入新安。"]'),
('yuding-10','贈丹陽橫山周處士惟長','李白','唐','御定全唐诗','yuding','','[]','周子橫山隱，開門臨城隅。連峰入戶牖，勝概淩方壺。',96,'御定全唐詩/json/168.json','["周子橫山隱，開門臨城隅。連峰入戶牖，勝概淩方壺。", "時作白紵詞，放歌丹陽湖。水色傲溟渤，川光秀菰蒲。", "當其得意時，心與天壤俱。閑雲隨舒卷，安識身有無。", "抱石恥獻玉，沉泉笑探珠。羽化如可作，相攜上清都。"]'),
('yuding-11','玉真公主別館苦雨，贈衛尉張卿二首','李白','唐','御定全唐诗','yuding','','[]','秋坐金張館，繁陰晝不開。空煙迷雨色，蕭颯望中來。',252,'御定全唐詩/json/168.json','["秋坐金張館，繁陰晝不開。空煙迷雨色，蕭颯望中來。", "翳翳昏墊苦，沉沉憂恨催。清秋何以慰，白酒盈吾杯。", "吟詠思管樂，此人已成灰。獨酌聊自勉，誰貴經綸才。", "彈劍謝公子，無魚良可哀。", "苦雨思白日，浮雲何由卷。稷契和天人，陰陽乃驕蹇。", "秋霖劇倒井，昏霧橫絕巘。欲往咫尺途，遂成山川限。", "潈潈奔溜聞，浩浩驚波轉。泥沙塞中途，牛馬不可辨。", "饑從漂母食，閑綴羽陵簡。園家逢秋蔬，藜藿不滿眼。", "蠨蛸結思幽，蟋蟀傷褊淺。廚灶無青煙，刀機生綠蘚。", "投箸解鷫鸘，換酒醉北堂。丹徒布衣者，慷慨未可量。", "何時黃金盤，一斛薦檳榔。功成拂衣去，搖曳滄洲傍。"]'),
('yuding-12','贈韋秘書子春二首','李白','唐','御定全唐诗','yuding','','[]','谷口鄭子真，躬耕在岩石。高名動京師，天下皆籍籍。',192,'御定全唐詩/json/168.json','["谷口鄭子真，躬耕在岩石。高名動京師，天下皆籍籍。", "斯人竟不起，雲臥從所適。苟無濟代心，獨善亦何益。", "惟君家世者，偃息逢休明。談天信浩蕩，說劍紛縱橫。", "謝公不徒然，起來為蒼生。秘書何寂寂，無乃羈豪英。", "且複歸碧山，安能戀金闕。舊宅樵漁地，蓬蒿已應沒。", "卻顧女幾峰，胡顏見雲月。", "徒為風塵苦，一官已白須。氣同萬里合，訪我來瓊都。", "披雲睹青天，捫虱話良圖。留侯將綺裏，出處未雲殊。", "終與安社稷，功成去五湖。"]'),
('yuding-13','贈韋侍禦黃裳二首','李白','唐','御定全唐诗','yuding','','[]','太華生長松，亭亭淩霜雪。天與百尺高，豈為微飆折。',120,'御定全唐詩/json/168.json','["太華生長松，亭亭淩霜雪。天與百尺高，豈為微飆折。", "桃李賣陽豔，路人行且迷。春光掃地盡，碧葉成黃泥。", "願君學長松，慎勿作桃李。受屈不改心，然後知君子。", "見君乘驄馬，知上太山道。此地果摧輪，全身以為寶。", "我如豐年玉，棄置秋田草。但勖冰壺心，無為歎衰老。"]'),
('yuding-14','贈薛校書','李白','唐','御定全唐诗','yuding','','[]','我有吳越曲，無人知此音。姑蘇成蔓草，麋鹿空悲吟。',48,'御定全唐詩/json/168.json','["我有吳越曲，無人知此音。姑蘇成蔓草，麋鹿空悲吟。", "未誇觀濤作，空鬱釣鼇心。舉手謝東海，虛行歸故林。"]'),
('yuding-15','贈何七判官昌浩','李白','唐','御定全唐诗','yuding','','[]','有時忽惆悵，匡坐至夜分。平明空嘯吒，思欲解世紛。',96,'御定全唐詩/json/168.json','["有時忽惆悵，匡坐至夜分。平明空嘯吒，思欲解世紛。", "心隨長風去，吹散萬里雲。羞作濟南生，九十誦古文。", "不然拂劍起，沙漠收奇勳。老死阡陌間，何因揚清芬。", "夫子今管樂，英才冠三軍。終與同出處，豈將沮溺群。"]'),
('yuding-16','讀諸葛武侯傳，書懷贈長安崔少府叔封昆季','李白','唐','御定全唐诗','yuding','','[]','漢道昔雲季，群雄方戰爭。霸圖各未立，割據資豪英。',132,'御定全唐詩/json/168.json','["漢道昔雲季，群雄方戰爭。霸圖各未立，割據資豪英。", "赤伏起頹運，臥龍得孔明。當其南陽時，隴畝躬自耕。", "魚水三顧合，風雲四海生。武侯立岷蜀，壯志吞咸京。", "何人先見許，但有崔州平。餘亦草間人，頗懷拯物情。", "晚途值子玉，華髮同衰榮。托意在經濟，結交為弟兄。", "毋令管與鮑，千載獨知名。"]'),
('yuding-17','贈郭將軍','李白','唐','御定全唐诗','yuding','','[]','將軍少年出武威，入掌銀台護紫微。平明拂劍朝天去，',40,'御定全唐詩/json/168.json','["將軍少年出武威，入掌銀台護紫微。平明拂劍朝天去，", "疇昔雄豪如夢裏，相逢且欲醉春暉。"]'),
('yuding-18','駕去溫泉後贈楊山人','李白','唐','御定全唐诗','yuding','','[]','少年落魄楚漢間，風塵蕭瑟多苦顏。自言管葛竟誰許，',48,'御定全唐詩/json/168.json','["少年落魄楚漢間，風塵蕭瑟多苦顏。自言管葛竟誰許，", "當時結交何紛紛，片言道合惟有君。待吾盡節報明主，"]'),
('yuding-19','溫泉侍從歸逢故人','李白','唐','御定全唐诗','yuding','','[]','漢帝長楊苑，誇胡羽獵歸。子雲叨侍從，獻賦有光輝。',48,'御定全唐詩/json/168.json','["漢帝長楊苑，誇胡羽獵歸。子雲叨侍從，獻賦有光輝。", "激賞搖天筆，承恩賜禦衣。逢君奏明主，他日共翻飛。"]'),
('yuding-20','贈裴十四','李白','唐','御定全唐诗','yuding','','[]','朝見裴叔則，朗如行玉山，黃河落天走東海，',36,'御定全唐詩/json/168.json','["朝見裴叔則，朗如行玉山，黃河落天走東海，", "裴回六合無相知，飄若浮雲且西去。"]'),
('yuding-21','贈崔侍郎','李白','唐','御定全唐诗','yuding','','[]','黃河二尺鯉，本在孟津居。點額不成龍，歸來伴凡魚。',48,'御定全唐詩/json/168.json','["黃河二尺鯉，本在孟津居。點額不成龍，歸來伴凡魚。", "故人東海客，一見借吹噓。風濤倘相見，更欲淩昆墟。"]'),
('yuding-22','述德兼陳情上哥舒大夫','李白','唐','御定全唐诗','yuding','','[]','天為國家孕英才，森森矛戟擁靈台。浩蕩深謀噴江海，',40,'御定全唐詩/json/168.json','["天為國家孕英才，森森矛戟擁靈台。浩蕩深謀噴江海，", "衛青謾作大將軍，白起真成一豎子。"]'),
('yuding-23','雪讒詩贈友人','李白','唐','御定全唐诗','yuding','','[]','嗟予沉迷，猖獗已久。五十知非，古人嘗有。立言補過，',189,'御定全唐詩/json/168.json','["嗟予沉迷，猖獗已久。五十知非，古人嘗有。立言補過，", "感悟遂晚，事往日遷。白璧何辜，青蠅屢前。群輕折軸，", "泥沙聚埃，珠玉不鮮。洪焰爍山，發自纖煙。蒼波蕩日，", "哀哉悲夫，誰察予之貞堅。彼婦人之倡狂，", "坦蕩君子，無悅簧言。擢發續罪，罪乃孔多。傾海流惡，", "天未喪文，其如余何。妲己滅紂，褒女惑周。天維蕩覆，", "螮蝀作昏，遂掩太陽。萬乘尚爾，匹夫何傷。辭殫意窮，", "神靡遁響，鬼無逃形。不我遐棄，庶昭忠誠。"]'),
('yuding-24','贈參寥子','李白','唐','御定全唐诗','yuding','','[]','白鶴飛天書，南荊訪高士。五雲在峴山，果得參寥子。',108,'御定全唐詩/json/168.json','["白鶴飛天書，南荊訪高士。五雲在峴山，果得參寥子。", "骯髒辭故園，昂藏入君門。天子分玉帛，百官接話言。", "毫墨時灑落，探玄有奇作。著論窮天人，千春秘麟閣。", "長揖不受官，拂衣歸林巒。余亦去金馬，藤蘿同所歡。", "相思在何處，桂樹青雲端。"]'),
('yuding-25','贈饒陽張司戶燧','李白','唐','御定全唐诗','yuding','','[]','朝飲蒼梧泉，夕棲碧海煙。寧知鸞鳳意，遠托椅桐前。',108,'御定全唐詩/json/168.json','["朝飲蒼梧泉，夕棲碧海煙。寧知鸞鳳意，遠托椅桐前。", "慕藺豈曩古，攀嵇是當年。愧非黃石老，安識子房賢。", "功業嗟落日，容華棄徂川。一語已道意，三山期著鞭。", "蹉跎人間世，寥落壺中天。獨見游物祖，探元窮化先。", "何當共攜手，相與排冥筌。"]'),
('yuding-26','贈清漳明府侄聿','李白','唐','御定全唐诗','yuding','','[]','我李百萬葉，柯條布中州。天開青雲器，日為蒼生憂。',240,'御定全唐詩/json/168.json','["我李百萬葉，柯條布中州。天開青雲器，日為蒼生憂。", "小邑且割雞，大刀佇烹牛。雷聲動四境，惠與清漳流。", "弦歌詠唐堯，脫落隱簪組。心和得天真，風俗猶太古。", "牛羊散阡陌，夜寢不扃戶。問此何以然，賢人宰吾土。", "舉邑樹桃李，垂陰亦流芬。河堤繞綠水，桑柘連青雲。", "趙女不冶容，提籠晝成群。繰絲鳴機杼，百里聲相聞。", "訟息鳥下階，高臥披道帙。蒲鞭掛簷枝，示恥無撲抶。", "琴清月當戶，人寂風入室。長嘯一無言，陶然上皇逸。", "白玉壺冰水，壺中見底清。清光洞毫髮，皎潔照群情。", "趙北美佳政，燕南播高名。過客覽行謠，因之誦德聲。"]'),
('yuding-27','贈臨洺縣令皓弟','李白','唐','御定全唐诗','yuding','','[]','陶令去彭澤，茫然太古心。大音自成曲，但奏無弦琴。',48,'御定全唐詩/json/168.json','["陶令去彭澤，茫然太古心。大音自成曲，但奏無弦琴。", "釣水路非遠，連鼇意何深。終期龍伯國，與爾相招尋。"]'),
('yuding-28','贈郭季鷹','李白','唐','御定全唐诗','yuding','','[]','河東郭有道，於世若浮雲。盛德無我位，清光獨映君。',48,'御定全唐詩/json/168.json','["河東郭有道，於世若浮雲。盛德無我位，清光獨映君。", "恥將雞並食，長與鳳為群。一擊九千仞，相期淩紫氛。"]'),
('yuding-29','鄴中贈王大','李白','唐','御定全唐诗','yuding','','[]','一身竟無托，遠與孤蓬征。千里失所依，複將落葉並。',180,'御定全唐詩/json/168.json','["一身竟無托，遠與孤蓬征。千里失所依，複將落葉並。", "中途偶良朋，問我將何行。欲獻濟時策，此心誰見明。", "君王制六合，海塞無交兵。壯士伏草間，沉憂亂縱橫。", "飄飄不得意，昨發南都城。紫燕櫪下嘶，青萍匣中鳴。", "投軀寄天下，長嘯尋豪英。恥學琅琊人，龍蟠事躬耕。", "富貴吾自取，建功及春榮。我願執爾手，爾方達我情。", "相知同一己，豈惟弟與兄。抱子弄白雲，琴歌發清聲。", "臨別意難盡，各希存令名。"]'),
('yuding-30','贈華州王司士','李白','唐','御定全唐诗','yuding','','[]','淮水不絕濤瀾高，盛德未泯生英髦。',32,'御定全唐詩/json/168.json','["淮水不絕濤瀾高，盛德未泯生英髦。", "知君先負廟堂器，今日還須贈寶刀。"]'),
('yuding-31','贈盧征君昆弟','李白','唐','御定全唐诗','yuding','','[]','明主訪賢逸，雲泉今已空。二盧竟不起，萬乘高其風。',72,'御定全唐詩/json/168.json','["明主訪賢逸，雲泉今已空。二盧竟不起，萬乘高其風。", "河上喜相得，壺中趣每同。滄州即此地，觀化遊無窮。", "水落海上清，鼇背睹方蓬。與君弄倒景，攜手淩星虹。"]'),
('yuding-32','贈新平少年','李白','唐','御定全唐诗','yuding','','[]','韓信在淮陰，少年相欺淩。屈體若無骨，壯心有所憑。',108,'御定全唐詩/json/168.json','["韓信在淮陰，少年相欺淩。屈體若無骨，壯心有所憑。", "一遭龍顏君，嘯吒從此興。千金答漂母，萬古共嗟稱。", "而我竟何為，寒苦坐相仍。長風入短袂，兩手如懷冰。", "故友不相恤，新交寧見矜。摧殘檻中虎，羈絏鞲上鷹。", "何時騰風雲，搏擊申所能。"]'),
('yuding-33','贈崔侍郎','李白','唐','御定全唐诗','yuding','','[]','長劍一杯酒，男兒方寸心。洛陽因劇孟，托宿話胸襟。',120,'御定全唐詩/json/168.json','["長劍一杯酒，男兒方寸心。洛陽因劇孟，托宿話胸襟。", "但仰山嶽秀，不知江海深。長安複攜手，再顧重千金。", "君乃輶軒佐，予叨翰墨林。高風摧秀木，虛彈落驚禽。", "不取回舟興，而來命駕尋。扶搖應借力，桃李願成陰。", "笑吐張儀舌，愁為莊舄吟。誰憐明月夜，腸斷聽秋砧。"]'),
('yuding-34','走筆贈獨孤駙馬','李白','唐','御定全唐诗','yuding','','[]','都尉朝天躍馬歸，香風吹人花亂飛。銀鞍紫鞚照雲日，',48,'御定全唐詩/json/168.json','["都尉朝天躍馬歸，香風吹人花亂飛。銀鞍紫鞚照雲日，", "長揖蒙垂國士恩，壯心剖出酬知己。一別蹉跎朝市間，"]'),
('yuding-35','贈嵩山焦煉師','李白','唐','御定全唐诗','yuding','','[]','二室淩青天，三花含紫煙。中有蓬海客，宛疑麻姑仙。',144,'御定全唐詩/json/168.json','["二室淩青天，三花含紫煙。中有蓬海客，宛疑麻姑仙。", "道在喧莫染，跡高想已綿。時餐金鵝蕊，屢讀青苔篇。", "八極恣遊憩，九垓長周旋。下瓢酌潁水，舞鶴來伊川。", "還歸空山上，獨拂秋霞眠。蘿月掛朝鏡，松風鳴夜弦。", "潛光隱嵩嶽，煉魄棲雲幄。霓裳何飄颻，鳳吹轉綿邈。", "願同西王母，下顧東方朔。紫書倘可傳，銘骨誓相學。"]'),
('yuding-36','口號贈征君鴻','李白','唐','御定全唐诗','yuding','','[]','陶令辭彭澤，梁鴻入會稽。我尋高士傳，君與古人齊。',48,'御定全唐詩/json/168.json','["陶令辭彭澤，梁鴻入會稽。我尋高士傳，君與古人齊。", "雲臥留丹壑，天書降紫泥。不知楊伯起，早晚向關西。"]'),
('yuding-37','上李邕','李白','唐','御定全唐诗','yuding','','[]','大鵬一日同風起，摶搖直上九萬里。假令風歇時下來，',40,'御定全唐詩/json/168.json','["大鵬一日同風起，摶搖直上九萬里。假令風歇時下來，", "宣父猶能畏後生，丈夫未可輕年少。"]'),
('yuding-38','贈張公洲革處士','李白','唐','御定全唐诗','yuding','','[]','列子居鄭圃，不將眾庶分。革侯遁南浦，常恐楚人聞。',96,'御定全唐詩/json/168.json','["列子居鄭圃，不將眾庶分。革侯遁南浦，常恐楚人聞。", "抱甕灌秋蔬，心閒遊天雲。每將瓜田叟，耕種漢水濆。", "時登張公洲，入獸不亂群。井無桔槔事，門絕刺繡文。", "長揖二千石，遠辭百里君。斯為真隱者，吾黨慕清芬。"]'),
('yuding-0','秋日煉藥院鑷白髮，贈元六兄林宗','李白','唐','御定全唐诗','yuding','','[]','木落識歲秋，瓶冰知天寒。桂枝日已綠，拂雪淩雲端。',120,'御定全唐詩/json/169.json','["木落識歲秋，瓶冰知天寒。桂枝日已綠，拂雪淩雲端。", "弱齡接光景，矯翼攀鴻鸞。投分三十載，榮枯同所歡。", "長籲望青雲，鑷白坐相看。秋顏入曉鏡，壯發凋危冠。", "窮與鮑生賈，饑從漂母餐。時來極天人，道在豈吟歎。", "樂毅方適趙，蘇秦初說韓。卷舒固在我，何事空摧殘。"]'),
('yuding-1','書情題蔡舍人雄','李白','唐','御定全唐诗','yuding','','[]','嘗高謝太傅，攜妓東山門。楚舞醉碧雲，吳歌斷清猿。',288,'御定全唐詩/json/169.json','["嘗高謝太傅，攜妓東山門。楚舞醉碧雲，吳歌斷清猿。", "暫因蒼生起，談笑安黎元。餘亦愛此人，丹霄冀飛翻。", "遭逢聖明主，敢進興亡言。白璧竟何辜，青蠅遂成冤。", "一朝去京國，十載客梁園。猛犬吠九關，殺人憤精魂。", "皇穹雪冤枉，白日開氛昏。泰階得夔龍，桃李滿中原。", "倒海索明月，淩山采芳蓀。愧無橫草功，虛負雨露恩。", "跡謝雲台閣，心隨天馬轅。夫子王佐才，而今複誰論。", "層飆振六翮，不日思騰騫。我縱五湖棹，煙濤恣崩奔。", "夢釣子陵湍，英風緬猶存。彼希客星隱，弱植不足援。", "千里一回首，萬里一長歌。黃鶴不復來，清風愁奈何。", "舟浮瀟湘月，山倒洞庭波。投汨笑古人，臨濠得天和。", "閒時田畝中，搔背牧雞鵝。別離解相訪，應在武陵多。"]'),
('yuding-2','憶襄陽舊游，贈馬少府巨','李白','唐','御定全唐诗','yuding','','[]','昔為大堤客，曾上山公樓。開窗碧嶂滿，拂鏡滄江流。',96,'御定全唐詩/json/169.json','["昔為大堤客，曾上山公樓。開窗碧嶂滿，拂鏡滄江流。", "高冠佩雄劍，長揖韓荊州。此地別夫子，今來思舊遊。", "朱顏君未老，白髮我先秋。壯志恐蹉跎，功名若雲浮。", "歸心結遠夢，落日懸春愁。空思羊叔子，墮淚峴山頭。"]'),
('yuding-3','對雪獻從兄虞城宰','李白','唐','御定全唐诗','yuding','','[]','昨夜梁園裏，弟寒兄不知。庭前看玉樹，腸斷憶連枝。',24,'御定全唐詩/json/169.json','["昨夜梁園裏，弟寒兄不知。庭前看玉樹，腸斷憶連枝。"]'),
('yuding-4','訪道安陵遇蓋還為餘造真籙，臨別留贈','李白','唐','御定全唐诗','yuding','','[]','清水見白石，仙人識青童。安陵蓋夫子，十歲與天通。',192,'御定全唐詩/json/169.json','["清水見白石，仙人識青童。安陵蓋夫子，十歲與天通。", "懸河與微言，談論安可窮。能令二千石，撫背驚神聰。", "揮毫贈新詩，高價掩山東。至今平原客，感激慕清風。", "學道北海仙，傳書蕊珠宮。丹田了玉闕，白日思雲空。", "為我草真籙，天人慚妙工。七元洞豁落，八角輝星虹。", "三災蕩璿璣，蛟龍翼微躬。舉手謝天地，虛無齊始終。", "黃金滿高堂，答荷難克充。下笑世上士，沉魂北羅酆。", "昔日萬乘墳，今成一科蓬。贈言若可重，實此輕華嵩。"]'),
('yuding-5','贈崔郎中宗之','李白','唐','御定全唐诗','yuding','','[]','胡雁拂海翼，翱翔鳴素秋。驚雲辭沙朔，飄蕩迷河洲。',132,'御定全唐詩/json/169.json','["胡雁拂海翼，翱翔鳴素秋。驚雲辭沙朔，飄蕩迷河洲。", "有如飛蓬人，去逐萬里遊。登高望浮雲，仿佛如舊丘。", "日從海傍沒，水向天邊流。長嘯倚孤劍，目極心悠悠。", "歲晏歸去來，富貴安可求。仲尼七十說，曆聘莫見收。", "魯連逃千金，珪組豈可酬。時哉苟不會，草木為我儔。", "希君同攜手，長往南山幽。"]'),
('yuding-6','贈崔諮議','李白','唐','御定全唐诗','yuding','','[]','綠驥本天馬，素非伏櫪駒。長嘶向清風，倏忽淩九區。',60,'御定全唐詩/json/169.json','["綠驥本天馬，素非伏櫪駒。長嘶向清風，倏忽淩九區。", "何言西北至，卻走東南隅。世道有翻覆，前期難豫圖。", "希君一翦拂，猶可騁中衢。"]'),
('yuding-7','贈升州王使君忠臣','李白','唐','御定全唐诗','yuding','','[]','六代帝王國，三吳佳麗城。賢人當重寄，天子借高名。',48,'御定全唐詩/json/169.json','["六代帝王國，三吳佳麗城。賢人當重寄，天子借高名。", "巨海一邊靜，長江萬里清。應須救趙策，未肯棄侯嬴。"]'),
('yuding-8','贈別從甥高五','李白','唐','御定全唐诗','yuding','','[]','魚目高泰山，不如一璵璠。賢甥即明月，聲價動天門。',240,'御定全唐詩/json/169.json','["魚目高泰山，不如一璵璠。賢甥即明月，聲價動天門。", "能成吾宅相，不減魏陽元。自顧寡籌略，功名安所存。", "五木思一擲，如繩系窮猿。櫪中駿馬空，堂上醉人喧。", "黃金久已罄，為報故交恩。聞君隴西行，使我驚心魂。", "與爾共飄颻，雲天各飛翻。江水流或卷，此心難具論。", "貧家羞好客，語拙覺辭繁。三朝空錯莫，對飯卻慚冤。", "自笑我非夫，生事多契闊。蓄積萬古憤，向誰得開豁。", "天地一浮雲，此身乃毫末。忽見無端倪，太虛可包括。", "去去何足道，臨歧空複愁。肝膽不楚越，山河亦衾裯。", "雲龍若相從，明主會見收。成功解相訪，溪水桃花流。"]'),
('yuding-9','贈裴司馬','李白','唐','御定全唐诗','yuding','','[]','翡翠黃金縷，繡成歌舞衣。若無雲間月，誰可比光輝。',108,'御定全唐詩/json/169.json','["翡翠黃金縷，繡成歌舞衣。若無雲間月，誰可比光輝。", "秀色一如此，多為眾女譏。君恩移昔愛，失寵秋風歸。", "愁苦不窺鄰，泣上流黃機。天寒素手冷，夜長燭複微。", "十日不滿匹，鬢蓬亂若絲。猶是可憐人，容華世中稀。", "向君發皓齒，顧我莫相違。"]'),
('yuding-10','敘舊贈江陽宰陸調','李白','唐','御定全唐诗','yuding','','[]','泰伯讓天下，仲雍揚波濤。清風蕩萬古，跡與星辰高。',252,'御定全唐詩/json/169.json','["泰伯讓天下，仲雍揚波濤。清風蕩萬古，跡與星辰高。", "開吳食東溟，陸氏世英髦。多君秉古節，嶽立冠人曹。", "風流少年時，京洛事遊遨。腰間延陵劍，玉帶明珠袍。", "我昔鬥雞徒，連延五陵豪。邀遮相組織，呵嚇來煎熬。", "君開萬叢人，鞍馬皆辟易。告急清憲台，脫餘北門厄。", "間宰江陽邑，翦棘樹蘭芳。城門何肅穆，五月飛秋霜。", "好鳥集珍木，高才列華堂。時從府中歸，絲管儼成行。", "但苦隔遠道，無由共銜觴。江北荷花開，江南楊梅熟。", "正好飲酒時，懷賢在心目。掛席拾海月，乘風下長川。", "多沽新豐醁，滿載剡溪船。中途不遇人，直到爾門前。", "大笑同一醉，取樂平生年。"]'),
('yuding-11','贈從孫義興宰銘','李白','唐','御定全唐诗','yuding','','[]','天子思茂宰，天枝得英才。朗然清秋月，獨出映吳台。',276,'御定全唐詩/json/169.json','["天子思茂宰，天枝得英才。朗然清秋月，獨出映吳台。", "落筆生綺繡，操刀振風雷。蠖屈雖百里，鵬鶱望三台。", "退食無外事，琴堂向山開。綠水寂以閑，白雲有時來。", "河陽富奇藻，彭澤縱名杯。所恨不見之，猶如仰昭回。", "元惡昔滔天，疲人散幽草。驚川無活鱗，舉邑罕遺老。", "誓雪會稽恥，將奔宛陵道。亞相素所重，投刃應桑林。", "獨坐傷激揚，神融一開襟。弦歌欣再理，和樂醉人心。", "蠹政除害馬，傾巢有歸禽。壺漿候君來，聚舞共謳吟。", "農人棄蓑笠，蠶女墮纓簪。歡笑相拜賀，則知惠愛深。", "曆職吾所聞，稱賢爾為最。化洽一邦上，名馳三江外。", "峻節貫雲霄，通方堪遠大。能文變風俗，好客留軒蓋。", "他日一來遊，因之嚴光瀨。"]'),
('yuding-12','草創大還，贈柳官迪','李白','唐','御定全唐诗','yuding','','[]','天地為橐鑰，周流行太易。造化合元符，交媾騰精魄。',240,'御定全唐詩/json/169.json','["天地為橐鑰，周流行太易。造化合元符，交媾騰精魄。", "自然成妙用，孰知其指的。羅絡四季間，綿微無一隙。", "日月更出沒，雙光豈雲只。姹女乘河車，黃金充轅軛。", "執樞相管轄，摧伏傷羽翮。朱鳥張炎威，白虎守本宅。", "相煎成苦老，消鑠凝津液。仿佛明窗塵，死灰同至寂。", "搗冶入赤色，十二周律曆。赫然稱大還，與道本無隔。", "白日可撫弄，清都在咫尺。北酆落死名，南斗上生籍。", "抑予是何者，身在方士格。才術信縱橫，世途自輕擲。", "吾求仙棄俗，君曉損勝益。不向金闕遊，思為玉皇客。", "鸞車速風電，龍騎無鞭策。一舉上九天，相攜同所適。"]'),
('yuding-13','贈崔司戶文昆季','李白','唐','御定全唐诗','yuding','','[]','雙珠出海底，俱是連城珍。明月兩特達，餘輝傍照人。',180,'御定全唐詩/json/169.json','["雙珠出海底，俱是連城珍。明月兩特達，餘輝傍照人。", "英聲振名都，高價動殊鄰。豈伊箕山故，特以風期親。", "惟昔不自媒，擔簦西入秦。攀龍九天上，忝列歲星臣。", "布衣侍丹墀，密勿草絲綸。才微惠渥重，讒巧生緇磷。", "一去已十載，今來複盈旬。清霜入曉鬢，白露生衣巾。", "側見綠水亭，開門列華茵。千金散義士，四坐無凡賓。", "欲折月中桂，持為寒者薪。路傍已竊笑，天路將何因。", "垂恩倘丘山，報德有微身。"]'),
('yuding-14','贈溧陽宋少府陟','李白','唐','御定全唐诗','yuding','','[]','李斯未相秦，且逐東門兔。宋玉事襄王，能為高唐賦。',120,'御定全唐詩/json/169.json','["李斯未相秦，且逐東門兔。宋玉事襄王，能為高唐賦。", "常聞綠水曲，忽此相逢遇。掃灑青天開，豁然披雲霧。", "葳蕤紫鸞鳥，巢在昆山樹。驚風西北吹，飛落南溟去。", "早懷經濟策，特受龍顏顧。白玉棲青蠅，君臣忽行路。", "人生感分義，貴欲呈丹素。何日清中原，相期廓天步。"]'),
('yuding-15','戲贈鄭溧陽','李白','唐','御定全唐诗','yuding','','[]','陶令日日醉，不知五柳春。素琴本無弦，漉酒用葛巾。',48,'御定全唐詩/json/169.json','["陶令日日醉，不知五柳春。素琴本無弦，漉酒用葛巾。", "清風北窗下，自謂羲皇人。何時到栗裏，一見平生親。"]'),
('yuding-16','贈僧崖公','李白','唐','御定全唐诗','yuding','','[]','昔在朗陵東，學禪白眉空。大地了鏡徹，迴旋寄輪風。',216,'御定全唐詩/json/169.json','["昔在朗陵東，學禪白眉空。大地了鏡徹，迴旋寄輪風。", "攬彼造化力，持為我神通。晚謁泰山君，親見日沒雲。", "中夜臥山月，拂衣逃人群。授余金仙道，曠劫未始聞。", "冥機發天光，獨朗謝垢氛。虛舟不系物，觀化游江濆。", "江濆遇同聲，道崖乃僧英。說法動海岳，游方化公卿。", "手秉玉麈尾，如登白樓亭。微言注百川，亹亹信可聽。", "一風鼓群有，萬籟各自鳴。啟閉八窗牖，托宿掣電霆。", "自言曆天臺，搏壁躡翠屏。淩兢石橋去，恍惚入青冥。", "昔往今來歸，絕景無不經。何日更攜手，乘杯向蓬瀛。"]'),
('yuding-17','游溧陽北湖亭望瓦屋山懷古贈同旅','李白','唐','御定全唐诗','yuding','','[]','朝登北湖亭，遙望瓦屋山。天清白露下，始覺秋風還。',168,'御定全唐詩/json/169.json','["朝登北湖亭，遙望瓦屋山。天清白露下，始覺秋風還。", "遊子托主人，仰觀眉睫間。目色送飛鴻，邈然不可攀。", "長籲相勸勉，何事來吳關。聞有貞義女，振窮溧水灣。", "清光了在眼，白日如披顏。高墳五六墩，崒兀棲猛虎。", "遺跡翳九泉，芳名動千古。子胥昔乞食，此女傾壺漿。", "運開展宿憤，入楚鞭平王。凜冽天地間，聞名若懷霜。", "壯夫或未達，十步九太行。與君拂衣去，萬里同翱翔。"]'),
('yuding-18','醉後贈從甥高鎮','李白','唐','御定全唐诗','yuding','','[]','馬上相逢揖馬鞭，客中相見客中憐。欲邀擊築悲歌飲，',73,'御定全唐詩/json/169.json','["馬上相逢揖馬鞭，客中相見客中憐。欲邀擊築悲歌飲，", "黃金逐手快意盡，昨日破產今朝貧。丈夫何事空嘯傲，", "時清不及英豪人，三尺童兒重廉藺。匣中盤劍裝eC魚，"]'),
('yuding-19','贈秋浦柳少府','李白','唐','御定全唐诗','yuding','','[]','秋浦舊蕭索，公庭人吏稀。因君樹桃李，此地忽芳菲。',60,'御定全唐詩/json/169.json','["秋浦舊蕭索，公庭人吏稀。因君樹桃李，此地忽芳菲。", "搖筆望白雲，開簾當翠微。時來引山月，縱酒酣清暉。", "而我愛夫子，淹留未忍歸。"]'),
('yuding-20','贈崔秋浦三首','李白','唐','御定全唐诗','yuding','','[]','吾愛崔秋浦，宛然陶令風。門前五楊柳，井上二梧桐。',144,'御定全唐詩/json/169.json','["吾愛崔秋浦，宛然陶令風。門前五楊柳，井上二梧桐。", "山鳥下廳事，簷花落酒中。懷君未忍去，惆悵意無窮。", "崔令學陶令，北窗常晝眠。抱琴時弄月，取意任無弦。", "見客但傾酒，為官不愛錢。東皋春事起，種黍早歸田。", "河陽花作縣，秋浦玉為人。地逐名賢好，風隨惠化春。", "水從天漢落，山逼畫屏新。應念金門客，投沙吊楚臣。"]'),
('yuding-21','望九華贈青陽韋仲堪','李白','唐','御定全唐诗','yuding','','[]','昔在九江上，遙望九華峰。天河掛綠水，秀出九芙蓉。',48,'御定全唐詩/json/169.json','["昔在九江上，遙望九華峰。天河掛綠水，秀出九芙蓉。", "我欲一揮手，誰人可相從。君為東道主，于此臥雲松。"]'),
('yuding-0','贈王判官，時余歸隱，居廬山屏風疊','李白','唐','御定全唐诗','yuding','','[]','昔別黃鶴樓，蹉跎淮海秋。俱飄零落葉，各散洞庭流。',156,'御定全唐詩/json/170.json','["昔別黃鶴樓，蹉跎淮海秋。俱飄零落葉，各散洞庭流。", "中年不相見，蹭蹬游吳越。何處我思君，天臺綠蘿月。", "會稽風月好，卻繞剡溪回。雲山海上出，人物鏡中來。", "一度浙江北，十年醉楚台。荊門倒屈宋，梁苑傾鄒枚。", "苦笑我誇誕，知音安在哉。大盜割鴻溝，如風掃秋葉。", "吾非濟代人，且隱屏風疊。中夜天中望，憶君思見君。", "明朝拂衣去，永與海鷗群。"]'),
('yuding-1','在水軍宴贈幕府諸侍禦','李白','唐','御定全唐诗','yuding','','[]','月化五白龍，翻飛淩九天。胡沙驚北海，電掃洛陽川。',180,'御定全唐詩/json/170.json','["月化五白龍，翻飛淩九天。胡沙驚北海，電掃洛陽川。", "虜箭雨宮闕，皇輿成播遷。英王受廟略，秉鉞清南邊。", "雲旗卷海雪，金戟羅江煙。聚散百萬人，弛張在一賢。", "霜台降群彥，水國奉戎旃。繡服開宴語，天人借樓船。", "如登黃金台，遙謁紫霞仙。卷身編蓬下，冥機四十年。", "寧知草間人，腰下有龍泉。浮雲在一決，誓欲清幽燕。", "願與四座公，靜談金匱篇。齊心戴朝恩，不惜微軀捐。", "所冀旄頭滅，功成追魯連。"]'),
('yuding-2','贈武十七諤','李白','唐','御定全唐诗','yuding','','[]','馬如一匹練，明日過吳門。乃是要離客，西來欲報恩。',96,'御定全唐詩/json/170.json','["馬如一匹練，明日過吳門。乃是要離客，西來欲報恩。", "笑開燕匕首，拂拭竟無言。狄犬吠清洛，天津成塞垣。", "愛子隔東魯，空悲斷腸猿。林回棄白璧，千里阻同奔。", "君為我致之，輕齎涉淮原。精誠合天道，不愧遠遊魂。"]'),
('yuding-3','贈閭丘宿松','李白','唐','御定全唐诗','yuding','','[]','阮籍為太守，乘驢上東平。剖竹十日間，一朝風化清。',96,'御定全唐詩/json/170.json','["阮籍為太守，乘驢上東平。剖竹十日間，一朝風化清。", "偶來拂衣去，誰測主人情。夫子理宿松，浮雲知古城。", "掃地物莽然，秋來百草生。飛鳥還舊巢，遷人返躬耕。", "何慚宓子賤，不減陶淵明。吾知千載後，卻掩二賢名。"]'),
('yuding-4','獄中上崔相渙','李白','唐','御定全唐诗','yuding','','[]','胡馬渡洛水，血流征戰場。千門閉秋景，萬姓危朝霜。',72,'御定全唐詩/json/170.json','["胡馬渡洛水，血流征戰場。千門閉秋景，萬姓危朝霜。", "賢相燮元氣，再欣海縣康。台庭有夔龍，列宿粲成行。", "羽翼三元聖，發輝兩太陽。應念覆盆下，雪泣拜天光。"]'),
('yuding-5','中丞宋公以吳兵三千赴河南軍次尋陽脫余之囚參謀幕府因贈之','李白','唐','御定全唐诗','yuding','','[]','獨坐清天下，專征出海隅。九江皆渡虎，三郡盡還珠。',96,'御定全唐詩/json/170.json','["獨坐清天下，專征出海隅。九江皆渡虎，三郡盡還珠。", "組練明秋浦，樓船入郢都。風高初選將，月滿欲平胡。", "殺氣橫千里，軍聲動九區。白猿慚劍術，黃石借兵符。", "戎虜行當翦，鯨鯢立可誅。自憐非劇孟，何以佐良圖。"]'),
('yuding-6','流夜郎贈辛判官','李白','唐','御定全唐诗','yuding','','[]','昔在長安醉花柳，五侯七貴同杯酒。氣岸遙淩豪士前，',64,'御定全唐詩/json/170.json','["昔在長安醉花柳，五侯七貴同杯酒。氣岸遙淩豪士前，", "文章獻納麒麟殿，歌舞淹留玳瑁筵。與君自謂長如此，", "我愁遠謫夜郎去，何日金雞放赦回。"]'),
('yuding-7','贈劉都使','李白','唐','御定全唐诗','yuding','','[]','東平劉公幹，南國秀餘芳。一鳴即朱紱，五十佩銀章。',120,'御定全唐詩/json/170.json','["東平劉公幹，南國秀餘芳。一鳴即朱紱，五十佩銀章。", "飲冰事戎幕，衣錦華水鄉。銅官幾萬人，諍訟清玉堂。", "吐言貴珠玉，落筆回風霜。而我謝明主，銜哀投夜郎。", "歸家酒債多，門客粲成行。高談滿四座，一日傾千觴。", "所求竟無緒，裘馬欲摧藏。主人若不顧，明發釣滄浪。"]'),
('yuding-8','贈常侍禦','李白','唐','御定全唐诗','yuding','','[]','安石在東山，無心濟天下。一起振橫流，功成複瀟灑。',84,'御定全唐詩/json/170.json','["安石在東山，無心濟天下。一起振橫流，功成複瀟灑。", "大賢有卷舒，季葉輕風雅。匡複屬何人，君為知音者。", "傳聞武安將，氣振長平瓦。燕趙期洗清，周秦保宗社。", "登朝若有言，為訪南遷賈。"]'),
('yuding-9','贈易秀才','李白','唐','御定全唐诗','yuding','','[]','少年解長劍，投贈即分離。何不斷犀象，精光暗往時。',72,'御定全唐詩/json/170.json','["少年解長劍，投贈即分離。何不斷犀象，精光暗往時。", "蹉跎君自惜，竄逐我因誰。地遠虞翻老，秋深宋玉悲。", "空摧芳桂色，不屈古松姿。感激平生意，勞歌寄此辭。"]'),
('yuding-10','經亂離後天恩流夜郎憶舊遊書懷贈江夏韋太守良宰','李白','唐','御定全唐诗','yuding','','[]','天上白玉京，十二樓五城。仙人撫我頂，結髮受長生。',576,'御定全唐詩/json/170.json','["天上白玉京，十二樓五城。仙人撫我頂，結髮受長生。", "誤逐世間樂，頗窮理亂情。九十六聖君，浮雲掛空名。", "天地賭一擲，未能忘戰爭。試涉霸王略，將期軒冕榮。", "時命乃大謬，棄之海上行。學劍翻自哂，為文竟何成。", "劍非萬人敵，文竊四海聲。兒戲不足道，五噫出西京。", "臨當欲去時，慷慨淚沾纓。歎君倜儻才，標舉冠群英。", "開筵引祖帳，慰此遠徂征。鞍馬若浮雲，送餘驃騎亭。", "歌鐘不盡意，白日落昆明。十月到幽州，戈鋋若羅星。", "君王棄北海，掃地借長鯨。呼吸走百川，燕然可摧傾。", "心知不得語，卻欲棲蓬瀛。彎弧懼天狼，挾矢不敢張。", "攬涕黃金台，呼天哭昭王。無人貴駿骨，騄耳空騰驤。", "樂毅倘再生，於今亦奔亡。蹉跎不得意，驅馬還貴鄉。", "逢君聽弦歌，肅穆坐華堂。百里獨太古，陶然臥羲皇。", "征樂昌樂館，開筵列壺觴。賢豪間青娥，對燭儼成行。", "醉舞紛綺席，清歌繞飛梁。歡娛未終朝，秩滿歸咸陽。", "祖道擁萬人，供帳遙相望。一別隔千里，榮枯異炎涼。", "炎涼幾度改，九土中橫潰。漢甲連胡兵，沙塵暗雲海。", "草木搖殺氣，星辰無光彩。白骨成丘山，蒼生竟何罪。", "函關壯帝居，國命懸哥舒。長戟三十萬，開門納凶渠。", "公卿如犬羊，忠讜醢與菹。二聖出遊豫，兩京遂丘墟。", "帝子許專征，秉旄控強楚。節制非桓文，軍師擁熊虎。", "人心失去就，賊勢騰風雨。惟君固房陵，誠節冠終古。", "僕臥香爐頂，餐霞漱瑤泉。門開九江轉，枕下五湖連。", "半夜水軍來，潯陽滿旌旃。空名適自誤，迫脅上樓船。"]'),
('yuding-11','江夏使君叔席上贈史郎中','李白','唐','御定全唐诗','yuding','','[]','鳳凰丹禁裏，銜出紫泥書。昔放三湘去，今還萬死餘。',84,'御定全唐詩/json/170.json','["鳳凰丹禁裏，銜出紫泥書。昔放三湘去，今還萬死餘。", "仙郎久為別，客舍問何如。涸轍思流水，浮雲失舊居。", "多慚華省貴，不以逐臣疏。複如竹林下，叨陪芳宴初。", "希君生羽翼，一化北溟魚。"]'),
('yuding-12','博平鄭太守自廬山千里相尋入江夏北市門見訪却之武陵立馬贈別','李白','唐','御定全唐诗','yuding','','[]','大樑貴公子，氣蓋蒼梧雲。若無三千客，誰道信陵君。',144,'御定全唐詩/json/170.json','["大樑貴公子，氣蓋蒼梧雲。若無三千客，誰道信陵君。", "救趙複存魏，英威天下聞。邯鄲能屈節，訪博從毛薛。", "夷門得隱淪，而與侯生親。仍要鼓刀者，乃是袖槌人。", "好士不盡心，何能保其身。多君重然諾，意氣遙相托。", "五馬入市門，金鞍照城郭。都忘虎竹貴，且與荷衣樂。", "去去桃花源，何時見歸軒。相思無終極，腸斷朗江猿。"]'),
('yuding-13','江上贈竇長史','李白','唐','御定全唐诗','yuding','','[]','漢求季布魯朱家，楚逐伍胥去章華。萬里南遷夜郎國，',48,'御定全唐詩/json/170.json','["漢求季布魯朱家，楚逐伍胥去章華。萬里南遷夜郎國，", "人疑天上坐樓船，水淨霞明兩重綺。相約相期何太深，"]'),
('yuding-14','贈王漢陽','李白','唐','御定全唐诗','yuding','','[]','天落白玉棺，王喬辭葉縣。一去未千年，漢陽複相見。',96,'御定全唐詩/json/170.json','["天落白玉棺，王喬辭葉縣。一去未千年，漢陽複相見。", "猶乘飛鳧舄，尚識仙人面。鬢髮何青青，童顏皎如練。", "吾曾弄海水，清淺嗟三變。果愜麻姑言，時光速流電。", "與君數杯酒，可以窮歡宴。白雲歸去來，何事坐交戰。"]'),
('yuding-15','贈漢陽輔錄事二首','李白','唐','御定全唐诗','yuding','','[]','聞君罷官意，我抱漢川湄。借問久疏索，何如聽訟時。',88,'御定全唐詩/json/170.json','["聞君罷官意，我抱漢川湄。借問久疏索，何如聽訟時。", "天清江月白，心靜海鷗知。應念投沙客，空餘吊屈悲。", "鸚鵡洲橫漢陽渡，水引寒煙沒江樹。南浦登樓不見君，", "其中字數無多少，只是相思秋複春。"]'),
('yuding-16','江夏贈韋南陵冰','李白','唐','御定全唐诗','yuding','','[]','胡驕馬驚沙塵起，胡雛飲馬天津水。君為張掖近酒泉，',118,'御定全唐詩/json/170.json','["胡驕馬驚沙塵起，胡雛飲馬天津水。君為張掖近酒泉，", "西憶故人不可見，東風吹夢到長安。寧期此地忽相遇，", "昨日繡衣傾綠尊，病如桃李竟何言。昔騎天子大宛馬，", "有似山開萬里雲，四望青天解人悶。人悶還心悶，", "山公醉後能騎馬，別是風流賢主人。頭陀雲月多僧氣，"]'),
('yuding-17','贈盧司戶','李白','唐','御定全唐诗','yuding','','[]','秋色無遠近，出門盡寒山。白雲遙相識，待我蒼梧間。',36,'御定全唐詩/json/170.json','["秋色無遠近，出門盡寒山。白雲遙相識，待我蒼梧間。", "借問盧耽鶴，西飛幾歲還。"]'),
('yuding-18','贈從弟南平太守之遙二首','李白','唐','御定全唐诗','yuding','','[]','少年不得意，落魄無安居。願隨任公子，欲釣吞舟魚。',192,'御定全唐詩/json/170.json','["少年不得意，落魄無安居。願隨任公子，欲釣吞舟魚。", "常時飲酒逐風景，壯心遂與功名疏。蘭生穀底人不鋤，", "天門九重謁聖人，龍顏一解四海春。彤庭左右呼萬歲，", "承恩初入銀台門，著書獨在金鑾殿。龍鉤雕鐙白玉鞍，", "一朝謝病游江海，疇昔相知幾人在。前門長揖後門關，", "夢得池塘生春草，使我長價登樓詩。別後遙傳臨海作，", "東平與南平，今古兩步兵。素心愛美酒，不是顧專城。", "謫官桃源去，尋花幾處行。秦人如舊識，出戶笑相迎。"]'),
('yuding-19','贈潘侍禦論錢少陽','李白','唐','御定全唐诗','yuding','','[]','繡衣柱史何昂藏，鐵冠白筆橫秋霜。三軍論事多引納，',48,'御定全唐詩/json/170.json','["繡衣柱史何昂藏，鐵冠白筆橫秋霜。三軍論事多引納，", "眉如松雪齊四皓，調笑可以安儲皇。君能禮此最下士，"]'),
('yuding-20','贈柳圓','李白','唐','御定全唐诗','yuding','','[]','竹實滿秋浦，鳳來何苦饑。還同月下鵲，三繞未安枝。',48,'御定全唐詩/json/170.json','["竹實滿秋浦，鳳來何苦饑。還同月下鵲，三繞未安枝。", "夫子即瓊樹，傾柯拂羽儀。懷君戀明德，歸去日相思。"]'),
('yuding-21','流夜郎半道承恩放還，兼欣克復之美書懷示息秀才','李白','唐','御定全唐诗','yuding','','[]','黃口為人羅，白龍乃魚服。得罪豈怨天，以愚陷網目。',240,'御定全唐詩/json/170.json','["黃口為人羅，白龍乃魚服。得罪豈怨天，以愚陷網目。", "鯨鯢未翦滅，豺狼屢翻履。悲作楚地囚，何日秦庭哭。", "遭逢二明主，前後兩遷逐。去國愁夜郎，投身竄荒穀。", "半道雪屯蒙，曠如鳥出籠。遙欣克復美，光武安可同。", "天子巡劍閣，儲皇守扶風。揚袂正北辰，開襟攬群雄。", "胡兵出月窟，雷破關之東。左掃因右拂，旋收洛陽宮。", "回輿入咸京，席捲六合通。叱吒開帝業，手成天地功。", "大駕還長安，兩日忽再中。一朝讓寶位，劍璽傳無窮。", "愧無秋毫力，誰念矍鑠翁。弋者何所慕，高飛仰冥鴻。", "棄劍學丹砂，臨爐雙玉童。寄言息夫子，歲晚陟方蓬。"]'),
('yuding-22','贈張相鎬二首','李白','唐','御定全唐诗','yuding','','[]','神器難竊弄，天狼窺紫宸。六龍遷白日，四海暗胡塵。',516,'御定全唐詩/json/170.json','["神器難竊弄，天狼窺紫宸。六龍遷白日，四海暗胡塵。", "昊穹降元宰，君子方經綸。澹然養浩氣，欻起持大鈞。", "秀骨象山嶽，英謀合鬼神。佐漢解鴻門，生唐為後身。", "擁旄秉金鉞，伐鼓乘朱輪。虎將如雷霆，總戎向東巡。", "諸侯拜馬首，猛士騎鯨鱗。澤被魚鳥悅，令行草木春。", "聖智不失時，建功及良辰。醜虜安足紀，可貽幗與巾。", "倒瀉溟海珠，盡為入幕珍。馮異獻赤伏，鄧生倏來臻。", "庶同昆陽舉，再睹漢儀新。昔為管將鮑，中奔吳隔秦。", "一生欲報主，百代思榮親。其事竟不就，哀哉難重陳。", "臥病宿松山，蒼茫空四鄰。風雲激壯志，枯槁驚常倫。", "聞君自天來，目張氣益振。亞夫得劇孟，敵國空無人。", "捫虱對桓公，願得論悲辛。大塊方噫氣，何辭鼓青蘋。", "斯言倘不合，歸老漢江濱。", "本家隴西人，先為漢邊將。功略蓋天地，名飛青雲上。", "苦戰竟不侯，富年頗惆悵。世傳崆峒勇，氣激金風壯。", "英烈遺厥孫，百代神猶王。十五觀奇書，作賦淩相如。", "龍顏惠殊寵，麟閣憑天居。晚途未雲已，蹭蹬遭讒毀。", "想像晉末時，崩騰胡塵起。衣冠陷鋒鏑，戎虜盈朝市。", "石勒窺神州，劉聰劫天子。撫劍夜吟嘯，雄心日千里。", "誓欲斬鯨鯢，澄清洛陽水。六合灑霖雨，萬物無凋枯。", "我揮一杯水，自笑何區區。因人恥成事，貴欲決良圖。", "滅虜不言功，飄然陟蓬壺。惟有安期舄，留之滄海隅。"]'),
('yuding-23','聞謝楊兒吟猛虎詞，因此有贈','李白','唐','御定全唐诗','yuding','','[]','同州隔秋浦，聞吟猛虎詞。晨朝來借問，知是謝楊兒。',24,'御定全唐詩/json/170.json','["同州隔秋浦，聞吟猛虎詞。晨朝來借問，知是謝楊兒。"]'),
('yuding-24','宿清溪主人','李白','唐','御定全唐诗','yuding','','[]','夜到清溪宿，主人碧岩裏。簷楹掛星斗，枕席響風水。',36,'御定全唐詩/json/170.json','["夜到清溪宿，主人碧岩裏。簷楹掛星斗，枕席響風水。", "月落西山時，啾啾夜猿起。"]'),
('yuding-25','系尋陽，上崔相渙三首','李白','唐','御定全唐诗','yuding','','[]','邯鄲四十萬，同日陷長平。能回造化筆，或冀一人生。',80,'御定全唐詩/json/170.json','["邯鄲四十萬，同日陷長平。能回造化筆，或冀一人生。", "毛遂不墮井，曾參寧殺人。虛言誤公子，投杼惑慈親。", "白璧雙明月，方知一玉真。", "虛傳一片雨，枉作陽臺神。縱為夢裏相隨去，"]'),
('yuding-26','巴陵贈賈舍人','李白','唐','御定全唐诗','yuding','','[]','賈生西望憶京華，湘浦南遷莫怨嗟。',32,'御定全唐詩/json/170.json','["賈生西望憶京華，湘浦南遷莫怨嗟。", "聖主恩深漢文帝，憐君不遣到長沙。"]'),
('yuding-0','贈別舍人弟台卿之江南','李白','唐','御定全唐诗','yuding','','[]','去國客行遠，還山秋夢長。梧桐落金井，一葉飛銀床。',132,'御定全唐詩/json/171.json','["去國客行遠，還山秋夢長。梧桐落金井，一葉飛銀床。", "覺罷攬明鏡，鬢毛颯已霜。良圖委蔓草，古貌成枯桑。", "欲道心下事，時人疑夜光。因為洞庭葉，飄落之瀟湘。", "令弟經濟士，謫居我何傷。潛虯隱尺水，著論談興亡。", "客遇王子喬，口傳不死方。入洞過天地，登真朝玉皇。", "吾將撫爾背，揮手遂翱翔。"]'),
('yuding-1','醉後贈王曆陽','李白','唐','御定全唐诗','yuding','','[]','書禿千兔毫，詩裁兩牛腰。筆蹤起龍虎，舞袖拂雲霄。',48,'御定全唐詩/json/171.json','["書禿千兔毫，詩裁兩牛腰。筆蹤起龍虎，舞袖拂雲霄。", "雙歌二胡姬，更奏遠清朝。舉酒挑朔雪，從君不相饒。"]'),
('yuding-2','贈曆陽褚司馬','李白','唐','御定全唐诗','yuding','','[]','北堂千萬壽，侍奉有光輝。先同稚子舞，更著老萊衣。',48,'御定全唐詩/json/171.json','["北堂千萬壽，侍奉有光輝。先同稚子舞，更著老萊衣。", "因為小兒啼，醉倒月下歸。人間無此樂，此樂世中稀。"]'),
('yuding-3','對雪醉後贈王曆陽','李白','唐','御定全唐诗','yuding','','[]','有身莫犯飛龍鱗，有手莫辮猛虎須。君看昔日汝南市，',64,'御定全唐詩/json/171.json','["有身莫犯飛龍鱗，有手莫辮猛虎須。君看昔日汝南市，", "曆陽何異山陰時，白雪飛花亂人目。君家有酒我何愁，", "清晨鼓棹過江去，千里相思明月樓。"]'),
('yuding-4','贈宣城宇文太守兼呈崔侍禦','李白','唐','御定全唐诗','yuding','','[]','白若白鷺鮮，清如清唳蟬。受氣有本性，不為外物遷。',516,'御定全唐詩/json/171.json','["白若白鷺鮮，清如清唳蟬。受氣有本性，不為外物遷。", "飲水箕山上，食雪首陽顛。回車避朝歌，掩口去盜泉。", "岧嶢廣成子，倜儻魯仲連。卓絕二公外，丹心無間然。", "昔攀六龍飛，今作百煉鉛。懷恩欲報主，投佩向北燕。", "彎弓綠弦開，滿月不憚堅。閑騎駿馬獵，一射兩虎穿。", "迴旋若流光，轉背落雙鳶。胡虜三歎息，兼知五兵權。", "槍槍突雲將，卻掩我之妍。多逢剿絕兒，先著祖生鞭。", "據鞍空矍鑠，壯志竟誰宣。蹉跎複來歸，憂恨坐相煎。", "無風難破浪，失計長江邊。危苦惜頹光，金波忽三圓。", "時遊敬亭上，閑聽松風眠。或弄宛溪月，虛舟信洄沿。", "顏公二十萬，盡付酒家錢。興發每取之，聊向醉中仙。", "過此無一事，靜談秋水篇。君從九卿來，水國有豐年。", "魚鹽滿市井，布帛如雲煙。下馬不作威，冰壺照清川。", "霜眉邑中叟，皆美太守賢。時時慰風俗，往往出東田。", "竹馬數小兒，拜迎白鹿前。含笑問使君，日晚可迴旋。", "遂歸池上酌，掩抑清風弦。曾標橫浮雲，下撫謝脁肩。", "樓高碧海出，樹古青蘿懸。光祿紫霞杯，伊昔忝相傳。", "良圖掃沙漠，別夢繞旌旃。富貴日成疏，願言杳無緣。", "登龍有直道，倚玉阻芳筵。敢獻繞朝策，思同郭泰船。", "何言一水淺，似隔九重天。崔生何傲岸，縱酒複談玄。", "身為名公子，英才苦迍邅。鳴鳳托高梧，淩風何翩翩。", "安知慕群客，彈劍拂秋蓮。"]'),
('yuding-5','贈宣城趙太守悅','李白','唐','御定全唐诗','yuding','','[]','趙得寶符盛，山河功業存。三千堂上客，出入擁平原。',288,'御定全唐詩/json/171.json','["趙得寶符盛，山河功業存。三千堂上客，出入擁平原。", "六國揚清風，英聲何喧喧。大賢茂遠業，虎竹光南藩。", "錯落千丈松，虯龍盤古根。枝下無俗草，所植唯蘭蓀。", "憶在南陽時，始承國士恩。公為柱下史，脫繡歸田園。", "伊昔簪白筆，幽都逐遊魂。持斧冠三軍，霜清天北門。", "差池宰兩邑，鶚立重飛翻。焚香入蘭台，起草多芳言。", "夔龍一顧重，矯翼淩翔鵷。赤縣揚雷聲，強項聞至尊。", "驚飆頹秀木，跡屈道彌敦。出牧曆三郡，所居猛獸奔。", "遷人同衛鶴，謬上懿公軒。自笑東郭履，側慚狐白溫。", "閑吟步竹石，精義忘朝昏。憔悴成醜士，風雲何足論。", "獼猴騎土牛，羸馬夾雙轅。願借羲皇景，為人照覆盆。", "溟海不振盪，何由縱鵬鯤。所期玄津白，倜儻假騰鶱。"]'),
('yuding-6','贈從弟宣州長史昭','李白','唐','御定全唐诗','yuding','','[]','淮南望江南，千里碧山對。我行倦過之，半落青天外。',144,'御定全唐詩/json/171.json','["淮南望江南，千里碧山對。我行倦過之，半落青天外。", "宗英佐雄郡，水陸相控帶。長川豁中流，千里瀉吳會。", "君心亦如此，包納無小大。搖筆起風霜，推誠結仁愛。", "訟庭垂桃李，賓館羅軒蓋。何意蒼梧雲，飄然忽相會。", "才將聖不偶，命與時俱背。獨立山海間，空老聖明代。", "知音不易得，撫劍增感慨。當結九萬期，中途莫先退。"]'),
('yuding-7','於五松山贈南陵常贊府','李白','唐','御定全唐诗','yuding','','[]','為草當作蘭，為木當作松。蘭秋香風遠，松寒不改容。',156,'御定全唐詩/json/171.json','["為草當作蘭，為木當作松。蘭秋香風遠，松寒不改容。", "松蘭相因依，蕭艾徒豐茸。雞與雞並食，鸞與鸞同枝。", "揀珠去沙礫，但有珠相隨。遠客投名賢，真堪寫懷抱。", "若惜方寸心，待誰可傾倒。虞卿棄趙相，便與魏齊行。", "海上五百人，同日死田橫。當時不好賢，豈傳千古名。", "願君同心人，於我少留情。寂寂還寂寂，出門迷所適。", "長鋏歸來乎，秋風思歸客。"]'),
('yuding-8','自梁園至敬亭山見會公談陵陽山水兼期同遊因有此贈','李白','唐','御定全唐诗','yuding','','[]','我隨秋風來，瑤草恐衰歇。中途寡名山，安得弄雲月。',240,'御定全唐詩/json/171.json','["我隨秋風來，瑤草恐衰歇。中途寡名山，安得弄雲月。", "渡江如昨日，黃葉向人飛。敬亭愜素尚，弭棹流清輝。", "冰穀明且秀，陵巒抱江城。粲粲吳與史，衣冠耀天京。", "水國饒英奇，潛光臥幽草。會公真名僧，所在即為寶。", "開堂振白拂，高論橫青雲。雪山掃粉壁，墨客多新文。", "為餘話幽棲，且述陵陽美。天開白龍潭，月映清秋水。", "黃山望石柱，突兀誰開張。黃鶴久不來，子安在蒼茫。", "東南焉可窮，山鳥飛絕處。稠疊千萬峰，相連入雲去。", "聞此期振策，歸來空閉關。相思如明月，可望不可攀。", "何當移白足，早晚淩蒼山。且寄一書劄，令予解愁顏。"]'),
('yuding-9','贈友人三首','李白','唐','御定全唐诗','yuding','','[]','蘭生不當戶，別是閒庭草。夙被霜露欺，紅榮已先老。',312,'御定全唐詩/json/171.json','["蘭生不當戶，別是閒庭草。夙被霜露欺，紅榮已先老。", "謬接瑤華枝，結根君王池。顧無馨香美，叨沐清風吹。", "餘芳若可佩，卒歲長相隨。", "袖中趙匕首，買自徐夫人。玉匣閉霜雪，經燕複曆秦。", "其事竟不捷，淪落歸沙塵。持此願投贈，與君同急難。", "荊卿一去後，壯士多摧殘。長號易水上，為我揚波瀾。", "鑿井當及泉，張帆當濟川。廉夫唯重義，駿馬不勞鞭。", "人生貴相知，何必金與錢。", "慢世薄功業，非無胸中畫。謔浪萬古賢，以為兒童劇。", "立產如廣費，匡君懷長策。但苦山北寒，誰知道南宅。", "歲酒上逐風，霜鬢兩邊白。蜀主思孔明，晉家望安石。", "時人列五鼎，談笑期一擲。虎伏被胡塵，漁歌游海濱。", "弊裘恥妻嫂，長劍托交親。夫子秉家義，群公難與鄰。", "莫持西江水，空許東溟臣。他日青雲去，黃金報主人。"]'),
('yuding-10','陳情贈友人','李白','唐','御定全唐诗','yuding','','[]','延陵有寶劍，價重千黃金。觀風曆上國，暗許故人深。',264,'御定全唐詩/json/171.json','["延陵有寶劍，價重千黃金。觀風曆上國，暗許故人深。", "歸來掛墳松，萬古知其心。懦夫感達節，壯士激青衿。", "鮑生薦夷吾，一舉置齊相。斯人無良朋，豈有青雲望。", "臨財不苟取，推分固辭讓。後世稱其賢，英風邈難尚。", "論交但若此，友道孰雲喪。多君騁逸藻，掩映當時人。", "舒文振頹波，秉德冠彝倫。卜居乃此地，共井為比鄰。", "清琴弄雲月，美酒娛冬春。薄德中見捐，忽之如遺塵。", "英豪未豹變，自古多艱辛。他人縱以疏，君意宜獨親。", "奈何成離居，相去複幾許。飄風吹雲霓，蔽目不得語。", "投珠冀相報，按劍恐相距。所思采芳蘭，欲贈隔荊渚。", "沉憂心若醉，積恨淚如雨。願假東壁輝，餘光照貧女。"]'),
('yuding-11','贈從弟冽','李白','唐','御定全唐诗','yuding','','[]','楚人不識鳳，重價求山雞。獻主昔雲是，今來方覺迷。',168,'御定全唐詩/json/171.json','["楚人不識鳳，重價求山雞。獻主昔雲是，今來方覺迷。", "自居漆園北，久別咸陽西。風飄落日去，節變流鶯啼。", "桃李寒未開，幽關豈來蹊。逢君發花萼，若與青雲齊。", "及此桑葉綠，春蠶起中閨。日出布穀鳴，田家擁鋤犁。", "顧餘乏尺土，東作誰相攜。傅說降霖雨，公輸造雲梯。", "羌戎事未息，君子悲塗泥。報國有長策，成功羞執珪。", "無由謁明主，杖策還蓬藜。他年爾相訪，知我在磻溪。"]'),
('yuding-12','贈閭丘處士','李白','唐','御定全唐诗','yuding','','[]','賢人有素業，乃在沙塘陂。竹影掃秋月，荷衣落古池。',72,'御定全唐詩/json/171.json','["賢人有素業，乃在沙塘陂。竹影掃秋月，荷衣落古池。", "閑讀山海經，散帙臥遙帷。且耽田家樂，遂曠林中期。", "野酌勸芳酒，園蔬烹露葵。如能樹桃李，為我結茅茨。"]'),
('yuding-13','贈錢征君少陽','李白','唐','御定全唐诗','yuding','','[]','白玉一杯酒，綠楊三月時。春風餘幾日，兩鬢各成絲。',48,'御定全唐詩/json/171.json','["白玉一杯酒，綠楊三月時。春風餘幾日，兩鬢各成絲。", "秉燭唯須飲，投竿也未遲。如逢渭川獵，猶可帝王師。"]'),
('yuding-14','贈宣州靈源寺仲浚公','李白','唐','御定全唐诗','yuding','','[]','敬亭白雲氣，秀色連蒼梧。下映雙溪水，如天落鏡湖。',72,'御定全唐詩/json/171.json','["敬亭白雲氣，秀色連蒼梧。下映雙溪水，如天落鏡湖。", "此中積龍象，獨許浚公殊。風韻逸江左，文章動海隅。", "觀心同水月，解領得明珠。今日逢支遁，高談出有無。"]'),
('yuding-15','贈僧朝美','李白','唐','御定全唐诗','yuding','','[]','水客淩洪波，長鯨湧溟海。百川隨龍舟，噓吸竟安在。',84,'御定全唐詩/json/171.json','["水客淩洪波，長鯨湧溟海。百川隨龍舟，噓吸竟安在。", "中有不死者，探得明月珠。高價傾宇宙，餘輝照江湖。", "苞卷金縷褐，蕭然若空無。誰人識此寶，竊笑有狂夫。", "了心何言說，各勉黃金軀。"]'),
('yuding-16','贈僧行融','李白','唐','御定全唐诗','yuding','','[]','梁有湯惠休，常從鮑照遊。峨眉史懷一，獨映陳公出。',96,'御定全唐詩/json/171.json','["梁有湯惠休，常從鮑照遊。峨眉史懷一，獨映陳公出。", "卓絕二道人，結交鳳與麟。行融亦俊發，吾知有英骨。", "海若不隱珠，驪龍吐明月。大海乘虛舟，隨波任安流。", "賦詩旃檀閣，縱酒鸚鵡洲。待我適東越，相攜上白樓。"]'),
('yuding-17','贈黃山胡公求白鷳','李白','唐','御定全唐诗','yuding','','[]','請以雙白璧，買君雙白鷳。白鷳白如錦，白雪恥容顏。',72,'御定全唐詩/json/171.json','["請以雙白璧，買君雙白鷳。白鷳白如錦，白雪恥容顏。", "照影玉潭裏，刷毛琪樹間。夜棲寒月靜，朝步落花閑。", "我願得此鳥，玩之坐碧山。胡公能輟贈，籠寄野人還。"]'),
('yuding-18','登敬亭山南望懷古，贈竇主簿','李白','唐','御定全唐诗','yuding','','[]','敬亭一回首，目盡天南端。仙者五六人，常聞此遊盤。',120,'御定全唐詩/json/171.json','["敬亭一回首，目盡天南端。仙者五六人，常聞此遊盤。", "溪流琴高水，石聳麻姑壇。白龍降陵陽，黃鶴呼子安。", "羽化騎日月，雲行翼鴛鸞。下視宇宙間，四溟皆波瀾。", "汰絕目下事，從之複何難。百歲落半途，前期浩漫漫。", "強食不成味，清晨起長歎。願隨子明去，煉火燒金丹。"]'),
('yuding-19','經亂後將避地剡中，留贈崔宣城','李白','唐','御定全唐诗','yuding','','[]','雙鵝飛洛陽，五馬渡江徼。何意上東門，胡雛更長嘯。',240,'御定全唐詩/json/171.json','["雙鵝飛洛陽，五馬渡江徼。何意上東門，胡雛更長嘯。", "中原走豺虎，烈火焚宗廟。太白晝經天，頹陽掩餘照。", "王城皆蕩覆，世路成奔峭。四海望長安，顰眉寡西笑。", "蒼生疑落葉，白骨空相吊。連兵似雪山，破敵誰能料。", "我垂北溟翼，且學南山豹。崔子賢主人，歡娛每相召。", "胡床紫玉笛，卻坐青雲叫。楊花滿州城，置酒同臨眺。", "忽思剡溪去，水石遠清妙。雪盡天地明，風開湖山貌。", "悶為洛生詠，醉發吳越調。赤霞動金光，日足森海嶠。", "獨散萬古意，閑垂一溪釣。猿近天上啼，人移月邊棹。", "無以墨綬苦，來求丹砂要。華髮長折腰，將貽陶公誚。"]'),
('yuding-20','獻從叔當塗宰陽冰','李白','唐','御定全唐诗','yuding','','[]','金鏡霾六國，亡新亂天經。焉知高光起，自有羽翼生。',337,'御定全唐詩/json/171.json','["金鏡霾六國，亡新亂天經。焉知高光起，自有羽翼生。", "蕭曹安zj屼，耿賈摧欃槍。吾家有季父，傑出聖代英。", "雖無三台位，不借四豪名。激昂風雲氣，終協龍虎精。", "弱冠燕趙來，賢彥多逢迎。魯連善談笑，季布折公卿。", "遙知禮數絕，常恐不合併。惕想結宵夢，素心久已冥。", "顧慚青雲器，謬奉玉樽傾。山陽五百年，綠竹忽再榮。", "高歌振林木，大笑喧雷霆。落筆灑篆文，崩雲使人驚。", "吐辭又炳煥，五色羅華星。秀句滿江國，高才掞天庭。", "宰邑艱難時，浮雲空古城。居人若薙草，掃地無纖莖。", "惠澤及飛走，農夫盡歸耕。廣漢水萬里，長流玉琴聲。", "雅頌播吳越，還如泰階平。小子別金陵，來時白下亭。", "群鳳憐客鳥，差池相哀鳴。各拔五色毛，意重泰山輕。", "贈微所費廣，鬥水澆長鯨。彈劍歌苦寒，嚴風起前楹。", "月銜天門曉，霜落牛渚清。長歎即歸路，臨川空屏營。"]'),
('yuding-21','書懷贈南陵常贊府','李白','唐','御定全唐诗','yuding','','[]','歲星入漢年，方朔見明主。調笑當時人，中天謝雲雨。',252,'御定全唐詩/json/171.json','["歲星入漢年，方朔見明主。調笑當時人，中天謝雲雨。", "一去麒麟閣，遂將朝市乖。故交不過門，秋草日上階。", "當時何特達，獨與我心諧。置酒淩歊台，歡娛未曾歇。", "歌動白紵山，舞回天門月。問我心中事，為君前致辭。", "君看我才能，何似魯仲尼。大聖猶不遇，小儒安足悲。", "雲南五月中，頻喪渡瀘師。毒草殺漢馬，張兵奪雲旗。", "至今西二河，流血擁僵屍。將無七擒略，魯女惜園葵。", "咸陽天下樞，累歲人不足。雖有數鬥玉，不如一盤粟。", "賴得契宰衡，持鈞慰風俗。自顧無所用，辭家方來歸。", "霜驚壯士發，淚滿逐臣衣。以此不安席，蹉跎身世違。", "終當滅衛謗，不受魯人譏。"]'),
('yuding-22','贈汪倫','李白','唐','御定全唐诗','yuding','','[]','李白乘舟將欲行，忽聞岸上踏歌聲。',32,'御定全唐詩/json/171.json','["李白乘舟將欲行，忽聞岸上踏歌聲。", "桃花潭水深千尺，不及汪倫送我情。"]'),
('yuding-0','安陸白兆山桃花岩寄劉侍禦綰','李白','唐','御定全唐诗','yuding','','[]','雲臥三十年，好閑複愛仙。蓬壺雖冥絕，鸞鶴心悠然。',132,'御定全唐詩/json/172.json','["雲臥三十年，好閑複愛仙。蓬壺雖冥絕，鸞鶴心悠然。", "歸來桃花岩，得憩雲窗眠。對嶺人共語，飲潭猿相連。", "時升翠微上，邈若羅浮巔。兩岑抱東壑，一嶂橫西天。", "樹雜日易隱，崖傾月難圓。芳草換野色，飛蘿搖春煙。", "入遠構石室，選幽開上田。獨此林下意，杳無區中緣。", "永辭霜台客，千載方來旋。"]'),
('yuding-1','淮南臥病書懷，寄蜀中趙征君蕤','李白','唐','御定全唐诗','yuding','','[]','吳會一浮雲，飄如遠行客。功業莫從就，歲光屢奔迫。',132,'御定全唐詩/json/172.json','["吳會一浮雲，飄如遠行客。功業莫從就，歲光屢奔迫。", "良圖俄棄捐，衰疾乃綿劇。古琴藏虛匣，長劍掛空壁。", "楚冠懷鐘儀，越吟比莊舄。國門遙天外，鄉路遠山隔。", "朝憶相如台，夜夢子雲宅。旅情初結緝，秋氣方寂曆。", "風入松下清，露出草間白。故人不可見，幽夢誰與適。", "寄書西飛鴻，贈爾慰離析。"]'),
('yuding-2','寄弄月溪吳山人','李白','唐','御定全唐诗','yuding','','[]','嘗聞龐德公，家住洞湖水。終身棲鹿門，不入襄陽市。',72,'御定全唐詩/json/172.json','["嘗聞龐德公，家住洞湖水。終身棲鹿門，不入襄陽市。", "夫君弄明月，滅景清淮裏。高蹤邈難追，可與古人比。", "清揚杳莫睹，白雲空望美。待我辭人間，攜手訪松子。"]'),
('yuding-3','秋山寄衛尉張卿及王征君','李白','唐','御定全唐诗','yuding','','[]','何以折相贈，白花青桂枝。月華若夜雪，見此令人思。',48,'御定全唐詩/json/172.json','["何以折相贈，白花青桂枝。月華若夜雪，見此令人思。", "雖然剡溪興，不異山陰時。明發懷二子，空吟招隱詩。"]'),
('yuding-4','望終南山，寄紫閣隱者','李白','唐','御定全唐诗','yuding','','[]','出門見南山，引領意無限。秀色難為名，蒼翠日在眼。',60,'御定全唐詩/json/172.json','["出門見南山，引領意無限。秀色難為名，蒼翠日在眼。", "有時白雲起，天際自舒卷。心中與之然，托興每不淺。", "何當造幽人，滅跡棲絕巘。"]'),
('yuding-5','夕霽杜陵登樓，寄韋繇','李白','唐','御定全唐诗','yuding','','[]','浮陽滅霽景，萬物生秋容。登樓送遠目，伏檻觀群峰。',96,'御定全唐詩/json/172.json','["浮陽滅霽景，萬物生秋容。登樓送遠目，伏檻觀群峰。", "原野曠超緬，關河紛雜重。清暉映竹日，翠色明雲松。", "蹈海寄遐想，還山迷舊蹤。徒然迫晚暮，未果諧心胸。", "結桂空佇立，折麻恨莫從。思君達永夜，長樂聞疏鐘。"]'),
('yuding-6','秋夜宿龍門香山寺奉寄王方城十七丈奉國瑩上人從弟幼成令問','李白','唐','御定全唐诗','yuding','','[]','朝發汝海東，暮棲龍門中。水寒夕波急，木落秋山空。',108,'御定全唐詩/json/172.json','["朝發汝海東，暮棲龍門中。水寒夕波急，木落秋山空。", "望極九霄迥，賞幽萬壑通。目皓沙上月，心清松下風。", "玉鬥橫網戶，銀河耿花宮。興在趣方逸，歡餘情未終。", "鳳駕憶王子，虎溪懷遠公。桂枝坐蕭瑟，棣華不復同。", "流恨寄伊水，盈盈焉可窮。"]'),
('yuding-7','春日獨坐，寄鄭明府','李白','唐','御定全唐诗','yuding','','[]','燕麥青青遊子悲，河堤弱柳郁金枝。長條一拂春風去，',40,'御定全唐詩/json/172.json','["燕麥青青遊子悲，河堤弱柳郁金枝。長條一拂春風去，", "情人道來竟不來，何人共醉新豐酒。"]'),
('yuding-8','寄淮南友人','李白','唐','御定全唐诗','yuding','','[]','紅顏悲舊國，青歲歇芳洲。不待金門詔，空持寶劍遊。',48,'御定全唐詩/json/172.json','["紅顏悲舊國，青歲歇芳洲。不待金門詔，空持寶劍遊。", "海雲迷驛道，江月隱鄉樓。複作淮南客，因逢桂樹留。"]'),
('yuding-9','沙丘城下寄杜甫','李白','唐','御定全唐诗','yuding','','[]','我來竟何事，高臥沙丘城。城邊有古樹，日夕連秋聲。',48,'御定全唐詩/json/172.json','["我來竟何事，高臥沙丘城。城邊有古樹，日夕連秋聲。", "魯酒不可醉，齊歌空複情。思君若汶水，浩蕩寄南征。"]'),
('yuding-10','聞丹丘子於城北營石門幽居中有高鳳遺跡僕離羣遠懷亦有棲遁之志因敘舊以寄之','李白','唐','御定全唐诗','yuding','','[]','春華滄江月，秋色碧海雲。離居盈寒暑，對此長思君。',264,'御定全唐詩/json/172.json','["春華滄江月，秋色碧海雲。離居盈寒暑，對此長思君。", "思君楚水南，望君淮山北。夢魂雖飛來，會面不可得。", "疇昔在嵩陽，同衾臥羲皇。綠蘿笑簪紱，丹壑賤岩廊。", "晚途各分析，乘興任所適。僕在雁門關，君為峨眉客。", "心懸萬里外，影滯兩鄉隔。長劍複歸來，相逢洛陽陌。", "陌上何喧喧，都令心意煩。迷津覺路失，托勢隨風翻。", "以茲謝朝列，長嘯歸故園。故園恣閒逸，求古散縹帙。", "久欲入名山，婚娶殊未畢。人生信多故，世事豈惟一。", "念此憂如焚，悵然若有失。聞君臥石門，宿昔契彌敦。", "方從桂樹隱，不羨桃花源。高風起遐曠，幽人跡複存。", "松風清瑤瑟，溪月湛芳樽。安居偶佳賞，丹心期此論。"]'),
('yuding-11','淮陰書懷，寄王宗成','李白','唐','御定全唐诗','yuding','','[]','沙墩至梁苑，二十五長亭。大舶夾雙櫓，中流鵝鸛鳴。',144,'御定全唐詩/json/172.json','["沙墩至梁苑，二十五長亭。大舶夾雙櫓，中流鵝鸛鳴。", "雲天掃空碧，川嶽涵餘清。飛鳧從西來，適與佳興並。", "眷言王喬舄，婉孌故人情。複此親懿會，而增交道榮。", "沿洄且不定，飄忽悵徂征。暝投淮陰宿，欣得漂母迎。", "鬥酒烹黃雞，一餐感素誠。予為楚壯士，不是魯諸生。", "有德必報之，千金恥為輕。緬書羈孤意，遠寄棹歌聲。"]'),
('yuding-12','聞王昌齡左遷龍標，遙有此寄','李白','唐','御定全唐诗','yuding','','[]','楊花落盡子規啼，聞道龍標過五溪。',32,'御定全唐詩/json/172.json','["楊花落盡子規啼，聞道龍標過五溪。", "我寄愁心與明月，隨風直到夜郎西。"]'),
('yuding-13','寄王屋山人孟大融','李白','唐','御定全唐诗','yuding','','[]','我昔東海上，勞山餐紫霞。親見安期公，食棗大如瓜。',68,'御定全唐詩/json/172.json','["我昔東海上，勞山餐紫霞。親見安期公，食棗大如瓜。", "中年謁漢主，不愜還歸家。朱顏謝春輝，白髮見生涯。", "所期就金液，飛步登雲車。願隨夫子天壇上，"]'),
('yuding-14','憶舊遊，寄譙郡元參軍','李白','唐','御定全唐诗','yuding','','[]','憶昔洛陽董糟丘，為余天津橋南造酒樓。',252,'御定全唐詩/json/172.json','["憶昔洛陽董糟丘，為余天津橋南造酒樓。", "黃金白璧買歌笑，一醉累月輕王侯。海內賢豪青雲客，", "我向淮南攀桂枝，君留洛北愁夢思。不忍別，還相隨。", "相隨迢迢訪仙城，三十六曲水回縈。一溪初入千花明，", "紫陽之真人，邀我吹玉笙。餐霞樓上動仙樂，", "手持錦袍覆我身，我醉橫眠枕其股。當筵意氣淩九霄，", "五月相呼度太行，摧輪不道羊腸苦。行來北涼歲月深，", "時時出向城西曲，晉祠流水如碧玉。浮舟弄水簫鼓鳴，", "紅妝欲醉宜斜日，百尺清潭寫翠娥。翠娥嬋娟初月輝，", "此時行樂難再遇，西遊因獻長楊賦。北闕青雲不可期，", "問餘別恨知多少，落花春暮爭紛紛。言亦不可盡，"]'),
('yuding-15','月夜江行，寄崔員外宗之','李白','唐','御定全唐诗','yuding','','[]','飄飄江風起，蕭颯海樹秋。登艫美清夜，掛席移輕舟。',96,'御定全唐詩/json/172.json','["飄飄江風起，蕭颯海樹秋。登艫美清夜，掛席移輕舟。", "月隨碧山轉，水合青天流。杳如星河上，但覺雲林幽。", "歸路方浩浩，徂川去悠悠。徒悲蕙草歇，複聽菱歌愁。", "岸曲迷後浦，沙明瞰前洲。懷君不可見，望遠增離憂。"]'),
('yuding-16','宿白鷺洲，寄楊江寧','李白','唐','御定全唐诗','yuding','','[]','朝別朱雀門，暮棲白鷺洲。波光搖海月，星影入城樓。',72,'御定全唐詩/json/172.json','["朝別朱雀門，暮棲白鷺洲。波光搖海月，星影入城樓。", "望美金陵宰，如思瓊樹憂。徒令魂入夢，翻覺夜成秋。", "綠水解人意，為餘西北流。因聲玉琴裏，蕩漾寄君愁。"]'),
('yuding-17','新林浦阻風，寄友人','李白','唐','御定全唐诗','yuding','','[]','潮水定可信，天風難與期。清晨西北轉，薄暮東南吹。',108,'御定全唐詩/json/172.json','["潮水定可信，天風難與期。清晨西北轉，薄暮東南吹。", "以此難掛席，佳期益相思。海月破圓影，菰蔣生綠池。", "昨日北湖梅，開花已滿枝。今朝東門柳，夾道垂青絲。", "歲物忽如此，我來定幾時。紛紛江上雪，草草客中悲。", "明發新林浦，空吟謝脁詩。"]'),
('yuding-18','寄韋南陵冰，余江上乘興訪之遇尋顏尚書笑有此贈','李白','唐','御定全唐诗','yuding','','[]','南船正東風，北船來自緩。江上相逢借問君，',42,'御定全唐詩/json/172.json','["南船正東風，北船來自緩。江上相逢借問君，", "堂上三千珠履客，甕中百斛金陵春。恨我阻此樂，"]'),
('yuding-19','題情深樹，寄象公','李白','唐','御定全唐诗','yuding','','[]','腸斷枝上猿，淚添山下樽。白雲見我去，亦為我飛翻。',24,'御定全唐詩/json/172.json','["腸斷枝上猿，淚添山下樽。白雲見我去，亦為我飛翻。"]'),
('yuding-20','北山獨酌，寄韋六','李白','唐','御定全唐诗','yuding','','[]','巢父將許由，未聞買山隱。道存跡自高，何憚去人近。',120,'御定全唐詩/json/172.json','["巢父將許由，未聞買山隱。道存跡自高，何憚去人近。", "紛吾下茲嶺，地閑喧亦泯。門橫群岫開，水鑿眾泉引。", "屏高而在雲，竇深莫能准。川光晝昏凝，林氣夕淒緊。", "于焉摘朱果，兼得養玄牝。坐月觀寶書，拂霜弄瑤軫。", "傾壺事幽酌，顧影還獨盡。念君風塵遊，傲爾令自哂。"]'),
('yuding-21','寄當塗趙少府炎','李白','唐','御定全唐诗','yuding','','[]','晚登高樓望，木落雙江清。寒山饒積翠，秀色連州城。',48,'御定全唐詩/json/172.json','["晚登高樓望，木落雙江清。寒山饒積翠，秀色連州城。", "目送楚雲盡，心悲胡雁聲。相思不可見，回首故人情。"]'),
('yuding-22','寄東魯二稚子','李白','唐','御定全唐诗','yuding','','[]','吳地桑葉綠，吳蠶已三眠。我家寄東魯，誰種龜陰田。',156,'御定全唐詩/json/172.json','["吳地桑葉綠，吳蠶已三眠。我家寄東魯，誰種龜陰田。", "春事已不及，江行複茫然。南風吹歸心，飛墮酒樓前。", "樓東一株桃，枝葉拂青煙。此樹我所種，別來向三年。", "桃今與樓齊，我行尚未旋。嬌女字平陽，折花倚桃邊。", "折花不見我，淚下如流泉。小兒名伯禽，與姊亦齊肩。", "雙行桃樹下，撫背複誰憐。念此失次第，肝腸日憂煎。", "裂素寫遠意，因之汶陽川。"]'),
('yuding-23','獨酌清溪江石上，寄權昭夷','李白','唐','御定全唐诗','yuding','','[]','我攜一樽酒，獨上江祖石。自從天地開，更長幾千尺。',60,'御定全唐詩/json/172.json','["我攜一樽酒，獨上江祖石。自從天地開，更長幾千尺。", "舉杯向天笑，天回日西照。永願坐此石，長垂嚴陵釣。", "寄謝山中人，可與爾同調。"]'),
('yuding-24','禪房懷友人岑倫','李白','唐','御定全唐诗','yuding','','[]','嬋娟羅浮月，搖豔桂水雲。美人竟獨往，而我安得群。',192,'御定全唐詩/json/172.json','["嬋娟羅浮月，搖豔桂水雲。美人竟獨往，而我安得群。", "一朝語笑隔，萬里歡情分。沉吟彩霞沒，夢寐群芳歇。", "歸鴻渡三湘，遊子在百粵。邊塵染衣劍，白日凋華髮。", "春風變楚關，秋聲落吳山。草木結悲緒，風沙淒苦顏。", "朅來已永久，頹思如迴圈。飄飄限江裔，想像空留滯。", "離憂每醉心，別淚徒盈袂。坐愁青天末，出望黃雲蔽。", "目極何悠悠，梅花南嶺頭。空長滅征鳥，水闊無還舟。", "寶劍終難托，金囊非易求。歸來倘有問，桂樹山之幽。"]'),
('yuding-0','廬山謠，寄盧侍禦虛舟','李白','唐','御定全唐诗','yuding','','[]','我本楚狂人，鳳歌笑孔丘。手持綠玉杖，朝別黃鶴樓。',116,'御定全唐詩/json/173.json','["我本楚狂人，鳳歌笑孔丘。手持綠玉杖，朝別黃鶴樓。", "五嶽尋仙不辭遠，一生好入名山遊。廬山秀出南斗傍，", "翠影紅霞映朝日，鳥飛不到吳天長。登高壯觀天地間，", "好為廬山謠，興因廬山發。閑窺石鏡清我心，", "遙見仙人彩雲裏，手把芙蓉朝玉京。先期汗漫九垓上，"]'),
('yuding-1','下尋陽城泛彭蠡，寄黃判官','李白','唐','御定全唐诗','yuding','','[]','浪動灌嬰井，尋陽江上風。開帆入天鏡，直向彭湖東。',72,'御定全唐詩/json/173.json','["浪動灌嬰井，尋陽江上風。開帆入天鏡，直向彭湖東。", "落景轉疏雨，晴雲散遠空。名山發佳興，清賞亦何窮。", "石鏡掛遙月，香爐滅彩虹。相思俱對此，舉目與君同。"]'),
('yuding-2','書情寄從弟邠州長史昭','李白','唐','御定全唐诗','yuding','','[]','自笑客行久，我行定幾時。綠楊已可折，攀取最長枝。',96,'御定全唐詩/json/173.json','["自笑客行久，我行定幾時。綠楊已可折，攀取最長枝。", "翩翩弄春色，延佇寄相思。誰言貴此物，意願重瓊蕤。", "昨夢見惠連，朝吟謝公詩。東風引碧草，不覺生華池。", "臨玩忽雲夕，杜鵑夜鳴悲。懷君芳歲歇，庭樹落紅滋。"]'),
('yuding-3','寄王漢陽','李白','唐','御定全唐诗','yuding','','[]','南湖秋月白，王宰夜相邀。錦帳郎官醉，羅衣舞女嬌。',48,'御定全唐詩/json/173.json','["南湖秋月白，王宰夜相邀。錦帳郎官醉，羅衣舞女嬌。", "笛聲喧沔鄂，歌曲上雲霄。別後空愁我，相思一水遙。"]'),
('yuding-4','春日歸山，寄孟浩然','李白','唐','御定全唐诗','yuding','','[]','朱紱遺塵境，青山謁梵筵。金繩開覺路，寶筏度迷川。',96,'御定全唐詩/json/173.json','["朱紱遺塵境，青山謁梵筵。金繩開覺路，寶筏度迷川。", "嶺樹攢飛栱，岩花覆穀泉。塔形標海月，樓勢出江煙。", "香氣三天下，鐘聲萬壑連。荷秋珠已滿，松密蓋初圓。", "鳥聚疑聞法，龍參若護禪。愧非流水韻，叨入伯牙弦。"]'),
('yuding-5','流夜郎永華寺，寄尋陽群官','李白','唐','御定全唐诗','yuding','','[]','朝別淩煙樓，賢豪滿行舟。暝投永華寺，賓散予獨醉。',60,'御定全唐詩/json/173.json','["朝別淩煙樓，賢豪滿行舟。暝投永華寺，賓散予獨醉。", "願結九江流，添成萬行淚。寫意寄廬岳，何當來此地。", "天命有所懸，安得苦愁思。"]'),
('yuding-6','流夜郎至西塞驛，寄裴隱','李白','唐','御定全唐诗','yuding','','[]','揚帆借天風，水驛苦不緩。平明及西塞，已先投沙伴。',96,'御定全唐詩/json/173.json','["揚帆借天風，水驛苦不緩。平明及西塞，已先投沙伴。", "回巒引群峰，橫蹙楚山斷。砯沖萬壑會，震遝百川滿。", "龍怪潛溟波，俟時救炎旱。我行望雷雨，安得沾枯散。", "鳥去天路長，人愁春光短。空將澤畔吟，寄爾江南管。"]'),
('yuding-7','自漢陽病酒歸，寄王明府','李白','唐','御定全唐诗','yuding','','[]','去歲左遷夜郎道，琉璃硯水長枯槁。今年敕放巫山陽，',44,'御定全唐詩/json/173.json','["去歲左遷夜郎道，琉璃硯水長枯槁。今年敕放巫山陽，", "願掃鸚鵡洲，與君醉百場。嘯起白雲飛七澤，"]'),
('yuding-8','望漢陽柳色，寄王宰','李白','唐','御定全唐诗','yuding','','[]','漢陽江上柳，望客引東枝。樹樹花如雪，紛紛亂若絲。',48,'御定全唐詩/json/173.json','["漢陽江上柳，望客引東枝。樹樹花如雪，紛紛亂若絲。", "春風傳我意，草木別前知。寄謝弦歌宰，西來定未遲。"]'),
('yuding-9','江夏寄漢陽輔錄事','李白','唐','御定全唐诗','yuding','','[]','誰道此水廣，狹如一匹練。江夏黃鶴樓，青山漢陽縣。',120,'御定全唐詩/json/173.json','["誰道此水廣，狹如一匹練。江夏黃鶴樓，青山漢陽縣。", "大語猶可聞，故人難可見。君草陳琳檄，我書魯連箭。", "報國有壯心，龍顏不回眷。西飛精衛鳥，東海何由填。", "鼓角徒悲鳴，樓船習征戰。抽劍步霜月，夜行空庭遍。", "長呼結浮雲，埋沒顧榮扇。他日觀軍容，投壺接高宴。"]'),
('yuding-10','早春寄王漢陽','李白','唐','御定全唐诗','yuding','','[]','聞道春還未相識，走傍寒梅訪消息。昨夜東風入武陽，',40,'御定全唐詩/json/173.json','["聞道春還未相識，走傍寒梅訪消息。昨夜東風入武陽，", "預拂青山一片石，與君連日醉壺觴。"]'),
('yuding-11','江上寄巴東故人','李白','唐','御定全唐诗','yuding','','[]','漢水波浪遠，巫山雲雨飛。東風吹客夢，西落此中時。',48,'御定全唐詩/json/173.json','["漢水波浪遠，巫山雲雨飛。東風吹客夢，西落此中時。", "覺後思白帝，佳人與我違。瞿塘饒賈客，音信莫令稀。"]'),
('yuding-12','江上寄元六林宗','李白','唐','御定全唐诗','yuding','','[]','霜落江始寒，楓葉綠未脫。客行悲清秋，永路苦不達。',120,'御定全唐詩/json/173.json','["霜落江始寒，楓葉綠未脫。客行悲清秋，永路苦不達。", "滄波眇川汜，白日隱天末。停棹依林巒，驚猿相叫聒。", "夜分河漢轉，起視溟漲闊。涼風何蕭蕭，流水鳴活活。", "浦沙淨如洗，海月明可掇。蘭交空懷思，瓊樹詎解渴。", "勖哉滄洲心，歲晚庶不奪。幽賞頗自得，興遠與誰豁。"]'),
('yuding-13','寄從弟宣州長史昭','李白','唐','御定全唐诗','yuding','','[]','爾佐宣州郡，守官清且閑。常誇雲月好，邀我敬亭山。',48,'御定全唐詩/json/173.json','["爾佐宣州郡，守官清且閑。常誇雲月好，邀我敬亭山。", "五落洞庭葉，三江遊未還。相思不可見，歎息損朱顏。"]'),
('yuding-14','涇溪東亭寄鄭少府諤','李白','唐','御定全唐诗','yuding','','[]','我遊東亭不見君，沙上行將白鷺群。白鷺行時散飛去，',40,'御定全唐詩/json/173.json','["我遊東亭不見君，沙上行將白鷺群。白鷺行時散飛去，", "杜鵑花開春已闌，歸向陵陽釣魚晚。"]'),
('yuding-15','宣州九日聞崔四侍御與宇文太守遊敬亭余時登響山不同此賞醉後寄崔侍御二首','李白','唐','御定全唐诗','yuding','','[]','九日茱萸熟，插鬢傷早白。登高望山海，滿目悲古昔。',228,'御定全唐詩/json/173.json','["九日茱萸熟，插鬢傷早白。登高望山海，滿目悲古昔。", "遠訪投沙人，因為逃名客。故交竟誰在，獨有崔亭伯。", "重陽不相知，載酒任所適。手持一枝菊，調笑二千石。", "日暮岸幘歸，傳呼隘阡陌。彤襜雙白鹿，賓從何輝赫。", "夫子在其間，遂成雲霄隔。良辰與美景，兩地方虛擲。", "晚從南峰歸，蘿月下水壁。卻登郡樓望，松色寒轉碧。", "咫尺不可親，棄我如遺舄。", "九卿天上落，五馬道傍來。列戟朱門曉，褰幃碧嶂開。", "登高望遠海，召客得英才。紫綬歡情洽，黃花逸興催。", "山從圖上見，溪即鏡中回。遙羨重陽作，應過戲馬台。"]'),
('yuding-16','寄崔侍禦','李白','唐','御定全唐诗','yuding','','[]','宛溪霜夜聽猿愁，去國長為不系舟。獨憐一雁飛南海，',40,'御定全唐詩/json/173.json','["宛溪霜夜聽猿愁，去國長為不系舟。獨憐一雁飛南海，", "此處別離同落葉，朝朝分散敬亭秋。"]'),
('yuding-17','涇溪南藍山下有落星潭可以卜築余泊舟石上寄何判官昌浩','李白','唐','御定全唐诗','yuding','','[]','藍岑竦天壁，突兀如鯨額。奔蹙橫澄潭，勢吞落星石。',72,'御定全唐詩/json/173.json','["藍岑竦天壁，突兀如鯨額。奔蹙橫澄潭，勢吞落星石。", "沙帶秋月明，水搖寒山碧。佳境宜緩棹，清輝能留客。", "恨君阻歡遊，使我自驚惕。所期俱蔔築，結茅煉金液。"]'),
('yuding-18','早過漆林渡，寄萬巨','李白','唐','御定全唐诗','yuding','','[]','西經大藍山，南來漆林渡。水色倒空青，林煙橫積素。',96,'御定全唐詩/json/173.json','["西經大藍山，南來漆林渡。水色倒空青，林煙橫積素。", "漏流昔吞翕，遝浪競奔注。潭落天上星，龍開水中霧。", "嶢岩注公柵，突兀陳焦墓。嶺峭紛上幹，川明屢回顧。", "因思萬夫子，解渴同瓊樹。何日睹清光，相歡詠佳句。"]'),
('yuding-19','遊敬亭寄崔侍禦','李白','唐','御定全唐诗','yuding','','[]','我家敬亭下，輒繼謝公作。相去數百年，風期宛如昨。',120,'御定全唐詩/json/173.json','["我家敬亭下，輒繼謝公作。相去數百年，風期宛如昨。", "登高素秋月，下望青山郭。俯視鴛鷺群，飲啄自鳴躍。", "夫子雖蹭蹬，瑤台雪中鶴。獨立窺浮雲，其心在寥廓。", "時來顧我笑，一飯葵與藿。世路如秋風，相逢盡蕭索。", "腰間玉具劍，意許無遺諾。壯士不可輕，相期在雲閣。"]'),
('yuding-20','三山望金陵，寄殷淑','李白','唐','御定全唐诗','yuding','','[]','三山懷謝脁，水澹望長安。蕪沒河陽縣，秋江正北看。',48,'御定全唐詩/json/173.json','["三山懷謝脁，水澹望長安。蕪沒河陽縣，秋江正北看。", "盧龍霜氣冷，鳷鵲月光寒。耿耿憶瓊樹，天涯寄一歡。"]'),
('yuding-21','自金陵溯流過白璧山玩月達天門，寄句容王主簿','李白','唐','御定全唐诗','yuding','','[]','滄江溯流歸，白璧見秋月。秋月照白璧，皓如山陰雪。',84,'御定全唐詩/json/173.json','["滄江溯流歸，白璧見秋月。秋月照白璧，皓如山陰雪。", "幽人停宵征，賈客忘早發。進帆天門山，回首牛渚沒。", "川長信風來，日出宿霧歇。故人在咫尺，新賞成胡越。", "寄君青蘭花，惠好庶不絕。"]'),
('yuding-22','寄上吳王三首','李白','唐','御定全唐诗','yuding','','[]','淮王愛八公，攜手綠雲中。小子忝枝葉，亦攀丹桂叢。',120,'御定全唐詩/json/173.json','["淮王愛八公，攜手綠雲中。小子忝枝葉，亦攀丹桂叢。", "謬以詞賦重，而將枚馬同。何日背淮水，東之觀土風。", "坐嘯廬江靜，閑聞進玉觴。去時無一物，東壁掛胡床。", "英明廬江守，聲譽廣平籍。灑掃黃金台，招邀青雲客。", "客曾與天通，出入清禁中。襄王憐宋玉，願入蘭台宮。"]'),
('yuding-0','秋日魯郡堯祠亭上宴別杜補闕、範侍禦','李白','唐','御定全唐诗','yuding','','[]','我覺秋興逸，誰雲秋興悲。山將落日去，水與晴空宜。',84,'御定全唐詩/json/174.json','["我覺秋興逸，誰雲秋興悲。山將落日去，水與晴空宜。", "魯酒白玉壺，送行駐金羈。歇鞍憩古木，解帶掛橫枝。", "歌鼓川上亭，曲度神飆吹。雲歸碧海夕，雁沒青天時。", "相失各萬里，茫然空爾思。"]'),
('yuding-1','別魯頌','李白','唐','御定全唐诗','yuding','','[]','誰道泰山高，下卻魯連節。誰雲秦軍眾，摧卻魯連舌。',72,'御定全唐詩/json/174.json','["誰道泰山高，下卻魯連節。誰雲秦軍眾，摧卻魯連舌。", "獨立天地間，清風灑蘭雪。夫子還倜儻，攻文繼前烈。", "錯落石上松，無為秋霜折。贈言鏤寶刀，千歲庶不滅。"]'),
('yuding-2','別中都明府兄','李白','唐','御定全唐诗','yuding','','[]','吾兄詩酒繼陶君，試宰中都天下聞。東樓喜奉連枝會，',40,'御定全唐詩/json/174.json','["吾兄詩酒繼陶君，試宰中都天下聞。東樓喜奉連枝會，", "取醉不辭留夜月，雁行中斷惜離群。"]'),
('yuding-3','夢遊天姥吟留別','李白','唐','御定全唐诗','yuding','','[]','海客談瀛洲，煙濤微茫信難求。越人語天姥，',156,'御定全唐詩/json/174.json','["海客談瀛洲，煙濤微茫信難求。越人語天姥，", "天臺四萬八千丈，對此欲倒東南傾。我欲因之夢吳越，", "謝公宿處今尚在，淥水蕩漾清猿啼。腳著謝公屐，", "千岩萬轉路不定，迷花倚石忽已暝。熊咆龍吟殷岩泉，", "列缺霹靂，丘巒崩摧。洞天石扇，訇然中開。", "青冥浩蕩不見底，日月照耀金銀台。霓為衣兮風為馬，", "惟覺時之枕席，失向來之煙霞。世間行樂亦如此，"]'),
('yuding-4','留別曹南群官之江南','李白','唐','御定全唐诗','yuding','','[]','我昔釣白龍，放龍溪水傍。道成本欲去，揮手淩蒼蒼。',264,'御定全唐詩/json/174.json','["我昔釣白龍，放龍溪水傍。道成本欲去，揮手淩蒼蒼。", "時來不關人，談笑遊軒皇。獻納少成事，歸休辭建章。", "十年罷西笑，覽鏡如秋霜。閉劍琉璃匣，煉丹紫翠房。", "身佩豁落圖，腰垂虎鞶囊。仙人駕彩鳳，志在窮遐荒。", "戀子四五人，裴回未翱翔。東流送白日，驟歌蘭蕙芳。", "仙宮兩無從，人間久摧藏。范蠡說句踐，屈平去懷王。", "飄飄紫霞心，流浪憶江鄉。愁為萬里別，複此一銜觴。", "淮水帝王州，金陵繞丹陽。樓臺照海色，衣馬搖川光。", "及此北望君，相思淚成行。朝雲落夢渚，瑤草空高堂。", "帝子隔洞庭，青楓滿瀟湘。懷君路綿邈，覽古情淒涼。", "登嶽眺百川，杳然萬恨長。知戀峨眉去，弄景偶騎羊。"]'),
('yuding-5','留別于十一兄逖、裴十三遊塞垣','李白','唐','御定全唐诗','yuding','','[]','太公渭川水，李斯上蔡門。釣周獵秦安黎元，',84,'御定全唐詩/json/174.json','["太公渭川水，李斯上蔡門。釣周獵秦安黎元，", "于公白首大樑野，使人悵望何可論。既知朱亥為壯士，", "裴生覽千古，龍鸞炳文章。悲吟雨雪動林木，", "爾為我楚舞，吾為爾楚歌。且探虎穴向沙漠，"]'),
('yuding-6','留別王司馬嵩','李白','唐','御定全唐诗','yuding','','[]','魯連賣談笑，豈是顧千金。陶朱雖相越，本有五湖心。',108,'御定全唐詩/json/174.json','["魯連賣談笑，豈是顧千金。陶朱雖相越，本有五湖心。", "余亦南陽子，時為梁甫吟。蒼山容偃蹇，白日惜頹侵。", "願一佐明主，功成還舊林。西來何所為，孤劍托知音。", "鳥愛碧山遠，魚遊滄海深。呼鷹過上蔡，賣畚向嵩岑。", "他日閑相訪，丘中有素琴。"]'),
('yuding-7','夜別張五','李白','唐','御定全唐诗','yuding','','[]','吾多張公子，別酌酣高堂。聽歌舞銀燭，把酒輕羅裳。',48,'御定全唐詩/json/174.json','["吾多張公子，別酌酣高堂。聽歌舞銀燭，把酒輕羅裳。", "橫笛弄秋月，琵琶彈陌桑。龍泉解錦帶，為爾傾千觴。"]'),
('yuding-8','魏郡別蘇明府因北遊','李白','唐','御定全唐诗','yuding','','[]','魏都接燕趙，美女誇芙蓉。淇水流碧玉，舟車日奔沖。',132,'御定全唐詩/json/174.json','["魏都接燕趙，美女誇芙蓉。淇水流碧玉，舟車日奔沖。", "青樓夾兩岸，萬室喧歌鐘。天下稱豪貴，遊此每相逢。", "洛陽蘇季子，劍戟森詞鋒。六印雖未佩，軒車若飛龍。", "黃金數百鎰，白璧有幾雙。散盡空掉臂，高歌賦還邛。", "落魄乃如此，何人不相從。遠別隔兩河，雲山杳千重。", "何時更杯酒，再得論心胸。"]'),
('yuding-9','留別西河劉少府','李白','唐','御定全唐诗','yuding','','[]','秋發已種種，所為竟無成。閑傾魯壺酒，笑對劉公榮。',120,'御定全唐詩/json/174.json','["秋發已種種，所為竟無成。閑傾魯壺酒，笑對劉公榮。", "謂我是方朔，人間落歲星。白衣千萬乘，何事去天庭。", "君亦不得意，高歌羨鴻冥。世人若醯雞，安可識梅生。", "雖為刀筆吏，緬懷在赤城。餘亦如流萍，隨波樂休明。", "自有兩少妾，雙騎駿馬行。東山春酒綠，歸隱謝浮名。"]'),
('yuding-10','潁陽別元丹丘之淮陽','李白','唐','御定全唐诗','yuding','','[]','吾將元夫子，異姓為天倫。本無軒裳契，素以煙霞親。',156,'御定全唐詩/json/174.json','["吾將元夫子，異姓為天倫。本無軒裳契，素以煙霞親。", "嘗恨迫世網，銘意俱未伸。松柏雖寒苦，羞逐桃李春。", "悠悠市朝間，玉顏日緇磷。所失重山嶽，所得輕埃塵。", "精魄漸蕪穢，衰老相憑因。我有錦囊訣，可以持君身。", "當餐黃金藥，去為紫陽賓。萬事難並立，百年猶崇晨。", "別爾東南去，悠悠多悲辛。前志庶不易，遠途期所遵。", "已矣歸去來，白雲飛天津。"]'),
('yuding-11','留別廣陵諸公','李白','唐','御定全唐诗','yuding','','[]','憶昔作少年，結交趙與燕。金羈絡駿馬，錦帶橫龍泉。',156,'御定全唐詩/json/174.json','["憶昔作少年，結交趙與燕。金羈絡駿馬，錦帶橫龍泉。", "寸心無疑事，所向非徒然。晚節覺此疏，獵精草太玄。", "空名束壯士，薄俗棄高賢。中回聖明顧，揮翰淩雲煙。", "騎虎不敢下，攀龍忽墮天。還家守清真，孤潔勵秋蟬。", "煉丹費火石，采藥窮山川。臥海不關人，租稅遼東田。", "乘興忽複起，棹歌溪中船。臨醉謝葛強，山公欲倒鞭。", "狂歌自此別，垂釣滄浪前。"]'),
('yuding-12','廣陵贈別','李白','唐','御定全唐诗','yuding','','[]','玉瓶沽美酒，數裏送君還。系馬垂楊下，銜杯大道間。',48,'御定全唐詩/json/174.json','["玉瓶沽美酒，數裏送君還。系馬垂楊下，銜杯大道間。", "天邊看淥水，海上見青山。興罷各分袂，何須醉別顏。"]'),
('yuding-13','感時留別從兄徐王延年、從弟延陵','李白','唐','御定全唐诗','yuding','','[]','天籟何參差，噫然大塊吹。玄元包橐鑰，紫氣何逶迤。',444,'御定全唐詩/json/174.json','["天籟何參差，噫然大塊吹。玄元包橐鑰，紫氣何逶迤。", "七葉運皇化，千齡光本支。仙風生指樹，大雅歌螽斯。", "諸王若鸞虯，肅穆列藩維。哲兄錫茅土，聖代羅榮滋。", "九卿領徐方，七步繼陳思。伊昔全盛日，雄豪動京師。", "冠劍朝鳳闕，樓船侍龍池。鼓鐘出朱邸，金翠照丹墀。", "君王一顧盼，選色獻蛾眉。列戟十八年，未曾輒遷移。", "大臣小喑嗚，謫竄天南垂。長沙不足舞，貝錦且成詩。", "佐郡浙江西，病閑絕驅馳。階軒日苔蘚，鳥雀噪簷帷。", "時乘平肩輿，出入畏人知。北宅聊偃憩，歡愉恤煢嫠。", "羞言梁苑地，烜赫耀旌旗。兄弟八九人，吳秦各分離。", "大賢達機兆，豈獨慮安危。小子謝麟閣，雁行忝肩隨。", "令弟字延陵，鳳毛出天姿。清英神仙骨，芬馥茝蘭蕤。", "夢得春草句，將非惠連誰。深心紫河車，與我特相宜。", "金膏猶罔象，玉液尚磷緇。伏枕寄賓館，宛同清漳湄。", "藥物多見饋，珍羞亦兼之。誰道溟渤深，猶言淺恩慈。", "鳴蟬遊子意，促織念歸期。驕陽何太赫，海水爍龍龜。", "百川盡凋枯，舟楫閣中逵。策馬搖涼月，通宵出郊圻。", "泣別目眷眷，傷心步遲遲。願言保明德，王室佇清夷。", "摻袂何所道，援毫投此辭。"]'),
('yuding-14','別儲邕之剡中','李白','唐','御定全唐诗','yuding','','[]','借問剡中道，東南指越鄉。舟從廣陵去，水入會稽長。',48,'御定全唐詩/json/174.json','["借問剡中道，東南指越鄉。舟從廣陵去，水入會稽長。", "竹色溪下綠，荷花鏡裏香。辭君向天姥，拂石臥秋霜。"]'),
('yuding-15','留別金陵諸公','李白','唐','御定全唐诗','yuding','','[]','海水昔飛動，三龍紛戰爭。鐘山危波瀾，傾側駭奔鯨。',120,'御定全唐詩/json/174.json','["海水昔飛動，三龍紛戰爭。鐘山危波瀾，傾側駭奔鯨。", "黃旗一掃蕩，割壤開吳京。六代更霸王，遺跡見都城。", "至今秦淮間，禮樂秀群英。地扇鄒魯學，詩騰顏謝名。", "五月金陵西，祖余白下亭。欲尋廬峰頂，先繞漢水行。", "香爐紫煙滅，瀑布落太清。若攀星辰去，揮手緬含情。"]'),
('yuding-16','口號','李白','唐','御定全唐诗','yuding','','[]','食出野田美，酒臨遠水傾。東流若未盡，應見別離情。',24,'御定全唐詩/json/174.json','["食出野田美，酒臨遠水傾。東流若未盡，應見別離情。"]'),
('yuding-17','金陵酒肆留別','李白','唐','御定全唐诗','yuding','','[]','風吹柳花滿店香，吳姬壓酒喚客嘗。金陵子弟來相送，',24,'御定全唐詩/json/174.json','["風吹柳花滿店香，吳姬壓酒喚客嘗。金陵子弟來相送，"]'),
('yuding-18','金陵白下亭留別','李白','唐','御定全唐诗','yuding','','[]','驛亭三楊樹，正當白下門。吳煙暝長條，漢水齧古根。',48,'御定全唐詩/json/174.json','["驛亭三楊樹，正當白下門。吳煙暝長條，漢水齧古根。", "向來送行處，回首阻笑言。別後若見之，為餘一攀翻。"]'),
('yuding-19','別東林寺僧','李白','唐','御定全唐诗','yuding','','[]','東林送客處，月出白猿啼。笑別廬山遠，何煩過虎溪。',24,'御定全唐詩/json/174.json','["東林送客處，月出白猿啼。笑別廬山遠，何煩過虎溪。"]'),
('yuding-20','竄夜郎，于烏江留別宗十六璟','李白','唐','御定全唐诗','yuding','','[]','君家全盛日，台鼎何陸離。斬鼇翼媧皇，煉石補天維。',156,'御定全唐詩/json/174.json','["君家全盛日，台鼎何陸離。斬鼇翼媧皇，煉石補天維。", "一回日月顧，三入鳳凰池。失勢青門傍，種瓜複幾時。", "猶會眾賓客，三千光路歧。皇恩雪憤懣，松柏含榮滋。", "我非東床人，令姊忝齊眉。浪跡未出世，空名動京師。", "適遭雲羅解，翻謫夜郎悲。拙妻莫邪劍，及此二龍隨。", "慚君湍波苦，千里遠從之。白帝曉猿斷，黃牛過客遲。", "遙瞻明月峽，西去益相思。"]'),
('yuding-21','留別龔處士','李白','唐','御定全唐诗','yuding','','[]','龔子棲閑地，都無人世喧。柳深陶令宅，竹暗辟疆園。',48,'御定全唐詩/json/174.json','["龔子棲閑地，都無人世喧。柳深陶令宅，竹暗辟疆園。", "我去黃牛峽，遙愁白帝猿。贈君卷葹草，心斷竟何言。"]'),
('yuding-22','贈別鄭判官','李白','唐','御定全唐诗','yuding','','[]','竄逐勿複哀，慚君問寒灰。浮雲本無意，吹落章華台。',48,'御定全唐詩/json/174.json','["竄逐勿複哀，慚君問寒灰。浮雲本無意，吹落章華台。", "遠別淚空盡，長愁心已摧。二年吟澤畔，憔悴幾時回。"]'),
('yuding-23','黃鶴樓送孟浩然之廣陵','李白','唐','御定全唐诗','yuding','','[]','故人西辭黃鶴樓，煙花三月下揚州。',32,'御定全唐詩/json/174.json','["故人西辭黃鶴樓，煙花三月下揚州。", "孤帆遠影碧山盡，唯見長江天際流。"]'),
('yuding-24','將游衡嶽，過漢陽雙松亭，留別族弟浮屠談皓','李白','唐','御定全唐诗','yuding','','[]','秦欺趙氏璧，卻入邯鄲宮。本是楚家玉，還來荊山中。',132,'御定全唐詩/json/174.json','["秦欺趙氏璧，卻入邯鄲宮。本是楚家玉，還來荊山中。", "丹彩瀉滄溟，精輝淩白虹。青蠅一相點，流落此時同。", "卓絕道門秀，談玄乃支公。延蘿結幽居，剪竹繞芳叢。", "涼花拂戶牖，天籟鳴虛空。憶我初來時，蒲萄開景風。", "今茲大火落，秋葉黃梧桐。水色夢沅湘，長沙去何窮。", "寄書訪衡嶠，但與南飛鴻。"]'),
('yuding-25','留別賈舍人至二首','李白','唐','御定全唐诗','yuding','','[]','大樑白雲起，飄颻來南洲。裴回蒼梧野，十見羅浮秋。',204,'御定全唐詩/json/174.json','["大樑白雲起，飄颻來南洲。裴回蒼梧野，十見羅浮秋。", "鼇抃山海傾，四溟揚洪流。意欲托孤鳳，從之摩天遊。", "鳳苦道路難，翱翔還昆丘。不肯銜我去，哀鳴慚不周。", "遠客謝主人，明珠難暗投。拂拭倚天劍，西登岳陽樓。", "長嘯萬里風，掃清胸中憂。誰念劉越石，化為繞指柔。", "秋風吹胡霜，凋此簷下芳。折芳怨歲晚，離別淒以傷。", "謬攀青瑣賢，延我於北堂。君為長沙客，我獨之夜郎。", "勸此一杯酒，豈惟道路長。割珠兩分贈，寸心貴不忘。", "何必兒女仁，相看淚成行。"]'),
('yuding-26','渡荊門送別','李白','唐','御定全唐诗','yuding','','[]','流遠荊門外，來從楚國遊。山隨平野盡，江入大荒流。',48,'御定全唐詩/json/174.json','["流遠荊門外，來從楚國遊。山隨平野盡，江入大荒流。", "月下飛天鏡，雲生結海樓。仍連故鄉水，萬里送行舟。"]'),
('yuding-27','聞李太尉大舉秦兵百萬出征東南懦夫請纓冀申一割之用半道病還留別金陵崔侍御十九韻','李白','唐','御定全唐诗','yuding','','[]','秦出天下兵，蹴踏燕趙傾。黃河飲馬竭，赤羽連天明。',228,'御定全唐詩/json/174.json','["秦出天下兵，蹴踏燕趙傾。黃河飲馬竭，赤羽連天明。", "太尉杖旄鉞，雲旗繞彭城。三軍受號令，千里肅雷霆。", "函谷絕飛鳥，武關擁連營。意在斬巨鼇，何論鱠長鯨。", "恨無左車略，多愧魯連生。拂劍照嚴霜，雕戈鬘胡纓。", "願雪會稽恥，將期報恩榮。半道謝病還，無因東南征。", "亞夫未見顧，劇孟阻先行。天奪壯士心，長籲別吳京。", "金陵遇太守，倒屣相逢迎。群公咸祖餞，四座羅朝英。", "初發臨滄觀，醉棲征虜亭。舊國見秋月，長江流寒聲。", "帝車信回轉，河漢複縱橫。孤鳳向西海，飛鴻辭北溟。", "因之出寥廓，揮手謝公卿。"]'),
('yuding-28','別韋少府','李白','唐','御定全唐诗','yuding','','[]','西出蒼龍門，南登白鹿原。欲尋商山皓，猶戀漢皇恩。',96,'御定全唐詩/json/174.json','["西出蒼龍門，南登白鹿原。欲尋商山皓，猶戀漢皇恩。", "水國遠行邁，仙經深討論。洗心向溪月，清耳敬亭猿。", "築室在人境，閉門無世喧。多君枉高駕，贈我以微言。", "交乃意氣合，道因風雅存。別離有相思，瑤瑟與金樽。"]'),
('yuding-29','南陵別兒童入京','李白','唐','御定全唐诗','yuding','','[]','白酒新熟山中歸，黃雞啄黍秋正肥。呼童烹雞酌白酒，',48,'御定全唐詩/json/174.json','["白酒新熟山中歸，黃雞啄黍秋正肥。呼童烹雞酌白酒，", "遊說萬乘苦不早，著鞭跨馬涉遠道。會稽愚婦輕買臣，"]'),
('yuding-30','別山僧','李白','唐','御定全唐诗','yuding','','[]','何處名僧到水西，乘舟弄月宿涇溪。平明別我上山去，',48,'御定全唐詩/json/174.json','["何處名僧到水西，乘舟弄月宿涇溪。平明別我上山去，", "謔浪肯居支遁下，風流還與遠公齊。此度別離何日見，"]'),
('yuding-31','贈別王山人歸布山','李白','唐','御定全唐诗','yuding','','[]','王子析道論，微言破秋毫。還歸布山隱，興入天雲高。',84,'御定全唐詩/json/174.json','["王子析道論，微言破秋毫。還歸布山隱，興入天雲高。", "爾去安可遲，瑤草恐衰歇。我心亦懷歸，屢夢松上月。", "傲然遂獨往，長嘯開岩扉。林壑久已蕪，石道生薔薇。", "願言弄笙鶴，歲晚來相依。"]'),
('yuding-32','江夏別宋之悌','李白','唐','御定全唐诗','yuding','','[]','楚水清若空，遙將碧海通。人分千裏外，興在一杯中。',48,'御定全唐詩/json/174.json','["楚水清若空，遙將碧海通。人分千裏外，興在一杯中。", "穀鳥吟晴日，江猿嘯晚風。平生不下淚，於此泣無窮。"]'),
('yuding-0','南陽送客','李白','唐','御定全唐诗','yuding','','[]','鬥酒勿為薄，寸心貴不忘。坐惜故人去，偏令遊子傷。',48,'御定全唐詩/json/175.json','["鬥酒勿為薄，寸心貴不忘。坐惜故人去，偏令遊子傷。", "離顏怨芳草，春思結垂楊。揮手再三別，臨岐空斷腸。"]'),
('yuding-1','送張舍人之江東','李白','唐','御定全唐诗','yuding','','[]','張翰江東去，正值秋風時。天清一雁遠，海闊孤帆遲。',48,'御定全唐詩/json/175.json','["張翰江東去，正值秋風時。天清一雁遠，海闊孤帆遲。", "白日行欲暮，滄波杳難期。吳洲如見月，千里幸相思。"]'),
('yuding-2','送王屋山人魏萬還王屋','李白','唐','御定全唐诗','yuding','','[]','仙人東方生，浩蕩弄雲海。沛然乘天遊，獨往失所在。',576,'御定全唐詩/json/175.json','["仙人東方生，浩蕩弄雲海。沛然乘天遊，獨往失所在。", "魏侯繼大名，本家聊攝城。卷舒入元化，跡與古賢並。", "十三弄文史，揮筆如振綺。辯折田巴生，心齊魯連子。", "西涉清洛源，頗驚人世喧。采秀臥王屋，因窺洞天門。", "朅來遊嵩峰，羽客何雙雙。朝攜月光子，暮宿玉女窗。", "鬼谷上窈窕，龍潭下奔潈。東浮汴河水，訪我三千里。", "逸興滿吳雲，飄颻浙江汜。揮手杭越間，樟亭望潮還。", "濤卷海門石，雲橫天際山。白馬走素車，雷奔駭心顏。", "遙聞會稽美，且度耶溪水。萬壑與千岩，崢嶸鏡湖裏。", "秀色不可名，清輝滿江城。人游月邊去，舟在空中行。", "此中久延佇，入剡尋王許。笑讀曹娥碑，沉吟黃絹語。", "天臺連四明，日入向國清。五峰轉月色，百里行松聲。", "靈溪咨沿越，華頂殊超忽。石樑橫青天，側足履半月。", "忽然思永嘉，不憚海路賒。掛席曆海嶠，回瞻赤城霞。", "赤城漸微沒，孤嶼前嶢兀。水續萬古流，亭空千霜月。", "縉雲川谷難，石門最可觀。瀑布掛北斗，莫窮此水端。", "噴壁灑素雪，空蒙生晝寒。卻思惡溪去，寧懼惡溪惡。", "咆哮七十灘，水石相噴薄。路創李北海，岩開謝康樂。", "松風和猿聲，搜索連洞壑。徑出梅花橋，雙溪納歸潮。", "落帆金華岸，赤松若可招。沈約八詠樓，城西孤岧嶢。", "岧嶢四荒外，曠望群川會。雲卷天地開，波連浙西大。", "亂流新安口，北指嚴光瀨。釣台碧雲中，邈與蒼嶺對。", "稍稍來吳都，裴回上姑蘇。煙綿橫九疑，漭蕩見五湖。", "目極心更遠，悲歌但長籲。回橈楚江濱，揮策揚子津。"]'),
('yuding-3','送當塗趙少府赴長蘆','李白','唐','御定全唐诗','yuding','','[]','我來揚都市，送客回輕舠。因誇楚太子，便睹廣陵濤。',72,'御定全唐詩/json/175.json','["我來揚都市，送客回輕舠。因誇楚太子，便睹廣陵濤。", "仙尉趙家玉，英風淩四豪。維舟至長蘆，目送煙雲高。", "搖扇對酒樓，持袂把蟹螯。前途倘相思，登嶽一長謠。"]'),
('yuding-4','送友人尋越中山水','李白','唐','御定全唐诗','yuding','','[]','聞道稽山去，偏宜謝客才。千岩泉灑落，萬壑樹縈回。',72,'御定全唐詩/json/175.json','["聞道稽山去，偏宜謝客才。千岩泉灑落，萬壑樹縈回。", "東海橫秦望，西陵繞越台。湖清霜鏡曉，濤白雪山來。", "八月枚乘筆，三吳張翰杯。此中多逸興，早晚向天臺。"]'),
('yuding-5','送族弟凝之滁求婚崔氏','李白','唐','御定全唐诗','yuding','','[]','與爾情不淺，忘筌已得魚。玉台掛寶鏡，持此意何如。',48,'御定全唐詩/json/175.json','["與爾情不淺，忘筌已得魚。玉台掛寶鏡，持此意何如。", "坦腹東床下，由來志氣疏。遙知向前路，擲果定盈車。"]'),
('yuding-6','送友人游梅湖','李白','唐','御定全唐诗','yuding','','[]','送君游梅湖，應見梅花發。有使寄我來，無令紅芳歇。',48,'御定全唐詩/json/175.json','["送君游梅湖，應見梅花發。有使寄我來，無令紅芳歇。", "暫行新林浦，定醉金陵月。莫惜一雁書，音塵坐胡越。"]'),
('yuding-7','送崔十二遊天竺寺','李白','唐','御定全唐诗','yuding','','[]','還聞天竺寺，夢想懷東越。每年海樹霜，桂子落秋月。',48,'御定全唐詩/json/175.json','["還聞天竺寺，夢想懷東越。每年海樹霜，桂子落秋月。", "送君遊此地，已屬流芳歇。待我來歲行，相隨浮溟渤。"]'),
('yuding-8','送楊山人歸天臺','李白','唐','御定全唐诗','yuding','','[]','客有思天臺，東行路超忽。濤落浙江秋，沙明浦陽月。',96,'御定全唐詩/json/175.json','["客有思天臺，東行路超忽。濤落浙江秋，沙明浦陽月。", "今游方厭楚，昨夢先歸越。且盡秉燭歡，無辭淩晨發。", "我家小阮賢，剖竹赤城邊。詩人多見重，官燭未曾然。", "興引登山屐，情催泛海船。石橋如可度，攜手弄雲煙。"]'),
('yuding-9','送溫處士歸黃山白鵝峰舊居','李白','唐','御定全唐诗','yuding','','[]','黃山四千仞，三十二蓮峰。丹崖夾石柱，菡萏金芙蓉。',132,'御定全唐詩/json/175.json','["黃山四千仞，三十二蓮峰。丹崖夾石柱，菡萏金芙蓉。", "伊昔升絕頂，下窺天目松。仙人煉玉處，羽化留餘蹤。", "亦聞溫伯雪，獨往今相逢。采秀辭五嶽，攀岩曆萬重。", "歸休白鵝嶺，渴飲丹砂井。鳳吹我時來，雲車爾當整。", "去去陵陽東，行行芳桂叢。回溪十六度，碧嶂盡晴空。", "他日還相訪，乘橋躡彩虹。"]'),
('yuding-10','送方士趙叟之東平','李白','唐','御定全唐诗','yuding','','[]','長桑曉洞視，五藏無全牛。趙叟得秘訣，還從方士游。',48,'御定全唐詩/json/175.json','["長桑曉洞視，五藏無全牛。趙叟得秘訣，還從方士游。", "西過獲麟台，為我吊孔丘。念別複懷古，潸然空淚流。"]'),
('yuding-11','送韓准、裴政、孔巢父還山','李白','唐','御定全唐诗','yuding','','[]','獵客張兔罝，不能掛龍虎。所以青雲人，高歌在岩戶。',144,'御定全唐詩/json/175.json','["獵客張兔罝，不能掛龍虎。所以青雲人，高歌在岩戶。", "韓生信英彥，裴子含清真。孔侯複秀出，俱與雲霞親。", "峻節淩遠松，同衾臥磐石。斧冰嗽寒泉，三子同二屐。", "時時或乘興，往往雲無心。出山揖牧伯，長嘯輕衣簪。", "昨宵夢裏還，雲弄竹溪月。今晨魯東門，帳飲與君別。", "雪崖滑去馬，蘿徑迷歸人。相思若煙草，曆亂無冬春。"]'),
('yuding-12','送楊少府赴選','李白','唐','御定全唐诗','yuding','','[]','大國置衡鏡，准平天地心。群賢無邪人，朗鑒窮情深。',156,'御定全唐詩/json/175.json','["大國置衡鏡，准平天地心。群賢無邪人，朗鑒窮情深。", "吾君詠南風，袞冕彈鳴琴。時泰多美士，京國會纓簪。", "山苗落澗底，幽松出高岑。夫子有盛才，主司得球琳。", "流水非鄭曲，前行遇知音。衣工剪綺繡，一誤傷千金。", "何惜刀尺餘，不裁寒女衾。我非彈冠者，感別但開襟。", "空谷無白駒，賢人豈悲吟。大道安棄物，時來或招尋。", "爾見山吏部，當應無陸沉。"]'),
('yuding-13','對雪奉餞任城六父秩滿歸京','李白','唐','御定全唐诗','yuding','','[]','龍虎謝鞭策，鵷鸞不司晨。君看海上鶴，何似籠中鶉。',144,'御定全唐詩/json/175.json','["龍虎謝鞭策，鵷鸞不司晨。君看海上鶴，何似籠中鶉。", "獨用天地心，浮雲乃吾身。雖將簪組狎，若與煙霞親。", "季父有英風，白眉超常倫。一官即夢寐，脫屣歸西秦。", "竇公敞華筵，墨客盡來臻。燕歌落胡雁，郢曲回陽春。", "征馬百度嘶，游車動行塵。躊躇未忍去，戀此四座人。", "餞離駐高駕，惜別空殷勤。何時竹林下，更與步兵鄰。"]'),
('yuding-14','魯郡堯祠送吳五之琅琊','李白','唐','御定全唐诗','yuding','','[]','堯沒三千歲，青松古廟存。送行奠桂酒，拜舞清心魂。',48,'御定全唐詩/json/175.json','["堯沒三千歲，青松古廟存。送行奠桂酒，拜舞清心魂。", "日色促歸人，連歌倒芳樽。馬嘶俱醉起，分手更何言。"]'),
('yuding-15','魯郡堯祠送竇明府薄華還西京','李白','唐','御定全唐诗','yuding','','[]','朝策犁眉騧，舉鞭力不堪。強扶愁疾向何處，',234,'御定全唐詩/json/175.json','["朝策犁眉騧，舉鞭力不堪。強扶愁疾向何處，", "笑誇故人指絕境，山光水色青于藍。廟中往往來擊鼓，", "銀鞍繡轂往復回，簸林蹶石鳴風雷。遠煙空翠時明滅，", "深沉百丈洞海底，那知不有蛟龍蟠。", "君不見綠珠潭水流東海，綠珠紅粉沉光彩。", "綠珠樓下花滿園，今日曾無一枝在。昨夜秋聲閶闔來，", "生前一笑輕九鼎，魏武何悲銅雀台。我歌白雲倚窗牖，", "酒中樂酣宵向分，舉觴酹堯堯可聞。", "何不令皋繇擁篲橫八極，直上青天揮浮雲。", "高陽小飲真瑣瑣，山公酩酊何如我。竹林七子去道賒，", "爾向西秦我東越，暫向瀛洲訪金闕。藍田太白若可期，"]'),
('yuding-16','金鄉送韋八之西京','李白','唐','御定全唐诗','yuding','','[]','客自長安來，還歸長安去。狂風吹我心，西掛咸陽樹。',48,'御定全唐詩/json/175.json','["客自長安來，還歸長安去。狂風吹我心，西掛咸陽樹。", "此情不可道，此別何時遇。望望不見君，連山起煙霧。"]'),
('yuding-17','送薛九被讒去魯','李白','唐','御定全唐诗','yuding','','[]','宋人不辨玉，魯賤東家丘。我笑薛夫子，胡為兩地遊。',192,'御定全唐詩/json/175.json','["宋人不辨玉，魯賤東家丘。我笑薛夫子，胡為兩地遊。", "黃金消眾口，白璧竟難投。梧桐生蒺藜，綠竹乏佳實。", "鳳凰宿誰家，遂與群雞匹。田家養老馬，窮士歸其門。", "蛾眉笑躃者，賓客去平原。卻斬美人首，三千還駿奔。", "毛公一挺劍，楚趙兩相存。孟嘗習狡兔，三窟賴馮諼。", "信陵奪兵符，為用侯生言。春申一何愚，刎首為李園。", "賢哉四公子，撫掌黃泉裏。借問笑何人，笑人不好士。", "爾去且勿喧，桃李竟何言。沙丘無漂母，誰肯飯王孫。"]'),
('yuding-18','單父東樓秋夜送族弟沈之秦','李白','唐','御定全唐诗','yuding','','[]','爾從咸陽來，問我何勞苦。沐猴而冠不足言，',114,'御定全唐詩/json/175.json','["爾從咸陽來，問我何勞苦。沐猴而冠不足言，", "坐來黃葉落四五，北斗已掛西城樓。絲桐感人弦亦絕，", "明日鬥酒別，惆悵清路塵。遙望長安日，不見長安人。", "長安宮闕九天上，此地曾經為近臣。一朝複一朝，", "折翮翻飛隨轉蓬，聞弦墜虛下霜空。聖朝久棄青雲士，"]'),
('yuding-19','送族弟凝至晏堌','李白','唐','御定全唐诗','yuding','','[]','雪滿原野白，戎裝出盤遊。揮鞭布獵騎，四顧登高丘。',84,'御定全唐詩/json/175.json','["雪滿原野白，戎裝出盤遊。揮鞭布獵騎，四顧登高丘。", "兔起馬足間，蒼鷹下平疇。喧呼相馳逐，取樂銷人憂。", "舍此戒禽荒，微聲列齊謳。鳴雞發晏堌，別雁驚淶溝。", "西行有東音，寄與長河流。"]'),
('yuding-20','魯城北郭曲腰桑下送張子還嵩陽','李白','唐','御定全唐诗','yuding','','[]','送別枯桑下，凋葉落半空。我行懵道遠，爾獨知天風。',48,'御定全唐詩/json/175.json','["送別枯桑下，凋葉落半空。我行懵道遠，爾獨知天風。", "誰念張仲蔚，還依蒿與蓬。何時一杯酒，更與李膺同。"]'),
('yuding-0','送魯郡劉長史遷弘農長史','李白','唐','御定全唐诗','yuding','','[]','魯國一杯水，難容橫海鱗。仲尼且不敬，況乃尋常人。',156,'御定全唐詩/json/176.json','["魯國一杯水，難容橫海鱗。仲尼且不敬，況乃尋常人。", "白玉換鬥粟，黃金買尺薪。閉門木葉下，始覺秋非春。", "聞君向西遷，地即鼎湖鄰。寶鏡匣蒼蘚，丹經埋素塵。", "軒後上天時，攀龍遺小臣。及此留惠愛，庶幾風化淳。", "魯縞如白煙，五縑不成束。臨行贈貧交，一尺重山嶽。", "相國齊晏子，贈行不及言。托陰當樹李，忘憂當樹萱。", "他日見張祿，綈袍懷舊恩。"]'),
('yuding-1','送族弟單父主簿凝攝宋城主簿至郭南月橋却迴棲霞山留飲贈之','李白','唐','御定全唐诗','yuding','','[]','吾家青萍劍，操割有餘閑。往來糾二邑，此去何時還。',72,'御定全唐詩/json/176.json','["吾家青萍劍，操割有餘閑。往來糾二邑，此去何時還。", "鞍馬月橋南，光輝歧路間。賢豪相追餞，卻到棲霞山。", "群花散芳園，鬥酒開離顏。樂酣相顧起，征馬無由攀。"]'),
('yuding-2','魯郡東石門送杜二甫','李白','唐','御定全唐诗','yuding','','[]','醉別複幾日，登臨遍池台。何時石門路，重有金樽開。',48,'御定全唐詩/json/176.json','["醉別複幾日，登臨遍池台。何時石門路，重有金樽開。", "秋波落泗水，海色明徂徠。飛蓬各自遠，且盡手中杯。"]'),
('yuding-3','魯郡堯祠送張十四游河北','李白','唐','御定全唐诗','yuding','','[]','猛虎伏尺草，雖藏難蔽身。有如張公子，骯髒在風塵。',60,'御定全唐詩/json/176.json','["猛虎伏尺草，雖藏難蔽身。有如張公子，骯髒在風塵。", "豈無橫腰劍，屈彼淮陰人。擊築向北燕，燕歌易水濱。", "歸來泰山上，當與爾為鄰。"]'),
('yuding-4','杭州送裴大澤赴廬州長史','李白','唐','御定全唐诗','yuding','','[]','西江天柱遠，東越海門深。去割慈親戀，行憂報國心。',48,'御定全唐詩/json/176.json','["西江天柱遠，東越海門深。去割慈親戀，行憂報國心。", "好風吹落日，流水引長吟。五月披裘者，應知不取金。"]'),
('yuding-5','灞陵行送別','李白','唐','御定全唐诗','yuding','','[]','送君灞陵亭，灞水流浩浩。上有無花之古樹，',20,'御定全唐詩/json/176.json','["送君灞陵亭，灞水流浩浩。上有無花之古樹，"]'),
('yuding-6','送賀監歸四明應制','李白','唐','御定全唐诗','yuding','','[]','久辭榮祿遂初衣，曾向長生說息機。真訣自從茅氏得，',40,'御定全唐詩/json/176.json','["久辭榮祿遂初衣，曾向長生說息機。真訣自從茅氏得，", "借問欲棲珠樹鶴，何年卻向帝城飛。"]'),
('yuding-7','送竇司馬貶宜春','李白','唐','御定全唐诗','yuding','','[]','天馬白銀鞍，親承明主歡。鬥雞金宮裏，射雁碧雲端。',72,'御定全唐詩/json/176.json','["天馬白銀鞍，親承明主歡。鬥雞金宮裏，射雁碧雲端。", "堂上羅中貴，歌鐘清夜闌。何言謫南國，拂劍坐長歎。", "趙璧為誰點，隋珠枉被彈。聖朝多雨露，莫厭此行難。"]'),
('yuding-8','送羽林陶將軍','李白','唐','御定全唐诗','yuding','','[]','將軍出使擁樓船，江上旌旗拂紫煙。萬里橫戈探虎穴，',24,'御定全唐詩/json/176.json','["將軍出使擁樓船，江上旌旗拂紫煙。萬里橫戈探虎穴，"]'),
('yuding-9','送程、劉二侍郎兼獨孤判官赴安西幕府','李白','唐','御定全唐诗','yuding','','[]','安西幕府多材雄，喧喧惟道三數公。繡衣貂裘明積雪，',48,'御定全唐詩/json/176.json','["安西幕府多材雄，喧喧惟道三數公。繡衣貂裘明積雪，", "天外飛霜下蔥海，火旗雲馬生光彩。胡塞清塵幾日歸，"]'),
('yuding-10','送侄良攜二妓赴會稽，戲有此贈','李白','唐','御定全唐诗','yuding','','[]','攜妓東山去，春光半道催。遙看若桃李，雙入鏡中開。',24,'御定全唐詩/json/176.json','["攜妓東山去，春光半道催。遙看若桃李，雙入鏡中開。"]'),
('yuding-11','送賀賓客歸越','李白','唐','御定全唐诗','yuding','','[]','鏡湖流水漾清波，狂客歸舟逸興多。',32,'御定全唐詩/json/176.json','["鏡湖流水漾清波，狂客歸舟逸興多。", "山陰道士如相見，應寫黃庭換白鵝。"]'),
('yuding-12','送張遙之壽陽幕府','李白','唐','御定全唐诗','yuding','','[]','壽陽信天險，天險橫荊關。苻堅百萬眾，遙阻八公山。',84,'御定全唐詩/json/176.json','["壽陽信天險，天險橫荊關。苻堅百萬眾，遙阻八公山。", "不假築長城，大賢在其間。戰夫若熊虎，破敵有餘閑。", "張子勇且英，少輕衛霍孱。投軀紫髯將，千里望風顏。", "勖爾效才略，功成衣錦還。"]'),
('yuding-13','送裴十八圖南歸嵩山二首','李白','唐','御定全唐诗','yuding','','[]','何處可為別，長安青綺門。胡姬招素手，延客醉金樽。',120,'御定全唐詩/json/176.json','["何處可為別，長安青綺門。胡姬招素手，延客醉金樽。", "臨當上馬時，我獨與君言。風吹芳蘭折，日沒鳥雀喧。", "舉手指飛鴻，此情難具論。同歸無早晚，潁水有清源。", "君思潁水綠，忽複歸嵩岑。歸時莫洗耳，為我洗其心。", "洗心得真情，洗耳徒買名。謝公終一起，相與濟蒼生。"]'),
('yuding-14','同王昌齡送族弟襄歸桂陽二首','李白','唐','御定全唐诗','yuding','','[]','秦地見碧草，楚謠對清樽。把酒爾何思，鷓鴣啼南園。',120,'御定全唐詩/json/176.json','["秦地見碧草，楚謠對清樽。把酒爾何思，鷓鴣啼南園。", "余欲羅浮隱，猶懷明主恩。躊躇紫宮戀，孤負滄洲言。", "終然無心雲，海上同飛翻。相期乃不淺，幽桂有芳根。", "爾家何在瀟湘川，青莎白石長沙邊。昨夢江花照江日，", "秦雲連山海相接，桂水橫煙不可涉。送君此去令人愁，"]'),
('yuding-15','送外甥鄭灌從軍三首','李白','唐','御定全唐诗','yuding','','[]','六博爭雄好彩來，金盤一擲萬人開。',96,'御定全唐詩/json/176.json','["六博爭雄好彩來，金盤一擲萬人開。", "丈夫賭命報天子，當斬胡頭衣錦回。", "丈八蛇予出隴西，彎弧拂箭白猿啼。", "破胡必用龍韜策，積甲應將熊耳齊。", "月蝕西方破敵時，及瓜歸日未應遲。", "斬胡血變黃河水，梟首當懸白鵲旗。"]'),
('yuding-16','送于十八應四子舉落第還嵩山','李白','唐','御定全唐诗','yuding','','[]','吾祖吹橐鑰，天人信森羅。歸根複太素，群動熙元和。',108,'御定全唐詩/json/176.json','["吾祖吹橐鑰，天人信森羅。歸根複太素，群動熙元和。", "炎炎四真人，摛辯若濤波。交流無時寂，楊墨日成科。", "夫子聞洛誦，誇才才固多。為金好踴躍，久客方蹉跎。", "道可束賣之，五寶溢山河。勸君還嵩丘，開酌盼庭柯。", "三花如未落，乘興一來過。"]'),
('yuding-17','送別','李白','唐','御定全唐诗','yuding','','[]','尋陽五溪水，沿洄直入巫山裏。勝境由來人共傳，',38,'御定全唐詩/json/176.json','["尋陽五溪水，沿洄直入巫山裏。勝境由來人共傳，", "雲帆望遠不相見，日暮長江空自流。"]'),
('yuding-18','送族弟綰從軍安西','李白','唐','御定全唐诗','yuding','','[]','漢家兵馬乘北風，鼓行而西破犬戎。爾隨漢將出門去，',40,'御定全唐詩/json/176.json','["漢家兵馬乘北風，鼓行而西破犬戎。爾隨漢將出門去，", "匈奴系頸數應盡，明年應入蒲萄宮。"]'),
('yuding-19','送梁公昌從信安北征','李白','唐','御定全唐诗','yuding','','[]','入幕推英選，捐書事遠戎。高談百戰術，郁作萬夫雄。',72,'御定全唐詩/json/176.json','["入幕推英選，捐書事遠戎。高談百戰術，郁作萬夫雄。", "起舞蓮花劍，行歌明月弓。將飛天地陣，兵出塞垣通。", "祖席留丹景，征麾拂彩虹。旋應獻凱入，麟閣佇深功。"]'),
('yuding-20','送白利從金吾董將軍西征','李白','唐','御定全唐诗','yuding','','[]','西羌延國討，白起佐軍威。劍決浮雲氣，弓彎明月輝。',48,'御定全唐詩/json/176.json','["西羌延國討，白起佐軍威。劍決浮雲氣，弓彎明月輝。", "馬行邊草綠，旌卷曙霜飛。抗手凜相顧，寒風生鐵衣。"]'),
('yuding-21','送張秀才從軍','李白','唐','御定全唐诗','yuding','','[]','六駁食猛虎，恥從駑馬群。一朝長鳴去，矯若龍行雲。',84,'御定全唐詩/json/176.json','["六駁食猛虎，恥從駑馬群。一朝長鳴去，矯若龍行雲。", "壯士懷遠略，志存解世紛。周粟猶不顧，齊珪安肯分。", "抱劍辭高堂，將投崔冠軍。長策掃河洛，寧親歸汝墳。", "當令千古後，麟閣著奇勳。"]'),
('yuding-22','送崔度還吳','李白','唐','御定全唐诗','yuding','','[]','幽燕沙雪地，萬里盡黃雲。朝吹歸秋雁，南飛日幾群。',96,'御定全唐詩/json/176.json','["幽燕沙雪地，萬里盡黃雲。朝吹歸秋雁，南飛日幾群。", "中有孤鳳雛，哀鳴九天聞。我乃重此鳥，彩章五色分。", "胡為雜凡禽，雛鶩輕賤君。舉手捧爾足，疾心若火焚。", "拂羽淚滿面，送之吳江濆。去影忽不見，躊躇日將曛。"]'),
('yuding-23','送祝八之江東，賦得浣紗石','李白','唐','御定全唐诗','yuding','','[]','西施越溪女，明豔光雲海。未入吳王宮殿時，',44,'御定全唐詩/json/176.json','["西施越溪女，明豔光雲海。未入吳王宮殿時，", "昔時紅粉照流水，今日青苔覆落花。君去西秦適東越，"]'),
('yuding-24','送侯十一','李白','唐','御定全唐诗','yuding','','[]','朱亥已擊晉，侯嬴尚隱身。時無魏公子，豈貴抱關人。',48,'御定全唐詩/json/176.json','["朱亥已擊晉，侯嬴尚隱身。時無魏公子，豈貴抱關人。", "餘亦不火食，游梁同在陳。空餘湛盧劍，贈爾托交親。"]'),
('yuding-25','魯中送二從弟赴舉之西京','李白','唐','御定全唐诗','yuding','','[]','魯客向西笑，君門若夢中。霜凋逐臣發，日憶明光宮。',72,'御定全唐詩/json/176.json','["魯客向西笑，君門若夢中。霜凋逐臣發，日憶明光宮。", "複羨二龍去，才華冠世雄。平衢騁高足，逸翰淩長風。", "舞袖拂秋月，歌筵聞早鴻。送君日千里，良會何由同。"]'),
('yuding-26','奉餞高尊師如貴道士傳道籙畢歸北海','李白','唐','御定全唐诗','yuding','','[]','道隱不可見，靈書藏洞天。吾師四萬劫，曆世遞相傳。',48,'御定全唐詩/json/176.json','["道隱不可見，靈書藏洞天。吾師四萬劫，曆世遞相傳。", "別杖留青竹，行歌躡紫煙。離心無遠近，長在玉京懸。"]'),
('yuding-27','金陵送張十一再游東吳','李白','唐','御定全唐诗','yuding','','[]','張翰黃花句，風流五百年。誰人今繼作，夫子世稱賢。',72,'御定全唐詩/json/176.json','["張翰黃花句，風流五百年。誰人今繼作，夫子世稱賢。", "再動游吳棹，還浮入海船。春光白門柳，霞色赤城天。", "去國難為別，思歸各未旋。空餘賈生淚，相顧共淒然。"]'),
('yuding-28','送紀秀才游越','李白','唐','御定全唐诗','yuding','','[]','海水不滿眼，觀濤難稱心。即知蓬萊石，卻是巨鼇簪。',72,'御定全唐詩/json/176.json','["海水不滿眼，觀濤難稱心。即知蓬萊石，卻是巨鼇簪。", "送爾游華頂，令餘發舄吟。仙人居射的，道士住山陰。", "禹穴尋溪入，雲門隔嶺深。綠蘿秋月夜，相憶在鳴琴。"]'),
('yuding-29','送長沙陳太守二首','李白','唐','御定全唐诗','yuding','','[]','長沙陳太守，逸氣淩青松。英主賜五馬，本是天池龍。',96,'御定全唐詩/json/176.json','["長沙陳太守，逸氣淩青松。英主賜五馬，本是天池龍。", "湘水回九曲，衡山望五峰。榮君按節去，不及遠相從。", "七郡長沙國，南連湘水濱。定王垂舞袖，地窄不回身。", "莫小二千石，當安遠俗人。洞庭鄉路遠，遙羨錦衣春。"]'),
('yuding-30','送楊燕之東魯','李白','唐','御定全唐诗','yuding','','[]','關西楊伯起，漢日舊稱賢。四代三公族，清風播人天。',108,'御定全唐詩/json/176.json','["關西楊伯起，漢日舊稱賢。四代三公族，清風播人天。", "夫子華陰居，開門對玉蓮。何事曆衡霍，雲帆今始還。", "君坐稍解顏，為君歌此篇。我固侯門士，謬登聖主筵。", "一辭金華殿，蹭蹬長江邊。二子魯門東，別來已經年。", "因君此中去，不覺淚如泉。"]'),
('yuding-31','送蔡山人','李白','唐','御定全唐诗','yuding','','[]','我本不棄世，世人自棄我。一乘無倪舟，八極縱遠舵。',60,'御定全唐詩/json/176.json','["我本不棄世，世人自棄我。一乘無倪舟，八極縱遠舵。", "燕客期躍馬，唐生安敢譏。采珠勿驚龍，大道可暗歸。", "故山有松月，遲爾玩清暉。"]'),
('yuding-32','送蕭三十一之魯中，兼問稚子伯禽','李白','唐','御定全唐诗','yuding','','[]','六月南風吹白沙，吳牛喘月氣成霞。水國鬱蒸不可處，',48,'御定全唐詩/json/176.json','["六月南風吹白沙，吳牛喘月氣成霞。水國鬱蒸不可處，", "高堂倚門望伯魚，魯中正是趨庭處。我家寄在沙丘傍，"]'),
('yuding-33','送楊山人歸嵩山','李白','唐','御定全唐诗','yuding','','[]','我有萬古宅，嵩陽玉女峰。長留一片月，掛在東溪松。',48,'御定全唐詩/json/176.json','["我有萬古宅，嵩陽玉女峰。長留一片月，掛在東溪松。", "爾去掇仙草，菖蒲花紫茸。歲晚或相訪，青天騎白龍。"]'),
('yuding-34','送殷淑三首','李白','唐','御定全唐诗','yuding','','[]','海水不可解，連江夜為潮。俄然浦嶼闊，岸去酒船遙。',120,'御定全唐詩/json/176.json','["海水不可解，連江夜為潮。俄然浦嶼闊，岸去酒船遙。", "惜別耐取醉，鳴榔且長謠。天明爾當去，應便有風飄。", "白鷺洲前月，天明送客回。青龍山后日，早出海雲來。", "流水無情去，征帆逐吹開。相看不忍別，更進手中杯。", "痛飲龍筇下，燈青月複寒。醉歌驚白鷺，半夜起沙灘。"]'),
('yuding-35','送岑征君歸鳴皋山','李白','唐','御定全唐诗','yuding','','[]','岑公相門子，雅望歸安石。奕世皆夔龍，中台竟三拆。',144,'御定全唐詩/json/176.json','["岑公相門子，雅望歸安石。奕世皆夔龍，中台竟三拆。", "至人達機兆，高揖九州伯。奈何天地間，而作隱淪客。", "貴道能全真，潛輝臥幽鄰。探元入窅默，觀化遊無垠。", "光武有天下，嚴陵為故人。雖登洛陽殿，不屈巢由身。", "余亦謝明主，今稱偃蹇臣。登高覽萬古，思與廣成鄰。", "蹈海寧受賞，還山非問津。西來一搖扇，共拂元規塵。"]'),
('yuding-36','送範山人歸泰山','李白','唐','御定全唐诗','yuding','','[]','魯客抱白鶴，別余往泰山。初行若片雲，杳在青崖間。',48,'御定全唐詩/json/176.json','["魯客抱白鶴，別余往泰山。初行若片雲，杳在青崖間。", "高高至天門，日觀近可攀。雲山望不及，此去何時還。"]'),
('yuding-0','送韓侍禦之廣德','李白','唐','御定全唐诗','yuding','','[]','昔日繡衣何足榮，今宵貰酒與君傾。',32,'御定全唐詩/json/177.json','["昔日繡衣何足榮，今宵貰酒與君傾。", "暫就東山賒月色，酣歌一夜送泉明。"]'),
('yuding-1','送通禪師還南陵隱靜寺','李白','唐','御定全唐诗','yuding','','[]','我聞隱靜寺，山水多奇蹤。岩種朗公橘，門深杯渡松。',48,'御定全唐詩/json/177.json','["我聞隱靜寺，山水多奇蹤。岩種朗公橘，門深杯渡松。", "道人制猛虎，振錫還孤峰。他日南陵下，相期穀口逢。"]'),
('yuding-2','送友人','李白','唐','御定全唐诗','yuding','','[]','青山橫北郭，白水繞東城。此地一為別，孤蓬萬里征。',48,'御定全唐詩/json/177.json','["青山橫北郭，白水繞東城。此地一為別，孤蓬萬里征。", "浮雲遊子意，落日故人情。揮手自茲去，蕭蕭班馬鳴。"]'),
('yuding-3','送別','李白','唐','御定全唐诗','yuding','','[]','鬥酒渭城邊，壚頭醉不眠。梨花千樹雪，楊葉萬條煙。',48,'御定全唐詩/json/177.json','["鬥酒渭城邊，壚頭醉不眠。梨花千樹雪，楊葉萬條煙。", "惜別傾壺醑，臨分贈馬鞭。看君潁上去，新月到應圓。"]'),
('yuding-4','江上送女道士褚三清遊南嶽','李白','唐','御定全唐诗','yuding','','[]','吳江女道士，頭戴蓮花巾。霓衣不濕雨，特異陽臺雲。',48,'御定全唐詩/json/177.json','["吳江女道士，頭戴蓮花巾。霓衣不濕雨，特異陽臺雲。", "足下遠遊履，淩波生素塵。尋仙向南嶽，應見魏夫人。"]'),
('yuding-5','送友人入蜀','李白','唐','御定全唐诗','yuding','','[]','見說蠶叢路，崎嶇不易行。山從人面起，雲傍馬頭生。',48,'御定全唐詩/json/177.json','["見說蠶叢路，崎嶇不易行。山從人面起，雲傍馬頭生。", "芳樹籠秦棧，春流繞蜀城。升沉應已定，不必問君平。"]'),
('yuding-6','送李青歸南葉陽川','李白','唐','御定全唐诗','yuding','','[]','伯陽仙家子，容色如青春。日月秘靈洞，雲霞辭世人。',48,'御定全唐詩/json/177.json','["伯陽仙家子，容色如青春。日月秘靈洞，雲霞辭世人。", "化心養精魄，隱幾窅天真。莫作千年別，歸來城郭新。"]'),
('yuding-7','送舍弟','李白','唐','御定全唐诗','yuding','','[]','吾家白額駒，遠別臨東道。他日相思一夢君，',20,'御定全唐詩/json/177.json','["吾家白額駒，遠別臨東道。他日相思一夢君，"]'),
('yuding-8','送別得書字','李白','唐','御定全唐诗','yuding','','[]','水色南天遠，舟行若在虛。遷人發佳興，吾子訪閒居。',48,'御定全唐詩/json/177.json','["水色南天遠，舟行若在虛。遷人發佳興，吾子訪閒居。", "日落看歸鳥，潭澄羨躍魚。聖朝思賈誼，應降紫泥書。"]'),
('yuding-9','送麹十少府','李白','唐','御定全唐诗','yuding','','[]','試發清秋興，因為吳會吟。碧雲斂海色，流水折江心。',48,'御定全唐詩/json/177.json','["試發清秋興，因為吳會吟。碧雲斂海色，流水折江心。", "我有延陵劍，君無陸賈金。艱難此為別，惆悵一何深。"]'),
('yuding-10','送張秀才謁高中丞','李白','唐','御定全唐诗','yuding','','[]','秦帝淪玉鏡，留侯降氛氳。感激黃石老，經過滄海君。',156,'御定全唐詩/json/177.json','["秦帝淪玉鏡，留侯降氛氳。感激黃石老，經過滄海君。", "壯士揮金槌，報仇六國聞。智勇冠終古，蕭陳難與群。", "兩龍爭鬥時，天地動風雲。酒酣舞長劍，倉卒解漢紛。", "宇宙初倒懸，鴻溝勢將分。英謀信奇絕，夫子揚清芬。", "胡月入紫微，三光亂天文。高公鎮淮海，談笑卻妖氛。", "采爾幕中畫，戡難光殊勳。我無燕霜感，玉石俱燒焚。", "但灑一行淚，臨歧竟何雲。"]'),
('yuding-11','尋陽送弟昌峒鄱陽司馬作','李白','唐','御定全唐诗','yuding','','[]','桑落洲渚連，滄江無雲煙。尋陽非剡水，忽見子猷船。',156,'御定全唐詩/json/177.json','["桑落洲渚連，滄江無雲煙。尋陽非剡水，忽見子猷船。", "飄然欲相近，來遲杳若仙。人乘海上月，帆落湖中天。", "一睹無二諾，朝歡更勝昨。爾則吾惠連，吾非爾康樂。", "朱紱白銀章，上官佐鄱陽。松門拂中道，石鏡回清光。", "搖扇及于越，水亭風氣涼。與爾期此亭，期在秋月滿。", "時過或未來，兩鄉心已斷。吳山對楚岸，彭蠡當中州。", "相思定如此，有窮盡年愁。"]'),
('yuding-12','餞校書叔雲','李白','唐','御定全唐诗','yuding','','[]','少年費白日，歌笑矜朱顏。不知忽已老，喜見春風還。',60,'御定全唐詩/json/177.json','["少年費白日，歌笑矜朱顏。不知忽已老，喜見春風還。", "惜別且為歡，裴回桃李間。看花飲美酒，聽鳥臨晴山。", "向晚竹林寂，無人空閉關。"]'),
('yuding-13','送王孝廉覲省','李白','唐','御定全唐诗','yuding','','[]','彭蠡將天合，姑蘇在日邊。寧親候海色，欲動孝廉船。',48,'御定全唐詩/json/177.json','["彭蠡將天合，姑蘇在日邊。寧親候海色，欲動孝廉船。", "窈窕晴江轉，參差遠岫連。相思無晝夜，東泣似長川。"]'),
('yuding-14','同吳王送杜秀芝赴舉入京','李白','唐','御定全唐诗','yuding','','[]','秀才何翩翩，王許回也賢。暫別廬江守，將遊京兆天。',48,'御定全唐詩/json/177.json','["秀才何翩翩，王許回也賢。暫別廬江守，將遊京兆天。", "秋山宜落日，秀水出寒煙。欲折一枝桂，還來雁沼前。"]'),
('yuding-15','洞庭醉後送絳州呂使君果流澧州','李白','唐','御定全唐诗','yuding','','[]','昔別若夢中，天涯忽相逢。洞庭破秋月，縱酒開愁容。',48,'御定全唐詩/json/177.json','["昔別若夢中，天涯忽相逢。洞庭破秋月，縱酒開愁容。", "贈劍刻玉字，延平兩蛟龍。送君不盡意，書及雁回峰。"]'),
('yuding-16','與諸公送陳郎將歸衡陽','李白','唐','御定全唐诗','yuding','','[]','衡山蒼蒼入紫冥，下看南極老人星。回飆吹散五峰雪，',48,'御定全唐詩/json/177.json','["衡山蒼蒼入紫冥，下看南極老人星。回飆吹散五峰雪，", "門前食客亂浮雲，世人皆比孟嘗君。江上送行無白璧，"]'),
('yuding-17','送趙判官赴黔府中丞叔幕','李白','唐','御定全唐诗','yuding','','[]','廓落青雲心，交結黃金盡。富貴翻相忘，令人忽自哂。',144,'御定全唐詩/json/177.json','["廓落青雲心，交結黃金盡。富貴翻相忘，令人忽自哂。", "蹭蹬鬢毛斑，盛時難再還。巨源咄石生，何事馬蹄間。", "綠蘿長不厭，卻欲還東山。君為魯曾子，拜揖高堂裏。", "叔繼趙平原，偏承明主恩。風霜推獨坐，旌節鎮雄藩。", "虎士秉金鉞，蛾眉開玉樽。才高幕下去，義重林中言。", "水宿五溪月，霜啼三峽猿。東風春草綠，江上候歸軒。"]'),
('yuding-18','送陸判官往琵琶峽','李白','唐','御定全唐诗','yuding','','[]','水國秋風夜，殊非遠別時。長安如夢裏，何日是歸期。',24,'御定全唐詩/json/177.json','["水國秋風夜，殊非遠別時。長安如夢裏，何日是歸期。"]'),
('yuding-19','送梁四歸東平','李白','唐','御定全唐诗','yuding','','[]','玉壺挈美酒，送別強為歡。大火南星月，長郊北路難。',48,'御定全唐詩/json/177.json','["玉壺挈美酒，送別強為歡。大火南星月，長郊北路難。", "殷王期負鼎，汶水起垂竿。莫學東山臥，參差老謝安。"]'),
('yuding-20','江夏送友人','李白','唐','御定全唐诗','yuding','','[]','雪點翠雲裘，送君黃鶴樓。黃鶴振玉羽，西飛帝王州。',48,'御定全唐詩/json/177.json','["雪點翠雲裘，送君黃鶴樓。黃鶴振玉羽，西飛帝王州。", "鳳無琅玕實，何以贈遠遊。裴回相顧影，淚下漢江流。"]'),
('yuding-21','送郤昂謫巴中','李白','唐','御定全唐诗','yuding','','[]','瑤草寒不死，移植滄江濱。東風灑雨露，會入天地春。',48,'御定全唐詩/json/177.json','["瑤草寒不死，移植滄江濱。東風灑雨露，會入天地春。", "予若洞庭葉，隨波送逐臣。思歸未可得，書此謝情人。"]'),
('yuding-22','江夏送張丞','李白','唐','御定全唐诗','yuding','','[]','欲別心不忍，臨行情更親。酒傾無限月，客醉幾重春。',48,'御定全唐詩/json/177.json','["欲別心不忍，臨行情更親。酒傾無限月，客醉幾重春。", "藉草依流水，攀花贈遠人。送君從此去，回首泣迷津。"]'),
('yuding-23','賦得白鷺鷥，送宋少府入三峽','李白','唐','御定全唐诗','yuding','','[]','白鷺拳一足，月明秋水寒。人驚遠飛去，直向使君灘。',24,'御定全唐詩/json/177.json','["白鷺拳一足，月明秋水寒。人驚遠飛去，直向使君灘。"]'),
('yuding-24','送二季之江東','李白','唐','御定全唐诗','yuding','','[]','初發強中作，題詩與惠連。多慚一日長，不及二龍賢。',72,'御定全唐詩/json/177.json','["初發強中作，題詩與惠連。多慚一日長，不及二龍賢。", "西塞當中路，南風欲進船。雲峰出遠海，帆影掛清川。", "禹穴藏書地，匡山種杏田。此行俱有適，遲爾早歸旋。"]'),
('yuding-25','江西送友人之羅浮','李白','唐','御定全唐诗','yuding','','[]','桂水分五嶺，衡山朝九疑。鄉關渺安西，流浪將何之。',96,'御定全唐詩/json/177.json','["桂水分五嶺，衡山朝九疑。鄉關渺安西，流浪將何之。", "素色愁明湖，秋渚晦寒姿。疇昔紫芳意，已過黃發期。", "君王縱疏散，雲壑借巢夷。爾去之羅浮，我還憩峨眉。", "中闊道萬里，霞月遙相思。如尋楚狂子，瓊樹有芳枝。"]'),
('yuding-26','宣州謝脁樓餞別校書叔雲','李白','唐','御定全唐诗','yuding','','[]','棄我去者昨日之日不可留，亂我心者今日之日多煩憂。',72,'御定全唐詩/json/177.json','["棄我去者昨日之日不可留，亂我心者今日之日多煩憂。", "長風萬里送秋雁，對此可以酣高樓。蓬萊文章建安骨，", "抽刀斷水水更流，舉懷銷愁愁更愁。人生在世不稱意，"]'),
('yuding-27','宣城送劉副使入秦','李白','唐','御定全唐诗','yuding','','[]','君即劉越石，雄豪冠當時。淒清橫吹曲，慷慨扶風詞。',252,'御定全唐詩/json/177.json','["君即劉越石，雄豪冠當時。淒清橫吹曲，慷慨扶風詞。", "虎嘯俟騰躍，雞鳴遭亂離。千金市駿馬，萬里逐王師。", "結交樓煩將，侍從羽林兒。統兵捍吳越，豺虎不敢窺。", "大勳竟莫敘，已過秋風吹。秉鉞有季公，凜然負英姿。", "寄深且戎幕，望重必台司。感激一然諾，縱橫兩無疑。", "伏奏歸北闕，鳴騶忽西馳。列將咸出祖，英僚惜分離。", "鬥酒滿四筵，歌嘯宛溪湄。君攜東山妓，我詠北門詩。", "貴賤交不易，恐傷中園葵。昔贈紫騮駒，今傾白玉卮。", "同歡萬斛酒，未足解相思。此別又千里，秦吳渺天涯。", "月明關山苦，水劇隴頭悲。借問幾時還，春風入黃池。", "無令長相憶，折斷綠楊枝。"]'),
('yuding-28','涇川送族弟錞','李白','唐','御定全唐诗','yuding','','[]','涇川三百里，若耶羞見之。錦石照碧山，兩邊白鷺鷥。',192,'御定全唐詩/json/177.json','["涇川三百里，若耶羞見之。錦石照碧山，兩邊白鷺鷥。", "佳境千萬曲，客行無歇時。上有琴高水，下有陵陽祠。", "仙人不見我，明月空相知。問我何事來，盧敖結幽期。", "蓬山振雄筆，繡服揮清詞。江湖發秀色，草木含榮滋。", "置酒送惠連，吾家稱白眉。愧無海嶠作，敢闕河梁詩。", "見爾複幾朝，俄然告將離。中流漾彩鷁，列岸叢金羈。", "歎息蒼梧鳳，分棲瓊樹枝。清晨各飛去，飄落天南垂。", "望極落日盡，秋深暝猿悲。寄情與流水，但有長相思。"]'),
('yuding-29','五松山送殷淑','李白','唐','御定全唐诗','yuding','','[]','秀色發江左，風流奈若何。仲文了不還，獨立揚清波。',72,'御定全唐詩/json/177.json','["秀色發江左，風流奈若何。仲文了不還，獨立揚清波。", "載酒五松山，頹然白雲歌。中天度落月，萬里遙相過。", "撫酒惜此月，流光畏蹉跎。明日別離去，連峰鬱嵯峨。"]'),
('yuding-30','送崔氏昆季之金陵','李白','唐','御定全唐诗','yuding','','[]','放歌倚東樓，行子期曉發。秋風渡江來，吹落山上月。',96,'御定全唐詩/json/177.json','["放歌倚東樓，行子期曉發。秋風渡江來，吹落山上月。", "主人出美酒，滅燭延清光。二崔向金陵，安得不盡觴。", "水客弄歸棹，雲帆卷輕霜。扁舟敬亭下，五兩先飄揚。", "峽石入水花，碧流日更長。思君無歲月，西笑阻河梁。"]'),
('yuding-31','登黃山淩歊台送族弟溧陽尉濟充泛舟赴華陰','李白','唐','御定全唐诗','yuding','','[]','鸞乃鳳之族，翱翔紫雲霓。文章輝五色，雙在瓊樹棲。',192,'御定全唐詩/json/177.json','["鸞乃鳳之族，翱翔紫雲霓。文章輝五色，雙在瓊樹棲。", "一朝各飛去，鳳與鸞俱啼。炎赫五月中，朱曦爍河堤。", "爾從泛舟役，使我心魂淒。秦地無碧草，南雲喧鼓鼙。", "君王減玉膳，早起思鳴雞。漕引救關輔，疲人免塗泥。", "宰相作霖雨，農夫得耕犁。靜者伏草間，群才滿金閨。", "空手無壯士，窮居使人低。送君登黃山，長嘯倚天梯。", "小舟若鳧雁，大舟若鯨鯢。開帆散長風，舒卷與雲齊。", "日入牛渚晦，蒼然夕煙迷。相思定何許，杳在洛陽西。"]'),
('yuding-32','送儲邕之武昌','李白','唐','御定全唐诗','yuding','','[]','黃鶴西樓月，長江萬里情。春風三十度，空憶武昌城。',72,'御定全唐詩/json/177.json','["黃鶴西樓月，長江萬里情。春風三十度，空憶武昌城。", "送爾難為別，銜杯惜未傾。湖連張樂地，山逐泛舟行。", "諾為楚人重，詩傳謝脁清。滄浪吾有曲，寄入棹歌聲。"]'),
('yuding-0','酬談少府','李白','唐','御定全唐诗','yuding','','[]','一尉居倏忽，梅生有仙骨。三事或可羞，匈奴哂千秋。',60,'御定全唐詩/json/178.json','["一尉居倏忽，梅生有仙骨。三事或可羞，匈奴哂千秋。", "壯心屈黃綬，浪跡寄滄洲。昨觀荊峴作，如從雲漢遊。", "老夫當暮矣，蹀足懼驊騮。"]'),
('yuding-1','酬宇文少府見贈桃竹書筒','李白','唐','御定全唐诗','yuding','','[]','桃竹書筒綺繡文，良工巧妙稱絕群。靈心圓映三江月，',24,'御定全唐詩/json/178.json','["桃竹書筒綺繡文，良工巧妙稱絕群。靈心圓映三江月，"]'),
('yuding-2','五月東魯行，答汶上君','李白','唐','御定全唐诗','yuding','','[]','五月梅始黃，蠶凋桑柘空。魯人重織作，機杼鳴簾櫳。',108,'御定全唐詩/json/178.json','["五月梅始黃，蠶凋桑柘空。魯人重織作，機杼鳴簾櫳。", "顧餘不及仕，學劍來山東。舉鞭訪前途，獲笑汶上翁。", "下愚忽壯士，未足論窮通。我以一箭書，能取聊城功。", "終然不受賞，羞與時人同。西歸去直道，落日昏陰虹。", "此去爾勿言，甘心為轉蓬。"]'),
('yuding-3','早秋單父南樓酬竇公衡','李白','唐','御定全唐诗','yuding','','[]','白露見日滅，紅顏隨霜凋。別君若俯仰，春芳辭秋條。',72,'御定全唐詩/json/178.json','["白露見日滅，紅顏隨霜凋。別君若俯仰，春芳辭秋條。", "泰山嵯峨夏雲在，疑是白波漲東海。散為飛雨川上來，", "我閉南樓看道書，幽簾清寂在仙居。曾無好事來相訪，"]'),
('yuding-4','山中問答','李白','唐','御定全唐诗','yuding','','[]','問余何意棲碧山，笑而不答心自閑。',32,'御定全唐詩/json/178.json','["問余何意棲碧山，笑而不答心自閑。", "桃花流水窅然去，別有天地非人間。"]'),
('yuding-5','答友人贈烏紗帽','李白','唐','御定全唐诗','yuding','','[]','領得烏紗帽，全勝白接z5。山人不照鏡，稚子道相宜。',25,'御定全唐詩/json/178.json','["領得烏紗帽，全勝白接z5。山人不照鏡，稚子道相宜。"]'),
('yuding-6','酬張司馬贈墨','李白','唐','御定全唐诗','yuding','','[]','上黨碧松煙，夷陵丹砂末。蘭麝凝珍墨，精光乃堪掇。',48,'御定全唐詩/json/178.json','["上黨碧松煙，夷陵丹砂末。蘭麝凝珍墨，精光乃堪掇。", "黃頭奴子雙鴉鬟，錦囊養之懷袖間。今日贈予蘭亭去，"]'),
('yuding-7','答湖州迦葉司馬問白是何人','李白','唐','御定全唐诗','yuding','','[]','青蓮居士謫仙人，酒肆藏名三十春。',32,'御定全唐詩/json/178.json','["青蓮居士謫仙人，酒肆藏名三十春。", "湖州司馬何須問，金粟如來是後身。"]'),
('yuding-8','答長安崔少府叔封游終南翠微寺太宗皇帝金沙泉見寄','李白','唐','御定全唐诗','yuding','','[]','河伯見海若，傲然誇秋水。小物昧遠圖，甯知通方士。',192,'御定全唐詩/json/178.json','["河伯見海若，傲然誇秋水。小物昧遠圖，甯知通方士。", "多君紫霄意，獨往蒼山裏。地古寒雲深，岩高長風起。", "初登翠微嶺，複憩金沙泉。踐苔朝霜滑，弄波夕月圓。", "飲彼石下流，結蘿宿溪煙。鼎湖夢淥水，龍駕空茫然。", "早行子午關，卻登山路遠。拂琴聽霜猿，滅燭乃星飯。", "人煙無明異，鳥道絕往返。攀崖倒青天，下視白日晚。", "既過石門隱，還唱石潭歌。涉雪搴紫芳，濯纓想清波。", "此人不可見，此地君自過。為余謝風泉，其如幽意何。"]'),
('yuding-9','酬崔五郎中','李白','唐','御定全唐诗','yuding','','[]','朔雲橫高天，萬里起秋色。壯士心飛揚，落日空歎息。',204,'御定全唐詩/json/178.json','["朔雲橫高天，萬里起秋色。壯士心飛揚，落日空歎息。", "長嘯出原野，凜然寒風生。幸遭聖明時，功業猶未成。", "奈何懷良圖，鬱悒獨愁坐。杖策尋英豪，立談乃知我。", "崔公生民秀，緬邈青雲姿。製作參造化，托諷含神祇。", "海岳尚可傾，吐諾終不移。是時霜飆寒，逸興臨華池。", "起舞拂長劍，四座皆揚眉。因得窮歡情，贈我以新詩。", "又結汗漫期，九垓遠相待。舉身憩蓬壺，濯足弄滄海。", "從此淩倒景，一去無時還。朝游明光宮，暮入閶闔關。", "但得長把袂，何必嵩丘山。"]'),
('yuding-10','以詩代書答元丹丘','李白','唐','御定全唐诗','yuding','','[]','青鳥海上來，今朝發何處。口銜雲錦字，與我忽飛去。',96,'御定全唐詩/json/178.json','["青鳥海上來，今朝發何處。口銜雲錦字，與我忽飛去。", "鳥去淩紫煙，書留綺窗前。開緘方一笑，乃是故人傳。", "故人深相勖，憶我勞心曲。離居在咸陽，三見秦草綠。", "置書雙袂間，引領不暫閑。長望杳難見，浮雲橫遠山。"]'),
('yuding-11','金門答蘇秀才','李白','唐','御定全唐诗','yuding','','[]','君還石門日，朱火始改木。春草如有情，山中尚含綠。',252,'御定全唐詩/json/178.json','["君還石門日，朱火始改木。春草如有情，山中尚含綠。", "折芳愧遙憶，永路當日勖。遠見故人心，平生以此足。", "巨海納百川，麟閣多才賢。獻書入金闕，酌醴奉瓊筵。", "屢忝白雲唱，恭聞黃竹篇。恩光照拙薄，雲漢希騰遷。", "銘鼎倘雲遂，扁舟方渺然。我留在金門，君去臥丹壑。", "未果三山期，遙欣一丘樂。玄珠寄象罔，赤水非寥廓。", "願狎東海鷗，共營西山藥。棲岩君寂滅，處世余龍蠖。", "良辰不同賞，永日應閒居。鳥吟簷間樹，花落窗下書。", "緣溪見綠筱，隔岫窺紅蕖。采薇行笑歌，眷我情何已。", "月出石鏡間，松鳴風琴裏。得心自虛妙，外物空頹靡。", "身世如兩忘，從君老煙水。"]'),
('yuding-12','酬坊州王司馬與閻正字對雪見贈','李白','唐','御定全唐诗','yuding','','[]','遊子東南來，自宛適京國。飄然無心雲，倏忽複西北。',120,'御定全唐詩/json/178.json','["遊子東南來，自宛適京國。飄然無心雲，倏忽複西北。", "訪戴昔未偶，尋嵇此相得。愁顏發新歡，終宴敘前識。", "閻公漢庭舊，沈郁富才力。價重銅龍樓，聲高重門側。", "甯期此相遇，華館陪遊息。積雪明遠峰，寒城鎖春色。", "主人蒼生望，假我青雲翼。風水如見資，投竿佐皇極。"]'),
('yuding-13','酬中都小吏攜鬥酒雙魚於逆旅見贈','李白','唐','御定全唐诗','yuding','','[]','魯酒若琥珀，汶魚紫錦鱗。山東豪吏有俊氣，',44,'御定全唐詩/json/178.json','["魯酒若琥珀，汶魚紫錦鱗。山東豪吏有俊氣，", "雙鰓呀呷鰭鬣張，蹳剌銀盤欲飛去。呼兒拂幾霜刃揮，"]'),
('yuding-14','酬張卿夜宿南陵見贈','李白','唐','御定全唐诗','yuding','','[]','月出魯城東，明如天上雪。魯女驚莎雞，鳴機應秋節。',180,'御定全唐詩/json/178.json','["月出魯城東，明如天上雪。魯女驚莎雞，鳴機應秋節。", "當君相思夜，火落金風高。河漢掛戶牖，欲濟無輕舠。", "我昔辭林丘，雲龍忽相見。客星動太微，朝去洛陽殿。", "爾來得茂彥，七葉仕漢餘。身為下邳客，家有圯橋書。", "傅說未夢時，終當起岩野。萬古騎辰星，光輝照天下。", "與君各未遇，長策委蒿萊。寶刀隱玉匣，鏽澀空莓苔。", "遂令世上愚，輕我土與灰。一朝攀龍去，蛙黽安在哉。", "故山定有酒，與爾傾金罍。"]'),
('yuding-15','酬岑勳見尋就元丹丘對酒相待，以詩見招','李白','唐','御定全唐诗','yuding','','[]','黃鶴東南來，寄書寫心曲。倚鬆開其緘，憶我腸斷續。',168,'御定全唐詩/json/178.json','["黃鶴東南來，寄書寫心曲。倚鬆開其緘，憶我腸斷續。", "不以千里遙，命駕來相招。中逢元丹丘，登嶺宴碧霄。", "對酒忽思我，長嘯臨清飆。蹇予未相知，茫茫綠雲垂。", "俄然素書及，解此長渴饑。策馬望山月，途窮造階墀。", "喜茲一會面，若睹瓊樹枝。憶君我遠來，我歡方速至。", "開顏酌美酒，樂極忽成醉。我情既不淺，君意方亦深。", "相知兩相得，一顧輕千金。且向山客笑，與君論素心。"]'),
('yuding-16','答從弟幼成過西園見贈','李白','唐','御定全唐诗','yuding','','[]','一身自瀟灑，萬物何囂喧。拙薄謝明時，棲閑歸故園。',108,'御定全唐詩/json/178.json','["一身自瀟灑，萬物何囂喧。拙薄謝明時，棲閑歸故園。", "二季過舊壑，四鄰馳華軒。衣劍照松宇，賓徒光石門。", "山童薦珍果，野老開芳樽。上陳樵漁事，下敘農圃言。", "昨來荷花滿，今見蘭苕繁。一笑複一歌，不知夕景昏。", "醉罷同所樂，此情難具論。"]'),
('yuding-17','酬王補闕惠翼莊廟宋丞泚贈別','李白','唐','御定全唐诗','yuding','','[]','學道三千春，自言羲和人。軒蓋宛若夢，雲松長相親。',120,'御定全唐詩/json/178.json','["學道三千春，自言羲和人。軒蓋宛若夢，雲松長相親。", "偶將二公合，複與三山鄰。喜結海上契，自為天外賓。", "鸞翮我先鎩，龍性君莫馴。朴散不尚古，時訛皆失真。", "勿踏荒溪坡，朅來浩然津。薜帶何辭楚，桃源堪避秦。", "世迫且離別，心在期隱淪。酬贈非炯誡，永言銘佩紳。"]'),
('yuding-18','酬裴侍禦對雨感時見贈','李白','唐','御定全唐诗','yuding','','[]','雨色秋來寒，風嚴清江爽。孤高繡衣人，瀟灑青霞賞。',120,'御定全唐詩/json/178.json','["雨色秋來寒，風嚴清江爽。孤高繡衣人，瀟灑青霞賞。", "平生多感激，忠義非外獎。禍連積怨生，事及徂川往。", "楚邦有壯士，鄢郢翻掃蕩。申包哭秦庭，泣血將安仰。", "鞭屍辱已及，堂上羅宿莽。頗似今之人，蟊賊陷忠讜。", "渺然一水隔，何由稅歸鞅。日夕聽猿怨，懷賢盈夢想。"]'),
('yuding-19','酬崔侍禦','李白','唐','御定全唐诗','yuding','','[]','嚴陵不從萬乘遊，歸臥空山釣碧流。',32,'御定全唐詩/json/178.json','["嚴陵不從萬乘遊，歸臥空山釣碧流。", "自是客星辭帝座，元非太白醉揚州。"]'),
('yuding-20','翫月金陵城西孫楚酒樓達曙歌吹日晚乘醉著紫綺裘烏紗巾與酒客數人櫂歌秦淮往石頭訪崔四侍御','李白','唐','御定全唐诗','yuding','','[]','昨翫西城月，青天垂玉鉤。朝沽金陵酒，歌吹孫楚樓。',180,'御定全唐詩/json/178.json','["昨翫西城月，青天垂玉鉤。朝沽金陵酒，歌吹孫楚樓。", "忽憶繡衣人，乘船往石頭。草裹烏紗巾，倒被紫綺裘。", "兩岸拍手笑，疑是王子猷。酒客十數公，崩騰醉中流。", "謔浪棹海客，喧呼傲陽侯。半道逢吳姬，捲簾出揶揄。", "我憶君到此，不知狂與羞。一月一見君，三杯便回橈。", "舍舟共連袂，行上南渡橋。興發歌綠水，秦客為之搖。", "雞鳴複相招，清宴逸雲霄。贈我數百字，字字淩風飆。", "系之衣裘上，相憶每長謠。"]'),
('yuding-21','江上答崔宣城','李白','唐','御定全唐诗','yuding','','[]','太華三芙蓉，明星玉女峰。尋仙下西嶽，陶令忽相逢。',96,'御定全唐詩/json/178.json','["太華三芙蓉，明星玉女峰。尋仙下西嶽，陶令忽相逢。", "問我將何事，湍波曆幾重。貂裘非季子，鶴氅似王恭。", "謬忝燕台召，而陪郭隗蹤。水流知入海，雲去或從龍。", "樹繞蘆洲月，山鳴鵲鎮鐘。還期如可訪，台嶺蔭長松。"]'),
('yuding-22','答族侄僧中孚贈玉泉仙人掌茶','李白','唐','御定全唐诗','yuding','','[]','常聞玉泉山，山洞多乳窟。仙鼠如白鴉，倒懸清溪月。',120,'御定全唐詩/json/178.json','["常聞玉泉山，山洞多乳窟。仙鼠如白鴉，倒懸清溪月。", "茗生此中石，玉泉流不歇。根柯灑芳津，采服潤肌骨。", "叢老卷綠葉，枝枝相接連。曝成仙人掌，似拍洪崖肩。", "舉世未見之，其名定誰傳。宗英乃禪伯，投贈有佳篇。", "清鏡燭無鹽，顧慚西子妍。朝坐有餘興，長吟播諸天。"]'),
('yuding-23','酬裴侍禦留岫師彈琴見寄','李白','唐','御定全唐诗','yuding','','[]','君同鮑明遠，邀彼休上人。鼓琴亂白雪，秋變江上春。',48,'御定全唐詩/json/178.json','["君同鮑明遠，邀彼休上人。鼓琴亂白雪，秋變江上春。", "瑤草綠未衰，攀翻寄情親。相思兩不見，流淚空盈巾。"]'),
('yuding-24','張相公出鎮荊州尋除太子詹事余時流夜郎行至江夏與張公去千里公因太府丞王昔使車寄羅衣二事及五月五日贈余詩余答以此詩','李白','唐','御定全唐诗','yuding','','[]','張衡殊不樂，應有四愁詩。慚君錦繡段，贈我慰相思。',48,'御定全唐詩/json/178.json','["張衡殊不樂，應有四愁詩。慚君錦繡段，贈我慰相思。", "鴻鵠複矯翼，鳳凰憶故池。榮樂一如此，商山老紫芝。"]'),
('yuding-25','醉後答丁十八以詩譏余捶碎黃鶴樓','李白','唐','御定全唐诗','yuding','','[]','黃鶴高樓已捶碎，黃鶴仙人無所依。黃鶴上天訴玉帝，',64,'御定全唐詩/json/178.json','["黃鶴高樓已捶碎，黃鶴仙人無所依。黃鶴上天訴玉帝，", "一州笑我為狂客，少年往往來相譏。君平簾下誰家子，", "待取明朝酒醒罷，與君爛漫尋春暉。"]'),
('yuding-26','答裴侍禦先行至石頭驛以書見招，期月滿泛洞庭','李白','唐','御定全唐诗','yuding','','[]','君至石頭驛，寄書黃鶴樓。開緘識遠意，速此南行舟。',96,'御定全唐詩/json/178.json','["君至石頭驛，寄書黃鶴樓。開緘識遠意，速此南行舟。", "風水無定準，湍波或滯留。憶昨新月生，西簷若瓊鉤。", "今來何所似，破鏡懸清秋。恨不三五明，平湖泛澄流。", "此歡竟莫遂，狂殺王子猷。巴陵定遙遠，持贈解人憂。"]'),
('yuding-27','答高山人兼呈權、顧二侯','李白','唐','御定全唐诗','yuding','','[]','虹霓掩天光，哲後起康濟。應運生夔龍，開元掃氛翳。',240,'御定全唐詩/json/178.json','["虹霓掩天光，哲後起康濟。應運生夔龍，開元掃氛翳。", "太微廓金鏡，端拱清遐裔。輕塵集嵩嶽，虛點盛明意。", "謬揮紫泥詔，獻納青雲際。讒惑英主心，恩疏佞臣計。", "彷徨庭闕下，歎息光陰逝。未作仲宣詩，先流賈生涕。", "掛帆秋江上，不為雲羅制。山海向東傾，百川無盡勢。", "我於鴟夷子，相去千餘歲。運闊英達稀，同風遙執袂。", "登艫望遠水，忽見滄浪枻。高士何處來，虛舟渺安系。", "衣貌本淳古，文章多佳麗。延引故鄉人，風義未淪替。", "顧侯達語默，權子識通蔽。曾是無心雲，俱為此留滯。", "雙萍易飄轉，獨鶴思淩曆。明晨去瀟湘，共謁蒼梧帝。"]'),
('yuding-28','答杜秀才五松見贈','李白','唐','御定全唐诗','yuding','','[]','昔獻長楊賦，天開雲雨歡。當時待詔承明裏，',156,'御定全唐詩/json/178.json','["昔獻長楊賦，天開雲雨歡。當時待詔承明裏，", "浮雲蔽日去不返，總為秋風摧紫蘭。角巾東出商山道，", "聞道金陵龍虎盤，還同謝脁望長安。千峰夾水向秋浦，", "陶公矍鑠呵赤電，回祿睢盱揚紫煙。此中豈是久留處，", "登崖獨立望九州，陽春欲奏誰相和。聞君往年遊錦城，", "骯髒不能就珪組，至今空揚高蹈名。夫子工文絕世奇，", "從茲一別武陵去，去後桃花春水深。"]'),
('yuding-29','至陵陽山登天柱石，酬韓侍禦見招隱黃山','李白','唐','御定全唐诗','yuding','','[]','韓眾騎白鹿，西往華山中。玉女千餘人，相隨在雲空。',180,'御定全唐詩/json/178.json','["韓眾騎白鹿，西往華山中。玉女千餘人，相隨在雲空。", "見我傳秘訣，精誠與天通。何意到陵陽，遊目送飛鴻。", "天子昔避狄，與君亦乘驄。擁兵五陵下，長策遏胡戎。", "時泰解繡衣，脫身若飛蓬。鸞鳳翻羽翼，啄粟坐樊籠。", "海鶴一笑之，思歸向遼東。黃山過石柱，巘崿上攢叢。", "因巢翠玉樹，忽見浮丘公。又引王子喬，吹笙舞松風。", "朗詠紫霞篇，請開蕊珠宮。步綱繞碧落，倚樹招青童。", "何日可攜手，遺形入無窮。"]'),
('yuding-30','酬崔十五見招','李白','唐','御定全唐诗','yuding','','[]','爾有鳥跡書，相招琴溪飲。手跡尺素中，如天落雲錦。',48,'御定全唐詩/json/178.json','["爾有鳥跡書，相招琴溪飲。手跡尺素中，如天落雲錦。", "讀罷向空笑，疑君在我前。長吟字不滅，懷袖且三年。"]'),
('yuding-31','答王十二寒夜獨酌有懷','李白','唐','御定全唐诗','yuding','','[]','昨夜吳中雪，子猷佳興發。萬里浮雲卷碧山，',201,'御定全唐詩/json/178.json','["昨夜吳中雪，子猷佳興發。萬里浮雲卷碧山，", "懷餘對酒夜霜白，玉床金井水崢嶸。人生飄忽百年內，", "世人聞此皆掉頭，有如東風射馬耳。魚目亦笑我，", "折楊皇華合流俗，晉君聽琴枉清角。巴人誰肯和陽春。", "楚地由來賤奇璞。黃金散盡交不成，白首為儒身被輕。", "一談一笑失顏色，蒼蠅貝錦喧謗聲。曾參豈是殺人者，", "孔聖猶聞傷鳳麟，董龍更是何雞狗。一生傲岸苦不諧，", "韓信羞將絳灌比，禰衡恥逐屠沽兒。君不見李北海，", "少年早欲五湖去，見此彌將鐘鼎疏。"]'),
('yuding-0','遊南陽白水登石激作','李白','唐','御定全唐诗','yuding','','[]','朝涉白水源，暫與人俗疏。島嶼佳境色，江天涵清虛。',48,'御定全唐詩/json/179.json','["朝涉白水源，暫與人俗疏。島嶼佳境色，江天涵清虛。", "目送去海雲，心閒遊川魚。長歌盡落日，乘月歸田廬。"]'),
('yuding-1','遊南陽清泠泉','李白','唐','御定全唐诗','yuding','','[]','惜彼落日暮，愛此寒泉清。西輝逐流水，蕩漾遊子情。',36,'御定全唐詩/json/179.json','["惜彼落日暮，愛此寒泉清。西輝逐流水，蕩漾遊子情。", "空歌望雲月，曲盡長松聲。"]'),
('yuding-2','尋魯城北范居士失道落蒼耳中見範置酒摘蒼耳作','李白','唐','御定全唐诗','yuding','','[]','雁度秋色遠，日靜無雲時。客心不自得，浩漫將何之。',168,'御定全唐詩/json/179.json','["雁度秋色遠，日靜無雲時。客心不自得，浩漫將何之。", "忽憶範野人，閑園養幽姿。茫然起逸興，但恐行來遲。", "城壕失往路，馬首迷荒陂。不惜翠雲裘，遂為蒼耳欺。", "入門且一笑，把臂君為誰。酒客愛秋蔬，山盤薦霜梨。", "他筵不下箸，此席忘朝饑。酸棗垂北郭，寒瓜蔓東籬。", "還傾四五酌，自詠猛虎詞。近作十日歡，遠為千載期。", "風流自簸蕩，謔浪偏相宜。酣來上馬去，卻笑高陽池。"]'),
('yuding-3','東魯門泛舟二首','李白','唐','御定全唐诗','yuding','','[]','日落沙明天倒開，波搖石動水縈回。',64,'御定全唐詩/json/179.json','["日落沙明天倒開，波搖石動水縈回。", "輕舟泛月尋溪轉，疑是山陰雪後來。", "水作青龍磐石堤，桃花夾岸魯門西。", "若教月下乘舟去，何啻風流到剡溪。"]'),
('yuding-4','秋獵孟諸夜歸，置酒單父東樓觀妓','李白','唐','御定全唐诗','yuding','','[]','傾暉速短炬，走海無停川。冀餐圓丘草，欲以還頹年。',120,'御定全唐詩/json/179.json','["傾暉速短炬，走海無停川。冀餐圓丘草，欲以還頹年。", "此事不可得，微生若浮煙。駿發跨名駒，雕弓控鳴弦。", "鷹豪魯草白，狐兔多肥鮮。邀遮相馳逐，遂出城東田。", "一掃四野空，喧呼鞍馬前。歸來獻所獲，炮炙宜霜天。", "出舞兩美人，飄颻若雲仙。留歡不知疲，清曉方來旋。"]'),
('yuding-5','游泰山六首','李白','唐','御定全唐诗','yuding','','[]','四月上泰山，石屏禦道開。六龍過萬壑，澗穀隨縈回。',540,'御定全唐詩/json/179.json','["四月上泰山，石屏禦道開。六龍過萬壑，澗穀隨縈回。", "馬跡繞碧峰，於今滿青苔。飛流灑絕巘，水急松聲哀。", "北眺崿嶂奇，傾崖向東摧。洞門閉石扇，地底興雲雷。", "登高望蓬瀛，想像金銀台。天門一長嘯，萬里清風來。", "玉女四五人，飄颻下九垓。含笑引素手，遺我流霞杯。", "稽首再拜之，自愧非仙才。曠然小宇宙，棄世何悠哉。", "清曉騎白鹿，直上天門山。山際逢羽人，方瞳好容顏。", "捫蘿欲就語，卻掩青雲關。遺我鳥跡書，飄然落岩間。", "其字乃上古，讀之了不閑。感此三歎息，從師方未還。", "平明登日觀，舉手開雲關。精神四飛揚，如出天地間。", "黃河從西來，窈窕入遠山。憑崖攬八極，目盡長空閒。", "偶然值青童，綠發雙雲鬟。笑我晚學仙，蹉跎凋朱顏。", "躊躇忽不見，浩蕩難追攀。", "清齋三千日，裂素寫道經。吟誦有所得，眾神衛我形。", "雲行信長風，颯若羽翼生。攀崖上日觀，伏檻窺東暝。", "海色動遠山，天雞已先鳴。銀台出倒景，白浪翻長鯨。", "安得不死藥，高飛向蓬瀛。", "日觀東北傾，兩崖夾雙石。海水落眼前，天光遙空碧。", "千峰爭攢聚，萬壑絕淩曆。緬彼鶴上仙，去無雲中跡。", "長松入雲漢，遠望不盈尺。山花異人間，五月雪中白。", "終當遇安期，於此煉玉液。", "朝飲王母池，暝投天門關。獨抱綠綺琴，夜行青山間。", "山明月露白，夜靜松風歇。仙人游碧峰，處處笙歌發。", "寂靜娛清暉，玉真連翠微。想像鸞鳳舞，飄颻龍虎衣。"]'),
('yuding-6','秋夜與劉碭山泛宴喜亭池','李白','唐','御定全唐诗','yuding','','[]','明宰試舟楫，張燈宴華池。文招梁苑客，歌動郢中兒。',48,'御定全唐詩/json/179.json','["明宰試舟楫，張燈宴華池。文招梁苑客，歌動郢中兒。", "月色望不盡，空天交相宜。令人欲泛海，只待長風吹。"]'),
('yuding-7','攜妓登梁王棲霞山孟氏桃園中','李白','唐','御定全唐诗','yuding','','[]','碧草已滿地，柳與梅爭春。謝公自有東山妓，',57,'御定全唐詩/json/179.json','["碧草已滿地，柳與梅爭春。謝公自有東山妓，", "白髮對綠酒，強歌心已摧。君不見梁王池上月，", "分明感激眼前事，莫惜醉臥桃園東。"]'),
('yuding-8','與從侄杭州刺史良游天竺寺','李白','唐','御定全唐诗','yuding','','[]','掛席淩蓬丘，觀濤憩樟樓。三山動逸興，五馬同遨遊。',72,'御定全唐詩/json/179.json','["掛席淩蓬丘，觀濤憩樟樓。三山動逸興，五馬同遨遊。", "天竺森在眼，松風颯驚秋。覽雲測變化，弄水窮清幽。", "疊嶂隔遙海，當軒寫歸流。詩成傲雲月，佳趣滿吳洲。"]'),
('yuding-9','同友人舟行游台越作','李白','唐','御定全唐诗','yuding','','[]','楚臣傷江楓，謝客拾海月。懷沙去瀟湘，掛席泛溟渤。',96,'御定全唐詩/json/179.json','["楚臣傷江楓，謝客拾海月。懷沙去瀟湘，掛席泛溟渤。", "蹇予訪前跡，獨往造窮發。古人不可攀，去若浮雲沒。", "願言弄倒景，從此煉真骨。華頂窺絕溟，蓬壺望超忽。", "不知青春度，但怪綠芳歇。空持釣鼇心，從此謝魏闕。"]'),
('yuding-10','下終南山過斛斯山人宿置酒','李白','唐','御定全唐诗','yuding','','[]','暮從碧山下，山月隨人歸。卻顧所來徑，蒼蒼橫翠微。',84,'御定全唐詩/json/179.json','["暮從碧山下，山月隨人歸。卻顧所來徑，蒼蒼橫翠微。", "相攜及田家，童稚開荊扉。綠竹入幽徑，青蘿拂行衣。", "歡言得所憩，美酒聊共揮。長歌吟松風，曲盡河星稀。", "我醉君複樂，陶然共忘機。"]'),
('yuding-11','朝下過盧郎中敘舊游','李白','唐','御定全唐诗','yuding','','[]','君登金華省，我入銀台門。幸遇聖明主，俱承雲雨恩。',72,'御定全唐詩/json/179.json','["君登金華省，我入銀台門。幸遇聖明主，俱承雲雨恩。", "複此休浣時，閑為疇昔言。卻話山海事，宛然林壑存。", "明湖思曉月，疊嶂憶清猿。何由返初服，田野醉芳樽。"]'),
('yuding-12','侍從游宿溫泉宮作','李白','唐','御定全唐诗','yuding','','[]','羽林十二將，羅列應星文。霜仗懸秋月，霓旌卷夜雲。',48,'御定全唐詩/json/179.json','["羽林十二將，羅列應星文。霜仗懸秋月，霓旌卷夜雲。", "嚴更千戶肅，清樂九天聞。日出瞻佳氣，蔥蔥繞聖君。"]'),
('yuding-13','邯鄲南亭觀妓','李白','唐','御定全唐诗','yuding','','[]','歌鼓燕趙兒，魏姝弄鳴絲。粉色豔日彩，舞袖拂花枝。',84,'御定全唐詩/json/179.json','["歌鼓燕趙兒，魏姝弄鳴絲。粉色豔日彩，舞袖拂花枝。", "把酒顧美人，請歌邯鄲詞。清箏何繚繞，度曲綠雲垂。", "平原君安在，科鬥生古池。座客三千人，於今知有誰。", "我輩不作樂，但為後代悲。"]'),
('yuding-14','春日游羅敷潭','李白','唐','御定全唐诗','yuding','','[]','行歌入谷口，路盡無人躋。攀崖度絕壑，弄水尋回溪。',48,'御定全唐詩/json/179.json','["行歌入谷口，路盡無人躋。攀崖度絕壑，弄水尋回溪。", "雲從石上起，客到花間迷。淹留未盡興，日落群峰西。"]'),
('yuding-15','春陪商州裴使君游石娥溪','李白','唐','御定全唐诗','yuding','','[]','裴公有仙標，拔俗數千丈。澹蕩滄洲雲，飄颻紫霞想。',168,'御定全唐詩/json/179.json','["裴公有仙標，拔俗數千丈。澹蕩滄洲雲，飄颻紫霞想。", "剖竹商洛間，政成心已閑。蕭條出世表，冥寂閉玄關。", "我來屬芳節，解榻時相悅。褰帷對雲峰，揚袂指松雪。", "暫出東城邊，遂遊西岩前。橫天聳翠壁，噴壑鳴紅泉。", "尋幽殊未歇，愛此春光發。溪傍饒名花，石上有好月。", "命駕歸去來，露華生翠苔。淹留惜將晚，複聽清猿哀。", "清猿斷人腸，遊子思故鄉。明發首東路，此歡焉可忘。"]'),
('yuding-16','陪從祖濟南太守泛鵲山湖三首','李白','唐','御定全唐诗','yuding','','[]','初謂鵲山近，寧知湖水遙。此行殊訪戴，自可緩歸橈。',72,'御定全唐詩/json/179.json','["初謂鵲山近，寧知湖水遙。此行殊訪戴，自可緩歸橈。", "湖闊數千里，湖光搖碧山。湖西正有月，獨送李膺還。", "水入北湖去，舟從南浦回。遙看鵲山轉，卻似送人來。"]'),
('yuding-17','春日陪楊江甯及諸官宴北湖感古作','李白','唐','御定全唐诗','yuding','','[]','昔聞顏光祿，攀龍宴京湖。樓船入天鏡，帳殿開雲衢。',168,'御定全唐詩/json/179.json','["昔聞顏光祿，攀龍宴京湖。樓船入天鏡，帳殿開雲衢。", "君王歌大風，如樂豐沛都。延年獻佳作，邈與詩人俱。", "我來不及此，獨立鐘山孤。楊宰穆清風，芳聲騰海隅。", "英僚滿四座，粲若瓊林敷。鷁首弄倒景，蛾眉綴明珠。", "新弦采梨園，古舞嬌吳歈。曲度繞雲漢，聽者皆歡娛。", "雞棲何嘈嘈，沿月沸笙竽。古之帝宮苑，今乃人樵蘇。", "感此勸一觴，願君覆瓢壺。榮盛當作樂，無令後賢籲。"]'),
('yuding-18','宴鄭參卿山池','李白','唐','御定全唐诗','yuding','','[]','爾恐碧草晚，我畏朱顏移。愁看楊花飛，置酒正相宜。',48,'御定全唐詩/json/179.json','["爾恐碧草晚，我畏朱顏移。愁看楊花飛，置酒正相宜。", "歌聲送落日，舞影回清池。今夕不盡杯，留歡更邀誰。"]'),
('yuding-19','游謝氏山亭','李白','唐','御定全唐诗','yuding','','[]','淪老臥江海，再歡天地清。病閑久寂寞，歲物徒芬榮。',96,'御定全唐詩/json/179.json','["淪老臥江海，再歡天地清。病閑久寂寞，歲物徒芬榮。", "借君西池遊，聊以散我情。掃雪松下去，捫蘿石道行。", "謝公池塘上，春草颯已生。花枝拂人來，山鳥向我鳴。", "田家有美酒，落日與之傾。醉罷弄歸月，遙欣稚子迎。"]'),
('yuding-20','把酒問月','李白','唐','御定全唐诗','yuding','','[]','青天有月來幾時，我今停杯一問之。人攀明月不可得，',72,'御定全唐詩/json/179.json','["青天有月來幾時，我今停杯一問之。人攀明月不可得，", "但見宵從海上來，甯知曉向雲間沒。白兔搗藥秋複春，", "古人今人若流水，共看明月皆如此。唯願當歌對酒時，"]'),
('yuding-21','同族侄評事黯游昌禪師山池二首','李白','唐','御定全唐诗','yuding','','[]','遠公愛康樂，為我開禪關。蕭然松石下，何異清涼山。',96,'御定全唐詩/json/179.json','["遠公愛康樂，為我開禪關。蕭然松石下，何異清涼山。", "花將色不染，水與心俱閑。一坐度小劫，觀空天地間。", "客來花雨際，秋水落金池。片石寒青錦，疏楊掛綠絲。", "高僧拂玉柄，童子獻霜梨。惜去愛佳景，煙蘿欲暝時。"]'),
('yuding-22','金陵鳳凰台置酒','李白','唐','御定全唐诗','yuding','','[]','置酒延落景，金陵鳳凰台。長波寫萬古，心與雲俱開。',108,'御定全唐詩/json/179.json','["置酒延落景，金陵鳳凰台。長波寫萬古，心與雲俱開。", "借問往昔時，鳳凰為誰來。鳳凰去已久，正當今日回。", "明君越羲軒，天老坐三台。豪士無所用，彈弦醉金罍。", "東風吹山花，安可不盡杯。六帝沒幽草，深宮冥綠苔。", "置酒勿複道，歌鐘但相催。"]'),
('yuding-23','秋浦清溪雪夜對酒，客有唱山鷓鴣者','李白','唐','御定全唐诗','yuding','','[]','披君貂襜褕，對君白玉壺。雪花酒上滅，頓覺夜寒無。',60,'御定全唐詩/json/179.json','["披君貂襜褕，對君白玉壺。雪花酒上滅，頓覺夜寒無。", "客有桂陽至，能吟山鷓鴣。清風動窗竹，越鳥起相呼。", "持此足為樂，何煩笙與竽。"]'),
('yuding-24','與周剛清溪玉鏡潭宴別','李白','唐','御定全唐诗','yuding','','[]','康樂上官去，永嘉游石門。江亭有孤嶼，千載跡猶存。',132,'御定全唐詩/json/179.json','["康樂上官去，永嘉游石門。江亭有孤嶼，千載跡猶存。", "我來遊秋浦，三入桃陂源。千峰照積雪，萬壑盡啼猿。", "興與謝公合，文因周子論。掃崖去落葉，席月開清樽。", "溪當大樓南，溪水正南奔。回作玉鏡潭，澄明洗心魂。", "此中得佳境，可以絕囂喧。清夜方歸來，酣歌出平原。", "別後經此地，為余謝蘭蓀。"]'),
('yuding-25','游秋浦白笴陂二首','李白','唐','御定全唐诗','yuding','','[]','何處夜行好，月明白笴陂。山光搖積雪，猿影掛寒枝。',96,'御定全唐詩/json/179.json','["何處夜行好，月明白笴陂。山光搖積雪，猿影掛寒枝。", "但恐佳景晚，小令歸棹移。人來有清興，及此有相思。", "白笴夜長嘯，爽然溪穀寒。魚龍動陂水，處處生波瀾。", "天借一明月，飛來碧雲端。故鄉不可見，腸斷正西看。"]'),
('yuding-26','宴陶家亭子','李白','唐','御定全唐诗','yuding','','[]','曲巷幽人宅，高門大士家。池開照膽鏡，林吐破顏花。',48,'御定全唐詩/json/179.json','["曲巷幽人宅，高門大士家。池開照膽鏡，林吐破顏花。", "綠水藏春日，青軒秘晚霞。若聞弦管妙，金穀不能誇。"]'),
('yuding-27','在水軍宴韋司馬樓船觀妓','李白','唐','御定全唐诗','yuding','','[]','搖曳帆在空，清流順歸風。詩因鼓吹發，酒為劍歌雄。',48,'御定全唐詩/json/179.json','["搖曳帆在空，清流順歸風。詩因鼓吹發，酒為劍歌雄。", "對舞青樓妓，雙鬟白玉童。行雲且莫去，留醉楚王宮。"]'),
('yuding-28','流夜郎至江夏，陪長史叔及薛明府宴興德寺南閣','李白','唐','御定全唐诗','yuding','','[]','紺殿橫江上，青山落鏡中。岸回沙不盡，日映水成空。',48,'御定全唐詩/json/179.json','["紺殿橫江上，青山落鏡中。岸回沙不盡，日映水成空。", "天樂流香閣，蓮舟颺晚風。恭陪竹林宴，留醉與陶公。"]'),
('yuding-29','泛沔州城南郎官湖','李白','唐','御定全唐诗','yuding','','[]','張公多逸興，共泛沔城隅。當時秋月好，不減武昌都。',60,'御定全唐詩/json/179.json','["張公多逸興，共泛沔城隅。當時秋月好，不減武昌都。", "四座醉清光，為歡古來無。郎官愛此水，因號郎官湖。", "風流若未減，名與此山俱。"]'),
('yuding-30','陪侍郎叔游洞庭醉後三首','李白','唐','御定全唐诗','yuding','','[]','今日竹林宴，我家賢侍郎。三杯容小阮，醉後發清狂。',72,'御定全唐詩/json/179.json','["今日竹林宴，我家賢侍郎。三杯容小阮，醉後發清狂。", "船上齊橈樂，湖心泛月歸。白鷗閑不去，爭拂酒筵飛。", "剗卻君山好，平鋪湘水流。巴陵無限酒，醉殺洞庭秋。"]'),
('yuding-31','夜泛洞庭，尋裴侍禦清酌','李白','唐','御定全唐诗','yuding','','[]','日晚湘水綠，孤舟無端倪。明湖漲秋月，獨泛巴陵西。',72,'御定全唐詩/json/179.json','["日晚湘水綠，孤舟無端倪。明湖漲秋月，獨泛巴陵西。", "過憩裴逸人，岩居陵丹梯。抱琴出深竹，為我彈鶤雞。", "曲盡酒亦傾，北窗醉如泥。人生且行樂，何必組與珪。"]'),
('yuding-32','陪族叔刑部侍郎曄及中書賈舍人至遊洞庭五首','李白','唐','御定全唐诗','yuding','','[]','洞庭西望楚江分，水盡南天不見雲。',160,'御定全唐詩/json/179.json','["洞庭西望楚江分，水盡南天不見雲。", "日落長沙秋色遠，不知何處吊湘君。", "南湖秋水夜無煙，耐可乘流直上天。", "且就洞庭賒月色，將船買酒白雲邊。", "洛陽才子謫湘川，元禮同舟月下仙。", "記得長安還欲笑，不知何處是西天。", "洞庭湖西秋月輝，瀟湘江北早鴻飛。", "醉客滿船歌白苧，不知霜露入秋衣。", "帝子瀟湘去不還，空餘秋草洞庭間。", "淡掃明湖開玉鏡，丹青畫出是君山。"]'),
('yuding-33','楚江黃龍磯南宴楊執戟治樓','李白','唐','御定全唐诗','yuding','','[]','五月入五洲，碧山對青樓。故人楊執戟，春賞楚江流。',48,'御定全唐詩/json/179.json','["五月入五洲，碧山對青樓。故人楊執戟，春賞楚江流。", "一見醉漂月，三杯歌棹謳。桂枝攀不盡，他日更相求。"]'),
('yuding-34','銅官山醉後絕句','李白','唐','御定全唐诗','yuding','','[]','我愛銅官樂，千年未擬還。要須回舞袖，拂盡五松山。',24,'御定全唐詩/json/179.json','["我愛銅官樂，千年未擬還。要須回舞袖，拂盡五松山。"]'),
('yuding-35','與南陵常贊府遊五松山','李白','唐','御定全唐诗','yuding','','[]','安石泛溟渤，獨嘯長風還。逸韻動海上，高情出人間。',120,'御定全唐詩/json/179.json','["安石泛溟渤，獨嘯長風還。逸韻動海上，高情出人間。", "靈異可並跡，澹然與世閑。我來五松下，置酒窮躋攀。", "征古絕遺老，因名五松山。五松何清幽，勝境美沃州。", "蕭颯鳴洞壑，終年風雨秋。響入百泉去，聽如三峽流。", "剪竹掃天花，且從傲吏遊。龍堂若可憩，吾欲歸精修。"]'),
('yuding-36','宣城青溪','李白','唐','御定全唐诗','yuding','','[]','青溪勝桐廬，水木有佳色。山貌日高古，石容天傾側。',48,'御定全唐詩/json/179.json','["青溪勝桐廬，水木有佳色。山貌日高古，石容天傾側。", "彩鳥昔未名，白猿初相識。不見同懷人，對之空歎息。"]'),
('yuding-37','與謝良輔遊涇川陵岩寺','李白','唐','御定全唐诗','yuding','','[]','乘君素舸泛涇西，宛似雲門對若溪。',32,'御定全唐詩/json/179.json','["乘君素舸泛涇西，宛似雲門對若溪。", "且從康樂尋山水，何必東遊入會稽。"]'),
('yuding-38','游水西簡鄭明府','李白','唐','御定全唐诗','yuding','','[]','天宮水西寺，雲錦照東郭。清湍鳴回溪，綠水繞飛閣。',96,'御定全唐詩/json/179.json','["天宮水西寺，雲錦照東郭。清湍鳴回溪，綠水繞飛閣。", "涼風日瀟灑，幽客時憩泊。五月思貂裘，謂言秋霜落。", "石蘿引古蔓，岸筍開新籜。吟玩空複情，相思爾佳作。", "鄭公詩人秀，逸韻宏寥廓。何當一來遊，愜我雪山諾。"]'),
('yuding-39','九日登山','李白','唐','御定全唐诗','yuding','','[]','淵明歸去來，不與世相逐。為無杯中物，遂偶本州牧。',204,'御定全唐詩/json/179.json','["淵明歸去來，不與世相逐。為無杯中物，遂偶本州牧。", "因招白衣人，笑酌黃花菊。我來不得意，虛過重陽時。", "題輿何俊發，遂結城南期。築土按響山，俯臨宛水湄。", "胡人叫玉笛，越女彈霜絲。自作英王胄，斯樂不可窺。", "赤鯉湧琴高，白龜道馮夷。靈仙如仿佛，奠酹遙相知。", "古來登高人，今複幾人在。滄洲違宿諾，明日猶可待。", "連山似驚波，合遝出溟海。揚袂揮四座，酩酊安所知。", "齊歌送清揚，起舞亂參差。賓隨落葉散，帽逐秋風吹。", "別後登此台，願言長相思。"]'),
('yuding-40','九日','李白','唐','御定全唐诗','yuding','','[]','今日雲景好，水綠秋山明。攜壺酌流霞，搴菊泛寒榮。',60,'御定全唐詩/json/179.json','["今日雲景好，水綠秋山明。攜壺酌流霞，搴菊泛寒榮。", "地遠松石古，風揚弦管清。窺觴照歡顏，獨笑還自傾。", "落帽醉山月，空歌懷友生。"]');
